window.KJV1769_STRONG_BOOKS["Gen"] = {"osis":"Gen","book":"창세기","verses":{"1:1":{"text":"In the beginning God created the heaven and the earth.","words":[["H7225","In the beginning",0,16],["H0430","God",17,20],["H1254","created",21,28],["H0853","",-1,-1],["H8064","the heaven",29,39],["H0853","and",40,43],["H0776","the earth",44,53]]},"1:2":{"text":"And the earth was without form, and void; and darkness was upon the face of the deep. And the Spirit of God moved upon the face of the waters.","words":[["H0776","And the earth",0,13],["H1961","was",14,17],["H8414","without form",18,30],["H0922","and void",32,40],["H2822","and darkness",42,54],["H6440","was upon the face",55,72],["H8415","of the deep",73,84],["H7307","And the Spirit",86,100],["H0430","of God",101,107],["H7363","moved",108,113],["H5921","upon",114,118],["H6440","the face",119,127],["H4325","of the waters",128,141]]},"1:3":{"text":"And God said, Let there be light: and there was light.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H1961","Let there be",14,26],["H0216","light",27,32],["H0216","and there was light",34,53]]},"1:4":{"text":"And God saw the light, that it was good: and God divided the light from the darkness.","words":[["H0430","And God",0,7],["H7200","saw",8,11],["H0853","",-1,-1],["H0216","the light",12,21],["H3588","that",23,27],["H2896","it was good",28,39],["H0430","and God",41,48],["H0914","divided",49,56],["H0996","divided",49,56],["H0216","the light",57,66],["H0996","from",67,71],["H2822","the darkness",72,84]]},"1:5":{"text":"And God called the light Day, and the darkness he called Night. And the evening and the morning were the first day.","words":[["H0430","And God",0,7],["H7121","called",8,14],["H0216","the light",15,24],["H3117","Day",25,28],["H2822","and the darkness",30,46],["H7121","he called",47,56],["H3915","Night",57,62],["H6153","And the evening",64,79],["H1242","and the morning",80,95],["H0259","were the first",96,110],["H3117","day",111,114]]},"1:6":{"text":"And God said, Let there be a firmament in the midst of the waters, and let it divide the waters from the waters.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H7549","Let there be a firmament",14,38],["H8432","in the midst",39,51],["H4325","of the waters",52,65],["H0914","and let it divide",67,84],["H4325","the waters",85,95],["H4325","from the waters",96,111]]},"1:7":{"text":"And God made the firmament, and divided the waters which were under the firmament from the waters which were above the firmament: and it was so.","words":[["H0430","And God",0,7],["H6213","made",8,12],["H7549","the firmament",13,26],["H0914","and divided",28,39],["H4325","the waters",40,50],["H0834","which",51,56],["H8478","were under",57,67],["H7549","the firmament",68,81],["H4325","from the waters",82,97],["H0834","which",98,103],["H5921","were above",104,114],["H7549","the firmament",115,128],["H3651","and it was so",130,143]]},"1:8":{"text":"And God called the firmament Heaven. And the evening and the morning were the second day.","words":[["H0430","And God",0,7],["H7121","called",8,14],["H7549","the firmament",15,28],["H8064","Heaven",29,35],["H6153","And the evening",37,52],["H1242","and the morning",53,68],["H8145","were the second",69,84],["H3117","day",85,88]]},"1:9":{"text":"And God said, Let the waters under the heaven be gathered together unto one place, and let the dry land appear: and it was so.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H4325","Let the waters",14,28],["H8064","under the heaven",29,45],["H6960","be gathered together",46,66],["H0413","unto",67,71],["H0259","one",72,75],["H4725","place",76,81],["H3004","and let the dry",83,98],["H7200","land appear",99,110]]},"1:10":{"text":"And God called the dry land Earth; and the gathering together of the waters called he Seas: and God saw that it was good.","words":[["H0430","And God",0,7],["H7121","called",8,14],["H3004","the dry",15,22],["H0776","land Earth",23,33],["H4723","and the gathering together",35,61],["H4325","of the waters",62,75],["H7121","called",76,82],["H3220","he Seas",83,90],["H0430","and God",92,99],["H7200","saw",100,103],["H2896","that it was good",104,120]]},"1:11":{"text":"And God said, Let the earth bring forth grass, the herb yielding seed, and the fruit tree yielding fruit after his kind, whose seed is in itself, upon the earth: and it was so.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0776","Let the earth",14,27],["H1876","bring forth",28,39],["H1877","grass",40,45],["H6212","the herb",47,55],["H2232","yielding",56,64],["H2233","seed",65,69],["H6529","and the fruit",71,84],["H6086","tree",85,89],["H6213","yielding",90,98],["H6529","fruit",99,104],["H4327","after his kind",105,119],["H0834","whose",121,126],["H2233","seed",127,131],["H0776","is in itself, upon the earth",132,160]]},"1:12":{"text":"And the earth brought forth grass, and herb yielding seed after his kind, and the tree yielding fruit, whose seed was in itself, after his kind: and God saw that it was good.","words":[["H0776","And the earth",0,13],["H3318","brought forth",14,27],["H1877","grass",28,33],["H6212","and herb",35,43],["H2232","yielding",44,52],["H2233","seed",53,57],["H4327","after his kind",58,72],["H6086","and the tree",74,86],["H6213","yielding",87,95],["H6529","fruit",96,101],["H2233","whose seed",103,113],["H4327","was in itself, after his kind",114,143],["H0430","and God",145,152],["H7200","saw",153,156],["H2896","that it was good",157,173]]},"1:13":{"text":"And the evening and the morning were the third day.","words":[["H6153","And the evening",0,15],["H1242","and the morning",16,31],["H7992","were the third",32,46],["H3117","day",47,50]]},"1:14":{"text":"And God said, Let there be lights in the firmament of the heaven to divide the day from the night; and let them be for signs, and for seasons, and for days, and years:","words":[["H0430","And God",0,7],["H0559","said",8,12],["H3974","Let there be lights",14,33],["H7549","in the firmament",34,50],["H8064","of the heaven",51,64],["H0914","to divide",65,74],["H3117","the day",75,82],["H3915","from the night",83,97],["H0226","and let them be for signs",99,124],["H4150","and for seasons",126,141],["H3117","and for days",143,155],["H8141","and years",157,166]]},"1:15":{"text":"And let them be for lights in the firmament of the heaven to give light upon the earth: and it was so.","words":[["H3974","And let them be for lights",0,26],["H7549","in the firmament",27,43],["H8064","of the heaven",44,57],["H0215","to give light",58,71],["H0776","upon the earth",72,86]]},"1:16":{"text":"And God made two great lights; the greater light to rule the day, and the lesser light to rule the night: he made the stars also.","words":[["H0430","And God",0,7],["H6213","made",8,12],["H8147","two",13,16],["H1419","great",17,22],["H3974","lights",23,29],["H1419","the greater",31,42],["H3974","light",43,48],["H4475","to rule",49,56],["H3117","the day",57,64],["H6996","and the lesser",66,80],["H3974","light",81,86],["H4475","to rule",87,94],["H3915","the night",95,104],["H3556","he made the stars",106,123]]},"1:17":{"text":"And God set them in the firmament of the heaven to give light upon the earth,","words":[["H0430","And God",0,7],["H5414","set",8,11],["H7549","them in the firmament",12,33],["H8064","of the heaven",34,47],["H0215","to give light",48,61],["H0776","upon the earth",62,76]]},"1:18":{"text":"And to rule over the day and over the night, and to divide the light from the darkness: and God saw that it was good.","words":[["H4910","And to rule",0,11],["H3117","over the day",12,24],["H3915","and over the night",25,43],["H0914","and to divide",45,58],["H0216","the light",59,68],["H2822","from the darkness",69,86],["H0430","and God",88,95],["H7200","saw",96,99],["H2896","that it was good",100,116]]},"1:19":{"text":"And the evening and the morning were the fourth day.","words":[["H6153","And the evening",0,15],["H1242","and the morning",16,31],["H7243","were the fourth",32,47],["H3117","day",48,51]]},"1:20":{"text":"And God said, Let the waters bring forth abundantly the moving creature that hath life, and fowl that may fly above the earth in the open firmament of heaven.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H4325","Let the waters",14,28],["H8317","bring forth abundantly",29,51],["H8318","the moving creature",52,71],["H5315","that hath",72,81],["H2416","life",82,86],["H5775","and fowl",88,96],["H5774","that may fly",97,109],["H5921","above",110,115],["H0776","the earth",116,125],["H6440","in the open",126,137],["H7549","firmament",138,147],["H8064","of heaven",148,157]]},"1:21":{"text":"And God created great whales, and every living creature that moveth, which the waters brought forth abundantly, after their kind, and every winged fowl after his kind: and God saw that it was good.","words":[["H0430","And God",0,7],["H1254","created",8,15],["H1419","great",16,21],["H8577","whales",22,28],["H2416","and every living",30,46],["H5315","creature",47,55],["H7430","that moveth",56,67],["H4325","which the waters",69,85],["H8317","brought forth abundantly",86,110],["H4327","after their kind",112,128],["H3671","and every winged",130,146],["H5775","fowl",147,151],["H4327","after his kind",152,166],["H0430","and God",168,175],["H7200","saw",176,179],["H2896","that it was good",180,196]]},"1:22":{"text":"And God blessed them, saying, Be fruitful, and multiply, and fill the waters in the seas, and let fowl multiply in the earth.","words":[["H0430","And God",0,7],["H1288","blessed",8,15],["H0559","them, saying",16,28],["H6509","Be fruitful",30,41],["H7235","and multiply",43,55],["H4390","and fill",57,65],["H4325","the waters",66,76],["H3220","in the seas",77,88],["H5775","and let fowl",90,102],["H7235","multiply",103,111],["H0776","in the earth",112,124]]},"1:23":{"text":"And the evening and the morning were the fifth day.","words":[["H6153","And the evening",0,15],["H1242","and the morning",16,31],["H2549","were the fifth",32,46],["H3117","day",47,50]]},"1:24":{"text":"And God said, Let the earth bring forth the living creature after his kind, cattle, and creeping thing, and beast of the earth after his kind: and it was so.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0776","Let the earth",14,27],["H3318","bring forth",28,39],["H2416","the living",40,50],["H5315","creature",51,59],["H4327","after his kind",60,74],["H0929","cattle",76,82],["H7431","and creeping thing",84,102],["H2416","and beast",104,113],["H0776","of the earth",114,126],["H4327","after his kind",127,141]]},"1:25":{"text":"And God made the beast of the earth after his kind, and cattle after their kind, and every thing that creepeth upon the earth after his kind: and God saw that it was good.","words":[["H0430","And God",0,7],["H6213","made",8,12],["H2416","the beast",13,22],["H0776","of the earth",23,35],["H4327","after his kind",36,50],["H0929","and cattle",52,62],["H4327","after their kind",63,79],["H7431","and every thing that creepeth",81,110],["H0127","upon the earth",111,125],["H4327","after his kind",126,140],["H0430","and God",142,149],["H7200","saw",150,153],["H2896","that it was good",154,170]]},"1:26":{"text":"And God said, Let us make man in our image, after our likeness: and let them have dominion over the fish of the sea, and over the fowl of the air, and over the cattle, and over all the earth, and over every creeping thing that creepeth upon the earth.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H6213","Let us make",14,25],["H0120","man",26,29],["H6754","in our image",30,42],["H1823","after our likeness",44,62],["H7287","and let them have dominion",64,90],["H1710","over the fish",91,104],["H3220","of the sea",105,115],["H5775","and over the fowl",117,134],["H8064","of the air",135,145],["H0929","and over the cattle",147,166],["H0776","and over all the earth",168,190],["H7431","and over every creeping thing",192,221],["H7430","that creepeth",222,235],["H0776","upon the earth",236,250]]},"1:27":{"text":"So God created man in his own image, in the image of God created he him; male and female created he them.","words":[["H0430","So God",0,6],["H1254","created",7,14],["H0120","man",15,18],["H6754","in his own image",19,35],["H6754","in the image",37,49],["H0430","of God",50,56],["H1254","created",57,64],["H2145","he him; male",65,77],["H5347","and female",78,88],["H1254","created",89,96]]},"1:28":{"text":"And God blessed them, and God said unto them, Be fruitful, and multiply, and replenish the earth, and subdue it: and have dominion over the fish of the sea, and over the fowl of the air, and over every living thing that moveth upon the earth.","words":[["H0430","And God",0,7],["H1288","blessed",8,15],["H0430","them, and God",16,29],["H0559","said",30,34],["H6509","unto them, Be fruitful",35,57],["H7235","and multiply",59,71],["H4390","and replenish",73,86],["H0776","the earth",87,96],["H3533","and subdue it",98,111],["H7287","and have dominion",113,130],["H1710","over the fish",131,144],["H3220","of the sea",145,155],["H5775","and over the fowl",157,174],["H8064","of the air",175,185],["H2416","and over every living thing",187,214],["H7430","that moveth",215,226],["H0776","upon the earth",227,241]]},"1:29":{"text":"And God said, Behold, I have given you every herb bearing seed, which is upon the face of all the earth, and every tree, in the which is the fruit of a tree yielding seed; to you it shall be for meat.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H2009","Behold",14,20],["H5414","I have given",22,34],["H6212","you every herb",35,49],["H2232","bearing",50,57],["H2233","seed",58,62],["H6440","which is upon the face",64,86],["H0776","of all the earth",87,103],["H6086","and every tree",105,119],["H6529","in the which is the fruit",121,146],["H6086","of a tree",147,156],["H2232","yielding",157,165],["H2233","seed",166,170],["H1961","to you it shall be",172,190],["H0402","for meat",191,199]]},"1:30":{"text":"And to every beast of the earth, and to every fowl of the air, and to every thing that creepeth upon the earth, wherein there is life, I have given every green herb for meat: and it was so.","words":[["H2416","And to every beast",0,18],["H0776","of the earth",19,31],["H5775","and to every fowl",33,50],["H8064","of the air",51,61],["H7430","and to every thing that creepeth",63,95],["H0776","upon the earth",96,110],["H2416","wherein there is life",112,133],["H5315","wherein there is life",112,133],["H3418","I have given every green",135,159],["H6212","herb",160,164],["H0402","for meat",165,173]]},"1:31":{"text":"And God saw every thing that he had made, and, behold, it was very good. And the evening and the morning were the sixth day.","words":[["H0430","And God",0,7],["H7200","saw",8,11],["H0834","every thing that",12,28],["H6213","he had made",29,40],["H3966","and, behold, it was very",42,66],["H2896","good",67,71],["H6153","And the evening",73,88],["H1242","and the morning",89,104],["H8345","were the sixth",105,119],["H3117","day",120,123]]},"2:1":{"text":"Thus the heavens and the earth were finished, and all the host of them.","words":[["H8064","Thus the heavens",0,16],["H0776","and the earth",17,30],["H3615","were finished",31,44],["H6635","and all the host of them",46,70]]},"2:2":{"text":"And on the seventh day God ended his work which he had made; and he rested on the seventh day from all his work which he had made.","words":[["H7637","And on the seventh",0,18],["H3117","day",19,22],["H0430","God",23,26],["H3615","ended",27,32],["H4399","his work",33,41],["H6213","which he had made",42,59],["H7673","and he rested",61,74],["H7637","on the seventh",75,89],["H3117","day",90,93],["H4399","from all his work",94,111],["H6213","which he had made",112,129]]},"2:3":{"text":"And God blessed the seventh day, and sanctified it: because that in it he had rested from all his work which God created and made.","words":[["H0430","And God",0,7],["H1288","blessed",8,15],["H7637","the seventh",16,27],["H3117","day",28,31],["H6942","and sanctified",33,47],["H3588","it: because",48,59],["H7673","that in it he had rested",60,84],["H4399","from all his work",85,102],["H0430","which God",103,112],["H1254","created",113,120],["H6213","and made",121,129]]},"2:4":{"text":"These are the generations of the heavens and of the earth when they were created, in the day that the LORD God made the earth and the heavens,","words":[["H0428","These",0,5],["H8435","are the generations",6,25],["H8064","of the heavens",26,40],["H0776","and of the earth",41,57],["H1254","when they were created",58,80],["H3117","in the day",82,92],["H3068","that the LORD",93,106],["H0430","God",107,110],["H6213","made",111,115],["H0776","the earth",116,125],["H8064","and the heavens",126,141]]},"2:5":{"text":"And every plant of the field before it was in the earth, and every herb of the field before it grew: for the LORD God had not caused it to rain upon the earth, and there was not a man to till the ground.","words":[["H7880","And every plant",0,15],["H7704","of the field",16,28],["H2962","before",29,35],["H0776","it was in the earth",36,55],["H6212","and every herb",57,71],["H7704","of the field",72,84],["H2962","before",85,91],["H6779","it grew",92,99],["H3588","for",101,104],["H3068","the LORD",105,113],["H0430","God",114,117],["H3808","had not",118,125],["H4305","caused it to rain",126,143],["H0776","upon the earth",144,158],["H0369","and there was not",160,177],["H0120","a man",178,183],["H5647","to till",184,191],["H0127","the ground",192,202]]},"2:6":{"text":"But there went up a mist from the earth, and watered the whole face of the ground.","words":[["H5927","But there went up",0,17],["H0108","a mist",18,24],["H4480","from",25,29],["H0776","the earth",30,39],["H8248","and watered",41,52],["H6440","the whole face",53,67],["H0127","of the ground",68,81]]},"2:7":{"text":"And the LORD God formed man of the dust of the ground, and breathed into his nostrils the breath of life; and man became a living soul.","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H3335","formed",17,23],["H0120","man",24,27],["H6083","of the dust",28,39],["H4480","of",40,42],["H0127","the ground",43,53],["H5301","and breathed",55,67],["H0639","into his nostrils",68,85],["H5397","the breath",86,96],["H2416","of life",97,104],["H0120","and man",106,113],["H2416","became a living",114,129],["H5315","soul",130,134]]},"2:8":{"text":"And the LORD God planted a garden eastward in Eden; and there he put the man whom he had formed.","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H5193","planted",17,24],["H1588","a garden",25,33],["H6924","eastward",34,42],["H5731","in Eden",43,50],["H8033","and there",52,61],["H7760","he put",62,68],["H0120","the man",69,76],["H0834","whom",77,81],["H3335","he had formed",82,95]]},"2:9":{"text":"And out of the ground made the LORD God to grow every tree that is pleasant to the sight, and good for food; the tree of life also in the midst of the garden, and the tree of knowledge of good and evil.","words":[["H4480","And out",0,7],["H0127","of the ground",8,21],["H6779","made",22,26],["H3068","the LORD",27,35],["H0430","God",36,39],["H6779","to grow",40,47],["H6086","every tree",48,58],["H2530","that is pleasant",59,75],["H4758","to the sight",76,88],["H2896","and good",90,98],["H3978","for food",99,107],["H6086","the tree",109,117],["H2416","of life",118,125],["H8432","also in the midst",126,143],["H1588","of the garden",144,157],["H6086","and the tree",159,171],["H1847","of knowledge",172,184],["H2896","of good",185,192],["H7451","and evil",193,201]]},"2:10":{"text":"And a river went out of Eden to water the garden; and from thence it was parted, and became into four heads.","words":[["H5104","And a river",0,11],["H3318","went out",12,20],["H5731","of Eden",21,28],["H8248","to water",29,37],["H1588","the garden",38,48],["H6504","and from thence it was parted",50,79],["H0702","and became into four",81,101],["H7218","heads",102,107]]},"2:11":{"text":"The name of the first is Pison: that is it which compasseth the whole land of Havilah, where there is gold;","words":[["H8034","The name",0,8],["H0259","of the first",9,21],["H6376","is Pison",22,30],["H1931","that",32,36],["H5437","is it which compasseth",37,59],["H0776","the whole land",60,74],["H2341","of Havilah",75,85],["H0834","where",87,92],["H2091","there is gold",93,106]]},"2:12":{"text":"And the gold of that land is good: there is bdellium and the onyx stone.","words":[["H2091","And the gold",0,12],["H1931","of that",13,20],["H0776","land",21,25],["H2896","is good",26,33],["H0916","there is bdellium",35,52],["H7718","and the onyx",53,65],["H0068","stone",66,71]]},"2:13":{"text":"And the name of the second river is Gihon: the same is it that compasseth the whole land of Ethiopia.","words":[["H8034","And the name",0,12],["H8145","of the second",13,26],["H5104","river",27,32],["H1521","is Gihon",33,41],["H5437","the same is it that compasseth",43,73],["H0776","the whole land",74,88],["H3568","of Ethiopia",89,100]]},"2:14":{"text":"And the name of the third river is Hiddekel: that is it which goeth toward the east of Assyria. And the fourth river is Euphrates.","words":[["H8034","And the name",0,12],["H7992","of the third",13,25],["H5104","river",26,31],["H2313","is Hiddekel",32,43],["H1980","that is it which goeth toward",45,74],["H6926","the east",75,83],["H0804","of Assyria",84,94],["H7243","And the fourth",96,110],["H5104","river",111,116],["H6578","is Euphrates",117,129]]},"2:15":{"text":"And the LORD God took the man, and put him into the garden of Eden to dress it and to keep it.","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H3947","took",17,21],["H0120","the man",22,29],["H3240","and put him",31,42],["H1588","into the garden",43,58],["H5731","of Eden",59,66],["H5647","to dress",67,75],["H8104","it and to keep",76,90]]},"2:16":{"text":"And the LORD God commanded the man, saying, Of every tree of the garden thou mayest freely eat:","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H6680","commanded",17,26],["H0120","the man",27,34],["H0559","saying",36,42],["H6086","Of every tree",44,57],["H1588","of the garden",58,71],["H0398","thou mayest freely",72,90],["H0398","eat",91,94]]},"2:17":{"text":"But of the tree of the knowledge of good and evil, thou shalt not eat of it: for in the day that thou eatest thereof thou shalt surely die.","words":[["H6086","But of the tree",0,15],["H1847","of the knowledge",16,32],["H2896","of good",33,40],["H7451","and evil",41,49],["H0398","thou shalt not eat",51,69],["H3117","of it: for in the day",70,91],["H0398","that thou eatest",92,108],["H4191","thereof thou shalt surely",109,134],["H4191","die",135,138]]},"2:18":{"text":"And the LORD God said, It is not good that the man should be alone; I will make him an help meet for him.","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H0559","said",17,21],["H2896","It is not good",23,37],["H0120","that the man",38,50],["H1961","should be",51,60],["H6213","alone; I will make",61,79],["H5828","him an help meet",80,96]]},"2:19":{"text":"And out of the ground the LORD God formed every beast of the field, and every fowl of the air; and brought them unto Adam to see what he would call them: and whatsoever Adam called every living creature, that was the name thereof.","words":[["H0127","And out of the ground",0,21],["H3068","the LORD",22,30],["H0430","God",31,34],["H3335","formed",35,41],["H2416","every beast",42,53],["H7704","of the field",54,66],["H5775","and every fowl",68,82],["H8064","of the air",83,93],["H0935","and brought",95,106],["H0120","them unto Adam",107,121],["H7200","to see",122,128],["H7121","what he would call",129,147],["H0120","them: and whatsoever Adam",148,173],["H7121","called",174,180],["H2416","every living",181,193],["H5315","creature",194,202],["H1931","that",204,208],["H8034","was the name thereof",209,229]]},"2:20":{"text":"And Adam gave names to all cattle, and to the fowl of the air, and to every beast of the field; but for Adam there was not found an help meet for him.","words":[["H0120","And Adam",0,8],["H7121","gave",9,13],["H8034","names",14,19],["H0929","to all cattle",20,33],["H5775","and to the fowl",35,50],["H8064","of the air",51,61],["H2416","and to every beast",63,81],["H7704","of the field",82,94],["H0120","but for Adam",96,108],["H4672","there was not found",109,128],["H5828","an help meet",129,141]]},"2:21":{"text":"And the LORD God caused a deep sleep to fall upon Adam, and he slept: and he took one of his ribs, and closed up the flesh instead thereof;","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H5307","caused",17,23],["H8639","a deep sleep",24,36],["H5307","to fall",37,44],["H0121","upon Adam",45,54],["H3462","and he slept",56,68],["H3947","and he took",70,81],["H0259","one",82,85],["H6763","of his ribs",86,97],["H5462","and closed up",99,112],["H1320","the flesh",113,122]]},"2:22":{"text":"And the rib, which the LORD God had taken from man, made he a woman, and brought her unto the man.","words":[["H6763","And the rib",0,11],["H3068","which the LORD",13,27],["H0430","God",28,31],["H3947","had taken",32,41],["H0120","from man",42,50],["H1129","made",52,56],["H0802","he a woman",57,67],["H0935","and brought",69,80],["H0120","her unto the man",81,97]]},"2:23":{"text":"And Adam said, This is now bone of my bones, and flesh of my flesh: she shall be called Woman, because she was taken out of Man.","words":[["H0120","And Adam",0,8],["H0559","said",9,13],["H2063","This",15,19],["H6471","is now",20,26],["H6106","bone",27,31],["H6106","of my bones",32,43],["H1320","and flesh",45,54],["H1320","of my flesh",55,66],["H2063","she",68,71],["H7121","shall be called",72,87],["H0802","Woman",88,93],["H2063","because she",95,106],["H3947","was taken",107,116],["H0376","out of Man",117,127]]},"2:24":{"text":"Therefore shall a man leave his father and his mother, and shall cleave unto his wife: and they shall be one flesh.","words":[["H3651","Therefore",0,9],["H0376","shall a man",10,21],["H5800","leave",22,27],["H0001","his father",28,38],["H0517","and his mother",39,53],["H1692","and shall cleave",55,71],["H0802","unto his wife",72,85],["H0259","and they shall be one",87,108],["H1320","flesh",109,114]]},"2:25":{"text":"And they were both naked, the man and his wife, and were not ashamed.","words":[["H8147","And they were both",0,18],["H6174","naked",19,24],["H0120","the man",26,33],["H0802","and his wife",34,46],["H0954","and were not ashamed",48,68]]},"3:1":{"text":"Now the serpent was more subtil than any beast of the field which the LORD God had made. And he said unto the woman, Yea, hath God said, Ye shall not eat of every tree of the garden?","words":[["H5175","Now the serpent",0,15],["H1961","was",16,19],["H6175","more subtil",20,31],["H2416","than any beast",32,46],["H7704","of the field",47,59],["H3068","which the LORD",60,74],["H0430","God",75,78],["H6213","had made",79,87],["H0559","And he said",89,100],["H0802","unto the woman",101,115],["H0637","Yea",117,120],["H0430","hath God",122,130],["H0559","said",131,135],["H0398","Ye shall not eat",137,153],["H6086","of every tree",154,167],["H1588","of the garden",168,181]]},"3:2":{"text":"And the woman said unto the serpent, We may eat of the fruit of the trees of the garden:","words":[["H0802","And the woman",0,13],["H0559","said",14,18],["H5175","unto the serpent",19,35],["H0398","We may eat",37,47],["H6529","of the fruit",48,60],["H6086","of the trees",61,73],["H1588","of the garden",74,87]]},"3:3":{"text":"But of the fruit of the tree which is in the midst of the garden, God hath said, Ye shall not eat of it, neither shall ye touch it, lest ye die.","words":[["H6529","But of the fruit",0,16],["H6086","of the tree",17,28],["H8432","which is in the midst",29,50],["H1588","of the garden",51,64],["H0430","God",66,69],["H0559","hath said",70,79],["H0398","Ye shall not eat",81,97],["H5060","of it, neither shall ye touch",98,127],["H6435","it, lest",128,136],["H4191","ye die",137,143]]},"3:4":{"text":"And the serpent said unto the woman, Ye shall not surely die:","words":[["H5175","And the serpent",0,15],["H0559","said",16,20],["H0802","unto the woman",21,35],["H4191","Ye shall not surely",37,56],["H4191","die",57,60]]},"3:5":{"text":"For God doth know that in the day ye eat thereof, then your eyes shall be opened, and ye shall be as gods, knowing good and evil.","words":[["H0430","For God",0,7],["H3045","doth know",8,17],["H3117","that in the day",18,33],["H0398","ye eat",34,40],["H5869","thereof, then your eyes",41,64],["H6491","shall be opened",65,80],["H0430","and ye shall be as gods",82,105],["H3045","knowing",107,114],["H2896","good",115,119],["H7451","and evil",120,128]]},"3:6":{"text":"And when the woman saw that the tree was good for food, and that it was pleasant to the eyes, and a tree to be desired to make one wise, she took of the fruit thereof, and did eat, and gave also unto her husband with her; and he did eat.","words":[["H0802","And when the woman",0,18],["H7200","saw",19,22],["H6086","that the tree",23,36],["H2896","was good",37,45],["H3978","for food",46,54],["H1931","and that it",56,67],["H8378","was pleasant",68,80],["H5869","to the eyes",81,92],["H6086","and a tree",94,104],["H2530","to be desired",105,118],["H7919","to make one wise",119,135],["H3947","she took",137,145],["H6529","of the fruit thereof",146,166],["H0398","and did eat",168,179],["H5414","and gave",181,189],["H1571","also",190,194],["H0376","unto her husband",195,211],["H0398","with her; and he did eat",212,236]]},"3:7":{"text":"And the eyes of them both were opened, and they knew that they were naked; and they sewed fig leaves together, and made themselves aprons.","words":[["H5869","And the eyes",0,12],["H8147","of them both",13,25],["H6491","were opened",26,37],["H1992","and they",39,47],["H3045","knew",48,52],["H5903","that they were naked",53,73],["H8609","and they sewed",75,89],["H8384","fig",90,93],["H5929","leaves",94,100],["H8609","together",101,109],["H6213","and made themselves",111,130],["H2290","aprons",131,137]]},"3:8":{"text":"And they heard the voice of the LORD God walking in the garden in the cool of the day: and Adam and his wife hid themselves from the presence of the LORD God amongst the trees of the garden.","words":[["H8085","And they heard",0,14],["H6963","the voice",15,24],["H3068","of the LORD",25,36],["H0430","God",37,40],["H1980","walking",41,48],["H1588","in the garden",49,62],["H7307","in the cool",63,74],["H3117","of the day",75,85],["H0120","and Adam",87,95],["H0802","and his wife",96,108],["H2244","hid themselves",109,123],["H6440","from the presence",124,141],["H3068","of the LORD",142,153],["H0430","God",154,157],["H8432","amongst",158,165],["H6086","the trees",166,175],["H1588","of the garden",176,189]]},"3:9":{"text":"And the LORD God called unto Adam, and said unto him, Where art thou?","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H7121","called",17,23],["H0120","unto Adam",24,33],["H0559","and said",35,43],["H0335","unto him, Where art thou",44,68]]},"3:10":{"text":"And he said, I heard thy voice in the garden, and I was afraid, because I was naked; and I hid myself.","words":[["H0559","And he said",0,11],["H8085","I heard",13,20],["H6963","thy voice",21,30],["H1588","in the garden",31,44],["H3372","and I was afraid",46,62],["H0595","because I",64,73],["H5903","was naked",74,83],["H2244","and I hid myself",85,101]]},"3:11":{"text":"And he said, Who told thee that thou wast naked? Hast thou eaten of the tree, whereof I commanded thee that thou shouldest not eat?","words":[["H0559","And he said",0,11],["H4310","Who",13,16],["H5046","told",17,21],["H5903","thee that thou wast naked",22,47],["H0398","Hast thou eaten",49,64],["H6086","of the tree",65,76],["H6680","whereof I commanded thee",78,102],["H1115","that thou shouldest not",103,126],["H0398","eat",127,130]]},"3:12":{"text":"And the man said, The woman whom thou gavest to be with me, she gave me of the tree, and I did eat.","words":[["H0120","And the man",0,11],["H0559","said",12,16],["H0802","The woman",18,27],["H5414","whom thou gavest",28,44],["H5978","to be with me",45,58],["H1931","she",60,63],["H5414","gave",64,68],["H6086","me of the tree",69,83],["H0398","and I did eat",85,98]]},"3:13":{"text":"And the LORD God said unto the woman, What is this that thou hast done? And the woman said, The serpent beguiled me, and I did eat.","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H0559","said",17,21],["H0802","unto the woman",22,36],["H6213","What is this that thou hast done",38,70],["H0802","And the woman",72,85],["H0559","said",86,90],["H5175","The serpent",92,103],["H5377","beguiled me",104,115],["H0398","and I did eat",117,130]]},"3:14":{"text":"And the LORD God said unto the serpent, Because thou hast done this, thou art cursed above all cattle, and above every beast of the field; upon thy belly shalt thou go, and dust shalt thou eat all the days of thy life:","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H0559","said",17,21],["H5175","unto the serpent",22,38],["H0859","Because thou",40,52],["H6213","hast done",53,62],["H0779","this, thou art cursed",63,84],["H0929","above all cattle",85,101],["H2416","and above every beast",103,124],["H7704","of the field",125,137],["H1512","upon thy belly",139,153],["H3212","shalt thou go",154,167],["H6083","and dust",169,177],["H0398","shalt thou eat",178,192],["H3117","all the days",193,205],["H2416","of thy life",206,217]]},"3:15":{"text":"And I will put enmity between thee and the woman, and between thy seed and her seed; it shall bruise thy head, and thou shalt bruise his heel.","words":[["H7896","And I will put",0,14],["H0342","enmity",15,21],["H0802","between thee and the woman",22,48],["H2233","and between thy seed",50,70],["H2233","and her seed",71,83],["H7779","it shall bruise",85,100],["H7218","thy head",101,109],["H7779","and thou shalt bruise",111,132],["H6119","his heel",133,141]]},"3:16":{"text":"Unto the woman he said, I will greatly multiply thy sorrow and thy conception; in sorrow thou shalt bring forth children; and thy desire shall be to thy husband, and he shall rule over thee.","words":[["H0802","Unto the woman",0,14],["H0559","he said",15,22],["H7235","I will greatly",24,38],["H7235","multiply",39,47],["H6093","thy sorrow",48,58],["H2032","and thy conception",59,77],["H6089","in sorrow",79,88],["H3205","thou shalt bring forth",89,111],["H1121","children",112,120],["H8669","and thy desire",122,136],["H0376","shall be to thy husband",137,160],["H4910","and he shall rule",162,179]]},"3:17":{"text":"And unto Adam he said, Because thou hast hearkened unto the voice of thy wife, and hast eaten of the tree, of which I commanded thee, saying, Thou shalt not eat of it: cursed is the ground for thy sake; in sorrow shalt thou eat of it all the days of thy life;","words":[["H0121","And unto Adam",0,13],["H0559","he said",14,21],["H8085","Because thou hast hearkened",23,50],["H6963","unto the voice",51,65],["H0802","of thy wife",66,77],["H0398","and hast eaten",79,93],["H6086","of the tree",94,105],["H0834","of which",107,115],["H6680","I commanded thee",116,132],["H0559","saying",134,140],["H0398","Thou shalt not eat",142,160],["H0779","of it: cursed",161,174],["H0127","is the ground",175,188],["H6093","for thy sake; in sorrow",189,212],["H0398","shalt thou eat",213,227],["H3605","of it all",228,237],["H3117","the days",238,246],["H2416","of thy life",247,258]]},"3:18":{"text":"Thorns also and thistles shall it bring forth to thee; and thou shalt eat the herb of the field;","words":[["H6975","Thorns also",0,11],["H1863","and thistles",12,24],["H6779","shall it bring forth",25,45],["H0398","to thee; and thou shalt eat",46,73],["H6212","the herb",74,82],["H7704","of the field",83,95]]},"3:19":{"text":"In the sweat of thy face shalt thou eat bread, till thou return unto the ground; for out of it wast thou taken: for dust thou art, and unto dust shalt thou return.","words":[["H2188","In the sweat",0,12],["H0639","of thy face",13,24],["H0398","shalt thou eat",25,39],["H3899","bread",40,45],["H5704","till",47,51],["H7725","thou return",52,63],["H0127","unto the ground",64,79],["H3947","for out of it wast thou taken",81,110],["H6083","for dust",112,120],["H0859","thou",121,125],["H6083","art, and unto dust",126,144],["H7725","shalt thou return",145,162]]},"3:20":{"text":"And Adam called his wife's name Eve; because she was the mother of all living.","words":[["H0120","And Adam",0,8],["H7121","called",9,15],["H0802","his wife's",16,26],["H8034","name",27,31],["H2332","Eve",32,35],["H0517","because she was the mother",37,63],["H2416","of all living",64,77]]},"3:21":{"text":"Unto Adam also and to his wife did the LORD God make coats of skins, and clothed them.","words":[["H0120","Unto Adam",0,9],["H0802","also and to his wife",10,30],["H3068","did the LORD",31,43],["H0430","God",44,47],["H6213","make",48,52],["H3801","coats",53,58],["H5785","of skins",59,67],["H3847","and clothed them",69,85]]},"3:22":{"text":"And the LORD God said, Behold, the man is become as one of us, to know good and evil: and now, lest he put forth his hand, and take also of the tree of life, and eat, and live for ever:","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H0559","said",17,21],["H2005","Behold",23,29],["H0120","the man",31,38],["H0259","is become as one",39,55],["H3045","of us, to know",56,70],["H2896","good",71,75],["H7451","and evil",76,84],["H7971","and now, lest he put forth",86,112],["H3027","his hand",113,121],["H3947","and take",123,131],["H6086","also of the tree",132,148],["H2416","of life",149,156],["H0398","and eat",158,165],["H2425","and live",167,175],["H5769","for ever",176,184]]},"3:23":{"text":"Therefore the LORD God sent him forth from the garden of Eden, to till the ground from whence he was taken.","words":[["H3068","Therefore the LORD",0,18],["H0430","God",19,22],["H7971","sent him forth",23,37],["H1588","from the garden",38,53],["H5731","of Eden",54,61],["H5647","to till",63,70],["H0127","the ground",71,81],["H3947","from whence he was taken",82,106]]},"3:24":{"text":"So he drove out the man; and he placed at the east of the garden of Eden Cherubims, and a flaming sword which turned every way, to keep the way of the tree of life.","words":[["H1644","So he drove out",0,15],["H0120","the man",16,23],["H7931","and he placed",25,38],["H6924","at the east",39,50],["H1588","of the garden",51,64],["H5731","of Eden",65,72],["H3742","Cherubims",73,82],["H3858","and a flaming",84,97],["H2719","sword",98,103],["H2015","which turned every way",104,126],["H8104","to keep",128,135],["H1870","the way",136,143],["H6086","of the tree",144,155],["H2416","of life",156,163]]},"4:1":{"text":"And Adam knew Eve his wife; and she conceived, and bare Cain, and said, I have gotten a man from the LORD.","words":[["H0120","And Adam",0,8],["H3045","knew",9,13],["H0853","",-1,-1],["H2332","Eve",14,17],["H0802","his wife",18,26],["H2029","and she conceived",28,45],["H3205","and bare",47,55],["H0853","",-1,-1],["H7014","Cain",56,60],["H0559","and said",62,70],["H7069","I have gotten",72,85],["H0376","a man",86,91],["H0854","from",92,96],["H3068","the LORD",97,105]]},"4:2":{"text":"And she again bare his brother Abel. And Abel was a keeper of sheep, but Cain was a tiller of the ground.","words":[["H3254","And she again",0,13],["H3205","bare",14,18],["H0251","his brother",19,30],["H1893","Abel",31,35],["H1893","And Abel",37,45],["H7462","was a keeper",46,58],["H6629","of sheep",59,67],["H7014","but Cain",69,77],["H5647","was a tiller",78,90],["H0127","of the ground",91,104]]},"4:3":{"text":"And in process of time it came to pass, that Cain brought of the fruit of the ground an offering unto the LORD.","words":[["H7093","And in process",0,14],["H3117","of time",15,22],["H7014","it came to pass, that Cain",23,49],["H0935","brought",50,57],["H6529","of the fruit",58,70],["H0127","of the ground",71,84],["H4503","an offering",85,96],["H3068","unto the LORD",97,110]]},"4:4":{"text":"And Abel, he also brought of the firstlings of his flock and of the fat thereof. And the LORD had respect unto Abel and to his offering:","words":[["H1893","And Abel",0,8],["H1931","he",10,12],["H0935","also brought",13,25],["H1062","of the firstlings",26,43],["H6629","of his flock",44,56],["H2459","and of the fat",57,71],["H3068","thereof. And the LORD",72,93],["H8159","had respect",94,105],["H1893","unto Abel",106,115],["H4503","and to his offering",116,135]]},"4:5":{"text":"But unto Cain and to his offering he had not respect. And Cain was very wroth, and his countenance fell.","words":[["H7014","But unto Cain",0,13],["H4503","and to his offering",14,33],["H8159","he had not respect",34,52],["H7014","And Cain",54,62],["H3966","was very",63,71],["H2734","wroth",72,77],["H6440","and his countenance",79,98],["H5307","fell",99,103]]},"4:6":{"text":"And the LORD said unto Cain, Why art thou wroth? and why is thy countenance fallen?","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7014","unto Cain",18,27],["H2734","Why art thou wroth",29,47],["H6440","and why is thy countenance",49,75],["H5307","fallen",76,82]]},"4:7":{"text":"If thou doest well, shalt thou not be accepted? and if thou doest not well, sin lieth at the door. And unto thee shall be his desire, and thou shalt rule over him.","words":[["H0518","If",0,2],["H3190","thou doest well",3,18],["H7613","shalt thou not be accepted",20,46],["H3190","and if thou doest not well",48,74],["H2403","sin",76,79],["H7257","lieth",80,85],["H6607","at the door",86,97],["H8669","And unto thee shall be his desire",99,132],["H4910","and thou shalt rule",134,153]]},"4:8":{"text":"And Cain talked with Abel his brother: and it came to pass, when they were in the field, that Cain rose up against Abel his brother, and slew him.","words":[["H7014","And Cain",0,8],["H0559","talked",9,15],["H0413","with",16,20],["H1893","Abel",21,25],["H0251","his brother",26,37],["H7704","and it came to pass, when they were in the field",39,87],["H7014","that Cain",89,98],["H6965","rose up",99,106],["H0413","against",107,114],["H1893","Abel",115,119],["H0251","his brother",120,131],["H2026","and slew him",133,145]]},"4:9":{"text":"And the LORD said unto Cain, Where is Abel thy brother? And he said, I know not: Am I my brother's keeper?","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7014","unto Cain",18,27],["H0335","Where",29,34],["H1893","is Abel",35,42],["H0251","thy brother",43,54],["H0559","And he said",56,67],["H3045","I know",69,75],["H0251","not: Am I my brother's",76,98],["H8104","keeper",99,105]]},"4:10":{"text":"And he said, What hast thou done? the voice of thy brother's blood crieth unto me from the ground.","words":[["H0559","And he said",0,11],["H4100","What",13,17],["H6213","hast thou done",18,32],["H6963","the voice",34,43],["H0251","of thy brother's",44,60],["H1818","blood",61,66],["H6817","crieth",67,73],["H0127","unto me from the ground",74,97]]},"4:11":{"text":"And now art thou cursed from the earth, which hath opened her mouth to receive thy brother's blood from thy hand;","words":[["H0779","And now art thou cursed",0,23],["H0127","from the earth",24,38],["H6475","which hath opened",40,57],["H6310","her mouth",58,67],["H3947","to receive",68,78],["H0251","thy brother's",79,92],["H1818","blood",93,98],["H3027","from thy hand",99,112]]},"4:12":{"text":"When thou tillest the ground, it shall not henceforth yield unto thee her strength; a fugitive and a vagabond shalt thou be in the earth.","words":[["H3588","When",0,4],["H5647","thou tillest",5,17],["H0127","the ground",18,28],["H3254","it shall not henceforth",30,53],["H5414","yield",54,59],["H3581","unto thee her strength",60,82],["H5128","a fugitive",84,94],["H5110","and a vagabond",95,109],["H0776","shalt thou be in the earth",110,136]]},"4:13":{"text":"And Cain said unto the LORD, My punishment is greater than I can bear.","words":[["H7014","And Cain",0,8],["H0559","said",9,13],["H3068","unto the LORD",14,27],["H5771","My punishment",29,42],["H1419","is greater",43,53],["H5375","than I can bear",54,69]]},"4:14":{"text":"Behold, thou hast driven me out this day from the face of the earth; and from thy face shall I be hid; and I shall be a fugitive and a vagabond in the earth; and it shall come to pass, that every one that findeth me shall slay me.","words":[["H1644","Behold, thou hast driven me out",0,31],["H3117","this day",32,40],["H6440","from the face",41,54],["H0127","of the earth",55,67],["H5921","and from",69,77],["H6440","thy face",78,86],["H5641","shall I be hid",87,101],["H5128","and I shall be a fugitive",103,128],["H5110","and a vagabond",129,143],["H0776","in the earth",144,156],["H1961","and it shall come to pass",158,183],["H4672","that every one that findeth me",185,215],["H2026","shall slay me",216,229]]},"4:15":{"text":"And the LORD said unto him, Therefore whosoever slayeth Cain, vengeance shall be taken on him sevenfold. And the LORD set a mark upon Cain, lest any finding him should kill him.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H3651","unto him, Therefore",18,37],["H2026","whosoever slayeth",38,55],["H7014","Cain",56,60],["H5358","vengeance shall be taken",62,86],["H7659","on him sevenfold",87,103],["H3068","And the LORD",105,117],["H7760","set",118,121],["H0226","a mark",122,128],["H7014","upon Cain",129,138],["H1115","lest",140,144],["H4672","any finding",145,156],["H5221","him should kill",157,172]]},"4:16":{"text":"And Cain went out from the presence of the LORD, and dwelt in the land of Nod, on the east of Eden.","words":[["H7014","And Cain",0,8],["H3318","went out",9,17],["H6440","from the presence",18,35],["H3068","of the LORD",36,47],["H3427","and dwelt",49,58],["H0776","in the land",59,70],["H5113","of Nod",71,77],["H6926","on the east",79,90],["H5731","of Eden",91,98]]},"4:17":{"text":"And Cain knew his wife; and she conceived, and bare Enoch: and he builded a city, and called the name of the city, after the name of his son, Enoch.","words":[["H7014","And Cain",0,8],["H3045","knew",9,13],["H0802","his wife",14,22],["H2029","and she conceived",24,41],["H3205","and bare",43,51],["H2585","Enoch",52,57],["H1129","and he builded",59,73],["H5892","a city",74,80],["H7121","and called",82,92],["H8034","the name",93,101],["H5892","of the city",102,113],["H8034","after the name",115,129],["H1121","of his son",130,140],["H2585","Enoch",142,147]]},"4:18":{"text":"And unto Enoch was born Irad: and Irad begat Mehujael: and Mehujael begat Methusael: and Methusael begat Lamech.","words":[["H2585","And unto Enoch",0,14],["H3205","was born",15,23],["H5897","Irad",24,28],["H5897","and Irad",30,38],["H3205","begat",39,44],["H4232","Mehujael",45,53],["H4232","and Mehujael",55,67],["H3205","begat",68,73],["H4967","Methusael",74,83],["H4967","and Methusael",85,98],["H3205","begat",99,104],["H3929","Lamech",105,111]]},"4:19":{"text":"And Lamech took unto him two wives: the name of the one was Adah, and the name of the other Zillah.","words":[["H3929","And Lamech",0,10],["H3947","took",11,15],["H8147","unto him two",16,28],["H0802","wives",29,34],["H8034","the name",36,44],["H0259","of the one",45,55],["H5711","was Adah",56,64],["H8034","and the name",66,78],["H8145","of the other",79,91],["H6741","Zillah",92,98]]},"4:20":{"text":"And Adah bare Jabal: he was the father of such as dwell in tents, and of such as have cattle.","words":[["H5711","And Adah",0,8],["H3205","bare",9,13],["H2989","Jabal",14,19],["H0001","he was the father",21,38],["H3427","of such as dwell",39,55],["H0168","in tents",56,64],["H4735","and of such as have cattle",66,92]]},"4:21":{"text":"And his brother's name was Jubal: he was the father of all such as handle the harp and organ.","words":[["H0251","And his brother's",0,17],["H8034","name",18,22],["H3106","was Jubal",23,32],["H0001","he was the father",34,51],["H8610","of all such as handle",52,73],["H3658","the harp",74,82],["H5748","and organ",83,92]]},"4:22":{"text":"And Zillah, she also bare Tubalcain, an instructer of every artificer in brass and iron: and the sister of Tubalcain was Naamah.","words":[["H6741","And Zillah",0,10],["H3205","she also bare",12,25],["H8423","Tubalcain",26,35],["H3913","an instructer",37,50],["H2794","of every artificer",51,69],["H5178","in brass",70,78],["H1270","and iron",79,87],["H0269","and the sister",89,103],["H8423","of Tubalcain",104,116],["H5279","was Naamah",117,127]]},"4:23":{"text":"And Lamech said unto his wives, Adah and Zillah, Hear my voice; ye wives of Lamech, hearken unto my speech: for I have slain a man to my wounding, and a young man to my hurt.","words":[["H3929","And Lamech",0,10],["H0559","said",11,15],["H0802","unto his wives",16,30],["H5711","Adah",32,36],["H6741","and Zillah",37,47],["H8085","Hear",49,53],["H6963","my voice",54,62],["H0802","ye wives",64,72],["H3929","of Lamech",73,82],["H0238","hearken",84,91],["H0565","unto my speech",92,106],["H2026","for I have slain",108,124],["H0376","a man",125,130],["H6482","to my wounding",131,145],["H3206","and a young man",147,162],["H2250","to my hurt",163,173]]},"4:24":{"text":"If Cain shall be avenged sevenfold, truly Lamech seventy and sevenfold.","words":[["H3588","If",0,2],["H7014","Cain",3,7],["H5358","shall be avenged",8,24],["H7659","sevenfold",25,34],["H3929","truly Lamech",36,48],["H7657","seventy",49,56],["H7651","and sevenfold",57,70]]},"4:25":{"text":"And Adam knew his wife again; and she bare a son, and called his name Seth: For God, said she, hath appointed me another seed instead of Abel, whom Cain slew.","words":[["H0120","And Adam",0,8],["H3045","knew",9,13],["H0802","his wife",14,22],["H5750","again",23,28],["H3205","and she bare",30,42],["H1121","a son",43,48],["H7121","and called",50,60],["H8034","his name",61,69],["H8352","Seth",70,74],["H0430","For God",76,83],["H7896","said she, hath appointed",85,109],["H0312","me another",110,120],["H2233","seed",121,125],["H8478","instead",126,133],["H1893","of Abel",134,141],["H3588","whom",143,147],["H7014","Cain",148,152],["H2026","slew",153,157]]},"4:26":{"text":"And to Seth, to him also there was born a son; and he called his name Enos: then began men to call upon the name of the LORD.","words":[["H8352","And to Seth",0,11],["H1931","to him",13,19],["H3205","also there was born",20,39],["H1121","a son",40,45],["H7121","and he called",47,60],["H8034","his name",61,69],["H0583","Enos",70,74],["H2490","then began men",76,90],["H7121","to call",91,98],["H8034","upon the name",99,112],["H3068","of the LORD",113,124]]},"5:1":{"text":"This is the book of the generations of Adam. In the day that God created man, in the likeness of God made he him;","words":[["H2088","This",0,4],["H5612","is the book",5,16],["H8435","of the generations",17,35],["H0121","of Adam",36,43],["H3117","In the day",45,55],["H0430","that God",56,64],["H1254","created",65,72],["H0120","man",73,76],["H1823","in the likeness",78,93],["H0430","of God",94,100],["H6213","made",101,105]]},"5:2":{"text":"Male and female created he them; and blessed them, and called their name Adam, in the day when they were created.","words":[["H2145","Male",0,4],["H5347","and female",5,15],["H1254","created",16,23],["H1288","he them; and blessed",24,44],["H7121","them, and called",45,61],["H8034","their name",62,72],["H0120","Adam",73,77],["H3117","in the day",79,89],["H1254","when they were created",90,112]]},"5:3":{"text":"And Adam lived an hundred and thirty years, and begat a son in his own likeness, after his image; and called his name Seth:","words":[["H0121","And Adam",0,8],["H2421","lived",9,14],["H3967","an hundred",15,25],["H7970","and thirty",26,36],["H8141","years",37,42],["H3205","and begat",44,53],["H1823","a son in his own likeness",54,79],["H6754","after his image",81,96],["H7121","and called",98,108],["H8034","his name",109,117],["H8352","Seth",118,122]]},"5:4":{"text":"And the days of Adam after he had begotten Seth were eight hundred years: and he begat sons and daughters:","words":[["H3117","And the days",0,12],["H0121","of Adam",13,20],["H0310","after",21,26],["H3205","he had begotten",27,42],["H8352","Seth",43,47],["H8083","were eight",48,58],["H3967","hundred",59,66],["H8141","years",67,72],["H3205","and he begat",74,86],["H1121","sons",87,91],["H1323","and daughters",92,105]]},"5:5":{"text":"And all the days that Adam lived were nine hundred and thirty years: and he died.","words":[["H3117","And all the days",0,16],["H0121","that Adam",17,26],["H2425","lived",27,32],["H8672","were nine",33,42],["H3967","hundred",43,50],["H8141","hundred",43,50],["H7970","and thirty",51,61],["H8141","years",62,67],["H4191","and he died",69,80]]},"5:6":{"text":"And Seth lived an hundred and five years, and begat Enos:","words":[["H8352","And Seth",0,8],["H2421","lived",9,14],["H3967","an hundred",15,25],["H8141","an hundred",15,25],["H2568","and five",26,34],["H8141","years",35,40],["H3205","and begat",42,51],["H0583","Enos",52,56]]},"5:7":{"text":"And Seth lived after he begat Enos eight hundred and seven years, and begat sons and daughters:","words":[["H8352","And Seth",0,8],["H2421","lived",9,14],["H0310","after",15,20],["H3205","he begat",21,29],["H0583","Enos",30,34],["H8083","eight",35,40],["H3967","hundred",41,48],["H8141","hundred",41,48],["H7651","and seven",49,58],["H8141","years",59,64],["H3205","and begat",66,75],["H1121","sons",76,80],["H1323","and daughters",81,94]]},"5:8":{"text":"And all the days of Seth were nine hundred and twelve years: and he died.","words":[["H3117","And all the days",0,16],["H8352","of Seth",17,24],["H8672","were nine",25,34],["H3967","hundred",35,42],["H8141","hundred",35,42],["H6240","and twelve",43,53],["H8147","and twelve",43,53],["H8141","years",54,59],["H4191","and he died",61,72]]},"5:9":{"text":"And Enos lived ninety years, and begat Cainan:","words":[["H0583","And Enos",0,8],["H2421","lived",9,14],["H8673","ninety",15,21],["H8141","years",22,27],["H3205","and begat",29,38],["H7018","Cainan",39,45]]},"5:10":{"text":"And Enos lived after he begat Cainan eight hundred and fifteen years, and begat sons and daughters:","words":[["H0583","And Enos",0,8],["H2421","lived",9,14],["H0310","after",15,20],["H3205","he begat",21,29],["H7018","Cainan",30,36],["H8083","eight",37,42],["H3967","hundred",43,50],["H8141","hundred",43,50],["H6240","and fifteen",51,62],["H2568","and fifteen",51,62],["H8141","years",63,68],["H3205","and begat",70,79],["H1121","sons",80,84],["H1323","and daughters",85,98]]},"5:11":{"text":"And all the days of Enos were nine hundred and five years: and he died.","words":[["H3117","And all the days",0,16],["H0583","of Enos",17,24],["H8672","were nine",25,34],["H3967","hundred",35,42],["H8141","hundred",35,42],["H2568","and five",43,51],["H8141","years",52,57],["H4191","and he died",59,70]]},"5:12":{"text":"And Cainan lived seventy years, and begat Mahalaleel:","words":[["H7018","And Cainan",0,10],["H2421","lived",11,16],["H7657","seventy",17,24],["H8141","years",25,30],["H3205","and begat",32,41],["H4111","Mahalaleel",42,52]]},"5:13":{"text":"And Cainan lived after he begat Mahalaleel eight hundred and forty years, and begat sons and daughters:","words":[["H7018","And Cainan",0,10],["H2421","lived",11,16],["H0310","after",17,22],["H3205","he begat",23,31],["H4111","Mahalaleel",32,42],["H8083","eight",43,48],["H3967","hundred",49,56],["H8141","hundred",49,56],["H0705","and forty",57,66],["H8141","years",67,72],["H3205","and begat",74,83],["H1121","sons",84,88],["H1323","and daughters",89,102]]},"5:14":{"text":"And all the days of Cainan were nine hundred and ten years: and he died.","words":[["H3117","And all the days",0,16],["H7018","of Cainan",17,26],["H8672","were nine",27,36],["H3967","hundred",37,44],["H8141","hundred",37,44],["H6235","and ten",45,52],["H8141","years",53,58],["H4191","and he died",60,71]]},"5:15":{"text":"And Mahalaleel lived sixty and five years, and begat Jared:","words":[["H4111","And Mahalaleel",0,14],["H2421","lived",15,20],["H8346","sixty",21,26],["H8141","sixty",21,26],["H2568","and five",27,35],["H8141","years",36,41],["H3205","and begat",43,52],["H3382","Jared",53,58]]},"5:16":{"text":"And Mahalaleel lived after he begat Jared eight hundred and thirty years, and begat sons and daughters:","words":[["H4111","And Mahalaleel",0,14],["H2421","lived",15,20],["H0310","after",21,26],["H3205","he begat",27,35],["H3382","Jared",36,41],["H8083","eight",42,47],["H3967","hundred",48,55],["H8141","hundred",48,55],["H7970","and thirty",56,66],["H8141","years",67,72],["H3205","and begat",74,83],["H1121","sons",84,88],["H1323","and daughters",89,102]]},"5:17":{"text":"And all the days of Mahalaleel were eight hundred ninety and five years: and he died.","words":[["H3117","And all the days",0,16],["H4111","of Mahalaleel",17,30],["H8083","were eight",31,41],["H3967","hundred",42,49],["H8141","hundred",42,49],["H8673","ninety",50,56],["H2568","and five",57,65],["H8141","years",66,71],["H4191","and he died",73,84]]},"5:18":{"text":"And Jared lived an hundred sixty and two years, and he begat Enoch:","words":[["H3382","And Jared",0,9],["H2421","lived",10,15],["H3967","an hundred",16,26],["H8346","sixty",27,32],["H8141","sixty",27,32],["H8147","and two",33,40],["H8141","years",41,46],["H3205","and he begat",48,60],["H2585","Enoch",61,66]]},"5:19":{"text":"And Jared lived after he begat Enoch eight hundred years, and begat sons and daughters:","words":[["H3382","And Jared",0,9],["H2421","lived",10,15],["H0310","after",16,21],["H3205","he begat",22,30],["H2585","Enoch",31,36],["H8083","eight",37,42],["H3967","hundred",43,50],["H8141","years",51,56],["H3205","and begat",58,67],["H1121","sons",68,72],["H1323","and daughters",73,86]]},"5:20":{"text":"And all the days of Jared were nine hundred sixty and two years: and he died.","words":[["H3117","And all the days",0,16],["H3382","of Jared",17,25],["H8672","were nine",26,35],["H3967","hundred",36,43],["H8141","hundred",36,43],["H8346","sixty",44,49],["H8147","and two",50,57],["H8141","years",58,63],["H4191","and he died",65,76]]},"5:21":{"text":"And Enoch lived sixty and five years, and begat Methuselah:","words":[["H2585","And Enoch",0,9],["H2421","lived",10,15],["H8346","sixty",16,21],["H2568","and five",22,30],["H8141","years",31,36],["H3205","and begat",38,47],["H4968","Methuselah",48,58]]},"5:22":{"text":"And Enoch walked with God after he begat Methuselah three hundred years, and begat sons and daughters:","words":[["H2585","And Enoch",0,9],["H1980","walked",10,16],["H0854","with",17,21],["H0430","God",22,25],["H0310","after",26,31],["H3205","he begat",32,40],["H0853","",-1,-1],["H4968","Methuselah",41,51],["H7969","three",52,57],["H3967","hundred",58,65],["H8141","years",66,71],["H3205","and begat",73,82],["H1121","sons",83,87],["H1323","and daughters",88,101]]},"5:23":{"text":"And all the days of Enoch were three hundred sixty and five years:","words":[["H3117","And all the days",0,16],["H2585","of Enoch",17,25],["H7969","were three",26,36],["H3967","hundred",37,44],["H8141","hundred",37,44],["H8346","sixty",45,50],["H2568","and five",51,59],["H8141","years",60,65]]},"5:24":{"text":"And Enoch walked with God: and he was not; for God took him.","words":[["H2585","And Enoch",0,9],["H1980","walked",10,16],["H0430","with God",17,25],["H0430","and he was not; for God",27,50],["H3947","took",51,55]]},"5:25":{"text":"And Methuselah lived an hundred eighty and seven years, and begat Lamech:","words":[["H4968","And Methuselah",0,14],["H2421","lived",15,20],["H3967","an hundred",21,31],["H8141","an hundred",21,31],["H8084","eighty",32,38],["H7651","and seven",39,48],["H8141","years",49,54],["H3205","and begat",56,65],["H3929","Lamech",66,72]]},"5:26":{"text":"And Methuselah lived after he begat Lamech seven hundred eighty and two years, and begat sons and daughters:","words":[["H4968","And Methuselah",0,14],["H2421","lived",15,20],["H0310","after",21,26],["H3205","he begat",27,35],["H3929","Lamech",36,42],["H7651","seven",43,48],["H3967","hundred",49,56],["H8141","hundred",49,56],["H8084","eighty",57,63],["H8147","and two",64,71],["H8141","years",72,77],["H3205","and begat",79,88],["H1121","sons",89,93],["H1323","and daughters",94,107]]},"5:27":{"text":"And all the days of Methuselah were nine hundred sixty and nine years: and he died.","words":[["H3117","And all the days",0,16],["H4968","of Methuselah",17,30],["H8672","were nine",31,40],["H3967","hundred",41,48],["H8141","hundred",41,48],["H8346","sixty",49,54],["H8672","and nine",55,63],["H8141","years",64,69],["H4191","and he died",71,82]]},"5:28":{"text":"And Lamech lived an hundred eighty and two years, and begat a son:","words":[["H3929","And Lamech",0,10],["H2421","lived",11,16],["H3967","an hundred",17,27],["H8141","an hundred",17,27],["H8084","eighty",28,34],["H8147","and two",35,42],["H8141","years",43,48],["H3205","and begat",50,59],["H1121","a son",60,65]]},"5:29":{"text":"And he called his name Noah, saying, This same shall comfort us concerning our work and toil of our hands, because of the ground which the LORD hath cursed.","words":[["H7121","And he called",0,13],["H8034","his name",14,22],["H5146","Noah",23,27],["H0559","saying",29,35],["H5162","This same shall comfort",37,60],["H4639","us concerning our work",61,83],["H6093","and toil",84,92],["H3027","of our hands",93,105],["H4480","because",107,114],["H0127","of the ground",115,128],["H3068","which the LORD",129,143],["H0779","hath cursed",144,155]]},"5:30":{"text":"And Lamech lived after he begat Noah five hundred ninety and five years, and begat sons and daughters:","words":[["H3929","And Lamech",0,10],["H2421","lived",11,16],["H0310","after",17,22],["H3205","he begat",23,31],["H5146","Noah",32,36],["H2568","five",37,41],["H3967","hundred",42,49],["H8141","hundred",42,49],["H8673","ninety",50,56],["H2568","and five",57,65],["H8141","years",66,71],["H3205","and begat",73,82],["H1121","sons",83,87],["H1323","and daughters",88,101]]},"5:31":{"text":"And all the days of Lamech were seven hundred seventy and seven years: and he died.","words":[["H3117","And all the days",0,16],["H3929","of Lamech",17,26],["H7651","were seven",27,37],["H3967","hundred",38,45],["H8141","hundred",38,45],["H7657","seventy",46,53],["H7651","and seven",54,63],["H8141","years",64,69],["H4191","and he died",71,82]]},"5:32":{"text":"And Noah was five hundred years old: and Noah begat Shem, Ham, and Japheth.","words":[["H5146","And Noah",0,8],["H2568","was five",9,17],["H3967","hundred",18,25],["H8141","years",26,31],["H1121","old",32,35],["H5146","and Noah",37,45],["H3205","begat",46,51],["H8035","Shem",52,56],["H2526","Ham",58,61],["H3315","and Japheth",63,74]]},"6:1":{"text":"And it came to pass, when men began to multiply on the face of the earth, and daughters were born unto them,","words":[["H0120","And it came to pass, when men",0,29],["H2490","began",30,35],["H7231","to multiply",36,47],["H5921","on",48,50],["H6440","the face",51,59],["H0127","of the earth",60,72],["H1323","and daughters",74,87],["H3205","were born",88,97]]},"6:2":{"text":"That the sons of God saw the daughters of men that they were fair; and they took them wives of all which they chose.","words":[["H1121","That the sons",0,13],["H0430","of God",14,20],["H7200","saw",21,24],["H1323","the daughters",25,38],["H0120","of men",39,45],["H2007","that they",46,55],["H2896","were fair",56,65],["H3947","and they took",67,80],["H0802","them wives",81,91],["H0977","of all which they chose",92,115]]},"6:3":{"text":"And the LORD said, My spirit shall not always strive with man, for that he also is flesh: yet his days shall be an hundred and twenty years.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7307","My spirit",19,28],["H5769","shall not always",29,45],["H1777","strive",46,52],["H0120","with man",53,61],["H1571","for that he also",63,79],["H1320","is flesh",80,88],["H7683","is flesh",80,88],["H3117","yet his days",90,102],["H3967","shall be an hundred",103,122],["H6242","and twenty",123,133],["H8141","years",134,139]]},"6:4":{"text":"There were giants in the earth in those days; and also after that, when the sons of God came in unto the daughters of men, and they bare children to them, the same became mighty men which were of old, men of renown.","words":[["H5303","There were giants",0,17],["H0776","in the earth",18,30],["H3117","in those days",31,44],["H0310","and also after",46,60],["H3651","that",61,65],["H0834","when",67,71],["H1121","the sons",72,80],["H0430","of God",81,87],["H0935","came in",88,95],["H1323","unto the daughters",96,114],["H0120","of men",115,121],["H3205","and they bare",123,136],["H1992","children to them, the same",137,163],["H1368","became mighty men",164,181],["H5769","which were of old",182,199],["H0582","men",201,204],["H8034","of renown",205,214]]},"6:5":{"text":"And GOD saw that the wickedness of man was great in the earth, and that every imagination of the thoughts of his heart was only evil continually.","words":[["H3068","And GOD",0,7],["H7200","saw",8,11],["H7451","that the wickedness",12,31],["H0120","of man",32,38],["H7227","was great",39,48],["H0776","in the earth",49,61],["H3336","and that every imagination",63,89],["H4284","of the thoughts",90,105],["H3820","of his heart",106,118],["H7535","was only",119,127],["H7451","evil",128,132],["H3117","continually",133,144]]},"6:6":{"text":"And it repented the LORD that he had made man on the earth, and it grieved him at his heart.","words":[["H5162","And it repented",0,15],["H3068","the LORD",16,24],["H6213","that he had made",25,41],["H0120","man",42,45],["H0776","on the earth",46,58],["H6087","and it grieved",60,74],["H0413","him at",75,81],["H3820","his heart",82,91]]},"6:7":{"text":"And the LORD said, I will destroy man whom I have created from the face of the earth; both man, and beast, and the creeping thing, and the fowls of the air; for it repenteth me that I have made them.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H4229","I will destroy",19,33],["H0120","man",34,37],["H1254","whom I have created",38,57],["H6440","from the face",58,71],["H0127","of the earth",72,84],["H0120","both man",86,94],["H5704","and",96,99],["H0929","beast",100,105],["H7431","and the creeping thing",107,129],["H5775","and the fowls",131,144],["H8064","of the air",145,155],["H5162","for it repenteth",157,173],["H6213","me that I have made",174,193]]},"6:8":{"text":"But Noah found grace in the eyes of the LORD.","words":[["H5146","But Noah",0,8],["H4672","found",9,14],["H2580","grace",15,20],["H5869","in the eyes",21,32],["H3068","of the LORD",33,44]]},"6:9":{"text":"These are the generations of Noah: Noah was a just man and perfect in his generations, and Noah walked with God.","words":[["H8435","These are the generations",0,25],["H5146","of Noah",26,33],["H5146","Noah",35,39],["H6662","was a just",40,50],["H0376","man",51,54],["H8549","and perfect",55,66],["H1755","in his generations",67,85],["H5146","and Noah",87,95],["H1980","walked",96,102],["H0430","with God",103,111]]},"6:10":{"text":"And Noah begat three sons, Shem, Ham, and Japheth.","words":[["H5146","And Noah",0,8],["H3205","begat",9,14],["H7969","three",15,20],["H1121","sons",21,25],["H8035","Shem",27,31],["H2526","Ham",33,36],["H3315","and Japheth",38,49]]},"6:11":{"text":"The earth also was corrupt before God, and the earth was filled with violence.","words":[["H0776","The earth",0,9],["H7843","also was corrupt",10,26],["H6440","before",27,33],["H0430","God",34,37],["H0776","and the earth",39,52],["H4390","was filled",53,63],["H2555","with violence",64,77]]},"6:12":{"text":"And God looked upon the earth, and, behold, it was corrupt; for all flesh had corrupted his way upon the earth.","words":[["H0430","And God",0,7],["H7200","looked",8,14],["H0776","upon the earth",15,29],["H7843","and, behold, it was corrupt",31,58],["H1320","for all flesh",60,73],["H7843","had corrupted",74,87],["H1870","his way",88,95],["H0776","upon the earth",96,110]]},"6:13":{"text":"And God said unto Noah, The end of all flesh is come before me; for the earth is filled with violence through them; and, behold, I will destroy them with the earth.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H5146","unto Noah",13,22],["H7093","The end",24,31],["H1320","of all flesh",32,44],["H0935","is come",45,52],["H6440","before me",53,62],["H0776","for the earth",64,77],["H4390","is filled with",78,92],["H2555","violence",93,101],["H6440","through them",102,114],["H7843","and, behold, I will destroy",116,143],["H0854","them with",144,153],["H0776","the earth",154,163]]},"6:14":{"text":"Make thee an ark of gopher wood; rooms shalt thou make in the ark, and shalt pitch it within and without with pitch.","words":[["H6213","Make",0,4],["H8392","thee an ark",5,16],["H1613","of gopher",17,26],["H6086","wood",27,31],["H7064","rooms",33,38],["H6213","shalt thou make",39,54],["H0854","in",55,57],["H8392","the ark",58,65],["H3722","and shalt pitch",67,82],["H1004","it within",83,92],["H2351","and without",93,104],["H3724","with pitch",105,115]]},"6:15":{"text":"And this is the fashion which thou shalt make it of: The length of the ark shall be three hundred cubits, the breadth of it fifty cubits, and the height of it thirty cubits.","words":[["H6213","And this is the fashion which thou shalt make",0,45],["H0753","it of: The length",46,63],["H8392","of the ark",64,74],["H7969","shall be three",75,89],["H3967","hundred",90,97],["H0520","cubits",98,104],["H7341","the breadth",106,117],["H2572","of it fifty",118,129],["H0520","cubits",130,136],["H6967","and the height",138,152],["H7970","of it thirty",153,165],["H0520","cubits",166,172]]},"6:16":{"text":"A window shalt thou make to the ark, and in a cubit shalt thou finish it above; and the door of the ark shalt thou set in the side thereof; with lower, second, and third stories shalt thou make it.","words":[["H6672","A window",0,8],["H6213","shalt thou make",9,24],["H8392","to the ark",25,35],["H0520","and in a cubit",37,51],["H3615","shalt thou finish",52,69],["H4605","it above",70,78],["H6607","and the door",80,92],["H8392","of the ark",93,103],["H7760","shalt thou set",104,118],["H6654","in the side thereof",119,138],["H8482","with lower",140,150],["H8145","second",152,158],["H7992","and third",160,169],["H6213","stories shalt thou make",170,193]]},"6:17":{"text":"And, behold, I, even I, do bring a flood of waters upon the earth, to destroy all flesh, wherein is the breath of life, from under heaven; and every thing that is in the earth shall die.","words":[["H2009","And, behold",0,11],["H0589","I",13,14],["H0935","even I, do bring",16,32],["H3999","a flood",33,40],["H4325","of waters",41,50],["H0776","upon the earth",51,65],["H7843","to destroy",67,77],["H1320","all flesh",78,87],["H7307","wherein is the breath",89,110],["H2416","of life",111,118],["H8478","from under",120,130],["H8064","heaven",131,137],["H3605","and every thing",139,154],["H0776","that is in the earth",155,175],["H1478","shall die",176,185]]},"6:18":{"text":"But with thee will I establish my covenant; and thou shalt come into the ark, thou, and thy sons, and thy wife, and thy sons' wives with thee.","words":[["H6965","But with thee will I establish",0,30],["H1285","my covenant",31,42],["H0935","and thou shalt come",44,63],["H0413","into",64,68],["H8392","the ark",69,76],["H0859","thou",78,82],["H1121","and thy sons",84,96],["H0802","and thy wife",98,110],["H1121","and thy sons'",112,125],["H0802","wives",126,131]]},"6:19":{"text":"And of every living thing of all flesh, two of every sort shalt thou bring into the ark, to keep them alive with thee; they shall be male and female.","words":[["H2416","And of every living thing",0,25],["H1320","of all flesh",26,38],["H8147","two",40,43],["H0935","of every sort shalt thou bring",44,74],["H8392","into the ark",75,87],["H2421","to keep them alive",89,107],["H2145","with thee; they shall be male",108,137],["H5347","and female",138,148]]},"6:20":{"text":"Of fowls after their kind, and of cattle after their kind, of every creeping thing of the earth after his kind, two of every sort shall come unto thee, to keep them alive.","words":[["H5775","Of fowls",0,8],["H4327","after their kind",9,25],["H0929","and of cattle",27,40],["H4327","after their kind",41,57],["H7431","of every creeping thing",59,82],["H0127","of the earth",83,95],["H4327","after his kind",96,110],["H8147","two",112,115],["H0935","of every sort shall come",116,140],["H2421","unto thee, to keep them alive",141,170]]},"6:21":{"text":"And take thou unto thee of all food that is eaten, and thou shalt gather it to thee; and it shall be for food for thee, and for them.","words":[["H3947","And take",0,8],["H3978","thou unto thee of all food",9,35],["H0398","that is eaten",36,49],["H0622","and thou shalt gather",51,72],["H0402","it to thee; and it shall be for food",73,109]]},"6:22":{"text":"Thus did Noah; according to all that God commanded him, so did he.","words":[["H6213","Thus did",0,8],["H5146","Noah",9,13],["H0430","according to all that God",15,40],["H6680","commanded",41,50],["H6213","him, so did",51,62]]},"7:1":{"text":"And the LORD said unto Noah, Come thou and all thy house into the ark; for thee have I seen righteous before me in this generation.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H5146","unto Noah",18,27],["H0935","Come",29,33],["H1004","thou and all thy house",34,56],["H8392","into the ark",57,69],["H7200","for thee have I seen",71,91],["H6662","righteous",92,101],["H6440","before me",102,111],["H2088","in this",112,119],["H1755","generation",120,130]]},"7:2":{"text":"Of every clean beast thou shalt take to thee by sevens, the male and his female: and of beasts that are not clean by two, the male and his female.","words":[["H2889","Of every clean",0,14],["H0929","beast",15,20],["H3947","thou shalt take",21,36],["H7651","to thee by sevens",37,54],["H7651","to thee by sevens",37,54],["H0376","the male",56,64],["H0802","and his female",65,79],["H0929","and of beasts",81,94],["H2889","that are not clean",95,113],["H1931","that are not clean",95,113],["H8147","by two",114,120],["H0376","the male",122,130],["H0802","and his female",131,145]]},"7:3":{"text":"Of fowls also of the air by sevens, the male and the female; to keep seed alive upon the face of all the earth.","words":[["H5775","Of fowls",0,8],["H8064","also of the air",9,24],["H7651","by sevens",25,34],["H7651","by sevens",25,34],["H2145","the male",36,44],["H5347","and the female",45,59],["H2421","to keep",61,68],["H2233","seed",69,73],["H2421","alive",74,79],["H6440","upon the face",80,93],["H0776","of all the earth",94,110]]},"7:4":{"text":"For yet seven days, and I will cause it to rain upon the earth forty days and forty nights; and every living substance that I have made will I destroy from off the face of the earth.","words":[["H5750","For yet",0,7],["H7651","seven",8,13],["H3117","days",14,18],["H4305","and I will cause it to rain",20,47],["H0776","upon the earth",48,62],["H0705","forty",63,68],["H3117","days",69,73],["H0705","and forty",74,83],["H3915","nights",84,90],["H3605","and every",92,101],["H3351","living substance",102,118],["H6213","that I have made",119,135],["H4229","will I destroy",136,150],["H5921","from off",151,159],["H6440","the face",160,168],["H0127","of the earth",169,181]]},"7:5":{"text":"And Noah did according unto all that the LORD commanded him.","words":[["H5146","And Noah",0,8],["H6213","did",9,12],["H3068","according unto all that the LORD",13,45],["H6680","commanded",46,55]]},"7:6":{"text":"And Noah was six hundred years old when the flood of waters was upon the earth.","words":[["H5146","And Noah",0,8],["H8337","was six",9,16],["H3967","hundred",17,24],["H8141","years",25,30],["H1121","old",31,34],["H3999","when the flood",35,49],["H4325","of waters",50,59],["H0776","was upon the earth",60,78]]},"7:7":{"text":"And Noah went in, and his sons, and his wife, and his sons' wives with him, into the ark, because of the waters of the flood.","words":[["H5146","And Noah",0,8],["H0935","went in",9,16],["H1121","and his sons",18,30],["H0802","and his wife",32,44],["H1121","and his sons'",46,59],["H0802","wives",60,65],["H8392","with him, into the ark",66,88],["H6440","because of",90,100],["H4325","the waters",101,111],["H3999","of the flood",112,124]]},"7:8":{"text":"Of clean beasts, and of beasts that are not clean, and of fowls, and of every thing that creepeth upon the earth,","words":[["H2889","Of clean",0,8],["H0929","beasts",9,15],["H0929","and of beasts",17,30],["H2889","that are not clean",31,49],["H5775","and of fowls",51,63],["H7430","and of every thing that creepeth",65,97],["H0127","upon the earth",98,112]]},"7:9":{"text":"There went in two and two unto Noah into the ark, the male and the female, as God had commanded Noah.","words":[["H0935","There went in",0,13],["H8147","two",14,17],["H8147","and two",18,25],["H5146","unto Noah",26,35],["H8392","into the ark",36,48],["H2145","the male",50,58],["H5347","and the female",59,73],["H0834","as",75,77],["H0430","God",78,81],["H6680","had commanded",82,95],["H5146","Noah",96,100]]},"7:10":{"text":"And it came to pass after seven days, that the waters of the flood were upon the earth.","words":[["H7651","And it came to pass after seven",0,31],["H3117","days",32,36],["H4325","that the waters",38,53],["H3999","of the flood",54,66],["H0776","were upon the earth",67,86]]},"7:11":{"text":"In the six hundredth year of Noah's life, in the second month, the seventeenth day of the month, the same day were all the fountains of the great deep broken up, and the windows of heaven were opened.","words":[["H8141","In",0,2],["H8337","the six",3,10],["H3967","hundredth",11,20],["H8141","year",21,25],["H5146","of Noah's",26,35],["H2416","life",36,40],["H8145","in the second",42,55],["H2320","month",56,61],["H7651","the seventeenth",63,78],["H6240","the seventeenth",63,78],["H3117","day",79,82],["H2320","of the month",83,95],["H2088","the same",97,105],["H3117","day",106,109],["H4599","were all the fountains",110,132],["H7227","of the great",133,145],["H8415","deep",146,150],["H1234","broken up",151,160],["H0699","and the windows",162,177],["H8064","of heaven",178,187],["H6605","were opened",188,199]]},"7:12":{"text":"And the rain was upon the earth forty days and forty nights.","words":[["H1653","And the rain",0,12],["H0776","was upon the earth",13,31],["H0705","forty",32,37],["H3117","days",38,42],["H0705","and forty",43,52],["H3915","nights",53,59]]},"7:13":{"text":"In the selfsame day entered Noah, and Shem, and Ham, and Japheth, the sons of Noah, and Noah's wife, and the three wives of his sons with them, into the ark;","words":[["H6106","In the selfsame",0,15],["H3117","day",16,19],["H0935","entered",20,27],["H5146","Noah",28,32],["H8035","and Shem",34,42],["H2526","and Ham",44,51],["H3315","and Japheth",53,64],["H1121","the sons",66,74],["H5146","of Noah",75,82],["H5146","and Noah's",84,94],["H0802","wife",95,99],["H7969","and the three",101,114],["H0802","wives",115,120],["H1121","of his sons",121,132],["H8392","with them, into the ark",133,156]]},"7:14":{"text":"They, and every beast after his kind, and all the cattle after their kind, and every creeping thing that creepeth upon the earth after his kind, and every fowl after his kind, every bird of every sort.","words":[["H1992","They",0,4],["H2416","and every beast",6,21],["H4327","after his kind",22,36],["H0929","and all the cattle",38,56],["H4327","after their kind",57,73],["H7431","and every creeping thing",75,99],["H7430","that creepeth",100,113],["H0776","upon the earth",114,128],["H4327","after his kind",129,143],["H5775","and every fowl",145,159],["H4327","after his kind",160,174],["H6833","every bird",176,186],["H3671","of every sort",187,200]]},"7:15":{"text":"And they went in unto Noah into the ark, two and two of all flesh, wherein is the breath of life.","words":[["H0935","And they went in",0,16],["H5146","unto Noah",17,26],["H8392","into the ark",27,39],["H8147","two",41,44],["H8147","and two",45,52],["H1320","of all flesh",53,65],["H0834","wherein",67,74],["H7307","is the breath",75,88],["H2416","of life",89,96]]},"7:16":{"text":"And they that went in, went in male and female of all flesh, as God had commanded him: and the LORD shut him in.","words":[["H0935","And they that went in",0,21],["H0935","went in",23,30],["H2145","male",31,35],["H5347","and female",36,46],["H1320","of all flesh",47,59],["H0430","as God",61,67],["H6680","had commanded",68,81],["H3068","him: and the LORD",82,99],["H5462","shut him in",100,111]]},"7:17":{"text":"And the flood was forty days upon the earth; and the waters increased, and bare up the ark, and it was lift up above the earth.","words":[["H3999","And the flood",0,13],["H0705","was forty",14,23],["H3117","days",24,28],["H0776","upon the earth",29,43],["H4325","and the waters",45,59],["H7235","increased",60,69],["H5375","and bare up",71,82],["H8392","the ark",83,90],["H7311","and it was lift up",92,110],["H0776","above the earth",111,126]]},"7:18":{"text":"And the waters prevailed, and were increased greatly upon the earth; and the ark went upon the face of the waters.","words":[["H4325","And the waters",0,14],["H1396","prevailed",15,24],["H7235","and were increased",26,44],["H3966","greatly",45,52],["H0776","upon the earth",53,67],["H8392","and the ark",69,80],["H3212","went",81,85],["H6440","upon the face",86,99],["H4325","of the waters",100,113]]},"7:19":{"text":"And the waters prevailed exceedingly upon the earth; and all the high hills, that were under the whole heaven, were covered.","words":[["H4325","And the waters",0,14],["H1396","prevailed",15,24],["H3966","exceedingly",25,36],["H3966","exceedingly",25,36],["H0776","upon the earth",37,51],["H1364","and all the high",53,69],["H2022","hills",70,75],["H8478","that were under",77,92],["H8064","the whole heaven",93,109],["H3680","were covered",111,123]]},"7:20":{"text":"Fifteen cubits upward did the waters prevail; and the mountains were covered.","words":[["H6240","Fifteen",0,7],["H2568","Fifteen",0,7],["H0520","cubits",8,14],["H4605","upward",15,21],["H4325","did the waters",22,36],["H1396","prevail",37,44],["H2022","and the mountains",46,63],["H3680","were covered",64,76]]},"7:21":{"text":"And all flesh died that moved upon the earth, both of fowl, and of cattle, and of beast, and of every creeping thing that creepeth upon the earth, and every man:","words":[["H1320","And all flesh",0,13],["H1478","died",14,18],["H7430","that moved",19,29],["H0776","upon the earth",30,44],["H5775","both of fowl",46,58],["H0929","and of cattle",60,73],["H2416","and of beast",75,87],["H8318","and of every creeping thing",89,116],["H8317","that creepeth",117,130],["H0776","upon the earth",131,145],["H0120","and every man",147,160]]},"7:22":{"text":"All in whose nostrils was the breath of life, of all that was in the dry land, died.","words":[["H0639","All in whose nostrils",0,21],["H5397","was the breath",22,36],["H7307","was the breath",22,36],["H2416","of life",37,44],["H2724","of all that was in the dry",46,72],["H4191","land, died",73,83]]},"7:23":{"text":"And every living substance was destroyed which was upon the face of the ground, both man, and cattle, and the creeping things, and the fowl of the heaven; and they were destroyed from the earth: and Noah only remained alive, and they that were with him in the ark.","words":[["H3351","And every living substance",0,26],["H4229","was destroyed",27,40],["H6440","which was upon the face",41,64],["H0127","of the ground",65,78],["H0120","both man",80,88],["H0929","and cattle",90,100],["H7431","and the creeping things",102,125],["H5775","and the fowl",127,139],["H8064","of the heaven",140,153],["H4229","and they were destroyed",155,178],["H0776","from the earth",179,193],["H5146","and Noah",195,203],["H0389","only",204,208],["H7604","remained",209,217],["H0834","alive, and they that",218,238],["H8392","were with him in the ark",239,263]]},"7:24":{"text":"And the waters prevailed upon the earth an hundred and fifty days.","words":[["H4325","And the waters",0,14],["H1396","prevailed",15,24],["H0776","upon the earth",25,39],["H3967","an hundred",40,50],["H2572","and fifty",51,60],["H3117","days",61,65]]},"8:1":{"text":"And God remembered Noah, and every living thing, and all the cattle that was with him in the ark: and God made a wind to pass over the earth, and the waters asswaged;","words":[["H0430","And God",0,7],["H2142","remembered",8,18],["H5146","Noah",19,23],["H2416","and every living thing",25,47],["H0929","and all the cattle",49,67],["H8392","that was with him in the ark",68,96],["H0430","and God",98,105],["H5674","made",106,110],["H7307","a wind",111,117],["H5674","to pass",118,125],["H5921","over",126,130],["H0776","the earth",131,140],["H4325","and the waters",142,156],["H7918","asswaged",157,165]]},"8:2":{"text":"The fountains also of the deep and the windows of heaven were stopped, and the rain from heaven was restrained;","words":[["H4599","The fountains",0,13],["H8415","also of the deep",14,30],["H0699","and the windows",31,46],["H8064","of heaven",47,56],["H5534","were stopped",57,69],["H1653","and the rain",71,83],["H8064","from heaven",84,95],["H3607","was restrained",96,110]]},"8:3":{"text":"And the waters returned from off the earth continually: and after the end of the hundred and fifty days the waters were abated.","words":[["H4325","And the waters",0,14],["H7725","returned",15,23],["H0776","from off the earth",24,42],["H1980","continually",43,54],["H7725","continually",43,54],["H7097","and after the end",56,73],["H3967","of the hundred",74,88],["H2572","and fifty",89,98],["H3117","days",99,103],["H4325","the waters",104,114],["H2637","were abated",115,126]]},"8:4":{"text":"And the ark rested in the seventh month, on the seventeenth day of the month, upon the mountains of Ararat.","words":[["H8392","And the ark",0,11],["H5117","rested",12,18],["H7637","in the seventh",19,33],["H2320","month",34,39],["H6240","on the seventeenth",41,59],["H7651","on the seventeenth",41,59],["H3117","day",60,63],["H2320","of the month",64,76],["H2022","upon the mountains",78,96],["H0780","of Ararat",97,106]]},"8:5":{"text":"And the waters decreased continually until the tenth month: in the tenth month, on the first day of the month, were the tops of the mountains seen.","words":[["H4325","And the waters",0,14],["H2637","decreased",15,24],["H1980","continually",25,36],["H5704","until",37,42],["H6224","the tenth",43,52],["H2320","month",53,58],["H6224","in the tenth",60,72],["H0259","month, on the first",73,92],["H2320","day of the month",93,109],["H7218","were the tops",111,124],["H2022","of the mountains",125,141],["H7200","seen",142,146]]},"8:6":{"text":"And it came to pass at the end of forty days, that Noah opened the window of the ark which he had made:","words":[["H7093","And it came to pass at the end",0,30],["H0705","of forty",31,39],["H3117","days",40,44],["H5146","that Noah",46,55],["H6605","opened",56,62],["H2474","the window",63,73],["H8392","of the ark",74,84],["H6213","which he had made",85,102]]},"8:7":{"text":"And he sent forth a raven, which went forth to and fro, until the waters were dried up from off the earth.","words":[["H7971","And he sent forth",0,17],["H6158","a raven",18,25],["H3318","which went forth",27,43],["H3318","to",44,46],["H7725","and fro",47,54],["H4325","until the waters",56,72],["H3001","were dried up",73,86],["H0776","from off the earth",87,105]]},"8:8":{"text":"Also he sent forth a dove from him, to see if the waters were abated from off the face of the ground;","words":[["H7971","Also he sent forth",0,18],["H3123","a dove",19,25],["H7200","from him, to see",26,42],["H4325","if the waters",43,56],["H7043","were abated",57,68],["H6440","from off the face",69,86],["H0127","of the ground",87,100]]},"8:9":{"text":"But the dove found no rest for the sole of her foot, and she returned unto him into the ark, for the waters were on the face of the whole earth: then he put forth his hand, and took her, and pulled her in unto him into the ark.","words":[["H3123","But the dove",0,12],["H4672","found",13,18],["H4494","no rest",19,26],["H3709","for the sole",27,39],["H7272","of her foot",40,51],["H7725","and she returned",53,69],["H8392","unto him into the ark",70,91],["H4325","for the waters",93,107],["H6440","were on the face",108,124],["H0776","of the whole earth",125,143],["H7971","then he put forth",145,162],["H3027","his hand",163,171],["H3947","and took her",173,185],["H0935","and pulled her in",187,204],["H8392","unto him into the ark",205,226]]},"8:10":{"text":"And he stayed yet other seven days; and again he sent forth the dove out of the ark;","words":[["H2342","And he stayed",0,13],["H0312","yet other",14,23],["H7651","seven",24,29],["H3117","days",30,34],["H3254","and again",36,45],["H7971","he sent forth",46,59],["H3123","the dove",60,68],["H8392","out of the ark",69,83]]},"8:11":{"text":"And the dove came in to him in the evening; and, lo, in her mouth was an olive leaf pluckt off: so Noah knew that the waters were abated from off the earth.","words":[["H3123","And the dove",0,12],["H0935","came in",13,20],["H6256","to him in the evening",21,42],["H6153","to him in the evening",21,42],["H6310","and, lo, in her mouth",44,65],["H2132","was an olive",66,78],["H5929","leaf",79,83],["H2965","pluckt off",84,94],["H5146","so Noah",96,103],["H3045","knew",104,108],["H4325","that the waters",109,124],["H7043","were abated",125,136],["H0776","from off the earth",137,155]]},"8:12":{"text":"And he stayed yet other seven days; and sent forth the dove; which returned not again unto him any more.","words":[["H3176","And he stayed",0,13],["H0312","yet other",14,23],["H7651","seven",24,29],["H3117","days",30,34],["H7971","and sent forth",36,50],["H3123","the dove",51,59],["H7725","which returned",61,75],["H3254","not again",76,85],["H5750","unto him any more",86,103]]},"8:13":{"text":"And it came to pass in the six hundredth and first year, in the first month, the first day of the month, the waters were dried up from off the earth: and Noah removed the covering of the ark, and looked, and, behold, the face of the ground was dry.","words":[["H8337","And it came to pass in the six",0,30],["H3967","hundredth",31,40],["H8141","and first year",41,55],["H7223","in the first",57,69],["H0259","month, the first",70,86],["H2320","day of the month",87,103],["H4325","the waters",105,115],["H2717","were dried up",116,129],["H0776","from off the earth",130,148],["H5146","and Noah",150,158],["H5493","removed",159,166],["H4372","the covering",167,179],["H8392","of the ark",180,190],["H7200","and looked",192,202],["H6440","and, behold, the face",204,225],["H0127","of the ground",226,239],["H2717","was dry",240,247]]},"8:14":{"text":"And in the second month, on the seven and twentieth day of the month, was the earth dried.","words":[["H8145","And in the second",0,17],["H2320","month",18,23],["H7651","on the seven",25,37],["H6242","and twentieth",38,51],["H3117","day",52,55],["H2320","of the month",56,68],["H0776","was the earth",70,83],["H3001","dried",84,89]]},"8:15":{"text":"And God spake unto Noah, saying,","words":[["H0430","And God",0,7],["H1696","spake",8,13],["H5146","unto Noah",14,23],["H0559","saying",25,31]]},"8:16":{"text":"Go forth of the ark, thou, and thy wife, and thy sons, and thy sons' wives with thee.","words":[["H3318","Go forth",0,8],["H8392","of the ark",9,19],["H0802","thou, and thy wife",21,39],["H1121","and thy sons",41,53],["H1121","and thy sons'",55,68],["H0802","wives",69,74]]},"8:17":{"text":"Bring forth with thee every living thing that is with thee, of all flesh, both of fowl, and of cattle, and of every creeping thing that creepeth upon the earth; that they may breed abundantly in the earth, and be fruitful, and multiply upon the earth.","words":[["H3318","Bring forth",0,11],["H2416","with thee every living thing",12,40],["H1320","that is with thee, of all flesh",41,72],["H5775","both of fowl",74,86],["H0929","and of cattle",88,101],["H7431","and of every creeping thing",103,130],["H7430","that creepeth",131,144],["H0776","upon the earth",145,159],["H8317","that they may breed abundantly",161,191],["H0776","in the earth",192,204],["H6509","and be fruitful",206,221],["H7235","and multiply",223,235],["H0776","upon the earth",236,250]]},"8:18":{"text":"And Noah went forth, and his sons, and his wife, and his sons' wives with him:","words":[["H5146","And Noah",0,8],["H3318","went forth",9,19],["H1121","and his sons",21,33],["H0802","and his wife",35,47],["H1121","and his sons'",49,62],["H0802","wives",63,68]]},"8:19":{"text":"Every beast, every creeping thing, and every fowl, and whatsoever creepeth upon the earth, after their kinds, went forth out of the ark.","words":[["H2416","Every beast",0,11],["H7431","every creeping thing",13,33],["H5775","and every fowl",35,49],["H3605","and whatsoever",51,65],["H7430","creepeth",66,74],["H0776","upon the earth",75,89],["H4940","after their kinds",91,108],["H3318","went forth",110,120],["H8392","out of the ark",121,135]]},"8:20":{"text":"And Noah builded an altar unto the LORD; and took of every clean beast, and of every clean fowl, and offered burnt offerings on the altar.","words":[["H5146","And Noah",0,8],["H1129","builded",9,16],["H4196","an altar",17,25],["H3068","unto the LORD",26,39],["H3947","and took",41,49],["H2889","of every clean",50,64],["H0929","beast",65,70],["H2889","and of every clean",72,90],["H5775","fowl",91,95],["H5927","and offered",97,108],["H5930","burnt offerings",109,124],["H4196","on the altar",125,137]]},"8:21":{"text":"And the LORD smelled a sweet savour; and the LORD said in his heart, I will not again curse the ground any more for man's sake; for the imagination of man's heart is evil from his youth; neither will I again smite any more every thing living, as I have done.","words":[["H3068","And the LORD",0,12],["H7306","smelled",13,20],["H5207","a sweet",21,28],["H7381","savour",29,35],["H3068","and the LORD",37,49],["H0559","said",50,54],["H0413","in",55,57],["H3820","his heart",58,67],["H3254","I will not again",69,85],["H7043","curse",86,91],["H0127","the ground",92,102],["H0120","any more for man's",103,121],["H5668","sake",122,126],["H3336","for the imagination",128,147],["H0120","of man's",148,156],["H3820","heart",157,162],["H7451","is evil",163,170],["H5271","from his youth",171,185],["H3254","neither will I again",187,207],["H5221","smite",208,213],["H2416","any more every thing living",214,241],["H6213","as I have done",243,257]]},"8:22":{"text":"While the earth remaineth, seedtime and harvest, and cold and heat, and summer and winter, and day and night shall not cease.","words":[["H0776","While the earth",0,15],["H3117","remaineth",16,25],["H2233","seedtime",27,35],["H7105","and harvest",36,47],["H7120","and cold",49,57],["H2527","and heat",58,66],["H7019","and summer",68,78],["H2779","and winter",79,89],["H3117","and day",91,98],["H3915","and night",99,108],["H7673","shall not cease",109,124]]},"9:1":{"text":"And God blessed Noah and his sons, and said unto them, Be fruitful, and multiply, and replenish the earth.","words":[["H0430","And God",0,7],["H1288","blessed",8,15],["H5146","Noah",16,20],["H1121","and his sons",21,33],["H0559","and said",35,43],["H6509","unto them, Be fruitful",44,66],["H7235","and multiply",68,80],["H4390","and replenish",82,95],["H0776","the earth",96,105]]},"9:2":{"text":"And the fear of you and the dread of you shall be upon every beast of the earth, and upon every fowl of the air, upon all that moveth upon the earth, and upon all the fishes of the sea; into your hand are they delivered.","words":[["H4172","And the fear of you",0,19],["H2844","and the dread of you",20,40],["H2416","shall be upon every beast",41,66],["H0776","of the earth",67,79],["H5775","and upon every fowl",81,100],["H8064","of the air",101,111],["H7430","upon all that moveth",113,133],["H0127","upon the earth",134,148],["H1709","and upon all the fishes",150,173],["H3220","of the sea",174,184],["H3027","into your hand",186,200],["H5414","are they delivered",201,219]]},"9:3":{"text":"Every moving thing that liveth shall be meat for you; even as the green herb have I given you all things.","words":[["H7431","Every moving thing",0,18],["H2416","that liveth",19,30],["H0402","shall be meat",31,44],["H3418","for you; even as the green",45,71],["H6212","herb",72,76],["H5414","have I given",77,89]]},"9:4":{"text":"But flesh with the life thereof, which is the blood thereof, shall ye not eat.","words":[["H0389","But",0,3],["H1320","flesh",4,9],["H5315","with the life",10,23],["H1818","thereof, which is the blood",24,51],["H0398","thereof, shall ye not eat",52,77]]},"9:5":{"text":"And surely your blood of your lives will I require; at the hand of every beast will I require it, and at the hand of man; at the hand of every man's brother will I require the life of man.","words":[["H0389","And surely",0,10],["H1818","your blood",11,21],["H5315","of your lives",22,35],["H1875","will I require",36,50],["H3027","at the hand",52,63],["H2416","of every beast",64,78],["H1875","will I require it",79,96],["H3027","and at the hand",98,113],["H0120","of man",114,120],["H3027","at the hand",122,133],["H0376","of every man's",134,148],["H0251","brother",149,156],["H1875","will I require",157,171],["H5315","the life",172,180],["H0120","of man",181,187]]},"9:6":{"text":"Whoso sheddeth man's blood, by man shall his blood be shed: for in the image of God made he man.","words":[["H8210","Whoso sheddeth",0,14],["H0120","man's",15,20],["H1818","blood",21,26],["H0120","by man",28,34],["H1818","shall his blood",35,50],["H8210","be shed",51,58],["H6754","for in the image",60,76],["H0430","of God",77,83],["H6213","made",84,88],["H0120","he man",89,95]]},"9:7":{"text":"And you, be ye fruitful, and multiply; bring forth abundantly in the earth, and multiply therein.","words":[["H6509","And you, be ye fruitful",0,23],["H7235","and multiply",25,37],["H8317","bring forth abundantly",39,61],["H0776","in the earth",62,74],["H7235","and multiply",76,88]]},"9:8":{"text":"And God spake unto Noah, and to his sons with him, saying,","words":[["H0430","And God",0,7],["H0559","spake",8,13],["H5146","unto Noah",14,23],["H1121","and to his sons",25,40],["H0559","with him, saying",41,57]]},"9:9":{"text":"And I, behold, I establish my covenant with you, and with your seed after you;","words":[["H6965","And I, behold, I establish",0,26],["H1285","my covenant",27,38],["H2233","with you, and with your seed",39,67],["H0310","after you",68,77]]},"9:10":{"text":"And with every living creature that is with you, of the fowl, of the cattle, and of every beast of the earth with you; from all that go out of the ark, to every beast of the earth.","words":[["H2416","And with every living",0,21],["H5315","creature",22,30],["H5775","that is with you, of the fowl",31,60],["H0929","of the cattle",62,75],["H2416","and of every beast",77,95],["H0776","of the earth",96,108],["H3318","with you; from all that go out",109,139],["H8392","of the ark",140,150],["H2416","to every beast",152,166],["H0776","of the earth",167,179]]},"9:11":{"text":"And I will establish my covenant with you; neither shall all flesh be cut off any more by the waters of a flood; neither shall there any more be a flood to destroy the earth.","words":[["H6965","And I will establish",0,20],["H1285","my covenant",21,32],["H1320","with you; neither shall all flesh",33,66],["H3772","be cut off",67,77],["H4325","any more by the waters",78,100],["H3999","of a flood",101,111],["H3999","neither shall there any more be a flood",113,152],["H7843","to destroy",153,163],["H0776","the earth",164,173]]},"9:12":{"text":"And God said, This is the token of the covenant which I make between me and you and every living creature that is with you, for perpetual generations:","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0226","This is the token",14,31],["H1285","of the covenant",32,47],["H0589","which I",48,55],["H5414","make",56,60],["H2416","between me and you and every living",61,96],["H5315","creature",97,105],["H5769","that is with you, for perpetual",106,137],["H1755","generations",138,149]]},"9:13":{"text":"I do set my bow in the cloud, and it shall be for a token of a covenant between me and the earth.","words":[["H5414","I do set",0,8],["H7198","my bow",9,15],["H6051","in the cloud",16,28],["H0226","and it shall be for a token",30,57],["H1285","of a covenant",58,71],["H0776","between me and the earth",72,96]]},"9:14":{"text":"And it shall come to pass, when I bring a cloud over the earth, that the bow shall be seen in the cloud:","words":[["H6049","And it shall come to pass, when I bring",0,39],["H6051","a cloud",40,47],["H0776","over the earth",48,62],["H7198","that the bow",64,76],["H7200","shall be seen",77,90],["H6051","in the cloud",91,103]]},"9:15":{"text":"And I will remember my covenant, which is between me and you and every living creature of all flesh; and the waters shall no more become a flood to destroy all flesh.","words":[["H2142","And I will remember",0,19],["H1285","my covenant",20,31],["H2416","which is between me and you and every living",33,77],["H5315","creature",78,86],["H1320","of all flesh",87,99],["H4325","and the waters",101,115],["H5750","shall no more",116,129],["H3999","become a flood",130,144],["H7843","to destroy",145,155],["H1320","all flesh",156,165]]},"9:16":{"text":"And the bow shall be in the cloud; and I will look upon it, that I may remember the everlasting covenant between God and every living creature of all flesh that is upon the earth.","words":[["H7198","And the bow",0,11],["H6051","shall be in the cloud",12,33],["H7200","and I will look upon it",35,58],["H2142","that I may remember",60,79],["H5769","the everlasting",80,95],["H1285","covenant",96,104],["H0996","between",105,112],["H0430","God",113,116],["H0996","and",117,120],["H2416","every living",121,133],["H5315","creature",134,142],["H1320","of all flesh",143,155],["H0776","that is upon the earth",156,178]]},"9:17":{"text":"And God said unto Noah, This is the token of the covenant, which I have established between me and all flesh that is upon the earth.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H5146","unto Noah",13,22],["H0226","This is the token",24,41],["H1285","of the covenant",42,57],["H6965","which I have established",59,83],["H1320","between me and all flesh",84,108],["H0776","that is upon the earth",109,131]]},"9:18":{"text":"And the sons of Noah, that went forth of the ark, were Shem, and Ham, and Japheth: and Ham is the father of Canaan.","words":[["H1121","And the sons",0,12],["H5146","of Noah",13,20],["H3318","that went forth",22,37],["H8392","of the ark",38,48],["H8035","were Shem",50,59],["H2526","and Ham",61,68],["H3315","and Japheth",70,81],["H2526","and Ham",83,90],["H1931","and Ham",83,90],["H0001","is the father",91,104],["H3667","of Canaan",105,114]]},"9:19":{"text":"These are the three sons of Noah: and of them was the whole earth overspread.","words":[["H7969","These are the three",0,19],["H1121","sons",20,24],["H5146","of Noah",25,32],["H0776","and of them was the whole earth",34,65],["H5310","overspread",66,76]]},"9:20":{"text":"And Noah began to be an husbandman, and he planted a vineyard:","words":[["H5146","And Noah",0,8],["H2490","began",9,14],["H0376","to be an husbandman",15,34],["H0127","to be an husbandman",15,34],["H5193","and he planted",36,50],["H3754","a vineyard",51,61]]},"9:21":{"text":"And he drank of the wine, and was drunken; and he was uncovered within his tent.","words":[["H8354","And he drank",0,12],["H3196","of the wine",13,24],["H7937","and was drunken",26,41],["H1540","and he was uncovered",43,63],["H8432","within",64,70],["H0168","his tent",71,79]]},"9:22":{"text":"And Ham, the father of Canaan, saw the nakedness of his father, and told his two brethren without.","words":[["H2526","And Ham",0,7],["H0001","the father",9,19],["H3667","of Canaan",20,29],["H7200","saw",31,34],["H6172","the nakedness",35,48],["H0001","of his father",49,62],["H5046","and told",64,72],["H8147","his two",73,80],["H0251","brethren",81,89],["H2351","without",90,97]]},"9:23":{"text":"And Shem and Japheth took a garment, and laid it upon both their shoulders, and went backward, and covered the nakedness of their father; and their faces were backward, and they saw not their father's nakedness.","words":[["H8035","And Shem",0,8],["H3315","and Japheth",9,20],["H3947","took",21,25],["H8071","a garment",26,35],["H7760","and laid",37,45],["H8147","it upon both",46,58],["H7926","their shoulders",59,74],["H3212","and went",76,84],["H0322","backward",85,93],["H3680","and covered",95,106],["H6172","the nakedness",107,120],["H0001","of their father",121,136],["H6440","and their faces",138,153],["H0322","were backward",154,167],["H7200","and they saw",169,181],["H0001","not their father's",182,200],["H6172","nakedness",201,210]]},"9:24":{"text":"And Noah awoke from his wine, and knew what his younger son had done unto him.","words":[["H5146","And Noah",0,8],["H3364","awoke",9,14],["H3196","from his wine",15,28],["H3045","and knew",30,38],["H6996","what his younger",39,55],["H1121","son",56,59],["H6213","had done",60,68]]},"9:25":{"text":"And he said, Cursed be Canaan; a servant of servants shall he be unto his brethren.","words":[["H0559","And he said",0,11],["H0779","Cursed",13,19],["H3667","be Canaan",20,29],["H5650","a servant",31,40],["H5650","of servants",41,52],["H0251","shall he be unto his brethren",53,82]]},"9:26":{"text":"And he said, Blessed be the LORD God of Shem; and Canaan shall be his servant.","words":[["H0559","And he said",0,11],["H1288","Blessed",13,20],["H3068","be the LORD",21,32],["H0430","God",33,36],["H8035","of Shem",37,44],["H3667","and Canaan",46,56],["H1961","shall be",57,65],["H5650","his servant",66,77]]},"9:27":{"text":"God shall enlarge Japheth, and he shall dwell in the tents of Shem; and Canaan shall be his servant.","words":[["H0430","God",0,3],["H6601","shall enlarge",4,17],["H3315","Japheth",18,25],["H7931","and he shall dwell",27,45],["H0168","in the tents",46,58],["H8035","of Shem",59,66],["H3667","and Canaan",68,78],["H5650","shall be his servant",79,99]]},"9:28":{"text":"And Noah lived after the flood three hundred and fifty years.","words":[["H5146","And Noah",0,8],["H2421","lived",9,14],["H0310","after",15,20],["H3999","the flood",21,30],["H7969","three",31,36],["H3967","hundred",37,44],["H8141","hundred",37,44],["H2572","and fifty",45,54],["H8141","years",55,60]]},"9:29":{"text":"And all the days of Noah were nine hundred and fifty years: and he died.","words":[["H3117","And all the days",0,16],["H5146","of Noah",17,24],["H8672","were nine",25,34],["H3967","hundred",35,42],["H8141","hundred",35,42],["H2572","and fifty",43,52],["H8141","years",53,58],["H4191","and he died",60,71]]},"10:1":{"text":"Now these are the generations of the sons of Noah, Shem, Ham, and Japheth: and unto them were sons born after the flood.","words":[["H8435","Now these are the generations",0,29],["H1121","of the sons",30,41],["H5146","of Noah",42,49],["H8035","Shem",51,55],["H2526","Ham",57,60],["H3315","and Japheth",62,73],["H1121","and unto them were sons",75,98],["H3205","born",99,103],["H0310","after",104,109],["H3999","the flood",110,119]]},"10:2":{"text":"The sons of Japheth; Gomer, and Magog, and Madai, and Javan, and Tubal, and Meshech, and Tiras.","words":[["H1121","The sons",0,8],["H3315","of Japheth",9,19],["H1586","Gomer",21,26],["H4031","and Magog",28,37],["H4074","and Madai",39,48],["H3120","and Javan",50,59],["H8422","and Tubal",61,70],["H4902","and Meshech",72,83],["H8494","and Tiras",85,94]]},"10:3":{"text":"And the sons of Gomer; Ashkenaz, and Riphath, and Togarmah.","words":[["H1121","And the sons",0,12],["H1586","of Gomer",13,21],["H0813","Ashkenaz",23,31],["H7384","and Riphath",33,44],["H8425","and Togarmah",46,58]]},"10:4":{"text":"And the sons of Javan; Elishah, and Tarshish, Kittim, and Dodanim.","words":[["H1121","And the sons",0,12],["H3120","of Javan",13,21],["H0473","Elishah",23,30],["H8659","and Tarshish",32,44],["H3794","Kittim",46,52],["H1721","and Dodanim",54,65]]},"10:5":{"text":"By these were the isles of the Gentiles divided in their lands; every one after his tongue, after their families, in their nations.","words":[["H0339","By these were the isles",0,23],["H1471","of the Gentiles",24,39],["H6504","divided in",40,50],["H0776","their lands",51,62],["H0376","every one",64,73],["H3956","after his tongue",74,90],["H4940","after their families",92,112],["H1471","in their nations",114,130]]},"10:6":{"text":"And the sons of Ham; Cush, and Mizraim, and Phut, and Canaan.","words":[["H1121","And the sons",0,12],["H2526","of Ham",13,19],["H3568","Cush",21,25],["H4714","and Mizraim",27,38],["H6316","and Phut",40,48],["H3667","and Canaan",50,60]]},"10:7":{"text":"And the sons of Cush; Seba, and Havilah, and Sabtah, and Raamah, and Sabtecha: and the sons of Raamah; Sheba, and Dedan.","words":[["H1121","And the sons",0,12],["H3568","of Cush",13,20],["H5434","Seba",22,26],["H2341","and Havilah",28,39],["H5454","and Sabtah",41,51],["H7484","and Raamah",53,63],["H5455","and Sabtecha",65,77],["H1121","and the sons",79,91],["H7484","of Raamah",92,101],["H7614","Sheba",103,108],["H1719","and Dedan",110,119]]},"10:8":{"text":"And Cush begat Nimrod: he began to be a mighty one in the earth.","words":[["H3568","And Cush",0,8],["H3205","begat",9,14],["H5248","Nimrod",15,21],["H2490","he began",23,31],["H1961","to be",32,37],["H1368","a mighty one",38,50],["H0776","in the earth",51,63]]},"10:9":{"text":"He was a mighty hunter before the LORD: wherefore it is said, Even as Nimrod the mighty hunter before the LORD.","words":[["H1368","He was a mighty",0,15],["H6718","hunter",16,22],["H6440","before",23,29],["H3068","the LORD",30,38],["H3651","wherefore",40,49],["H0559","it is said",50,60],["H5248","Even as Nimrod",62,76],["H1368","the mighty",77,87],["H6718","hunter",88,94],["H6440","before",95,101],["H3068","the LORD",102,110]]},"10:10":{"text":"And the beginning of his kingdom was Babel, and Erech, and Accad, and Calneh, in the land of Shinar.","words":[["H7225","And the beginning",0,17],["H4467","of his kingdom",18,32],["H0894","was Babel",33,42],["H0751","and Erech",44,53],["H0390","and Accad",55,64],["H3641","and Calneh",66,76],["H0776","in the land",78,89],["H8152","of Shinar",90,99]]},"10:11":{"text":"Out of that land went forth Asshur, and builded Nineveh, and the city Rehoboth, and Calah,","words":[["H0776","Out of that land",0,16],["H3318","went forth",17,27],["H0804","Asshur",28,34],["H1129","and builded",36,47],["H5210","Nineveh",48,55],["H5892","and the city",57,69],["H7344","Rehoboth",70,78],["H3625","and Calah",80,89]]},"10:12":{"text":"And Resen between Nineveh and Calah: the same is a great city.","words":[["H7449","And Resen",0,9],["H5210","between Nineveh",10,25],["H3625","and Calah",26,35],["H1419","the same is a great",37,56],["H5892","city",57,61]]},"10:13":{"text":"And Mizraim begat Ludim, and Anamim, and Lehabim, and Naphtuhim,","words":[["H4714","And Mizraim",0,11],["H3205","begat",12,17],["H3866","Ludim",18,23],["H6047","and Anamim",25,35],["H3853","and Lehabim",37,48],["H5320","and Naphtuhim",50,63]]},"10:14":{"text":"And Pathrusim, and Casluhim, (out of whom came Philistim,) and Caphtorim.","words":[["H6625","And Pathrusim",0,13],["H3695","and Casluhim",15,27],["H3318","(out of whom came",29,46],["H6430","Philistim",47,56],["H3732",") and Caphtorim",57,72]]},"10:15":{"text":"And Canaan begat Sidon his firstborn, and Heth,","words":[["H3667","And Canaan",0,10],["H3205","begat",11,16],["H6721","Sidon",17,22],["H1060","his firstborn",23,36],["H2845","and Heth",38,46]]},"10:16":{"text":"And the Jebusite, and the Amorite, and the Girgasite,","words":[["H2983","And the Jebusite",0,16],["H0567","and the Amorite",18,33],["H1622","and the Girgasite",35,52]]},"10:17":{"text":"And the Hivite, and the Arkite, and the Sinite,","words":[["H2340","And the Hivite",0,14],["H6208","and the Arkite",16,30],["H5513","and the Sinite",32,46]]},"10:18":{"text":"And the Arvadite, and the Zemarite, and the Hamathite: and afterward were the families of the Canaanites spread abroad.","words":[["H0721","And the Arvadite",0,16],["H6786","and the Zemarite",18,34],["H2577","and the Hamathite",36,53],["H0310","and afterward",55,68],["H4940","were the families",69,86],["H3669","of the Canaanites",87,104],["H6327","spread abroad",105,118]]},"10:19":{"text":"And the border of the Canaanites was from Sidon, as thou comest to Gerar, unto Gaza; as thou goest, unto Sodom, and Gomorrah, and Admah, and Zeboim, even unto Lasha.","words":[["H1366","And the border",0,14],["H3669","of the Canaanites",15,32],["H6721","was from Sidon",33,47],["H0935","as thou comest",49,63],["H1642","to Gerar",64,72],["H5804","unto Gaza",74,83],["H0935","as thou goest",85,98],["H5467","unto Sodom",100,110],["H6017","and Gomorrah",112,124],["H0126","and Admah",126,135],["H6636","and Zeboim",137,147],["H3962","even unto Lasha",149,164]]},"10:20":{"text":"These are the sons of Ham, after their families, after their tongues, in their countries, and in their nations.","words":[["H1121","These are the sons",0,18],["H2526","of Ham",19,25],["H4940","after their families",27,47],["H3956","after their tongues",49,68],["H0776","in their countries",70,88],["H1471","and in their nations",90,110]]},"10:21":{"text":"Unto Shem also, the father of all the children of Eber, the brother of Japheth the elder, even to him were children born.","words":[["H8035","Unto Shem",0,9],["H0001","also, the father",10,26],["H1121","of all the children",27,46],["H5677","of Eber",47,54],["H0251","the brother",56,67],["H3315","of Japheth",68,78],["H1419","the elder",79,88],["H3205","even to him were children born",90,120]]},"10:22":{"text":"The children of Shem; Elam, and Asshur, and Arphaxad, and Lud, and Aram.","words":[["H1121","The children",0,12],["H8035","of Shem",13,20],["H5867","Elam",22,26],["H0804","and Asshur",28,38],["H0775","and Arphaxad",40,52],["H3865","and Lud",54,61],["H0758","and Aram",63,71]]},"10:23":{"text":"And the children of Aram; Uz, and Hul, and Gether, and Mash.","words":[["H1121","And the children",0,16],["H0758","of Aram",17,24],["H5780","Uz",26,28],["H2343","and Hul",30,37],["H1666","and Gether",39,49],["H4851","and Mash",51,59]]},"10:24":{"text":"And Arphaxad begat Salah; and Salah begat Eber.","words":[["H0775","And Arphaxad",0,12],["H3205","begat",13,18],["H7974","Salah",19,24],["H7974","and Salah",26,35],["H3205","begat",36,41],["H5677","Eber",42,46]]},"10:25":{"text":"And unto Eber were born two sons: the name of one was Peleg; for in his days was the earth divided; and his brother's name was Joktan.","words":[["H5677","And unto Eber",0,13],["H3205","were born",14,23],["H8147","two",24,27],["H1121","sons",28,32],["H8034","the name",34,42],["H0259","of one",43,49],["H6389","was Peleg",50,59],["H3117","for in his days",61,76],["H0776","was the earth",77,90],["H6385","divided",91,98],["H0251","and his brother's",100,117],["H8034","name",118,122],["H3355","was Joktan",123,133]]},"10:26":{"text":"And Joktan begat Almodad, and Sheleph, and Hazarmaveth, and Jerah,","words":[["H3355","And Joktan",0,10],["H3205","begat",11,16],["H0486","Almodad",17,24],["H8026","and Sheleph",26,37],["H2700","and Hazarmaveth",39,54],["H3392","and Jerah",56,65]]},"10:27":{"text":"And Hadoram, and Uzal, and Diklah,","words":[["H1913","And Hadoram",0,11],["H0187","and Uzal",13,21],["H1853","and Diklah",23,33]]},"10:28":{"text":"And Obal, and Abimael, and Sheba,","words":[["H5745","And Obal",0,8],["H0039","and Abimael",10,21],["H7614","and Sheba",23,32]]},"10:29":{"text":"And Ophir, and Havilah, and Jobab: all these were the sons of Joktan.","words":[["H0211","And Ophir",0,9],["H2341","and Havilah",11,22],["H3103","and Jobab",24,33],["H1121","all these were the sons",35,58],["H3355","of Joktan",59,68]]},"10:30":{"text":"And their dwelling was from Mesha, as thou goest unto Sephar a mount of the east.","words":[["H4186","And their dwelling",0,18],["H4852","was from Mesha",19,33],["H0935","as thou goest",35,48],["H5611","unto Sephar",49,60],["H2022","a mount",61,68],["H6924","of the east",69,80]]},"10:31":{"text":"These are the sons of Shem, after their families, after their tongues, in their lands, after their nations.","words":[["H1121","These are the sons",0,18],["H8035","of Shem",19,26],["H4940","after their families",28,48],["H3956","after their tongues",50,69],["H0776","in their lands",71,85],["H1471","after their nations",87,106]]},"10:32":{"text":"These are the families of the sons of Noah, after their generations, in their nations: and by these were the nations divided in the earth after the flood.","words":[["H4940","These are the families",0,22],["H1121","of the sons",23,34],["H5146","of Noah",35,42],["H8435","after their generations",44,67],["H1471","in their nations",69,85],["H1471","and by these were the nations",87,116],["H6504","divided",117,124],["H0776","in the earth",125,137],["H0310","after",138,143],["H3999","the flood",144,153]]},"11:1":{"text":"And the whole earth was of one language, and of one speech.","words":[["H0776","And the whole earth",0,19],["H0259","was of one",20,30],["H8193","language",31,39],["H0259","and of one",41,51],["H1697","speech",52,58]]},"11:2":{"text":"And it came to pass, as they journeyed from the east, that they found a plain in the land of Shinar; and they dwelt there.","words":[["H5265","And it came to pass, as they journeyed",0,38],["H6924","from the east",39,52],["H4672","that they found",54,69],["H1237","a plain",70,77],["H0776","in the land",78,89],["H8152","of Shinar",90,99],["H3427","and they dwelt",101,115]]},"11:3":{"text":"And they said one to another, Go to, let us make brick, and burn them throughly. And they had brick for stone, and slime had they for morter.","words":[["H0559","And they said",0,13],["H0376","one",14,17],["H7453","to another",18,28],["H3051","Go to",30,35],["H3835","let us make",37,48],["H3843","brick",49,54],["H8313","and burn",56,64],["H8316","them throughly",65,79],["H3843","And they had brick",81,99],["H0068","for stone",100,109],["H2564","and slime",111,120],["H1961","had",121,124],["H2563","they for morter",125,140]]},"11:4":{"text":"And they said, Go to, let us build us a city and a tower, whose top may reach unto heaven; and let us make us a name, lest we be scattered abroad upon the face of the whole earth.","words":[["H0559","And they said",0,13],["H3051","Go to",15,20],["H1129","let us build",22,34],["H5892","us a city",35,44],["H4026","and a tower",45,56],["H7218","whose top",58,67],["H8064","may reach unto heaven",68,89],["H6213","and let us make",91,106],["H8034","us a name",107,116],["H6327","lest we be scattered abroad",118,145],["H6440","upon the face",146,159],["H0776","of the whole earth",160,178]]},"11:5":{"text":"And the LORD came down to see the city and the tower, which the children of men builded.","words":[["H3068","And the LORD",0,12],["H3381","came down",13,22],["H7200","to see",23,29],["H5892","the city",30,38],["H4026","and the tower",39,52],["H1121","which the children",54,72],["H0120","of men",73,79],["H1129","builded",80,87]]},"11:6":{"text":"And the LORD said, Behold, the people is one, and they have all one language; and this they begin to do: and now nothing will be restrained from them, which they have imagined to do.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H5971","Behold, the people",19,37],["H0259","is one",38,44],["H0259","and they have all one",46,67],["H8193","language",68,76],["H2490","and this they begin",78,97],["H6213","to do",98,103],["H3808","and now nothing",105,120],["H3605","and now nothing",105,120],["H1219","will be restrained",121,139],["H2161","from them, which they have imagined",140,175],["H6213","to do",176,181]]},"11:7":{"text":"Go to, let us go down, and there confound their language, that they may not understand one another's speech.","words":[["H3051","Go to",0,5],["H3381","let us go down",7,21],["H1101","and there confound",23,41],["H8193","their language",42,56],["H0834","that",58,62],["H8085","they may not understand",63,86],["H0376","one",87,90],["H7453","another's",91,100],["H8193","speech",101,107]]},"11:8":{"text":"So the LORD scattered them abroad from thence upon the face of all the earth: and they left off to build the city.","words":[["H3068","So the LORD",0,11],["H6327","scattered them abroad",12,33],["H8033","from thence",34,45],["H6440","upon the face",46,59],["H0776","of all the earth",60,76],["H2308","and they left off",78,95],["H1129","to build",96,104],["H5892","the city",105,113]]},"11:9":{"text":"Therefore is the name of it called Babel; because the LORD did there confound the language of all the earth: and from thence did the LORD scatter them abroad upon the face of all the earth.","words":[["H8034","Therefore is the name of it",0,27],["H7121","called",28,34],["H0894","Babel",35,40],["H3068","because the LORD",42,58],["H1101","did there confound",59,77],["H8193","the language",78,90],["H0776","of all the earth",91,107],["H6327","and from thence did",109,128],["H3068","the LORD",129,137],["H6327","scatter them abroad",138,157],["H6440","upon the face",158,171],["H0776","of all the earth",172,188]]},"11:10":{"text":"These are the generations of Shem: Shem was an hundred years old, and begat Arphaxad two years after the flood:","words":[["H8435","These are the generations",0,25],["H8035","of Shem",26,33],["H8035","Shem",35,39],["H3967","was an hundred",40,54],["H8141","years",55,60],["H1121","old",61,64],["H3205","and begat",66,75],["H0775","Arphaxad",76,84],["H8141","two years",85,94],["H0310","after",95,100],["H3999","the flood",101,110]]},"11:11":{"text":"And Shem lived after he begat Arphaxad five hundred years, and begat sons and daughters.","words":[["H8035","And Shem",0,8],["H2421","lived",9,14],["H0310","after",15,20],["H3205","he begat",21,29],["H0775","Arphaxad",30,38],["H2568","five",39,43],["H3967","hundred",44,51],["H8141","years",52,57],["H3205","and begat",59,68],["H1121","sons",69,73],["H1323","and daughters",74,87]]},"11:12":{"text":"And Arphaxad lived five and thirty years, and begat Salah:","words":[["H0775","And Arphaxad",0,12],["H2425","lived",13,18],["H2568","five",19,23],["H7970","and thirty",24,34],["H8141","years",35,40],["H3205","and begat",42,51],["H7974","Salah",52,57]]},"11:13":{"text":"And Arphaxad lived after he begat Salah four hundred and three years, and begat sons and daughters.","words":[["H0775","And Arphaxad",0,12],["H2421","lived",13,18],["H0310","after",19,24],["H3205","he begat",25,33],["H7974","Salah",34,39],["H0702","four",40,44],["H3967","hundred",45,52],["H8141","hundred",45,52],["H7969","and three",53,62],["H8141","years",63,68],["H3205","and begat",70,79],["H1121","sons",80,84],["H1323","and daughters",85,98]]},"11:14":{"text":"And Salah lived thirty years, and begat Eber:","words":[["H7974","And Salah",0,9],["H2425","lived",10,15],["H7970","thirty",16,22],["H8141","years",23,28],["H3205","and begat",30,39],["H5677","Eber",40,44]]},"11:15":{"text":"And Salah lived after he begat Eber four hundred and three years, and begat sons and daughters.","words":[["H7974","And Salah",0,9],["H2421","lived",10,15],["H0310","after",16,21],["H3205","he begat",22,30],["H5677","Eber",31,35],["H0702","four",36,40],["H3967","hundred",41,48],["H8141","hundred",41,48],["H7969","and three",49,58],["H8141","years",59,64],["H3205","and begat",66,75],["H1121","sons",76,80],["H1323","and daughters",81,94]]},"11:16":{"text":"And Eber lived four and thirty years, and begat Peleg:","words":[["H5677","And Eber",0,8],["H2421","lived",9,14],["H0702","four",15,19],["H7970","and thirty",20,30],["H8141","years",31,36],["H3205","and begat",38,47],["H6389","Peleg",48,53]]},"11:17":{"text":"And Eber lived after he begat Peleg four hundred and thirty years, and begat sons and daughters.","words":[["H5677","And Eber",0,8],["H2421","lived",9,14],["H0310","after",15,20],["H3205","he begat",21,29],["H6389","Peleg",30,35],["H0702","four",36,40],["H3967","hundred",41,48],["H8141","hundred",41,48],["H7970","and thirty",49,59],["H8141","years",60,65],["H3205","and begat",67,76],["H1121","sons",77,81],["H1323","and daughters",82,95]]},"11:18":{"text":"And Peleg lived thirty years, and begat Reu:","words":[["H6389","And Peleg",0,9],["H2421","lived",10,15],["H7970","thirty",16,22],["H8141","years",23,28],["H3205","and begat",30,39],["H7466","Reu",40,43]]},"11:19":{"text":"And Peleg lived after he begat Reu two hundred and nine years, and begat sons and daughters.","words":[["H6389","And Peleg",0,9],["H2421","lived",10,15],["H0310","after",16,21],["H3205","he begat",22,30],["H7466","Reu",31,34],["H3967","two hundred",35,46],["H8141","two hundred",35,46],["H8672","and nine",47,55],["H8141","years",56,61],["H3205","and begat",63,72],["H1121","sons",73,77],["H1323","and daughters",78,91]]},"11:20":{"text":"And Reu lived two and thirty years, and begat Serug:","words":[["H7466","And Reu",0,7],["H2421","lived",8,13],["H8147","two",14,17],["H7970","and thirty",18,28],["H8141","years",29,34],["H3205","and begat",36,45],["H8286","Serug",46,51]]},"11:21":{"text":"And Reu lived after he begat Serug two hundred and seven years, and begat sons and daughters.","words":[["H7466","And Reu",0,7],["H2421","lived",8,13],["H0310","after",14,19],["H3205","he begat",20,28],["H8286","Serug",29,34],["H3967","two hundred",35,46],["H8141","two hundred",35,46],["H7651","and seven",47,56],["H8141","years",57,62],["H3205","and begat",64,73],["H1121","sons",74,78],["H1323","and daughters",79,92]]},"11:22":{"text":"And Serug lived thirty years, and begat Nahor:","words":[["H8286","And Serug",0,9],["H2421","lived",10,15],["H7970","thirty",16,22],["H8141","years",23,28],["H3205","and begat",30,39],["H5152","Nahor",40,45]]},"11:23":{"text":"And Serug lived after he begat Nahor two hundred years, and begat sons and daughters.","words":[["H8286","And Serug",0,9],["H2421","lived",10,15],["H0310","after",16,21],["H3205","he begat",22,30],["H5152","Nahor",31,36],["H3967","two hundred",37,48],["H8141","years",49,54],["H3205","and begat",56,65],["H1121","sons",66,70],["H1323","and daughters",71,84]]},"11:24":{"text":"And Nahor lived nine and twenty years, and begat Terah:","words":[["H5152","And Nahor",0,9],["H2421","lived",10,15],["H8672","nine",16,20],["H6242","and twenty",21,31],["H8141","years",32,37],["H3205","and begat",39,48],["H8646","Terah",49,54]]},"11:25":{"text":"And Nahor lived after he begat Terah an hundred and nineteen years, and begat sons and daughters.","words":[["H5152","And Nahor",0,9],["H2421","lived",10,15],["H0310","after",16,21],["H3205","he begat",22,30],["H8646","Terah",31,36],["H3967","an hundred",37,47],["H8141","an hundred",37,47],["H6240","and nineteen",48,60],["H8672","and nineteen",48,60],["H8141","years",61,66],["H3205","and begat",68,77],["H1121","sons",78,82],["H1323","and daughters",83,96]]},"11:26":{"text":"And Terah lived seventy years, and begat Abram, Nahor, and Haran.","words":[["H8646","And Terah",0,9],["H2421","lived",10,15],["H7657","seventy",16,23],["H8141","years",24,29],["H3205","and begat",31,40],["H0087","Abram",41,46],["H5152","Nahor",48,53],["H2039","and Haran",55,64]]},"11:27":{"text":"Now these are the generations of Terah: Terah begat Abram, Nahor, and Haran; and Haran begat Lot.","words":[["H8435","Now these are the generations",0,29],["H8646","of Terah",30,38],["H8646","Terah",40,45],["H3205","begat",46,51],["H0087","Abram",52,57],["H5152","Nahor",59,64],["H2039","and Haran",66,75],["H2039","and Haran",77,86],["H3205","begat",87,92],["H3876","Lot",93,96]]},"11:28":{"text":"And Haran died before his father Terah in the land of his nativity, in Ur of the Chaldees.","words":[["H2039","And Haran",0,9],["H4191","died",10,14],["H6440","before",15,21],["H0001","his father",22,32],["H8646","Terah",33,38],["H0776","in the land",39,50],["H4138","of his nativity",51,66],["H0218","in Ur",68,73],["H3778","of the Chaldees",74,89]]},"11:29":{"text":"And Abram and Nahor took them wives: the name of Abram's wife was Sarai; and the name of Nahor's wife, Milcah, the daughter of Haran, the father of Milcah, and the father of Iscah.","words":[["H0087","And Abram",0,9],["H5152","and Nahor",10,19],["H3947","took",20,24],["H0802","them wives",25,35],["H8034","the name",37,45],["H0087","of Abram's",46,56],["H0802","wife",57,61],["H8297","was Sarai",62,71],["H8034","and the name",73,85],["H5152","of Nahor's",86,96],["H0802","wife",97,101],["H4435","Milcah",103,109],["H1323","the daughter",111,123],["H2039","of Haran",124,132],["H0001","the father",134,144],["H4435","of Milcah",145,154],["H0001","and the father",156,170],["H3252","of Iscah",171,179]]},"11:30":{"text":"But Sarai was barren; she had no child.","words":[["H8297","But Sarai",0,9],["H6135","was barren",10,20],["H2056","she had no child",22,38]]},"11:31":{"text":"And Terah took Abram his son, and Lot the son of Haran his son's son, and Sarai his daughter in law, his son Abram's wife; and they went forth with them from Ur of the Chaldees, to go into the land of Canaan; and they came unto Haran, and dwelt there.","words":[["H8646","And Terah",0,9],["H3947","took",10,14],["H0087","Abram",15,20],["H1121","his son",21,28],["H3876","and Lot",30,37],["H1121","the son",38,45],["H2039","of Haran",46,54],["H1121","his son's",55,64],["H1121","son",65,68],["H8297","and Sarai",70,79],["H3618","his daughter in law",80,99],["H1121","his son",101,108],["H0087","Abram's",109,116],["H0802","wife",117,121],["H3318","and they went forth",123,142],["H0218","with them from Ur",143,160],["H3778","of the Chaldees",161,176],["H3212","to go",178,183],["H0776","into the land",184,197],["H3667","of Canaan",198,207],["H0935","and they came",209,222],["H2771","unto Haran",223,233],["H3427","and dwelt",235,244]]},"11:32":{"text":"And the days of Terah were two hundred and five years: and Terah died in Haran.","words":[["H3117","And the days",0,12],["H8646","of Terah",13,21],["H3967","were two hundred",22,38],["H8141","were two hundred",22,38],["H2568","and five",39,47],["H8141","years",48,53],["H8646","and Terah",55,64],["H4191","died",65,69],["H2771","in Haran",70,78]]},"12:1":{"text":"Now the LORD had said unto Abram, Get thee out of thy country, and from thy kindred, and from thy father's house, unto a land that I will shew thee:","words":[["H3068","Now the LORD",0,12],["H0559","had said",13,21],["H0087","unto Abram",22,32],["H3212","Get thee out",34,46],["H0776","of thy country",47,61],["H4138","and from thy kindred",63,83],["H0001","and from thy father's",85,106],["H1004","house",107,112],["H0776","unto a land",114,125],["H7200","that I will shew",126,142]]},"12:2":{"text":"And I will make of thee a great nation, and I will bless thee, and make thy name great; and thou shalt be a blessing:","words":[["H6213","And I will make of thee",0,23],["H1419","a great",24,31],["H1471","nation",32,38],["H1288","and I will bless",40,56],["H1431","thee, and make",57,71],["H8034","thy name",72,80],["H1431","great",81,86],["H1293","and thou shalt be a blessing",88,116]]},"12:3":{"text":"And I will bless them that bless thee, and curse him that curseth thee: and in thee shall all families of the earth be blessed.","words":[["H1288","And I will bless",0,16],["H1288","them that bless",17,32],["H0779","thee, and curse",33,48],["H7043","him that curseth",49,65],["H4940","thee: and in thee shall all families",66,102],["H0127","of the earth",103,115],["H1288","be blessed",116,126]]},"12:4":{"text":"So Abram departed, as the LORD had spoken unto him; and Lot went with him: and Abram was seventy and five years old when he departed out of Haran.","words":[["H0087","So Abram",0,8],["H3212","departed",9,17],["H3068","as the LORD",19,30],["H1696","had spoken",31,41],["H3876","unto him; and Lot",42,59],["H3212","went",60,64],["H0087","with him: and Abram",65,84],["H7657","was seventy",85,96],["H8141","was seventy",85,96],["H2568","and five",97,105],["H8141","years",106,111],["H1121","old",112,115],["H3318","when he departed",116,132],["H2771","out of Haran",133,145]]},"12:5":{"text":"And Abram took Sarai his wife, and Lot his brother's son, and all their substance that they had gathered, and the souls that they had gotten in Haran; and they went forth to go into the land of Canaan; and into the land of Canaan they came.","words":[["H0087","And Abram",0,9],["H3947","took",10,14],["H8297","Sarai",15,20],["H0802","his wife",21,29],["H3876","and Lot",31,38],["H0251","his brother's",39,52],["H1121","son",53,56],["H7399","and all their substance",58,81],["H7408","that they had gathered",82,104],["H5315","and the souls",106,119],["H6213","that they had gotten",120,140],["H2771","in Haran",141,149],["H3318","and they went forth",151,170],["H3212","to go",171,176],["H0776","into the land",177,190],["H3667","of Canaan",191,200],["H0776","and into the land",202,219],["H3667","of Canaan",220,229],["H0935","they came",230,239]]},"12:6":{"text":"And Abram passed through the land unto the place of Sichem, unto the plain of Moreh. And the Canaanite was then in the land.","words":[["H0087","And Abram",0,9],["H5674","passed through",10,24],["H0776","the land",25,33],["H4725","unto the place",34,48],["H7927","of Sichem",49,58],["H0436","unto the plain",60,74],["H4176","of Moreh",75,83],["H3669","And the Canaanite",85,102],["H0227","was then",103,111],["H0776","in the land",112,123]]},"12:7":{"text":"And the LORD appeared unto Abram, and said, Unto thy seed will I give this land: and there builded he an altar unto the LORD, who appeared unto him.","words":[["H3068","And the LORD",0,12],["H7200","appeared",13,21],["H0087","unto Abram",22,32],["H0559","and said",34,42],["H2233","Unto thy seed",44,57],["H5414","will I give",58,69],["H2063","this",70,74],["H0776","land",75,79],["H1129","and there builded",81,98],["H4196","he an altar",99,110],["H3068","unto the LORD",111,124],["H7200","who appeared",126,138]]},"12:8":{"text":"And he removed from thence unto a mountain on the east of Bethel, and pitched his tent, having Bethel on the west, and Hai on the east: and there he builded an altar unto the LORD, and called upon the name of the LORD.","words":[["H6275","And he removed",0,14],["H2022","from thence unto a mountain",15,42],["H6924","on the east",43,54],["H1008","of Bethel",55,64],["H5186","and pitched",66,77],["H0168","his tent",78,86],["H1008","having Bethel",88,101],["H3220","on the west",102,113],["H5857","and Hai",115,122],["H6924","on the east",123,134],["H1129","and there he builded",136,156],["H4196","an altar",157,165],["H3068","unto the LORD",166,179],["H7121","and called",181,191],["H8034","upon the name",192,205],["H3068","of the LORD",206,217]]},"12:9":{"text":"And Abram journeyed, going on still toward the south.","words":[["H0087","And Abram",0,9],["H5265","journeyed",10,19],["H1980","going on",21,29],["H5265","still",30,35],["H5045","toward the south",36,52]]},"12:10":{"text":"And there was a famine in the land: and Abram went down into Egypt to sojourn there; for the famine was grievous in the land.","words":[["H7458","And there was a famine",0,22],["H0776","in the land",23,34],["H0087","and Abram",36,45],["H3381","went down",46,55],["H4714","into Egypt",56,66],["H1481","to sojourn",67,77],["H7458","there; for the famine",78,99],["H3515","was grievous",100,112],["H0776","in the land",113,124]]},"12:11":{"text":"And it came to pass, when he was come near to enter into Egypt, that he said unto Sarai his wife, Behold now, I know that thou art a fair woman to look upon:","words":[["H0834","And it came to pass, when",0,25],["H7126","he was come near",26,42],["H0935","to enter",43,51],["H4714","into Egypt",52,62],["H0559","that he said",64,76],["H8297","unto Sarai",77,87],["H0802","his wife",88,96],["H2009","Behold",98,104],["H4994","now",105,108],["H3045","I know",110,116],["H3303","that thou art a fair",117,137],["H0802","woman",138,143],["H4758","to look upon",144,156]]},"12:12":{"text":"Therefore it shall come to pass, when the Egyptians shall see thee, that they shall say, This is his wife: and they will kill me, but they will save thee alive.","words":[["H4713","Therefore it shall come to pass, when the Egyptians",0,51],["H7200","shall see",52,61],["H0559","thee, that they shall say",62,87],["H0802","This is his wife",89,105],["H2026","and they will kill",107,125],["H2421","me, but they will save thee alive",126,159]]},"12:13":{"text":"Say, I pray thee, thou art my sister: that it may be well with me for thy sake; and my soul shall live because of thee.","words":[["H0559","Say",0,3],["H4994","I pray thee",5,16],["H0269","thou art my sister",18,36],["H4616","that",38,42],["H3190","it may be well",43,57],["H5315","with me for thy sake; and my soul",58,91],["H2421","shall live",92,102],["H1558","because of thee",103,118]]},"12:14":{"text":"And it came to pass, that, when Abram was come into Egypt, the Egyptians beheld the woman that she was very fair.","words":[["H0087","And it came to pass, that, when Abram",0,37],["H0935","was come",38,46],["H4714","into Egypt",47,57],["H4713","the Egyptians",59,72],["H7200","beheld",73,79],["H0802","the woman",80,89],["H3966","that she was very",90,107],["H3303","fair",108,112]]},"12:15":{"text":"The princes also of Pharaoh saw her, and commended her before Pharaoh: and the woman was taken into Pharaoh's house.","words":[["H8269","The princes",0,11],["H6547","also of Pharaoh",12,27],["H7200","saw",28,31],["H1984","her, and commended",32,50],["H0413","her before",51,61],["H6547","Pharaoh",62,69],["H0802","and the woman",71,84],["H3947","was taken",85,94],["H6547","into Pharaoh's",95,109],["H1004","house",110,115]]},"12:16":{"text":"And he entreated Abram well for her sake: and he had sheep, and oxen, and he asses, and menservants, and maidservants, and she asses, and camels.","words":[["H3190","And he entreated",0,16],["H0087","Abram",17,22],["H3190","well",23,27],["H6629","for her sake: and he had sheep",28,58],["H1241","and oxen",60,68],["H2543","and he asses",70,82],["H5650","and menservants",84,99],["H8198","and maidservants",101,117],["H0860","and she asses",119,132],["H1581","and camels",134,144]]},"12:17":{"text":"And the LORD plagued Pharaoh and his house with great plagues because of Sarai Abram's wife.","words":[["H3068","And the LORD",0,12],["H5060","plagued",13,20],["H6547","Pharaoh",21,28],["H1004","and his house",29,42],["H1419","with great",43,53],["H5061","plagues",54,61],["H1697","because of",62,72],["H8297","Sarai",73,78],["H0087","Abram's",79,86],["H0802","wife",87,91]]},"12:18":{"text":"And Pharaoh called Abram, and said, What is this that thou hast done unto me? why didst thou not tell me that she was thy wife?","words":[["H6547","And Pharaoh",0,11],["H7121","called",12,18],["H0087","Abram",19,24],["H0559","and said",26,34],["H6213","What is this that thou hast done",36,68],["H5046","unto me? why didst thou not tell",69,101],["H0802","me that she was thy wife",102,126]]},"12:19":{"text":"Why saidst thou, She is my sister? so I might have taken her to me to wife: now therefore behold thy wife, take her, and go thy way.","words":[["H0559","Why saidst thou",0,15],["H0269","She is my sister",17,33],["H3947","so I might have taken",35,56],["H0802","her to me to wife",57,74],["H0802","now therefore behold thy wife",76,105],["H3947","take",107,111],["H3212","her, and go thy way",112,131]]},"12:20":{"text":"And Pharaoh commanded his men concerning him: and they sent him away, and his wife, and all that he had.","words":[["H6547","And Pharaoh",0,11],["H6680","commanded",12,21],["H0582","his men",22,29],["H7971","concerning him: and they sent him away",30,68],["H0802","and his wife",70,82]]},"13:1":{"text":"And Abram went up out of Egypt, he, and his wife, and all that he had, and Lot with him, into the south.","words":[["H0087","And Abram",0,9],["H5927","went up",10,17],["H4714","out of Egypt",18,30],["H0802","he, and his wife",32,48],["H3876","and all that he had, and Lot",50,78],["H5045","with him, into the south",79,103]]},"13:2":{"text":"And Abram was very rich in cattle, in silver, and in gold.","words":[["H0087","And Abram",0,9],["H3966","was very",10,18],["H3513","rich",19,23],["H4735","in cattle",24,33],["H3701","in silver",35,44],["H2091","and in gold",46,57]]},"13:3":{"text":"And he went on his journeys from the south even to Bethel, unto the place where his tent had been at the beginning, between Bethel and Hai;","words":[["H3212","And he went",0,11],["H4550","on his journeys",12,27],["H5045","from the south",28,42],["H1008","even to Bethel",43,57],["H4725","unto the place",59,73],["H0168","where his tent",74,88],["H1961","had been",89,97],["H8462","at the beginning",98,114],["H1008","between Bethel",116,130],["H5857","and Hai",131,138]]},"13:4":{"text":"Unto the place of the altar, which he had made there at the first: and there Abram called on the name of the LORD.","words":[["H4725","Unto the place",0,14],["H4196","of the altar",15,27],["H6213","which he had made",29,46],["H7223","there at the first",47,65],["H0087","and there Abram",67,82],["H7121","called",83,89],["H8034","on the name",90,101],["H3068","of the LORD",102,113]]},"13:5":{"text":"And Lot also, which went with Abram, had flocks, and herds, and tents.","words":[["H3876","And Lot",0,7],["H1980","also, which went",8,24],["H0854","with",25,29],["H0087","Abram",30,35],["H6629","had flocks",37,47],["H1241","and herds",49,58],["H0168","and tents",60,69]]},"13:6":{"text":"And the land was not able to bear them, that they might dwell together: for their substance was great, so that they could not dwell together.","words":[["H0776","And the land",0,12],["H5375","was not able to bear",13,33],["H3427","them, that they might dwell",34,61],["H3162","together",62,70],["H7399","for their substance",72,91],["H7227","was great",92,101],["H3201","so that they could",103,121],["H3427","not dwell",122,131],["H3162","together",132,140]]},"13:7":{"text":"And there was a strife between the herdmen of Abram's cattle and the herdmen of Lot's cattle: and the Canaanite and the Perizzite dwelled then in the land.","words":[["H7379","And there was a strife",0,22],["H7462","between the herdmen",23,42],["H0087","of Abram's",43,53],["H4735","cattle",54,60],["H7462","and the herdmen",61,76],["H3876","of Lot's",77,85],["H4735","cattle",86,92],["H3669","and the Canaanite",94,111],["H6522","and the Perizzite",112,129],["H3427","dwelled",130,137],["H0776","then in the land",138,154]]},"13:8":{"text":"And Abram said unto Lot, Let there be no strife, I pray thee, between me and thee, and between my herdmen and thy herdmen; for we be brethren.","words":[["H0087","And Abram",0,9],["H0559","said",10,14],["H3876","unto Lot",15,23],["H1961","Let there be",25,37],["H0408","no",38,40],["H4808","strife",41,47],["H7462","I pray thee, between me and thee, and between my herdmen",49,105],["H7462","and thy herdmen",106,121],["H0582","for we",123,129],["H0251","be brethren",130,141]]},"13:9":{"text":"Is not the whole land before thee? separate thyself, I pray thee, from me: if thou wilt take the left hand, then I will go to the right; or if thou depart to the right hand, then I will go to the left.","words":[["H0776","Is not the whole land",0,21],["H6440","before thee",22,33],["H6504","separate thyself",35,51],["H8040","I pray thee, from me: if thou wilt take the left hand",53,106],["H3231","then I will go to the right",108,135],["H3225","or if thou depart to the right hand",137,172],["H8041","then I will go to the left",174,200]]},"13:10":{"text":"And Lot lifted up his eyes, and beheld all the plain of Jordan, that it was well watered every where, before the LORD destroyed Sodom and Gomorrah, even as the garden of the LORD, like the land of Egypt, as thou comest unto Zoar.","words":[["H3876","And Lot",0,7],["H5375","lifted up",8,17],["H5869","his eyes",18,26],["H7200","and beheld",28,38],["H3603","all the plain",39,52],["H3383","of Jordan",53,62],["H4945","that it was well watered",64,88],["H6440","every where, before",89,108],["H3068","the LORD",109,117],["H7843","destroyed",118,127],["H5467","Sodom",128,133],["H6017","and Gomorrah",134,146],["H1588","even as the garden",148,166],["H3068","of the LORD",167,178],["H0776","like the land",180,193],["H4714","of Egypt",194,202],["H0935","as thou comest",204,218],["H6820","unto Zoar",219,228]]},"13:11":{"text":"Then Lot chose him all the plain of Jordan; and Lot journeyed east: and they separated themselves the one from the other.","words":[["H3876","Then Lot",0,8],["H0977","chose",9,14],["H3603","him all the plain",15,32],["H3383","of Jordan",33,42],["H3876","and Lot",44,51],["H5265","journeyed",52,61],["H6924","east",62,66],["H6504","and they separated themselves",68,97],["H0376","the one",98,105],["H0251","from the other",106,120]]},"13:12":{"text":"Abram dwelled in the land of Canaan, and Lot dwelled in the cities of the plain, and pitched his tent toward Sodom.","words":[["H0087","Abram",0,5],["H3427","dwelled",6,13],["H0776","in the land",14,25],["H3667","of Canaan",26,35],["H3876","and Lot",37,44],["H3427","dwelled",45,52],["H5892","in the cities",53,66],["H3603","of the plain",67,79],["H0167","and pitched his tent",81,101],["H5704","toward",102,108],["H5467","Sodom",109,114]]},"13:13":{"text":"But the men of Sodom were wicked and sinners before the LORD exceedingly.","words":[["H0582","But the men",0,11],["H5467","of Sodom",12,20],["H7451","were wicked",21,32],["H2400","and sinners",33,44],["H3068","before the LORD",45,60],["H3966","exceedingly",61,72]]},"13:14":{"text":"And the LORD said unto Abram, after that Lot was separated from him, Lift up now thine eyes, and look from the place where thou art northward, and southward, and eastward, and westward:","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H0087","unto Abram",18,28],["H0310","after",30,35],["H3876","that Lot",36,44],["H6504","was separated",45,58],["H5375","from him, Lift up",59,76],["H5869","now thine eyes",77,91],["H7200","and look",93,101],["H4725","from the place",102,116],["H6828","where thou art northward",117,141],["H5045","and southward",143,156],["H6924","and eastward",158,170],["H3220","and westward",172,184]]},"13:15":{"text":"For all the land which thou seest, to thee will I give it, and to thy seed for ever.","words":[["H0776","For all the land",0,16],["H7200","which thou seest",17,33],["H5414","to thee will I give it",35,57],["H2233","and to thy seed",59,74],["H5704","for",75,78],["H5769","ever",79,83]]},"13:16":{"text":"And I will make thy seed as the dust of the earth: so that if a man can number the dust of the earth, then shall thy seed also be numbered.","words":[["H7760","And I will make",0,15],["H2233","thy seed",16,24],["H6083","as the dust",25,36],["H0776","of the earth",37,49],["H0834","so that",51,58],["H0376","if a man",59,67],["H3201","can",68,71],["H4487","number",72,78],["H6083","the dust",79,87],["H0776","of the earth",88,100],["H2233","then shall thy seed",102,121],["H4487","also be numbered",122,138]]},"13:17":{"text":"Arise, walk through the land in the length of it and in the breadth of it; for I will give it unto thee.","words":[["H6965","Arise",0,5],["H1980","walk",7,11],["H0776","through the land",12,28],["H0753","in the length",29,42],["H7341","of it and in the breadth",43,67],["H5414","of it; for I will give",68,90]]},"13:18":{"text":"Then Abram removed his tent, and came and dwelt in the plain of Mamre, which is in Hebron, and built there an altar unto the LORD.","words":[["H0087","Then Abram",0,10],["H0167","removed his tent",11,27],["H0935","and came",29,37],["H3427","and dwelt",38,47],["H0436","in the plain",48,60],["H4471","of Mamre",61,69],["H2275","which is in Hebron",71,89],["H1129","and built",91,100],["H4196","there an altar",101,115],["H3068","unto the LORD",116,129]]},"14:1":{"text":"And it came to pass in the days of Amraphel king of Shinar, Arioch king of Ellasar, Chedorlaomer king of Elam, and Tidal king of nations;","words":[["H3117","And it came to pass in the days",0,31],["H0569","of Amraphel",32,43],["H4428","king",44,48],["H8152","of Shinar",49,58],["H0746","Arioch",60,66],["H4428","king",67,71],["H0495","of Ellasar",72,82],["H3540","Chedorlaomer",84,96],["H4428","king",97,101],["H5867","of Elam",102,109],["H8413","and Tidal",111,120],["H4428","king",121,125],["H1471","of nations",126,136]]},"14:2":{"text":"That these made war with Bera king of Sodom, and with Birsha king of Gomorrah, Shinab king of Admah, and Shemeber king of Zeboiim, and the king of Bela, which is Zoar.","words":[["H6213","That these made",0,15],["H4421","war",16,19],["H0854","with",20,24],["H1298","Bera",25,29],["H4428","king",30,34],["H5467","of Sodom",35,43],["H1306","and with Birsha",45,60],["H4428","king",61,65],["H6017","of Gomorrah",66,77],["H8134","Shinab",79,85],["H4428","king",86,90],["H0126","of Admah",91,99],["H8038","and Shemeber",101,113],["H4428","king",114,118],["H6636","of Zeboiim",119,129],["H4428","and the king",131,143],["H1106","of Bela",144,151],["H1931","which is",153,161],["H6820","Zoar",162,166]]},"14:3":{"text":"All these were joined together in the vale of Siddim, which is the salt sea.","words":[["H2266","All these were joined together",0,30],["H6010","in the vale",31,42],["H7708","of Siddim",43,52],["H1931","which",54,59],["H4417","is the salt",60,71],["H3220","sea",72,75]]},"14:4":{"text":"Twelve years they served Chedorlaomer, and in the thirteenth year they rebelled.","words":[["H6240","Twelve",0,6],["H8147","Twelve",0,6],["H8141","years",7,12],["H5647","they served",13,24],["H0853","",-1,-1],["H3540","Chedorlaomer",25,37],["H7969","and in the thirteenth",39,60],["H6240","and in the thirteenth",39,60],["H8141","year",61,65],["H4775","they rebelled",66,79]]},"14:5":{"text":"And in the fourteenth year came Chedorlaomer, and the kings that were with him, and smote the Rephaims in Ashteroth Karnaim, and the Zuzims in Ham, and the Emims in Shaveh Kiriathaim,","words":[["H6240","And in the fourteenth",0,21],["H0702","And in the fourteenth",0,21],["H8141","year",22,26],["H0935","came",27,31],["H3540","Chedorlaomer",32,44],["H4428","and the kings",46,59],["H5221","that were with him, and smote",60,89],["H7497","the Rephaims",90,102],["H6255","in Ashteroth Karnaim",103,123],["H2104","and the Zuzims",125,139],["H1990","in Ham",140,146],["H0368","and the Emims",148,161],["H7741","in Shaveh Kiriathaim",162,182]]},"14:6":{"text":"And the Horites in their mount Seir, unto Elparan, which is by the wilderness.","words":[["H2752","And the Horites",0,15],["H2042","in their mount",16,30],["H8165","Seir",31,35],["H0364","unto Elparan",37,49],["H5921","which is by",51,62],["H4057","the wilderness",63,77]]},"14:7":{"text":"And they returned, and came to Enmishpat, which is Kadesh, and smote all the country of the Amalekites, and also the Amorites, that dwelt in Hazezontamar.","words":[["H7725","And they returned",0,17],["H0935","and came",19,27],["H0413","to",28,30],["H5880","Enmishpat",31,40],["H6946","which is Kadesh",42,57],["H5221","and smote",59,68],["H7704","all the country",69,84],["H6003","of the Amalekites",85,102],["H0567","and also the Amorites",104,125],["H3427","that dwelt",127,137],["H2688","in Hazezontamar",138,153]]},"14:8":{"text":"And there went out the king of Sodom, and the king of Gomorrah, and the king of Admah, and the king of Zeboiim, and the king of Bela (the same is Zoar;) and they joined battle with them in the vale of Siddim;","words":[["H3318","And there went out",0,18],["H4428","the king",19,27],["H5467","of Sodom",28,36],["H4428","and the king",38,50],["H6017","of Gomorrah",51,62],["H4428","and the king",64,76],["H0126","of Admah",77,85],["H4428","and the king",87,99],["H6636","of Zeboiim",100,110],["H4428","and the king",112,124],["H1106","of Bela",125,132],["H1931","(the same",133,142],["H6820","is Zoar",143,150],["H6186",") and they joined",151,168],["H4421","battle",169,175],["H6010","with them in the vale",176,197],["H7708","of Siddim",198,207]]},"14:9":{"text":"With Chedorlaomer the king of Elam, and with Tidal king of nations, and Amraphel king of Shinar, and Arioch king of Ellasar; four kings with five.","words":[["H3540","With Chedorlaomer",0,17],["H4428","the king",18,26],["H5867","of Elam",27,34],["H8413","and with Tidal",36,50],["H4428","king",51,55],["H1471","of nations",56,66],["H0569","and Amraphel",68,80],["H4428","king",81,85],["H8152","of Shinar",86,95],["H0746","and Arioch",97,107],["H4428","king",108,112],["H0495","of Ellasar",113,123],["H0702","four",125,129],["H4428","kings",130,135],["H2568","with five",136,145]]},"14:10":{"text":"And the vale of Siddim was full of slimepits; and the kings of Sodom and Gomorrah fled, and fell there; and they that remained fled to the mountain.","words":[["H6010","And the vale",0,12],["H7708","of Siddim",13,22],["H0875","was full of",23,34],["H0875","slimepits",35,44],["H2564","slimepits",35,44],["H4428","and the kings",46,59],["H5467","of Sodom",60,68],["H6017","and Gomorrah",69,81],["H5127","fled",82,86],["H5307","and fell",88,96],["H7604","there; and they that remained",97,126],["H5127","fled",127,131],["H2022","to the mountain",132,147]]},"14:11":{"text":"And they took all the goods of Sodom and Gomorrah, and all their victuals, and went their way.","words":[["H3947","And they took",0,13],["H7399","all the goods",14,27],["H5467","of Sodom",28,36],["H6017","and Gomorrah",37,49],["H0400","and all their victuals",51,73],["H3212","and went their way",75,93]]},"14:12":{"text":"And they took Lot, Abram's brother's son, who dwelt in Sodom, and his goods, and departed.","words":[["H3947","And they took",0,13],["H3876","Lot",14,17],["H0087","Abram's",19,26],["H0251","brother's",27,36],["H1121","son",37,40],["H3427","who dwelt",42,51],["H5467","in Sodom",52,60],["H7399","and his goods",62,75],["H3212","and departed",77,89]]},"14:13":{"text":"And there came one that had escaped, and told Abram the Hebrew; for he dwelt in the plain of Mamre the Amorite, brother of Eshcol, and brother of Aner: and these were confederate with Abram.","words":[["H0935","And there came",0,14],["H6412","one that had escaped",15,35],["H5046","and told",37,45],["H0087","Abram",46,51],["H5680","the Hebrew",52,62],["H7931","for he dwelt",64,76],["H0436","in the plain",77,89],["H4471","of Mamre",90,98],["H0567","the Amorite",99,110],["H0251","brother",112,119],["H0812","of Eshcol",120,129],["H0251","and brother",131,142],["H6063","of Aner",143,150],["H1167","and these were confederate",152,178],["H1285","and these were confederate",152,178],["H0087","with Abram",179,189]]},"14:14":{"text":"And when Abram heard that his brother was taken captive, he armed his trained servants, born in his own house, three hundred and eighteen, and pursued them unto Dan.","words":[["H0087","And when Abram",0,14],["H8085","heard",15,20],["H0251","that his brother",21,37],["H7617","was taken captive",38,55],["H7324","he armed",57,65],["H2593","his trained",66,77],["H3211","servants, born",78,92],["H1004","in his own house",93,109],["H7969","three",111,116],["H3967","hundred",117,124],["H6240","and eighteen",125,137],["H8083","and eighteen",125,137],["H7291","and pursued",139,150],["H1835","them unto Dan",151,164]]},"14:15":{"text":"And he divided himself against them, he and his servants, by night, and smote them, and pursued them unto Hobah, which is on the left hand of Damascus.","words":[["H2505","And he divided",0,14],["H5650","himself against them, he and his servants",15,56],["H3915","by night",58,66],["H5221","and smote",68,77],["H7291","them, and pursued",78,95],["H2327","them unto Hobah",96,111],["H8040","which is on the left hand",113,138],["H1834","of Damascus",139,150]]},"14:16":{"text":"And he brought back all the goods, and also brought again his brother Lot, and his goods, and the women also, and the people.","words":[["H7725","And he brought back",0,19],["H7399","all the goods",20,33],["H7725","and also brought again",35,57],["H0251","his brother",58,69],["H3876","Lot",70,73],["H7399","and his goods",75,88],["H0802","and the women",90,103],["H5971","also, and the people",104,124]]},"14:17":{"text":"And the king of Sodom went out to meet him after his return from the slaughter of Chedorlaomer, and of the kings that were with him, at the valley of Shaveh, which is the king's dale.","words":[["H4428","And the king",0,12],["H5467","of Sodom",13,21],["H3318","went out",22,30],["H7125","to meet",31,38],["H0310","him after",39,48],["H7725","his return",49,59],["H5221","from the slaughter",60,78],["H3540","of Chedorlaomer",79,94],["H4428","and of the kings",96,112],["H6010","that were with him, at the valley",113,146],["H7740","of Shaveh",147,156],["H1931","which",158,163],["H4428","is the king's",164,177],["H6010","dale",178,182]]},"14:18":{"text":"And Melchizedek king of Salem brought forth bread and wine: and he was the priest of the most high God.","words":[["H4442","And Melchizedek",0,15],["H4428","king",16,20],["H8004","of Salem",21,29],["H3318","brought forth",30,43],["H3899","bread",44,49],["H3196","and wine",50,58],["H3548","and he was the priest",60,81],["H5945","of the most high",82,98],["H0410","God",99,102]]},"14:19":{"text":"And he blessed him, and said, Blessed be Abram of the most high God, possessor of heaven and earth:","words":[["H1288","And he blessed",0,14],["H0559","him, and said",15,28],["H1288","Blessed",30,37],["H0087","be Abram",38,46],["H5945","of the most high",47,63],["H0410","God",64,67],["H7069","possessor",69,78],["H8064","of heaven",79,88],["H0776","and earth",89,98]]},"14:20":{"text":"And blessed be the most high God, which hath delivered thine enemies into thy hand. And he gave him tithes of all.","words":[["H1288","And blessed",0,11],["H5945","be the most high",12,28],["H0410","God",29,32],["H4042","which hath delivered",34,54],["H6862","thine enemies",55,68],["H3027","into thy hand",69,82],["H5414","And he gave",84,95],["H4643","him tithes",96,106]]},"14:21":{"text":"And the king of Sodom said unto Abram, Give me the persons, and take the goods to thyself.","words":[["H4428","And the king",0,12],["H5467","of Sodom",13,21],["H0559","said",22,26],["H0087","unto Abram",27,37],["H5414","Give",39,43],["H5315","me the persons",44,58],["H3947","and take",60,68],["H7399","the goods",69,78]]},"14:22":{"text":"And Abram said to the king of Sodom, I have lift up mine hand unto the LORD, the most high God, the possessor of heaven and earth,","words":[["H0087","And Abram",0,9],["H0559","said",10,14],["H4428","to the king",15,26],["H5467","of Sodom",27,35],["H7311","I have lift up",37,51],["H3027","mine hand",52,61],["H3068","unto the LORD",62,75],["H5945","the most high",77,90],["H0410","God",91,94],["H7069","the possessor",96,109],["H8064","of heaven",110,119],["H0776","and earth",120,129]]},"14:23":{"text":"That I will not take from a thread even to a shoelatchet, and that I will not take any thing that is thine, lest thou shouldest say, I have made Abram rich:","words":[["H0518","That I will not",0,15],["H2339","take from a thread",16,34],["H5275","even to a shoelatchet",35,56],["H8288","even to a shoelatchet",35,56],["H0518","and that I will not",58,77],["H3947","take",78,82],["H0559","any thing that is thine, lest thou shouldest say",83,131],["H6238","I have made",133,144],["H0087","Abram",145,150],["H6238","rich",151,155]]},"14:24":{"text":"Save only that which the young men have eaten, and the portion of the men which went with me, Aner, Eshcol, and Mamre; let them take their portion.","words":[["H1107","Save",0,4],["H0834","only that which",5,20],["H5288","the young men",21,34],["H0398","have eaten",35,45],["H2506","and the portion",47,62],["H0582","of the men",63,73],["H1980","which went",74,84],["H0854","with",85,89],["H6063","me, Aner",90,98],["H0812","Eshcol",100,106],["H4471","and Mamre",108,117],["H1992","let them",119,127],["H3947","take",128,132],["H2506","their portion",133,146]]},"15:1":{"text":"After these things the word of the LORD came unto Abram in a vision, saying, Fear not, Abram: I am thy shield, and thy exceeding great reward.","words":[["H0310","After",0,5],["H1697","these things",6,18],["H1697","the word",19,27],["H3068","of the LORD",28,39],["H1961","came",40,44],["H0087","unto Abram",45,55],["H4236","in a vision",56,67],["H0559","saying",69,75],["H3372","Fear",77,81],["H0087","not, Abram",82,92],["H4043","I am thy shield",94,109],["H3966","and thy exceeding",111,128],["H7235","great",129,134],["H7939","reward",135,141]]},"15:2":{"text":"And Abram said, Lord GOD, what wilt thou give me, seeing I go childless, and the steward of my house is this Eliezer of Damascus?","words":[["H0087","And Abram",0,9],["H0559","said",10,14],["H0136","Lord",16,20],["H3069","GOD",21,24],["H5414","what wilt thou give",26,45],["H1980","me, seeing I go",46,61],["H6185","childless",62,71],["H1121","and the steward",73,88],["H4943","and the steward",73,88],["H1004","of my house",89,100],["H1931","is this",101,108],["H0461","Eliezer",109,116],["H1834","of Damascus",117,128]]},"15:3":{"text":"And Abram said, Behold, to me thou hast given no seed: and, lo, one born in my house is mine heir.","words":[["H0087","And Abram",0,9],["H0559","said",10,14],["H5414","Behold, to me thou hast given",16,45],["H3808","no",46,48],["H2233","seed",49,53],["H1121","and, lo, one born",55,72],["H1004","in my house",73,84],["H3423","is mine heir",85,97]]},"15:4":{"text":"And, behold, the word of the LORD came unto him, saying, This shall not be thine heir; but he that shall come forth out of thine own bowels shall be thine heir.","words":[["H1697","And, behold, the word",0,21],["H3068","of the LORD",22,33],["H0559","came unto him, saying",34,55],["H3423","This shall not be thine heir",57,85],["H3318","but he that shall come forth",87,115],["H4578","out of thine own bowels",116,139],["H3423","shall be thine heir",140,159]]},"15:5":{"text":"And he brought him forth abroad, and said, Look now toward heaven, and tell the stars, if thou be able to number them: and he said unto him, So shall thy seed be.","words":[["H3318","And he brought him forth",0,24],["H2351","abroad",25,31],["H0559","and said",33,41],["H5027","Look",43,47],["H8064","now toward heaven",48,65],["H5608","and tell",67,75],["H3556","the stars",76,85],["H3201","if thou be able",87,102],["H5608","to number",103,112],["H0559","them: and he said",113,130],["H3541","unto him, So",131,143],["H2233","shall thy seed",144,158]]},"15:6":{"text":"And he believed in the LORD; and he counted it to him for righteousness.","words":[["H0539","And he believed",0,15],["H3068","in the LORD",16,27],["H2803","and he counted",29,43],["H6666","it to him for righteousness",44,71]]},"15:7":{"text":"And he said unto him, I am the LORD that brought thee out of Ur of the Chaldees, to give thee this land to inherit it.","words":[["H0559","And he said",0,11],["H3068","unto him, I am the LORD",12,35],["H3318","that brought thee out",36,57],["H0218","of Ur",58,63],["H3778","of the Chaldees",64,79],["H5414","to give",81,88],["H0776","thee this land",89,103],["H3423","to inherit",104,114]]},"15:8":{"text":"And he said, Lord GOD, whereby shall I know that I shall inherit it?","words":[["H0559","And he said",0,11],["H0136","Lord",13,17],["H3069","GOD",18,21],["H4100","whereby",23,30],["H3045","shall I know",31,43],["H3423","that I shall inherit it",44,67]]},"15:9":{"text":"And he said unto him, Take me an heifer of three years old, and a she goat of three years old, and a ram of three years old, and a turtledove, and a young pigeon.","words":[["H0559","And he said",0,11],["H3947","unto him, Take",12,26],["H5697","me an heifer",27,39],["H8027","of three years old",40,58],["H5795","and a she goat",60,74],["H8027","of three years old",75,93],["H0352","and a ram",95,104],["H8027","of three years old",105,123],["H8449","and a turtledove",125,141],["H1469","and a young pigeon",143,161]]},"15:10":{"text":"And he took unto him all these, and divided them in the midst, and laid each piece one against another: but the birds divided he not.","words":[["H3947","And he took",0,11],["H1334","unto him all these, and divided",12,43],["H8432","them in the midst",44,61],["H5414","and laid",63,71],["H0376","each",72,76],["H1335","piece",77,82],["H7125","one against",83,94],["H7453","another",95,102],["H6833","but the birds",104,117],["H1334","divided",118,125]]},"15:11":{"text":"And when the fowls came down upon the carcases, Abram drove them away.","words":[["H5861","And when the fowls",0,18],["H3381","came down",19,28],["H6297","upon the carcases",29,46],["H0087","Abram",48,53],["H5380","drove them away",54,69]]},"15:12":{"text":"And when the sun was going down, a deep sleep fell upon Abram; and, lo, an horror of great darkness fell upon him.","words":[["H8121","And when the sun",0,16],["H0935","was going down",17,31],["H8639","a deep sleep",33,45],["H5307","fell",46,50],["H0087","upon Abram",51,61],["H0367","and, lo, an horror",63,81],["H1419","of great",82,90],["H2825","darkness",91,99],["H5307","fell",100,104]]},"15:13":{"text":"And he said unto Abram, Know of a surety that thy seed shall be a stranger in a land that is not theirs, and shall serve them; and they shall afflict them four hundred years;","words":[["H0559","And he said",0,11],["H0087","unto Abram",12,22],["H3045","Know",24,28],["H3045","of a surety",29,40],["H2233","that thy seed",41,54],["H1616","shall be a stranger",55,74],["H0776","in a land",75,84],["H5647","that is not theirs, and shall serve",85,120],["H6031","them; and they shall afflict",121,149],["H0702","them four",150,159],["H3967","hundred",160,167],["H8141","years",168,173]]},"15:14":{"text":"And also that nation, whom they shall serve, will I judge: and afterward shall they come out with great substance.","words":[["H1471","And also that nation",0,20],["H5647","whom they shall serve",22,43],["H1777","will I judge",45,57],["H0310","and afterward",59,72],["H3651","and afterward",59,72],["H3318","shall they come out",73,92],["H1419","with great",93,103],["H7399","substance",104,113]]},"15:15":{"text":"And thou shalt go to thy fathers in peace; thou shalt be buried in a good old age.","words":[["H0935","And thou shalt go",0,17],["H0001","to thy fathers",18,32],["H7965","in peace",33,41],["H6912","thou shalt be buried",43,63],["H2896","in a good",64,73],["H7872","old age",74,81]]},"15:16":{"text":"But in the fourth generation they shall come hither again: for the iniquity of the Amorites is not yet full.","words":[["H7243","But in the fourth",0,17],["H1755","generation",18,28],["H2008","they shall come hither",29,51],["H7725","again",52,57],["H5771","for the iniquity",59,75],["H0567","of the Amorites",76,91],["H2008","is not yet",92,102],["H8003","full",103,107]]},"15:17":{"text":"And it came to pass, that, when the sun went down, and it was dark, behold a smoking furnace, and a burning lamp that passed between those pieces.","words":[["H8121","And it came to pass, that, when the sun",0,39],["H0935","went down",40,49],["H5939","and it was dark",51,66],["H6227","behold a smoking",68,84],["H8574","furnace",85,92],["H0784","and a burning",94,107],["H3940","lamp",108,112],["H5674","that passed",113,124],["H0996","between",125,132],["H1506","those pieces",133,145]]},"15:18":{"text":"In the same day the LORD made a covenant with Abram, saying, Unto thy seed have I given this land, from the river of Egypt unto the great river, the river Euphrates:","words":[["H1931","In the same",0,11],["H3117","day",12,15],["H3068","the LORD",16,24],["H3772","made",25,29],["H1285","a covenant",30,40],["H0087","with Abram",41,51],["H0559","saying",53,59],["H2233","Unto thy seed",61,74],["H5414","have I given",75,87],["H0776","this land",88,97],["H5104","from the river",99,113],["H4714","of Egypt",114,122],["H1419","unto the great",123,137],["H5104","river",138,143],["H5104","the river",145,154],["H6578","Euphrates",155,164]]},"15:19":{"text":"The Kenites, and the Kenizzites, and the Kadmonites,","words":[["H7017","The Kenites",0,11],["H7074","and the Kenizzites",13,31],["H6935","and the Kadmonites",33,51]]},"15:20":{"text":"And the Hittites, and the Perizzites, and the Rephaims,","words":[["H2850","And the Hittites",0,16],["H6522","and the Perizzites",18,36],["H7497","and the Rephaims",38,54]]},"15:21":{"text":"And the Amorites, and the Canaanites, and the Girgashites, and the Jebusites.","words":[["H0567","And the Amorites",0,16],["H3669","and the Canaanites",18,36],["H1622","and the Girgashites",38,57],["H2983","and the Jebusites",59,76]]},"16:1":{"text":"Now Sarai Abram's wife bare him no children: and she had an handmaid, an Egyptian, whose name was Hagar.","words":[["H8297","Now Sarai",0,9],["H0087","Abram's",10,17],["H0802","wife",18,22],["H3205","bare",23,27],["H3808","him no",28,34],["H3205","children",35,43],["H8198","and she had an handmaid",45,68],["H4713","an Egyptian",70,81],["H8034","whose name",83,93],["H1904","was Hagar",94,103]]},"16:2":{"text":"And Sarai said unto Abram, Behold now, the LORD hath restrained me from bearing: I pray thee, go in unto my maid; it may be that I may obtain children by her. And Abram hearkened to the voice of Sarai.","words":[["H8297","And Sarai",0,9],["H0559","said",10,14],["H0087","unto Abram",15,25],["H3068","Behold now, the LORD",27,47],["H6113","hath restrained me",48,66],["H3205","from bearing",67,79],["H0935","I pray thee, go in",81,99],["H8198","unto my maid",100,112],["H0194","it may",114,120],["H1129","be that I may obtain children",121,150],["H0087","by her. And Abram",151,168],["H8085","hearkened",169,178],["H6963","to the voice",179,191],["H8297","of Sarai",192,200]]},"16:3":{"text":"And Sarai Abram's wife took Hagar her maid the Egyptian, after Abram had dwelt ten years in the land of Canaan, and gave her to her husband Abram to be his wife.","words":[["H8297","And Sarai",0,9],["H0087","Abram's",10,17],["H0802","wife",18,22],["H3947","took",23,27],["H1904","Hagar",28,33],["H8198","her maid",34,42],["H4713","the Egyptian",43,55],["H7093","after",57,62],["H0087","Abram",63,68],["H3427","had dwelt",69,78],["H6235","ten",79,82],["H8141","years",83,88],["H0776","in the land",89,100],["H3667","of Canaan",101,110],["H5414","and gave",112,120],["H0376","her to her husband",121,139],["H0087","Abram",140,145],["H0802","to be his wife",146,160]]},"16:4":{"text":"And he went in unto Hagar, and she conceived: and when she saw that she had conceived, her mistress was despised in her eyes.","words":[["H0935","And he went in",0,14],["H1904","unto Hagar",15,25],["H2029","and she conceived",27,44],["H7200","and when she saw",46,62],["H2029","that she had conceived",63,85],["H1404","her mistress",87,99],["H7043","was despised",100,112],["H5869","in her eyes",113,124]]},"16:5":{"text":"And Sarai said unto Abram, My wrong be upon thee: I have given my maid into thy bosom; and when she saw that she had conceived, I was despised in her eyes: the LORD judge between me and thee.","words":[["H8297","And Sarai",0,9],["H0559","said",10,14],["H0087","unto Abram",15,25],["H2555","My wrong",27,35],["H5414","be upon thee: I have given",36,62],["H8198","my maid",63,70],["H2436","into thy bosom",71,85],["H7200","and when she saw",87,103],["H2029","that she had conceived",104,126],["H7043","I was despised",128,142],["H5869","in her eyes",143,154],["H3068","the LORD",156,164],["H8199","judge",165,170]]},"16:6":{"text":"But Abram said unto Sarai, Behold, thy maid is in thy hand; do to her as it pleaseth thee. And when Sarai dealt hardly with her, she fled from her face.","words":[["H0087","But Abram",0,9],["H0559","said",10,14],["H8297","unto Sarai",15,25],["H8198","Behold, thy maid",27,43],["H3027","is in thy hand",44,58],["H6213","do",60,62],["H2896","to her as it pleaseth thee",63,89],["H5869","to her as it pleaseth thee",63,89],["H8297","And when Sarai",91,105],["H6031","dealt hardly with",106,123],["H1272","her, she fled",124,137],["H6440","from her face",138,151]]},"16:7":{"text":"And the angel of the LORD found her by a fountain of water in the wilderness, by the fountain in the way to Shur.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H4672","found her",26,35],["H5869","by a fountain",36,49],["H4325","of water",50,58],["H4057","in the wilderness",59,76],["H5869","by the fountain",78,93],["H1870","in the way",94,104],["H7793","to Shur",105,112]]},"16:8":{"text":"And he said, Hagar, Sarai's maid, whence camest thou? and whither wilt thou go? And she said, I flee from the face of my mistress Sarai.","words":[["H0559","And he said",0,11],["H1904","Hagar",13,18],["H8297","Sarai's",20,27],["H8198","maid",28,32],["H0335","whence",34,40],["H0935","camest thou",41,52],["H3212","and whither wilt thou go",54,78],["H0559","And she said",80,92],["H1272","I flee",94,100],["H6440","from the face",101,114],["H1404","of my mistress",115,129],["H8297","Sarai",130,135]]},"16:9":{"text":"And the angel of the LORD said unto her, Return to thy mistress, and submit thyself under her hands.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H0559","said",26,30],["H7725","unto her, Return",31,47],["H1404","to thy mistress",48,63],["H6031","and submit",65,75],["H3027","thyself under her hands",76,99]]},"16:10":{"text":"And the angel of the LORD said unto her, I will multiply thy seed exceedingly, that it shall not be numbered for multitude.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H0559","said",26,30],["H7235","unto her, I will multiply",31,56],["H2233","thy seed",57,65],["H7235","exceedingly",66,77],["H5608","that it shall not be numbered",79,108],["H7230","for multitude",109,122]]},"16:11":{"text":"And the angel of the LORD said unto her, Behold, thou art with child, and shalt bear a son, and shalt call his name Ishmael; because the LORD hath heard thy affliction.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H0559","said",26,30],["H2009","unto her, Behold",31,47],["H2030","thou art with child",49,68],["H3205","and shalt bear",70,84],["H1121","a son",85,90],["H7121","and shalt call",92,106],["H8034","his name",107,115],["H3458","Ishmael",116,123],["H3068","because the LORD",125,141],["H8085","hath heard",142,152],["H6040","thy affliction",153,167]]},"16:12":{"text":"And he will be a wild man; his hand will be against every man, and every man's hand against him; and he shall dwell in the presence of all his brethren.","words":[["H6501","And he will be a wild",0,21],["H0120","man",22,25],["H3027","his hand",27,35],["H3027","will be against every man, and every man's hand",36,83],["H7931","against him; and he shall dwell",84,115],["H6440","in the presence",116,131],["H0251","of all his brethren",132,151]]},"16:13":{"text":"And she called the name of the LORD that spake unto her, Thou God seest me: for she said, Have I also here looked after him that seeth me?","words":[["H7121","And she called",0,14],["H8034","the name",15,23],["H3068","of the LORD",24,35],["H1696","that spake",36,46],["H0410","unto her, Thou God",47,65],["H7210","seest me",66,74],["H0559","for she said",76,88],["H1988","Have I also here",90,106],["H7200","looked",107,113],["H0310","after him",114,123],["H7210","that seeth me",124,137]]},"16:14":{"text":"Wherefore the well was called Beerlahairoi; behold, it is between Kadesh and Bered.","words":[["H0875","Wherefore the well",0,18],["H7121","was called",19,29],["H0883","Beerlahairoi",30,42],["H2416","Beerlahairoi",30,42],["H6946","behold, it is between Kadesh",44,72],["H1260","and Bered",73,82]]},"16:15":{"text":"And Hagar bare Abram a son: and Abram called his son's name, which Hagar bare, Ishmael.","words":[["H1904","And Hagar",0,9],["H3205","bare",10,14],["H0087","Abram",15,20],["H1121","a son",21,26],["H0087","and Abram",28,37],["H7121","called",38,44],["H1121","his son's",45,54],["H8034","name",55,59],["H1904","which Hagar",61,72],["H3205","bare",73,77],["H3458","Ishmael",79,86]]},"16:16":{"text":"And Abram was fourscore and six years old, when Hagar bare Ishmael to Abram.","words":[["H0087","And Abram",0,9],["H8084","was fourscore",10,23],["H8141","was fourscore",10,23],["H8337","and six",24,31],["H8141","years",32,37],["H1121","old",38,41],["H1904","when Hagar",43,53],["H3205","bare",54,58],["H3458","Ishmael",59,66],["H0087","to Abram",67,75]]},"17:1":{"text":"And when Abram was ninety years old and nine, the LORD appeared to Abram, and said unto him, I am the Almighty God; walk before me, and be thou perfect.","words":[["H0087","And when Abram",0,14],["H8673","was ninety",15,25],["H8141","was ninety",15,25],["H8141","years",26,31],["H1121","old",32,35],["H8672","and nine",36,44],["H3068","the LORD",46,54],["H7200","appeared",55,63],["H0087","to Abram",64,72],["H0559","and said",74,82],["H7706","unto him, I am the Almighty",83,110],["H0410","God",111,114],["H1980","walk",116,120],["H6440","before me",121,130],["H8549","and be thou perfect",132,151]]},"17:2":{"text":"And I will make my covenant between me and thee, and will multiply thee exceedingly.","words":[["H5414","And I will make",0,15],["H1285","my covenant",16,27],["H7235","between me and thee, and will multiply",28,66],["H3966","thee exceedingly",67,83],["H3966","thee exceedingly",67,83]]},"17:3":{"text":"And Abram fell on his face: and God talked with him, saying,","words":[["H0087","And Abram",0,9],["H5307","fell",10,14],["H6440","on his face",15,26],["H0430","and God",28,35],["H1696","talked",36,42],["H0559","with him, saying",43,59]]},"17:4":{"text":"As for me, behold, my covenant is with thee, and thou shalt be a father of many nations.","words":[["H0589","As for me",0,9],["H1285","behold, my covenant",11,30],["H0001","is with thee, and thou shalt be a father",31,71],["H1995","of many",72,79],["H1471","nations",80,87]]},"17:5":{"text":"Neither shall thy name any more be called Abram, but thy name shall be Abraham; for a father of many nations have I made thee.","words":[["H8034","Neither shall thy name",0,22],["H7121","any more be called",23,41],["H0087","Abram",42,47],["H8034","but thy name",49,61],["H0085","shall be Abraham",62,78],["H0001","for a father",80,92],["H1995","of many",93,100],["H1471","nations",101,108],["H5414","have I made thee",109,125]]},"17:6":{"text":"And I will make thee exceeding fruitful, and I will make nations of thee, and kings shall come out of thee.","words":[["H6509","And I will make",0,15],["H3966","thee exceeding",16,30],["H3966","thee exceeding",16,30],["H6509","fruitful",31,39],["H5414","and I will make",41,56],["H1471","nations",57,64],["H4428","of thee, and kings",65,83],["H3318","shall come out",84,98]]},"17:7":{"text":"And I will establish my covenant between me and thee and thy seed after thee in their generations for an everlasting covenant, to be a God unto thee, and to thy seed after thee.","words":[["H6965","And I will establish",0,20],["H1285","my covenant",21,32],["H2233","between me and thee and thy seed",33,65],["H0310","after thee",66,76],["H1755","in their generations",77,97],["H5769","for an everlasting",98,116],["H1285","covenant",117,125],["H0430","to be a God",127,138],["H2233","unto thee, and to thy seed",139,165],["H0310","after thee",166,176]]},"17:8":{"text":"And I will give unto thee, and to thy seed after thee, the land wherein thou art a stranger, all the land of Canaan, for an everlasting possession; and I will be their God.","words":[["H5414","And I will give",0,15],["H2233","unto thee, and to thy seed",16,42],["H0310","after thee",43,53],["H0776","the land",55,63],["H4033","wherein thou art a stranger",64,91],["H0776","all the land",93,105],["H3667","of Canaan",106,115],["H5769","for an everlasting",117,135],["H0272","possession",136,146],["H0430","and I will be their God",148,171]]},"17:9":{"text":"And God said unto Abraham, Thou shalt keep my covenant therefore, thou, and thy seed after thee in their generations.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0085","unto Abraham",13,25],["H8104","Thou shalt keep",27,42],["H1285","my covenant",43,54],["H2233","therefore, thou, and thy seed",55,84],["H0310","after thee",85,95],["H1755","in their generations",96,116]]},"17:10":{"text":"This is my covenant, which ye shall keep, between me and you and thy seed after thee; Every man child among you shall be circumcised.","words":[["H1285","This is my covenant",0,19],["H8104","which ye shall keep",21,40],["H2233","between me and you and thy seed",42,73],["H0310","after thee",74,84],["H2145","Every man child",86,101],["H4135","among you shall be circumcised",102,132]]},"17:11":{"text":"And ye shall circumcise the flesh of your foreskin; and it shall be a token of the covenant betwixt me and you.","words":[["H5243","And ye shall circumcise",0,23],["H1320","the flesh",24,33],["H6190","of your foreskin",34,50],["H0226","and it shall be a token",52,75],["H1285","of the covenant",76,91]]},"17:12":{"text":"And he that is eight days old shall be circumcised among you, every man child in your generations, he that is born in the house, or bought with money of any stranger, which is not of thy seed.","words":[["H8083","And he that is eight",0,20],["H3117","days",21,25],["H1121","old",26,29],["H4135","shall be circumcised",30,50],["H2145","among you, every man child",51,77],["H1755","in your generations",78,97],["H3211","he that is born",99,114],["H1004","in the house",115,127],["H4736","or bought",129,138],["H3701","with money",139,149],["H1121","of any stranger",150,165],["H5236","of any stranger",150,165],["H2233","which is not of thy seed",167,191]]},"17:13":{"text":"He that is born in thy house, and he that is bought with thy money, must needs be circumcised: and my covenant shall be in your flesh for an everlasting covenant.","words":[["H3211","He that is born",0,15],["H1004","in thy house",16,28],["H4736","and he that is bought",30,51],["H3701","with thy money",52,66],["H4135","must needs",68,78],["H4135","be circumcised",79,93],["H1285","and my covenant",95,110],["H1320","shall be in your flesh",111,133],["H5769","for an everlasting",134,152],["H1285","covenant",153,161]]},"17:14":{"text":"And the uncircumcised man child whose flesh of his foreskin is not circumcised, that soul shall be cut off from his people; he hath broken my covenant.","words":[["H6189","And the uncircumcised",0,21],["H2145","man child",22,31],["H0834","whose",32,37],["H1320","flesh",38,43],["H6190","of his foreskin",44,59],["H4135","is not circumcised",60,78],["H5315","that soul",80,89],["H3772","shall be cut off",90,106],["H5971","from his people",107,122],["H6565","he hath broken",124,138],["H1285","my covenant",139,150]]},"17:15":{"text":"And God said unto Abraham, As for Sarai thy wife, thou shalt not call her name Sarai, but Sarah shall her name be.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0085","unto Abraham",13,25],["H8297","As for Sarai",27,39],["H0802","thy wife",40,48],["H7121","thou shalt not call",50,69],["H8034","her name",70,78],["H8297","Sarai",79,84],["H3588","but",86,89],["H8283","Sarah",90,95],["H8034","shall her name",96,110]]},"17:16":{"text":"And I will bless her, and give thee a son also of her: yea, I will bless her, and she shall be a mother of nations; kings of people shall be of her.","words":[["H1288","And I will bless",0,16],["H5414","her, and give",17,30],["H1121","thee a son",31,41],["H1288","also of her: yea, I will bless",42,72],["H1471","her, and she shall be a mother of nations",73,114],["H4428","kings",116,121],["H5971","of people",122,131]]},"17:17":{"text":"Then Abraham fell upon his face, and laughed, and said in his heart, Shall a child be born unto him that is an hundred years old? and shall Sarah, that is ninety years old, bear?","words":[["H0085","Then Abraham",0,12],["H5307","fell",13,17],["H6440","upon his face",18,31],["H6711","and laughed",33,44],["H0559","and said",46,54],["H3820","in his heart",55,67],["H3205","Shall a child be born",69,90],["H3967","unto him that is an hundred",91,118],["H8141","years",119,124],["H1121","old",125,128],["H8283","and shall Sarah",130,145],["H8673","that is ninety",147,161],["H8141","years",162,167],["H1323","old",168,171],["H3205","bear",173,177]]},"17:18":{"text":"And Abraham said unto God, O that Ishmael might live before thee!","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H0430","unto God",17,25],["H3863","O that",27,33],["H3458","Ishmael",34,41],["H2421","might live",42,52],["H6440","before thee",53,64]]},"17:19":{"text":"And God said, Sarah thy wife shall bear thee a son indeed; and thou shalt call his name Isaac: and I will establish my covenant with him for an everlasting covenant, and with his seed after him.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H8283","Sarah",14,19],["H0802","thy wife",20,28],["H3205","shall bear",29,39],["H1121","thee a son",40,50],["H0061","indeed",51,57],["H7121","and thou shalt call",59,78],["H8034","his name",79,87],["H3327","Isaac",88,93],["H6965","and I will establish",95,115],["H1285","my covenant",116,127],["H5769","with him for an everlasting",128,155],["H1285","covenant",156,164],["H2233","and with his seed",166,183],["H0310","after him",184,193]]},"17:20":{"text":"And as for Ishmael, I have heard thee: Behold, I have blessed him, and will make him fruitful, and will multiply him exceedingly; twelve princes shall he beget, and I will make him a great nation.","words":[["H3458","And as for Ishmael",0,18],["H8085","I have heard thee",20,37],["H1288","Behold, I have blessed",39,61],["H6509","him, and will make him fruitful",62,93],["H7235","and will multiply",95,112],["H3966","him exceedingly",113,128],["H3966","him exceedingly",113,128],["H6240","twelve",130,136],["H8147","twelve",130,136],["H5387","princes",137,144],["H3205","shall he beget",145,159],["H5414","and I will make him",161,180],["H1419","a great",181,188],["H1471","nation",189,195]]},"17:21":{"text":"But my covenant will I establish with Isaac, which Sarah shall bear unto thee at this set time in the next year.","words":[["H1285","But my covenant",0,15],["H6965","will I establish",16,32],["H3327","with Isaac",33,43],["H8283","which Sarah",45,56],["H3205","shall bear",57,67],["H4150","unto thee at this set time",68,94],["H0312","in the next",95,106],["H8141","year",107,111]]},"17:22":{"text":"And he left off talking with him, and God went up from Abraham.","words":[["H3615","And he left off",0,15],["H1696","talking",16,23],["H0430","with him, and God",24,41],["H5927","went up",42,49],["H0085","from Abraham",50,62]]},"17:23":{"text":"And Abraham took Ishmael his son, and all that were born in his house, and all that were bought with his money, every male among the men of Abraham's house; and circumcised the flesh of their foreskin in the selfsame day, as God had said unto him.","words":[["H0085","And Abraham",0,11],["H3947","took",12,16],["H3458","Ishmael",17,24],["H1121","his son",25,32],["H3211","and all that were born",34,56],["H1004","in his house",57,69],["H4736","and all that were bought",71,95],["H3701","with his money",96,110],["H2145","every male",112,122],["H0582","among the men",123,136],["H0085","of Abraham's",137,149],["H1004","house",150,155],["H4135","and circumcised",157,172],["H1320","the flesh",173,182],["H6190","of their foreskin",183,200],["H6106","in the selfsame",201,216],["H3117","day",217,220],["H0430","as God",222,228],["H1696","had said",229,237]]},"17:24":{"text":"And Abraham was ninety years old and nine, when he was circumcised in the flesh of his foreskin.","words":[["H0085","And Abraham",0,11],["H8673","was ninety",12,22],["H8141","years",23,28],["H1121","old",29,32],["H8672","and nine",33,41],["H4135","when he was circumcised",43,66],["H1320","in the flesh",67,79],["H6190","of his foreskin",80,95]]},"17:25":{"text":"And Ishmael his son was thirteen years old, when he was circumcised in the flesh of his foreskin.","words":[["H3458","And Ishmael",0,11],["H1121","his son",12,19],["H6240","was thirteen",20,32],["H7969","was thirteen",20,32],["H8141","years",33,38],["H1121","old",39,42],["H4135","when he was circumcised",44,67],["H1320","in the flesh",68,80],["H6190","of his foreskin",81,96]]},"17:26":{"text":"In the selfsame day was Abraham circumcised, and Ishmael his son.","words":[["H6106","In the selfsame",0,15],["H3117","day",16,19],["H0085","was Abraham",20,31],["H4135","circumcised",32,43],["H3458","and Ishmael",45,56],["H1121","his son",57,64]]},"17:27":{"text":"And all the men of his house, born in the house, and bought with money of the stranger, were circumcised with him.","words":[["H0582","And all the men",0,15],["H1004","of his house",16,28],["H3211","born",30,34],["H1004","in the house",35,47],["H4736","and bought",49,59],["H3701","with money",60,70],["H1121","of the stranger",71,86],["H5236","of the stranger",71,86],["H4135","were circumcised",88,104]]},"18:1":{"text":"And the LORD appeared unto him in the plains of Mamre: and he sat in the tent door in the heat of the day;","words":[["H3068","And the LORD",0,12],["H7200","appeared",13,21],["H0436","unto him in the plains",22,44],["H4471","of Mamre",45,53],["H3427","and he sat",55,65],["H0168","in the tent",66,77],["H6607","door",78,82],["H2527","in the heat",83,94],["H3117","of the day",95,105]]},"18:2":{"text":"And he lift up his eyes and looked, and, lo, three men stood by him: and when he saw them, he ran to meet them from the tent door, and bowed himself toward the ground,","words":[["H5375","And he lift up",0,14],["H5869","his eyes",15,23],["H7200","and looked",24,34],["H7969","and, lo, three",36,50],["H0582","men",51,54],["H5324","stood",55,60],["H7200","by him: and when he saw",61,84],["H7323","them, he ran",85,97],["H7125","to meet",98,105],["H0168","them from the tent",106,124],["H6607","door",125,129],["H7812","and bowed",131,140],["H0776","himself toward the ground",141,166]]},"18:3":{"text":"And said, My Lord, if now I have found favour in thy sight, pass not away, I pray thee, from thy servant:","words":[["H0559","And said",0,8],["H0136","My Lord",10,17],["H4672","if now I have found",19,38],["H2580","favour",39,45],["H5869","in thy sight",46,58],["H5674","pass not away",60,73],["H5650","I pray thee, from thy servant",75,104]]},"18:4":{"text":"Let a little water, I pray you, be fetched, and wash your feet, and rest yourselves under the tree:","words":[["H4592","Let a little",0,12],["H4325","water",13,18],["H4994","I pray you",20,30],["H3947","be fetched",32,42],["H7364","and wash",44,52],["H7272","your feet",53,62],["H8172","and rest yourselves",64,83],["H6086","under the tree",84,98]]},"18:5":{"text":"And I will fetch a morsel of bread, and comfort ye your hearts; after that ye shall pass on: for therefore are ye come to your servant. And they said, So do, as thou hast said.","words":[["H3947","And I will fetch",0,16],["H6595","a morsel",17,25],["H3899","of bread",26,34],["H5582","and comfort ye",36,50],["H3820","your hearts",51,62],["H0310","after that",64,74],["H5674","ye shall pass on",75,91],["H5674","for therefore are ye come",93,118],["H5921","to",119,121],["H5650","your servant",122,134],["H1696","And they said",136,149],["H6213","So do",151,156],["H0559","as thou hast said",158,175]]},"18:6":{"text":"And Abraham hastened into the tent unto Sarah, and said, Make ready quickly three measures of fine meal, knead it, and make cakes upon the hearth.","words":[["H0085","And Abraham",0,11],["H4116","hastened",12,20],["H0168","into the tent",21,34],["H8283","unto Sarah",35,45],["H0559","and said",47,55],["H4116","Make ready quickly",57,75],["H7969","three",76,81],["H5429","measures",82,90],["H5560","of fine",91,98],["H7058","meal",99,103],["H3888","knead",105,110],["H6213","it, and make",111,123],["H5692","cakes",124,129],["H6213","upon the hearth",130,145]]},"18:7":{"text":"And Abraham ran unto the herd, and fetcht a calf tender and good, and gave it unto a young man; and he hasted to dress it.","words":[["H0085","And Abraham",0,11],["H7323","ran",12,15],["H1241","unto the herd",16,29],["H3947","and fetcht",31,41],["H1121","a calf",42,48],["H1241","a calf",42,48],["H7390","tender",49,55],["H2896","and good",56,64],["H5414","and gave",66,74],["H5288","it unto a young man",75,94],["H4116","and he hasted",96,109],["H6213","to dress",110,118]]},"18:8":{"text":"And he took butter, and milk, and the calf which he had dressed, and set it before them; and he stood by them under the tree, and they did eat.","words":[["H3947","And he took",0,11],["H2529","butter",12,18],["H2461","and milk",20,28],["H1121","and the calf",30,42],["H1241","and the calf",30,42],["H6213","which he had dressed",43,63],["H5414","and set",65,72],["H6440","it before them",73,87],["H5975","and he stood",89,101],["H6086","by them under the tree",102,124],["H0398","and they did eat",126,142]]},"18:9":{"text":"And they said unto him, Where is Sarah thy wife? And he said, Behold, in the tent.","words":[["H0559","And they said",0,13],["H0346","unto him, Where",14,29],["H8283","is Sarah",30,38],["H0802","thy wife",39,47],["H0559","And he said",49,60],["H0168","Behold, in the tent",62,81]]},"18:10":{"text":"And he said, I will certainly return unto thee according to the time of life; and, lo, Sarah thy wife shall have a son. And Sarah heard it in the tent door, which was behind him.","words":[["H0559","And he said",0,11],["H7725","I will certainly",13,29],["H7725","return",30,36],["H6256","unto thee according to the time",37,68],["H2416","of life",69,76],["H8283","and, lo, Sarah",78,92],["H0802","thy wife",93,101],["H1121","shall have a son",102,118],["H8283","And Sarah",120,129],["H8085","heard",130,135],["H0168","it in the tent",136,150],["H6607","door",151,155],["H0310","which was behind him",157,177]]},"18:11":{"text":"Now Abraham and Sarah were old and well stricken in age; and it ceased to be with Sarah after the manner of women.","words":[["H0085","Now Abraham",0,11],["H8283","and Sarah",12,21],["H2205","were old",22,30],["H0935","and well stricken",31,48],["H3117","in age",49,55],["H2308","and it ceased",57,70],["H8283","to be with Sarah",71,87],["H0734","after the manner",88,104],["H0802","of women",105,113]]},"18:12":{"text":"Therefore Sarah laughed within herself, saying, After I am waxed old shall I have pleasure, my lord being old also?","words":[["H8283","Therefore Sarah",0,15],["H6711","laughed",16,23],["H7130","within herself",24,38],["H0559","saying",40,46],["H0310","After",48,53],["H1086","I am waxed old",54,68],["H5730","shall I have pleasure",69,90],["H0113","my lord",92,99],["H2204","being old also",100,114]]},"18:13":{"text":"And the LORD said unto Abraham, Wherefore did Sarah laugh, saying, Shall I of a surety bear a child, which am old?","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H0085","unto Abraham",18,30],["H4100","Wherefore",32,41],["H8283","did Sarah",42,51],["H6711","laugh",52,57],["H0559","saying",59,65],["H0552","Shall I of a surety",67,86],["H3205","bear",87,91],["H0589","a child, which",92,106],["H2204","am old",107,113]]},"18:14":{"text":"Is any thing too hard for the LORD? At the time appointed I will return unto thee, according to the time of life, and Sarah shall have a son.","words":[["H6381","Is",0,2],["H1697","any thing",3,12],["H6381","too hard",13,21],["H3068","for the LORD",22,34],["H4150","At the time appointed",36,57],["H7725","I will return",58,71],["H6256","unto thee, according to the time",72,104],["H2416","of life",105,112],["H8283","and Sarah",114,123],["H1121","shall have a son",124,140]]},"18:15":{"text":"Then Sarah denied, saying, I laughed not; for she was afraid. And he said, Nay; but thou didst laugh.","words":[["H8283","Then Sarah",0,10],["H3584","denied",11,17],["H0559","saying",19,25],["H6711","I laughed",27,36],["H3372","not; for she was afraid",37,60],["H0559","And he said",62,73],["H3808","Nay",75,78],["H6711","but thou didst laugh",80,100]]},"18:16":{"text":"And the men rose up from thence, and looked toward Sodom: and Abraham went with them to bring them on the way.","words":[["H0582","And the men",0,11],["H6965","rose up",12,19],["H8259","from thence, and looked",20,43],["H6440","toward",44,50],["H5467","Sodom",51,56],["H0085","and Abraham",58,69],["H1980","went",70,74],["H7971","with them to bring them on the way",75,109]]},"18:17":{"text":"And the LORD said, Shall I hide from Abraham that thing which I do;","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H3680","Shall I hide",19,31],["H0085","from Abraham",32,44],["H0834","that thing which",45,61],["H6213","I do",62,66]]},"18:18":{"text":"Seeing that Abraham shall surely become a great and mighty nation, and all the nations of the earth shall be blessed in him?","words":[["H0085","Seeing that Abraham",0,19],["H1419","shall surely become a great",20,47],["H6099","and mighty",48,58],["H1471","nation",59,65],["H1471","and all the nations",67,86],["H0776","of the earth",87,99],["H1288","shall be blessed",100,116]]},"18:19":{"text":"For I know him, that he will command his children and his household after him, and they shall keep the way of the LORD, to do justice and judgment; that the LORD may bring upon Abraham that which he hath spoken of him.","words":[["H3045","For I know",0,10],["H0834","him, that",11,20],["H6680","he will command",21,36],["H1121","his children",37,49],["H1004","and his household",50,67],["H0310","after him",68,77],["H8104","and they shall keep",79,98],["H1870","the way",99,106],["H3068","of the LORD",107,118],["H6213","to do",120,125],["H6666","justice",126,133],["H4941","and judgment",134,146],["H3068","that the LORD",148,161],["H0935","may bring",162,171],["H0085","upon Abraham",172,184],["H1696","that which he hath spoken",185,210]]},"18:20":{"text":"And the LORD said, Because the cry of Sodom and Gomorrah is great, and because their sin is very grievous;","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H2201","Because the cry",19,34],["H5467","of Sodom",35,43],["H6017","and Gomorrah",44,56],["H7227","is great",57,65],["H2403","and because their sin",67,88],["H3966","is very",89,96],["H3513","grievous",97,105]]},"18:21":{"text":"I will go down now, and see whether they have done altogether according to the cry of it, which is come unto me; and if not, I will know.","words":[["H3381","I will go down",0,14],["H7200","now, and see",15,27],["H6213","whether they have done",28,50],["H3617","altogether",51,61],["H6818","according to the cry",62,82],["H0935","of it, which is come",83,103],["H3045","unto me; and if not, I will know",104,136]]},"18:22":{"text":"And the men turned their faces from thence, and went toward Sodom: but Abraham stood yet before the LORD.","words":[["H0582","And the men",0,11],["H6437","turned their faces",12,30],["H3212","from thence, and went",31,52],["H5467","toward Sodom",53,65],["H0085","but Abraham",67,78],["H5975","stood",79,84],["H5750","yet",85,88],["H6440","before",89,95],["H3068","the LORD",96,104]]},"18:23":{"text":"And Abraham drew near, and said, Wilt thou also destroy the righteous with the wicked?","words":[["H0085","And Abraham",0,11],["H5066","drew near",12,21],["H0559","and said",23,31],["H5595","Wilt thou also destroy",33,55],["H6662","the righteous",56,69],["H5973","with",70,74],["H7563","the wicked",75,85]]},"18:24":{"text":"Peradventure there be fifty righteous within the city: wilt thou also destroy and not spare the place for the fifty righteous that are therein?","words":[["H3426","Peradventure there be",0,21],["H2572","fifty",22,27],["H6662","righteous",28,37],["H8432","within",38,44],["H5892","the city",45,53],["H5595","wilt thou also destroy",55,77],["H5375","and not spare",78,91],["H4725","the place",92,101],["H4616","for",102,105],["H2572","the fifty",106,115],["H6662","righteous",116,125],["H7130","that are therein",126,142]]},"18:25":{"text":"That be far from thee to do after this manner, to slay the righteous with the wicked: and that the righteous should be as the wicked, that be far from thee: Shall not the Judge of all the earth do right?","words":[["H2486","That be far",0,11],["H6213","from thee to do",12,27],["H1697","after this manner",28,45],["H4191","to slay",47,54],["H6662","the righteous",55,68],["H7563","with the wicked",69,84],["H6662","and that the righteous",86,108],["H7563","should be as the wicked",109,132],["H2486","that be far",134,145],["H8199","from thee: Shall not the Judge",146,176],["H0776","of all the earth",177,193],["H6213","do",194,196],["H4941","right",197,202]]},"18:26":{"text":"And the LORD said, If I find in Sodom fifty righteous within the city, then I will spare all the place for their sakes.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H4672","If I find",19,28],["H5467","in Sodom",29,37],["H2572","fifty",38,43],["H6662","righteous",44,53],["H8432","within",54,60],["H5892","the city",61,69],["H5375","then I will spare",71,88],["H4725","all the place",89,102]]},"18:27":{"text":"And Abraham answered and said, Behold now, I have taken upon me to speak unto the Lord, which am but dust and ashes:","words":[["H0085","And Abraham",0,11],["H6030","answered",12,20],["H0559","and said",21,29],["H2974","Behold now, I have taken upon me",31,63],["H1696","to speak",64,72],["H0136","unto the Lord",73,86],["H0595","which",88,93],["H6083","am but dust",94,105],["H0665","and ashes",106,115]]},"18:28":{"text":"Peradventure there shall lack five of the fifty righteous: wilt thou destroy all the city for lack of five? And he said, If I find there forty and five, I will not destroy it.","words":[["H2637","Peradventure there shall lack",0,29],["H2568","five",30,34],["H2572","of the fifty",35,47],["H6662","righteous",48,57],["H7843","wilt thou destroy",59,76],["H5892","all the city",77,89],["H2568","for lack of five",90,106],["H0559","And he said",108,119],["H4672","If I find",121,130],["H0705","there forty",131,142],["H2568","and five",143,151],["H7843","I will not destroy",153,171]]},"18:29":{"text":"And he spake unto him yet again, and said, Peradventure there shall be forty found there. And he said, I will not do it for forty's sake.","words":[["H1696","And he spake",0,12],["H3254","unto him yet again",13,31],["H0559","and said",33,41],["H0705","Peradventure there shall be forty",43,76],["H4672","found",77,82],["H0559","there. And he said",83,101],["H6213","I will not do",103,116],["H0705","it for forty's",117,131]]},"18:30":{"text":"And he said unto him, Oh let not the Lord be angry, and I will speak: Peradventure there shall thirty be found there. And he said, I will not do it, if I find thirty there.","words":[["H0559","And he said",0,11],["H4994","unto him, Oh",12,24],["H0136","let not the Lord",25,41],["H2734","be angry",42,50],["H1696","and I will speak",52,68],["H7970","Peradventure there shall thirty",70,101],["H4672","be found",102,110],["H0559","there. And he said",111,129],["H6213","I will not do",131,144],["H4672","it, if I find",145,158],["H7970","thirty",159,165]]},"18:31":{"text":"And he said, Behold now, I have taken upon me to speak unto the Lord: Peradventure there shall be twenty found there. And he said, I will not destroy it for twenty's sake.","words":[["H0559","And he said",0,11],["H2974","Behold now, I have taken upon me",13,45],["H1696","to speak",46,54],["H0136","unto the Lord",55,68],["H6242","Peradventure there shall be twenty",70,104],["H4672","found",105,110],["H0559","there. And he said",111,129],["H7843","I will not destroy",131,149],["H6242","it for twenty's",150,165]]},"18:32":{"text":"And he said, Oh let not the Lord be angry, and I will speak yet but this once: Peradventure ten shall be found there. And he said, I will not destroy it for ten's sake.","words":[["H0559","And he said",0,11],["H0136","Oh let not the Lord",13,32],["H2734","be angry",33,41],["H1696","and I will speak",43,59],["H0389","yet",60,63],["H6471","but this once",64,77],["H6235","Peradventure ten",79,95],["H4672","shall be found",96,110],["H0559","there. And he said",111,129],["H7843","I will not destroy",131,149],["H6235","it for ten's",150,162]]},"18:33":{"text":"And the LORD went his way, as soon as he had left communing with Abraham: and Abraham returned unto his place.","words":[["H3068","And the LORD",0,12],["H3212","went his way",13,25],["H0834","as soon as",27,37],["H3615","he had left",38,49],["H1696","communing",50,59],["H0085","with Abraham",60,72],["H0085","and Abraham",74,85],["H7725","returned",86,94],["H4725","unto his place",95,109]]},"19:1":{"text":"And there came two angels to Sodom at even; and Lot sat in the gate of Sodom: and Lot seeing them rose up to meet them; and he bowed himself with his face toward the ground;","words":[["H0935","And there came",0,14],["H8147","two",15,18],["H4397","angels",19,25],["H5467","to Sodom",26,34],["H6153","at even",35,42],["H3876","and Lot",44,51],["H3427","sat",52,55],["H8179","in the gate",56,67],["H5467","of Sodom",68,76],["H3876","and Lot",78,85],["H7200","seeing",86,92],["H6965","them rose up",93,105],["H7125","to meet",106,113],["H7812","them; and he bowed",114,132],["H0639","himself with his face",133,154],["H0776","toward the ground",155,172]]},"19:2":{"text":"And he said, Behold now, my lords, turn in, I pray you, into your servant's house, and tarry all night, and wash your feet, and ye shall rise up early, and go on your ways. And they said, Nay; but we will abide in the street all night.","words":[["H0559","And he said",0,11],["H0113","Behold now, my lords",13,33],["H5493","turn in",35,42],["H5650","I pray you, into your servant's",44,75],["H1004","house",76,81],["H3885","and tarry all night",83,102],["H7364","and wash",104,112],["H7272","your feet",113,122],["H7925","and ye shall rise up early",124,150],["H1980","and go",152,158],["H1870","on your ways",159,171],["H0559","And they said",173,186],["H3885","Nay; but we will abide",188,210],["H7339","in the street",211,224],["H3885","all night",225,234]]},"19:3":{"text":"And he pressed upon them greatly; and they turned in unto him, and entered into his house; and he made them a feast, and did bake unleavened bread, and they did eat.","words":[["H6484","And he pressed",0,14],["H3966","upon them greatly",15,32],["H5493","and they turned in",34,52],["H0935","unto him, and entered",53,74],["H1004","into his house",75,89],["H6213","and he made",91,102],["H4960","them a feast",103,115],["H0644","and did bake",117,129],["H4682","unleavened bread",130,146],["H0398","and they did eat",148,164]]},"19:4":{"text":"But before they lay down, the men of the city, even the men of Sodom, compassed the house round, both old and young, all the people from every quarter:","words":[["H7901","But before they lay down",0,24],["H0582","the men",26,33],["H5892","of the city",34,45],["H0582","even the men",47,59],["H5467","of Sodom",60,68],["H5437","compassed",70,79],["H1004","the house",80,89],["H5437","round",90,95],["H2205","both old",97,105],["H5288","and young",106,115],["H5971","all the people",117,131],["H7097","from every quarter",132,150]]},"19:5":{"text":"And they called unto Lot, and said unto him, Where are the men which came in to thee this night? bring them out unto us, that we may know them.","words":[["H7121","And they called",0,15],["H3876","unto Lot",16,24],["H0559","and said",26,34],["H0582","unto him, Where are the men",35,62],["H0935","which came in",63,76],["H3915","to thee this night",77,95],["H3318","bring them out",97,111],["H3045","unto us, that we may know",112,137]]},"19:6":{"text":"And Lot went out at the door unto them, and shut the door after him,","words":[["H3876","And Lot",0,7],["H3318","went out",8,16],["H6607","at the door",17,28],["H5462","unto them, and shut",29,48],["H1817","the door",49,57],["H0310","after him",58,67]]},"19:7":{"text":"And said, I pray you, brethren, do not so wickedly.","words":[["H0559","And said",0,8],["H0251","I pray you, brethren",10,30],["H7489","do not so wickedly",32,50]]},"19:8":{"text":"Behold now, I have two daughters which have not known man; let me, I pray you, bring them out unto you, and do ye to them as is good in your eyes: only unto these men do nothing; for therefore came they under the shadow of my roof.","words":[["H8147","Behold now, I have two",0,22],["H1323","daughters",23,32],["H3045","which have not known",33,53],["H0376","man",54,57],["H3318","let me, I pray you, bring them out",59,93],["H6213","unto you, and do",94,110],["H2896","ye to them as is good",111,132],["H5869","in your eyes",133,145],["H0411","only unto these",147,162],["H0582","men",163,166],["H6213","do",167,169],["H0408","nothing",170,177],["H1697","nothing",170,177],["H0935","for therefore came",179,197],["H6738","they under the shadow",198,219],["H6982","of my roof",220,230]]},"19:9":{"text":"And they said, Stand back. And they said again, This one fellow came in to sojourn, and he will needs be a judge: now will we deal worse with thee, than with them. And they pressed sore upon the man, even Lot, and came near to break the door.","words":[["H0559","And they said",0,13],["H5066","Stand",15,20],["H1973","back",21,25],["H0559","And they said",27,40],["H0259","again, This one",41,56],["H0935","fellow came in",57,71],["H1481","to sojourn",72,82],["H8199","and he will needs",84,101],["H8199","be a judge",102,112],["H7489","now will we deal worse",114,136],["H6484","with thee, than with them. And they pressed",137,180],["H3966","sore",181,185],["H0376","upon the man",186,198],["H3876","even Lot",200,208],["H5066","and came near",210,223],["H7665","to break",224,232],["H1817","the door",233,241]]},"19:10":{"text":"But the men put forth their hand, and pulled Lot into the house to them, and shut to the door.","words":[["H0582","But the men",0,11],["H7971","put forth",12,21],["H3027","their hand",22,32],["H0935","and pulled",34,44],["H3876","Lot",45,48],["H1004","into the house",49,63],["H5462","to them, and shut",64,81],["H1817","to the door",82,93]]},"19:11":{"text":"And they smote the men that were at the door of the house with blindness, both small and great: so that they wearied themselves to find the door.","words":[["H5221","And they smote",0,14],["H0582","the men",15,22],["H6607","that were at the door",23,44],["H1004","of the house",45,57],["H5575","with blindness",58,72],["H6996","both small",74,84],["H1419","and great",85,94],["H3811","so that they wearied",96,116],["H4672","themselves to find",117,135],["H6607","the door",136,144]]},"19:12":{"text":"And the men said unto Lot, Hast thou here any besides? son in law, and thy sons, and thy daughters, and whatsoever thou hast in the city, bring them out of this place:","words":[["H0582","And the men",0,11],["H0559","said",12,16],["H3876","unto Lot",17,25],["H6311","Hast thou here",27,41],["H4310","any",42,45],["H2860","besides? son in law",46,65],["H1121","and thy sons",67,79],["H1323","and thy daughters",81,98],["H0834","and whatsoever",100,114],["H5892","thou hast in the city",115,136],["H3318","bring them out",138,152],["H4725","of this place",153,166]]},"19:13":{"text":"For we will destroy this place, because the cry of them is waxen great before the face of the LORD; and the LORD hath sent us to destroy it.","words":[["H0587","For we",0,6],["H7843","will destroy",7,19],["H0853","",-1,-1],["H4725","this place",20,30],["H6818","because the cry of them",32,55],["H1431","is waxen great",56,70],["H0854","before",71,77],["H6440","the face",78,86],["H3068","of the LORD",87,98],["H3068","and the LORD",100,112],["H7971","hath sent",113,122],["H7843","us to destroy",123,136]]},"19:14":{"text":"And Lot went out, and spake unto his sons in law, which married his daughters, and said, Up, get you out of this place; for the LORD will destroy this city. But he seemed as one that mocked unto his sons in law.","words":[["H3876","And Lot",0,7],["H3318","went out",8,16],["H1696","and spake",18,27],["H2860","unto his sons in law",28,48],["H3947","which married",50,63],["H1323","his daughters",64,77],["H0559","and said",79,87],["H6965","Up",89,91],["H3318","get you out",93,104],["H4725","of this place",105,118],["H3068","for the LORD",120,132],["H7843","will destroy",133,145],["H5892","this city",146,155],["H6711","But he seemed as one that mocked",157,189],["H5869","unto",190,194],["H2860","his sons in law",195,210]]},"19:15":{"text":"And when the morning arose, then the angels hastened Lot, saying, Arise, take thy wife, and thy two daughters, which are here; lest thou be consumed in the iniquity of the city.","words":[["H3644","And when",0,8],["H7837","the morning",9,20],["H5927","arose",21,26],["H4397","then the angels",28,43],["H0213","hastened",44,52],["H3876","Lot",53,56],["H0559","saying",58,64],["H6965","Arise",66,71],["H3947","take",73,77],["H0802","thy wife",78,86],["H8147","and thy two",88,99],["H1323","daughters",100,109],["H4672","which are here",111,125],["H5595","lest thou be consumed",127,148],["H5771","in the iniquity",149,164],["H5892","of the city",165,176]]},"19:16":{"text":"And while he lingered, the men laid hold upon his hand, and upon the hand of his wife, and upon the hand of his two daughters; the LORD being merciful unto him: and they brought him forth, and set him without the city.","words":[["H4102","And while he lingered",0,21],["H0582","the men",23,30],["H2388","laid hold",31,40],["H3027","upon his hand",41,54],["H3027","and upon the hand",56,73],["H0802","of his wife",74,85],["H3027","and upon the hand",87,104],["H8147","of his two",105,115],["H1323","daughters",116,125],["H3068","the LORD",127,135],["H2551","being merciful",136,150],["H3318","unto him: and they brought him forth",151,187],["H3240","and set him",189,200],["H2351","without",201,208],["H5892","the city",209,217]]},"19:17":{"text":"And it came to pass, when they had brought them forth abroad, that he said, Escape for thy life; look not behind thee, neither stay thou in all the plain; escape to the mountain, lest thou be consumed.","words":[["H3318","And it came to pass, when they had brought them forth",0,53],["H2351","abroad",54,60],["H0559","that he said",62,74],["H4422","Escape",76,82],["H5921","for",83,86],["H5315","thy life",87,95],["H5027","look",97,101],["H0310","not behind thee",102,117],["H5975","neither stay",119,131],["H3603","thou in all the plain",132,153],["H4422","escape",155,161],["H2022","to the mountain",162,177],["H5595","lest thou be consumed",179,200]]},"19:18":{"text":"And Lot said unto them, Oh, not so, my Lord:","words":[["H3876","And Lot",0,7],["H0559","said",8,12],["H0113","unto them, Oh, not so, my Lord",13,43]]},"19:19":{"text":"Behold now, thy servant hath found grace in thy sight, and thou hast magnified thy mercy, which thou hast shewed unto me in saving my life; and I cannot escape to the mountain, lest some evil take me, and I die:","words":[["H5650","Behold now, thy servant",0,23],["H4672","hath found",24,34],["H2580","grace",35,40],["H5869","in thy sight",41,53],["H1431","and thou hast magnified",55,78],["H2617","thy mercy",79,88],["H6213","which thou hast shewed",90,112],["H5978","unto me",113,120],["H2421","in saving",121,130],["H5315","my life",131,138],["H3201","and I cannot",140,152],["H4422","escape",153,159],["H2022","to the mountain",160,175],["H7451","lest some evil",177,191],["H1692","take",192,196],["H4191","me, and I die",197,210]]},"19:20":{"text":"Behold now, this city is near to flee unto, and it is a little one: Oh, let me escape thither, (is it not a little one?) and my soul shall live.","words":[["H5892","Behold now, this city",0,21],["H7138","is near",22,29],["H5127","to flee",30,37],["H1931","unto, and it",38,50],["H4705","is a little one",51,66],["H4422","Oh, let me escape",68,85],["H4705","thither, (is it not a little one",86,118],["H5315",") and my soul",119,132],["H2421","shall live",133,143]]},"19:21":{"text":"And he said unto him, See, I have accepted thee concerning this thing also, that I will not overthrow this city, for the which thou hast spoken.","words":[["H0559","And he said",0,11],["H2009","unto him, See",12,25],["H5375","I have accepted",27,42],["H6440","thee",43,47],["H1697","concerning this thing",48,69],["H2015","also, that I will not overthrow",70,101],["H5892","this city",102,111],["H0834","for the which",113,126],["H1696","thou hast spoken",127,143]]},"19:22":{"text":"Haste thee, escape thither; for I cannot do any thing till thou be come thither. Therefore the name of the city was called Zoar.","words":[["H4116","Haste",0,5],["H4422","thee, escape",6,18],["H3201","thither; for I cannot",19,40],["H6213","do",41,43],["H1697","any thing",44,53],["H0935","till thou be come",54,71],["H8034","thither. Therefore the name",72,99],["H5892","of the city",100,111],["H7121","was called",112,122],["H6820","Zoar",123,127]]},"19:23":{"text":"The sun was risen upon the earth when Lot entered into Zoar.","words":[["H8121","The sun",0,7],["H3318","was risen",8,17],["H0776","upon the earth",18,32],["H3876","when Lot",33,41],["H0935","entered",42,49],["H6820","into Zoar",50,59]]},"19:24":{"text":"Then the LORD rained upon Sodom and upon Gomorrah brimstone and fire from the LORD out of heaven;","words":[["H3068","Then the LORD",0,13],["H4305","rained",14,20],["H5467","upon Sodom",21,31],["H6017","and upon Gomorrah",32,49],["H1614","brimstone",50,59],["H0784","and fire",60,68],["H3068","from the LORD",69,82],["H8064","out of heaven",83,96]]},"19:25":{"text":"And he overthrew those cities, and all the plain, and all the inhabitants of the cities, and that which grew upon the ground.","words":[["H2015","And he overthrew",0,16],["H0411","those",17,22],["H5892","cities",23,29],["H3603","and all the plain",31,48],["H3427","and all the inhabitants",50,73],["H5892","of the cities",74,87],["H6780","and that which grew",89,108],["H0127","upon the ground",109,124]]},"19:26":{"text":"But his wife looked back from behind him, and she became a pillar of salt.","words":[["H0802","But his wife",0,12],["H5027","looked back",13,24],["H0310","from behind him",25,40],["H5333","and she became a pillar",42,65],["H4417","of salt",66,73]]},"19:27":{"text":"And Abraham gat up early in the morning to the place where he stood before the LORD:","words":[["H0085","And Abraham",0,11],["H7925","gat up early",12,24],["H1242","in the morning",25,39],["H4725","to the place",40,52],["H5975","where he stood",53,67],["H6440","before",68,74],["H3068","the LORD",75,83]]},"19:28":{"text":"And he looked toward Sodom and Gomorrah, and toward all the land of the plain, and beheld, and, lo, the smoke of the country went up as the smoke of a furnace.","words":[["H8259","And he looked",0,13],["H6440","toward",14,20],["H5467","Sodom",21,26],["H6017","and Gomorrah",27,39],["H6440","and toward",41,51],["H0776","all the land",52,64],["H3603","of the plain",65,77],["H7200","and beheld",79,89],["H7008","and, lo, the smoke",91,109],["H0776","of the country",110,124],["H5927","went up",125,132],["H7008","as the smoke",133,145],["H3536","of a furnace",146,158]]},"19:29":{"text":"And it came to pass, when God destroyed the cities of the plain, that God remembered Abraham, and sent Lot out of the midst of the overthrow, when he overthrew the cities in the which Lot dwelt.","words":[["H0430","And it came to pass, when God",0,29],["H7843","destroyed",30,39],["H5892","the cities",40,50],["H3603","of the plain",51,63],["H0430","that God",65,73],["H2142","remembered",74,84],["H0085","Abraham",85,92],["H7971","and sent",94,102],["H3876","Lot",103,106],["H8432","out of the midst",107,123],["H2018","of the overthrow",124,140],["H2015","when he overthrew",142,159],["H5892","the cities",160,170],["H2004","in the which",171,183],["H3876","Lot",184,187],["H3427","dwelt",188,193]]},"19:30":{"text":"And Lot went up out of Zoar, and dwelt in the mountain, and his two daughters with him; for he feared to dwell in Zoar: and he dwelt in a cave, he and his two daughters.","words":[["H3876","And Lot",0,7],["H5927","went up",8,15],["H6820","out of Zoar",16,27],["H3427","and dwelt",29,38],["H2022","in the mountain",39,54],["H8147","and his two",56,67],["H1323","daughters",68,77],["H3372","with him; for he feared",78,101],["H3427","to dwell",102,110],["H6820","in Zoar",111,118],["H3427","and he dwelt",120,132],["H4631","in a cave",133,142],["H8147","he and his two",144,158],["H1323","daughters",159,168]]},"19:31":{"text":"And the firstborn said unto the younger, Our father is old, and there is not a man in the earth to come in unto us after the manner of all the earth:","words":[["H1067","And the firstborn",0,17],["H0559","said",18,22],["H6810","unto the younger",23,39],["H0001","Our father",41,51],["H2204","is old",52,58],["H0376","and there is not a man",60,82],["H0776","in the earth",83,95],["H0935","to come in",96,106],["H1870","unto us after the manner",107,131],["H0776","of all the earth",132,148]]},"19:32":{"text":"Come, let us make our father drink wine, and we will lie with him, that we may preserve seed of our father.","words":[["H3212","Come",0,4],["H8248","let us make",6,17],["H0001","our father",18,28],["H8248","drink",29,34],["H3196","wine",35,39],["H7901","and we will lie",41,56],["H2421","with him, that we may preserve",57,87],["H2233","seed",88,92],["H0001","of our father",93,106]]},"19:33":{"text":"And they made their father drink wine that night: and the firstborn went in, and lay with her father; and he perceived not when she lay down, nor when she arose.","words":[["H8248","And they made",0,13],["H0001","their father",14,26],["H8248","drink",27,32],["H3196","wine",33,37],["H3915","that night",38,48],["H1067","and the firstborn",50,67],["H0935","went in",68,75],["H7901","and lay",77,84],["H0001","with her father",85,100],["H3045","and he perceived",102,118],["H7901","not when she lay down",119,140],["H6965","nor when she arose",142,160]]},"19:34":{"text":"And it came to pass on the morrow, that the firstborn said unto the younger, Behold, I lay yesternight with my father: let us make him drink wine this night also; and go thou in, and lie with him, that we may preserve seed of our father.","words":[["H4283","And it came to pass on the morrow",0,33],["H1067","that the firstborn",35,53],["H0559","said",54,58],["H6810","unto the younger",59,75],["H7901","Behold, I lay",77,90],["H0570","yesternight",91,102],["H0001","with my father",103,117],["H8248","let us make him drink",119,140],["H3196","wine",141,145],["H3915","this night",146,156],["H0935","also; and go thou in",157,177],["H7901","and lie",179,186],["H2421","with him, that we may preserve",187,217],["H2233","seed",218,222],["H0001","of our father",223,236]]},"19:35":{"text":"And they made their father drink wine that night also: and the younger arose, and lay with him; and he perceived not when she lay down, nor when she arose.","words":[["H8248","And they made",0,13],["H0001","their father",14,26],["H8248","drink",27,32],["H3196","wine",33,37],["H1931","that",38,42],["H3915","night",43,48],["H6810","also: and the younger",49,70],["H6965","arose",71,76],["H7901","and lay",78,85],["H3045","with him; and he perceived",86,112],["H7901","not when she lay down",113,134],["H6965","nor when she arose",136,154]]},"19:36":{"text":"Thus were both the daughters of Lot with child by their father.","words":[["H8147","Thus were both",0,14],["H1323","the daughters",15,28],["H3876","of Lot",29,35],["H2029","with child",36,46],["H0001","by their father",47,62]]},"19:37":{"text":"And the firstborn bare a son, and called his name Moab: the same is the father of the Moabites unto this day.","words":[["H1067","And the firstborn",0,17],["H3205","bare",18,22],["H1121","a son",23,28],["H7121","and called",30,40],["H8034","his name",41,49],["H4124","Moab",50,54],["H1931","the same",56,64],["H0001","is the father",65,78],["H4124","of the Moabites",79,94],["H3117","unto this day",95,108]]},"19:38":{"text":"And the younger, she also bare a son, and called his name Benammi: the same is the father of the children of Ammon unto this day.","words":[["H6810","And the younger",0,15],["H3205","she also bare",17,30],["H1121","a son",31,36],["H7121","and called",38,48],["H8034","his name",49,57],["H1151","Benammi",58,65],["H0001","the same is the father",67,89],["H1121","of the children",90,105],["H5983","of Ammon",106,114],["H3117","unto this day",115,128]]},"20:1":{"text":"And Abraham journeyed from thence toward the south country, and dwelled between Kadesh and Shur, and sojourned in Gerar.","words":[["H0085","And Abraham",0,11],["H5265","journeyed",12,21],["H5045","from thence toward the south",22,50],["H0776","country",51,58],["H3427","and dwelled",60,71],["H6946","between Kadesh",72,86],["H7793","and Shur",87,95],["H1481","and sojourned",97,110],["H1642","in Gerar",111,119]]},"20:2":{"text":"And Abraham said of Sarah his wife, She is my sister: and Abimelech king of Gerar sent, and took Sarah.","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H0413","of",17,19],["H8283","Sarah",20,25],["H0802","his wife",26,34],["H0269","She is my sister",36,52],["H0040","and Abimelech",54,67],["H4428","king",68,72],["H1642","of Gerar",73,81],["H7971","sent",82,86],["H3947","and took",88,96],["H8283","Sarah",97,102]]},"20:3":{"text":"But God came to Abimelech in a dream by night, and said to him, Behold, thou art but a dead man, for the woman which thou hast taken; for she is a man's wife.","words":[["H0430","But God",0,7],["H0935","came",8,12],["H0040","to Abimelech",13,25],["H2472","in a dream",26,36],["H3915","by night",37,45],["H0559","and said",47,55],["H4191","to him, Behold, thou art but a dead man",56,95],["H0802","for the woman",97,110],["H3947","which thou hast taken",111,132],["H1167","for she is a man's",134,152],["H1166","wife",153,157]]},"20:4":{"text":"But Abimelech had not come near her: and he said, Lord, wilt thou slay also a righteous nation?","words":[["H0040","But Abimelech",0,13],["H7126","had not come near",14,31],["H0559","her: and he said",32,48],["H0136","Lord",50,54],["H2026","wilt thou slay",56,70],["H6662","also a righteous",71,87],["H1471","nation",88,94]]},"20:5":{"text":"Said he not unto me, She is my sister? and she, even she herself said, He is my brother: in the integrity of my heart and innocency of my hands have I done this.","words":[["H0559","Said",0,4],["H1931","he not unto me, She",5,24],["H0269","is my sister",25,37],["H1931","and she",39,46],["H1571","even",48,52],["H1931","she",53,56],["H0559","herself said",57,69],["H0251","He is my brother",71,87],["H8537","in the integrity",89,105],["H3824","of my heart",106,117],["H5356","and innocency",118,131],["H3709","of my hands",132,143],["H6213","have I done",144,155]]},"20:6":{"text":"And God said unto him in a dream, Yea, I know that thou didst this in the integrity of thy heart; for I also withheld thee from sinning against me: therefore suffered I thee not to touch her.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H2472","unto him in a dream",13,32],["H1571","Yea",34,37],["H3045","I know",39,45],["H6213","that thou didst",46,61],["H8537","this in the integrity",62,83],["H3824","of thy heart",84,96],["H2820","for I also withheld",98,117],["H2398","thee from sinning",118,135],["H5414","against me: therefore suffered",136,166],["H5060","I thee not to touch",167,186]]},"20:7":{"text":"Now therefore restore the man his wife; for he is a prophet, and he shall pray for thee, and thou shalt live: and if thou restore her not, know thou that thou shalt surely die, thou, and all that are thine.","words":[["H7725","Now therefore restore",0,21],["H0376","the man",22,29],["H0802","his wife",30,38],["H5030","for he is a prophet",40,59],["H6419","and he shall pray",61,78],["H1157","for thee",79,87],["H2421","and thou shalt live",89,108],["H7725","and if thou restore",110,129],["H3045","her not, know",130,143],["H4191","thou that thou shalt surely",144,171],["H4191","die",172,175]]},"20:8":{"text":"Therefore Abimelech rose early in the morning, and called all his servants, and told all these things in their ears: and the men were sore afraid.","words":[["H0040","Therefore Abimelech",0,19],["H7925","rose early",20,30],["H1242","in the morning",31,45],["H7121","and called",47,57],["H5650","all his servants",58,74],["H1696","and told",76,84],["H1697","all these things",85,101],["H0241","in their ears",102,115],["H0582","and the men",117,128],["H3966","were sore",129,138],["H3372","afraid",139,145]]},"20:9":{"text":"Then Abimelech called Abraham, and said unto him, What hast thou done unto us? and what have I offended thee, that thou hast brought on me and on my kingdom a great sin? thou hast done deeds unto me that ought not to be done.","words":[["H0040","Then Abimelech",0,14],["H7121","called",15,21],["H0085","Abraham",22,29],["H0559","and said",31,39],["H6213","unto him, What hast thou done",40,69],["H2398","unto us? and what have I offended",70,103],["H0935","thee, that thou hast brought",104,132],["H4467","on me and on my kingdom",133,156],["H1419","a great",157,164],["H2401","sin",165,168],["H6213","thou hast done",170,184],["H4639","deeds",185,190],["H6213","unto me that ought not to be done",191,224]]},"20:10":{"text":"And Abimelech said unto Abraham, What sawest thou, that thou hast done this thing?","words":[["H0040","And Abimelech",0,13],["H0559","said",14,18],["H0085","unto Abraham",19,31],["H4100","What",33,37],["H7200","sawest thou",38,49],["H6213","that thou hast done",51,70],["H1697","this thing",71,81]]},"20:11":{"text":"And Abraham said, Because I thought, Surely the fear of God is not in this place; and they will slay me for my wife's sake.","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H0559","Because I thought",18,35],["H7535","Surely",37,43],["H3374","the fear",44,52],["H0430","of God",53,59],["H4725","is not in this place",60,80],["H2026","and they will slay me",82,103],["H0802","for my wife's",104,117],["H1697","sake",118,122]]},"20:12":{"text":"And yet indeed she is my sister; she is the daughter of my father, but not the daughter of my mother; and she became my wife.","words":[["H0546","And yet indeed",0,14],["H0269","she is my sister",15,31],["H1323","she is the daughter",33,52],["H0001","of my father",53,65],["H1323","but not the daughter",67,87],["H0517","of my mother",88,100],["H0802","and she became my wife",102,124]]},"20:13":{"text":"And it came to pass, when God caused me to wander from my father's house, that I said unto her, This is thy kindness which thou shalt shew unto me; at every place whither we shall come, say of me, He is my brother.","words":[["H0430","And it came to pass, when God",0,29],["H8582","caused me to wander",30,49],["H0001","from my father's",50,66],["H1004","house",67,72],["H0559","that I said",74,85],["H2617","unto her, This is thy kindness",86,116],["H6213","which thou shalt shew",117,138],["H4725","unto me; at every place",139,162],["H0935","whither we shall come",163,184],["H0559","say",186,189],["H0251","of me, He is my brother",190,213]]},"20:14":{"text":"And Abimelech took sheep, and oxen, and menservants, and womenservants, and gave them unto Abraham, and restored him Sarah his wife.","words":[["H0040","And Abimelech",0,13],["H3947","took",14,18],["H6629","sheep",19,24],["H1241","and oxen",26,34],["H5650","and menservants",36,51],["H8198","and womenservants",53,70],["H5414","and gave",72,80],["H0085","them unto Abraham",81,98],["H7725","and restored",100,112],["H8283","him Sarah",113,122],["H0802","his wife",123,131]]},"20:15":{"text":"And Abimelech said, Behold, my land is before thee: dwell where it pleaseth thee.","words":[["H0040","And Abimelech",0,13],["H0559","said",14,18],["H0776","Behold, my land",20,35],["H6440","is before thee",36,50],["H3427","dwell",52,57],["H2896","where it pleaseth",58,75],["H5869","where it pleaseth",58,75]]},"20:16":{"text":"And unto Sarah he said, Behold, I have given thy brother a thousand pieces of silver: behold, he is to thee a covering of the eyes, unto all that are with thee, and with all other: thus she was reproved.","words":[["H8283","And unto Sarah",0,14],["H0559","he said",15,22],["H5414","Behold, I have given",24,44],["H0251","thy brother",45,56],["H0505","a thousand",57,67],["H3701","pieces of silver",68,84],["H3682","behold, he is to thee a covering",86,118],["H5869","of the eyes",119,130],["H3198","unto all that are with thee, and with all other: thus she was reproved",132,202]]},"20:17":{"text":"So Abraham prayed unto God: and God healed Abimelech, and his wife, and his maidservants; and they bare children.","words":[["H0085","So Abraham",0,10],["H6419","prayed",11,17],["H0430","unto God",18,26],["H0430","and God",28,35],["H7495","healed",36,42],["H0040","Abimelech",43,52],["H0802","and his wife",54,66],["H0519","and his maidservants",68,88],["H3205","and they bare",90,103]]},"20:18":{"text":"For the LORD had fast closed up all the wombs of the house of Abimelech, because of Sarah Abraham's wife.","words":[["H3068","For the LORD",0,12],["H6113","had fast",13,21],["H6113","closed up",22,31],["H7358","all the wombs",32,45],["H1004","of the house",46,58],["H0040","of Abimelech",59,71],["H1697","because",73,80],["H8283","of Sarah",81,89],["H0085","Abraham's",90,99],["H0802","wife",100,104]]},"21:1":{"text":"And the LORD visited Sarah as he had said, and the LORD did unto Sarah as he had spoken.","words":[["H3068","And the LORD",0,12],["H6485","visited",13,20],["H8283","Sarah",21,26],["H0559","as he had said",27,41],["H3068","and the LORD",43,55],["H6213","did",56,59],["H8283","unto Sarah",60,70],["H1696","as he had spoken",71,87]]},"21:2":{"text":"For Sarah conceived, and bare Abraham a son in his old age, at the set time of which God had spoken to him.","words":[["H8283","For Sarah",0,9],["H2029","conceived",10,19],["H3205","and bare",21,29],["H0085","Abraham",30,37],["H1121","a son",38,43],["H2208","in his old age",44,58],["H4150","at the set time",60,75],["H0430","of which God",76,88],["H1696","had spoken",89,99]]},"21:3":{"text":"And Abraham called the name of his son that was born unto him, whom Sarah bare to him, Isaac.","words":[["H0085","And Abraham",0,11],["H7121","called",12,18],["H8034","the name",19,27],["H1121","of his son",28,38],["H3205","that was born",39,52],["H8283","unto him, whom Sarah",53,73],["H3205","bare",74,78],["H3327","to him, Isaac",79,92]]},"21:4":{"text":"And Abraham circumcised his son Isaac being eight days old, as God had commanded him.","words":[["H0085","And Abraham",0,11],["H4135","circumcised",12,23],["H1121","his son",24,31],["H3327","Isaac",32,37],["H8083","being eight",38,49],["H3117","days",50,54],["H1121","old",55,58],["H0430","as God",60,66],["H6680","had commanded",67,80]]},"21:5":{"text":"And Abraham was an hundred years old, when his son Isaac was born unto him.","words":[["H0085","And Abraham",0,11],["H3967","was an hundred",12,26],["H8141","years",27,32],["H1121","old",33,36],["H1121","when his son",38,50],["H3327","Isaac",51,56],["H3205","was born",57,65]]},"21:6":{"text":"And Sarah said, God hath made me to laugh, so that all that hear will laugh with me.","words":[["H8283","And Sarah",0,9],["H0559","said",10,14],["H0430","God",16,19],["H6213","hath made",20,29],["H6712","me to laugh",30,41],["H8085","so that all that hear",43,64],["H6711","will laugh",65,75]]},"21:7":{"text":"And she said, Who would have said unto Abraham, that Sarah should have given children suck? for I have born him a son in his old age.","words":[["H0559","And she said",0,12],["H4448","Who would have said",14,33],["H0085","unto Abraham",34,46],["H8283","that Sarah",48,58],["H1121","should have given children",59,85],["H3243","suck",86,90],["H3205","for I have born",92,107],["H1121","him a son",108,117],["H2208","in his old age",118,132]]},"21:8":{"text":"And the child grew, and was weaned: and Abraham made a great feast the same day that Isaac was weaned.","words":[["H3206","And the child",0,13],["H1431","grew",14,18],["H1580","and was weaned",20,34],["H0085","and Abraham",36,47],["H6213","made",48,52],["H1419","a great",53,60],["H4960","feast",61,66],["H3117","the same day",67,79],["H3327","that Isaac",80,90],["H1580","was weaned",91,101]]},"21:9":{"text":"And Sarah saw the son of Hagar the Egyptian, which she had born unto Abraham, mocking.","words":[["H8283","And Sarah",0,9],["H7200","saw",10,13],["H1121","the son",14,21],["H1904","of Hagar",22,30],["H4713","the Egyptian",31,43],["H3205","which she had born",45,63],["H0085","unto Abraham",64,76],["H6711","mocking",78,85]]},"21:10":{"text":"Wherefore she said unto Abraham, Cast out this bondwoman and her son: for the son of this bondwoman shall not be heir with my son, even with Isaac.","words":[["H0559","Wherefore she said",0,18],["H0085","unto Abraham",19,31],["H1644","Cast out",33,41],["H0519","this bondwoman",42,56],["H1121","and her son",57,68],["H1121","for the son",70,81],["H0519","of this bondwoman",82,99],["H3423","shall not be heir",100,117],["H1121","with my son",118,129],["H3327","even with Isaac",131,146]]},"21:11":{"text":"And the thing was very grievous in Abraham's sight because of his son.","words":[["H1697","And the thing",0,13],["H3966","was very",14,22],["H3415","grievous",23,31],["H0085","in Abraham's",32,44],["H5869","sight",45,50],["H0182","because",51,58],["H1121","of his son",59,69]]},"21:12":{"text":"And God said unto Abraham, Let it not be grievous in thy sight because of the lad, and because of thy bondwoman; in all that Sarah hath said unto thee, hearken unto her voice; for in Isaac shall thy seed be called.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0085","unto Abraham",13,25],["H3415","Let it not be grievous",27,49],["H5869","in thy sight",50,62],["H5288","because of the lad",63,81],["H0519","and because of thy bondwoman",83,111],["H8283","in all that Sarah",113,130],["H0559","hath said",131,140],["H8085","unto thee, hearken",141,159],["H6963","unto her voice",160,174],["H3327","for in Isaac",176,188],["H2233","shall thy seed",189,203],["H7121","be called",204,213]]},"21:13":{"text":"And also of the son of the bondwoman will I make a nation, because he is thy seed.","words":[["H1121","And also of the son",0,19],["H0519","of the bondwoman",20,36],["H7760","will I make",37,48],["H1471","a nation",49,57],["H2233","because he is thy seed",59,81]]},"21:14":{"text":"And Abraham rose up early in the morning, and took bread, and a bottle of water, and gave it unto Hagar, putting it on her shoulder, and the child, and sent her away: and she departed, and wandered in the wilderness of Beersheba.","words":[["H0085","And Abraham",0,11],["H7925","rose up early",12,25],["H1242","in the morning",26,40],["H3947","and took",42,50],["H3899","bread",51,56],["H2573","and a bottle",58,70],["H4325","of water",71,79],["H5414","and gave",81,89],["H1904","it unto Hagar",90,103],["H7760","putting",105,112],["H7926","it on her shoulder",113,131],["H3206","and the child",133,146],["H7971","and sent her away",148,165],["H3212","and she departed",167,183],["H8582","and wandered",185,197],["H4057","in the wilderness",198,215],["H0884","of Beersheba",216,228]]},"21:15":{"text":"And the water was spent in the bottle, and she cast the child under one of the shrubs.","words":[["H4325","And the water",0,13],["H3615","was spent",14,23],["H4480","in",24,26],["H2573","the bottle",27,37],["H7993","and she cast",39,51],["H3206","the child",52,61],["H0259","under one",62,71],["H7880","of the shrubs",72,85]]},"21:16":{"text":"And she went, and sat her down over against him a good way off, as it were a bowshot: for she said, Let me not see the death of the child. And she sat over against him, and lift up her voice, and wept.","words":[["H3212","And she went",0,12],["H3427","and sat her down",14,30],["H5048","over against",31,43],["H7368","him a good way off",44,62],["H2909","as it were a bowshot",64,84],["H7198","as it were a bowshot",64,84],["H0559","for she said",86,98],["H7200","Let me not see",100,114],["H4194","the death",115,124],["H3206","of the child",125,137],["H3427","And she sat",139,150],["H5375","over against him, and lift up",151,180],["H6963","her voice",181,190],["H1058","and wept",192,200]]},"21:17":{"text":"And God heard the voice of the lad; and the angel of God called to Hagar out of heaven, and said unto her, What aileth thee, Hagar? fear not; for God hath heard the voice of the lad where he is.","words":[["H0430","And God",0,7],["H8085","heard",8,13],["H6963","the voice",14,23],["H5288","of the lad",24,34],["H4397","and the angel",36,49],["H0430","of God",50,56],["H7121","called",57,63],["H1904","to Hagar",64,72],["H8064","out of heaven",73,86],["H0559","and said",88,96],["H1904","unto her, What aileth thee, Hagar",97,130],["H3372","fear",132,136],["H0430","not; for God",137,149],["H8085","hath heard",150,160],["H6963","the voice",161,170],["H5288","of the lad",171,181]]},"21:18":{"text":"Arise, lift up the lad, and hold him in thine hand; for I will make him a great nation.","words":[["H6965","Arise",0,5],["H5375","lift up",7,14],["H5288","the lad",15,22],["H2388","and hold",24,32],["H3027","him in thine hand",33,50],["H7760","for I will make",52,67],["H1419","him a great",68,79],["H1471","nation",80,86]]},"21:19":{"text":"And God opened her eyes, and she saw a well of water; and she went, and filled the bottle with water, and gave the lad drink.","words":[["H0430","And God",0,7],["H6491","opened",8,14],["H5869","her eyes",15,23],["H7200","and she saw",25,36],["H0875","a well",37,43],["H4325","of water",44,52],["H3212","and she went",54,66],["H4390","and filled",68,78],["H2573","the bottle",79,89],["H4325","with water",90,100],["H8248","and gave",102,110],["H5288","the lad",111,118],["H8248","drink",119,124]]},"21:20":{"text":"And God was with the lad; and he grew, and dwelt in the wilderness, and became an archer.","words":[["H0430","And God",0,7],["H5288","was with the lad",8,24],["H1431","and he grew",26,37],["H3427","and dwelt",39,48],["H4057","in the wilderness",49,66],["H7235","and became an archer",68,88],["H7199","and became an archer",68,88]]},"21:21":{"text":"And he dwelt in the wilderness of Paran: and his mother took him a wife out of the land of Egypt.","words":[["H3427","And he dwelt",0,12],["H4057","in the wilderness",13,30],["H6290","of Paran",31,39],["H0517","and his mother",41,55],["H3947","took",56,60],["H0802","him a wife",61,71],["H0776","out of the land",72,87],["H4714","of Egypt",88,96]]},"21:22":{"text":"And it came to pass at that time, that Abimelech and Phichol the chief captain of his host spake unto Abraham, saying, God is with thee in all that thou doest:","words":[["H6256","And it came to pass at that time",0,32],["H0040","that Abimelech",34,48],["H6369","and Phichol",49,60],["H8269","the chief captain",61,78],["H6635","of his host",79,90],["H0559","spake",91,96],["H0085","unto Abraham",97,109],["H0559","saying",111,117],["H0430","God",119,122],["H6213","is with thee in all that thou doest",123,158]]},"21:23":{"text":"Now therefore swear unto me here by God that thou wilt not deal falsely with me, nor with my son, nor with my son's son: but according to the kindness that I have done unto thee, thou shalt do unto me, and to the land wherein thou hast sojourned.","words":[["H7650","Now therefore swear",0,19],["H2008","unto me here",20,32],["H0430","by God",33,39],["H8266","that thou wilt not deal falsely",40,71],["H5209","with me, nor with my son",72,96],["H5220","nor with my son's son",98,119],["H2617","but according to the kindness",121,150],["H6213","that I have done",151,167],["H6213","unto thee, thou shalt do",168,192],["H0776","unto me, and to the land",193,217],["H1481","wherein thou hast sojourned",218,245]]},"21:24":{"text":"And Abraham said, I will swear.","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H7650","I will swear",18,30]]},"21:25":{"text":"And Abraham reproved Abimelech because of a well of water, which Abimelech's servants had violently taken away.","words":[["H0085","And Abraham",0,11],["H3198","reproved",12,20],["H0040","Abimelech",21,30],["H0182","because",31,38],["H0875","of a well",39,48],["H4325","of water",49,57],["H0040","which Abimelech's",59,76],["H5650","servants",77,85],["H1497","had violently taken away",86,110]]},"21:26":{"text":"And Abimelech said, I wot not who hath done this thing: neither didst thou tell me, neither yet heard I of it, but to day.","words":[["H0040","And Abimelech",0,13],["H0559","said",14,18],["H3045","I wot",20,25],["H6213","not who hath done",26,43],["H1697","this thing",44,54],["H3808","neither",56,63],["H5046","didst thou tell",64,79],["H3808","me, neither",80,91],["H8085","yet heard",92,101],["H1115","I of it, but",102,114],["H3117","to day",115,121]]},"21:27":{"text":"And Abraham took sheep and oxen, and gave them unto Abimelech; and both of them made a covenant.","words":[["H0085","And Abraham",0,11],["H3947","took",12,16],["H6629","sheep",17,22],["H1241","and oxen",23,31],["H5414","and gave",33,41],["H0040","them unto Abimelech",42,61],["H8147","and both of them",63,79],["H3772","made",80,84],["H1285","a covenant",85,95]]},"21:28":{"text":"And Abraham set seven ewe lambs of the flock by themselves.","words":[["H0085","And Abraham",0,11],["H5324","set",12,15],["H7651","seven",16,21],["H3535","ewe lambs",22,31],["H6629","of the flock",32,44]]},"21:29":{"text":"And Abimelech said unto Abraham, What mean these seven ewe lambs which thou hast set by themselves?","words":[["H0040","And Abimelech",0,13],["H0559","said",14,18],["H0085","unto Abraham",19,31],["H2008","What",33,37],["H7651","mean these seven",38,54],["H3535","ewe lambs",55,64],["H5324","which thou hast set",65,84]]},"21:30":{"text":"And he said, For these seven ewe lambs shalt thou take of my hand, that they may be a witness unto me, that I have digged this well.","words":[["H0559","And he said",0,11],["H7651","For these seven",13,28],["H3535","ewe lambs",29,38],["H3947","shalt thou take",39,54],["H3027","of my hand",55,65],["H5668","that",67,71],["H5713","they may be a witness",72,93],["H2658","unto me, that I have digged",94,121],["H0875","this well",122,131]]},"21:31":{"text":"Wherefore he called that place Beersheba; because there they sware both of them.","words":[["H7121","Wherefore he called",0,19],["H4725","that place",20,30],["H0884","Beersheba",31,40],["H7650","because there they sware",42,66],["H8147","both of them",67,79]]},"21:32":{"text":"Thus they made a covenant at Beersheba: then Abimelech rose up, and Phichol the chief captain of his host, and they returned into the land of the Philistines.","words":[["H3772","Thus they made",0,14],["H1285","a covenant",15,25],["H0884","at Beersheba",26,38],["H0040","then Abimelech",40,54],["H6965","rose up",55,62],["H6369","and Phichol",64,75],["H8269","the chief captain",76,93],["H6635","of his host",94,105],["H7725","and they returned",107,124],["H0776","into the land",125,138],["H6430","of the Philistines",139,157]]},"21:33":{"text":"And Abraham planted a grove in Beersheba, and called there on the name of the LORD, the everlasting God.","words":[["H5193","And Abraham planted",0,19],["H0815","a grove",20,27],["H0884","in Beersheba",28,40],["H7121","and called",42,52],["H8034","there on the name",53,70],["H3068","of the LORD",71,82],["H5769","the everlasting",84,99],["H0410","God",100,103]]},"21:34":{"text":"And Abraham sojourned in the Philistines' land many days.","words":[["H0085","And Abraham",0,11],["H1481","sojourned",12,21],["H6430","in the Philistines'",22,41],["H0776","land",42,46],["H7227","many",47,51],["H3117","days",52,56]]},"22:1":{"text":"And it came to pass after these things, that God did tempt Abraham, and said unto him, Abraham: and he said, Behold, here I am.","words":[["H0310","And it came to pass after",0,25],["H1697","these things",26,38],["H0430","that God",40,48],["H5254","did tempt",49,58],["H0085","Abraham",59,66],["H0559","and said",68,76],["H0085","unto him, Abraham",77,94],["H0559","and he said",96,107]]},"22:2":{"text":"And he said, Take now thy son, thine only son Isaac, whom thou lovest, and get thee into the land of Moriah; and offer him there for a burnt offering upon one of the mountains which I will tell thee of.","words":[["H0559","And he said",0,11],["H3947","Take now",13,21],["H1121","thy son",22,29],["H3173","thine only",31,41],["H3327","son Isaac",42,51],["H0157","whom thou lovest",53,69],["H3212","and get thee",71,83],["H0776","into the land",84,97],["H4179","of Moriah",98,107],["H5927","and offer him",109,122],["H5930","there for a burnt offering",123,149],["H0259","upon one",150,158],["H2022","of the mountains",159,175],["H0559","which I will tell",176,193]]},"22:3":{"text":"And Abraham rose up early in the morning, and saddled his ass, and took two of his young men with him, and Isaac his son, and clave the wood for the burnt offering, and rose up, and went unto the place of which God had told him.","words":[["H0085","And Abraham",0,11],["H7925","rose up early",12,25],["H1242","in the morning",26,40],["H2280","and saddled",42,53],["H2543","his ass",54,61],["H3947","and took",63,71],["H8147","two",72,75],["H5288","of his young men",76,92],["H3327","with him, and Isaac",93,112],["H1121","his son",113,120],["H1234","and clave",122,131],["H6086","the wood",132,140],["H5930","for the burnt offering",141,163],["H6965","and rose up",165,176],["H3212","and went",178,186],["H4725","unto the place",187,201],["H0430","of which God",202,214],["H0559","had told",215,223]]},"22:4":{"text":"Then on the third day Abraham lifted up his eyes, and saw the place afar off.","words":[["H7992","Then on the third",0,17],["H3117","day",18,21],["H0085","Abraham",22,29],["H5375","lifted up",30,39],["H5869","his eyes",40,48],["H7200","and saw",50,57],["H4725","the place",58,67],["H7350","afar off",68,76]]},"22:5":{"text":"And Abraham said unto his young men, Abide ye here with the ass; and I and the lad will go yonder and worship, and come again to you.","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H5288","unto his young men",17,35],["H3427","Abide",37,42],["H2543","ye here with the ass",43,63],["H5288","and I and the lad",65,82],["H3212","will go",83,90],["H3541","yonder",91,97],["H7812","and worship",98,109],["H7725","and come again",111,125]]},"22:6":{"text":"And Abraham took the wood of the burnt offering, and laid it upon Isaac his son; and he took the fire in his hand, and a knife; and they went both of them together.","words":[["H0085","And Abraham",0,11],["H3947","took",12,16],["H6086","the wood",17,25],["H5930","of the burnt offering",26,47],["H7760","and laid",49,57],["H3327","it upon Isaac",58,71],["H1121","his son",72,79],["H3947","and he took",81,92],["H0784","the fire",93,101],["H3027","in his hand",102,113],["H3979","and a knife",115,126],["H3212","and they went",128,141],["H8147","both",142,146],["H3162","of them together",147,163]]},"22:7":{"text":"And Isaac spake unto Abraham his father, and said, My father: and he said, Here am I, my son. And he said, Behold the fire and the wood: but where is the lamb for a burnt offering?","words":[["H3327","And Isaac",0,9],["H0559","spake",10,15],["H0085","unto Abraham",16,28],["H0001","his father",29,39],["H0559","and said",41,49],["H0001","My father",51,60],["H0559","and he said",62,73],["H1121","Here am I, my son",75,92],["H0559","And he said",94,105],["H0784","Behold the fire",107,122],["H6086","and the wood",123,135],["H7716","but where is the lamb",137,158],["H5930","for a burnt offering",159,179]]},"22:8":{"text":"And Abraham said, My son, God will provide himself a lamb for a burnt offering: so they went both of them together.","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H1121","My son",18,24],["H0430","God",26,29],["H7200","will provide",30,42],["H7716","himself a lamb",43,57],["H5930","for a burnt offering",58,78],["H3212","so they went",80,92],["H8147","both of them",93,105],["H3162","together",106,114]]},"22:9":{"text":"And they came to the place which God had told him of; and Abraham built an altar there, and laid the wood in order, and bound Isaac his son, and laid him on the altar upon the wood.","words":[["H0935","And they came",0,13],["H4725","to the place",14,26],["H0430","which God",27,36],["H0559","had told",37,45],["H0085","him of; and Abraham",46,65],["H1129","built",66,71],["H4196","an altar",72,80],["H6186","there, and laid",81,96],["H6086","the wood",97,105],["H6186","in order",106,114],["H6123","and bound",116,125],["H3327","Isaac",126,131],["H1121","his son",132,139],["H7760","and laid",141,149],["H4196","him on the altar",150,166],["H4605","upon",167,171],["H6086","the wood",172,180]]},"22:10":{"text":"And Abraham stretched forth his hand, and took the knife to slay his son.","words":[["H0085","And Abraham",0,11],["H7971","stretched forth",12,27],["H3027","his hand",28,36],["H3947","and took",38,46],["H3979","the knife",47,56],["H7819","to slay",57,64],["H1121","his son",65,72]]},"22:11":{"text":"And the angel of the LORD called unto him out of heaven, and said, Abraham, Abraham: and he said, Here am I.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H7121","called",26,32],["H8064","unto him out of heaven",33,55],["H0559","and said",57,65],["H0085","Abraham",67,74],["H0085","Abraham",76,83],["H0559","and he said",85,96]]},"22:12":{"text":"And he said, Lay not thine hand upon the lad, neither do thou any thing unto him: for now I know that thou fearest God, seeing thou hast not withheld thy son, thine only son from me.","words":[["H0559","And he said",0,11],["H7971","Lay",13,16],["H3027","not thine hand",17,31],["H0413","upon",32,36],["H5288","the lad",37,44],["H6213","neither do thou",46,61],["H3972","any thing",62,71],["H6258","unto him: for now",72,89],["H3045","I know",90,96],["H3373","that thou fearest",97,114],["H0430","God",115,118],["H3808","seeing thou hast not",120,140],["H2820","withheld",141,149],["H1121","thy son",150,157],["H3173","thine only",159,169]]},"22:13":{"text":"And Abraham lifted up his eyes, and looked, and behold behind him a ram caught in a thicket by his horns: and Abraham went and took the ram, and offered him up for a burnt offering in the stead of his son.","words":[["H0085","And Abraham",0,11],["H5375","lifted up",12,21],["H5869","his eyes",22,30],["H7200","and looked",32,42],["H0310","and behold behind",44,61],["H0352","him a ram",62,71],["H0270","caught",72,78],["H5442","in a thicket",79,91],["H7161","by his horns",92,104],["H0085","and Abraham",106,117],["H3212","went",118,122],["H3947","and took",123,131],["H0352","the ram",132,139],["H5927","and offered him up",141,159],["H5930","for a burnt offering",160,180],["H8478","in the stead",181,193],["H1121","of his son",194,204]]},"22:14":{"text":"And Abraham called the name of that place Jehovahjireh: as it is said to this day, In the mount of the LORD it shall be seen.","words":[["H0085","And Abraham",0,11],["H7121","called",12,18],["H8034","the name",19,27],["H4725","of that place",28,41],["H3070","Jehovahjireh",42,54],["H0834","as",56,58],["H0559","it is said",59,69],["H3117","to this day",70,81],["H2022","In the mount",83,95],["H3068","of the LORD",96,107],["H7200","it shall be seen",108,124]]},"22:15":{"text":"And the angel of the LORD called unto Abraham out of heaven the second time,","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H7121","called",26,32],["H0085","unto Abraham",33,45],["H8064","out of heaven",46,59],["H8145","the second time",60,75]]},"22:16":{"text":"And said, By myself have I sworn, saith the LORD, for because thou hast done this thing, and hast not withheld thy son, thine only son:","words":[["H0559","And said",0,8],["H7650","By myself have I sworn",10,32],["H5002","saith",34,39],["H3068","the LORD",40,48],["H3282","for because",50,61],["H0834","for because",50,61],["H6213","thou hast done",62,76],["H1697","this thing",77,87],["H3808","and hast not",89,101],["H2820","withheld",102,110],["H1121","thy son",111,118],["H3173","thine only",120,130]]},"22:17":{"text":"That in blessing I will bless thee, and in multiplying I will multiply thy seed as the stars of the heaven, and as the sand which is upon the sea shore; and thy seed shall possess the gate of his enemies;","words":[["H1288","That in blessing",0,16],["H1288","I will bless",17,29],["H7235","thee, and in multiplying",30,54],["H7235","I will multiply",55,70],["H2233","thy seed",71,79],["H3556","as the stars",80,92],["H8064","of the heaven",93,106],["H2344","and as the sand",108,123],["H3220","which is upon the sea",124,145],["H8193","shore",146,151],["H2233","and thy seed",153,165],["H3423","shall possess",166,179],["H8179","the gate",180,188],["H0341","of his enemies",189,203]]},"22:18":{"text":"And in thy seed shall all the nations of the earth be blessed; because thou hast obeyed my voice.","words":[["H2233","And in thy seed",0,15],["H1471","shall all the nations",16,37],["H0776","of the earth",38,50],["H1288","be blessed",51,61],["H0834","because",63,70],["H6118","because",63,70],["H8085","thou hast obeyed",71,87],["H6963","my voice",88,96]]},"22:19":{"text":"So Abraham returned unto his young men, and they rose up and went together to Beersheba; and Abraham dwelt at Beersheba.","words":[["H0085","So Abraham",0,10],["H7725","returned",11,19],["H5288","unto his young men",20,38],["H6965","and they rose up",40,56],["H3212","and went",57,65],["H3162","together",66,74],["H0884","to Beersheba",75,87],["H0085","and Abraham",89,100],["H3427","dwelt",101,106],["H0884","at Beersheba",107,119]]},"22:20":{"text":"And it came to pass after these things, that it was told Abraham, saying, Behold, Milcah, she hath also born children unto thy brother Nahor;","words":[["H0310","And it came to pass after",0,25],["H1697","these things",26,38],["H5046","that it was told",40,56],["H0085","Abraham",57,64],["H0559","saying",66,72],["H4435","Behold, Milcah",74,88],["H3205","she hath also born",90,108],["H1121","children",109,117],["H0251","unto thy brother",118,134],["H5152","Nahor",135,140]]},"22:21":{"text":"Huz his firstborn, and Buz his brother, and Kemuel the father of Aram,","words":[["H5780","Huz",0,3],["H1060","his firstborn",4,17],["H0938","and Buz",19,26],["H0251","his brother",27,38],["H7055","and Kemuel",40,50],["H0001","the father",51,61],["H0758","of Aram",62,69]]},"22:22":{"text":"And Chesed, and Hazo, and Pildash, and Jidlaph, and Bethuel.","words":[["H3777","And Chesed",0,10],["H2375","and Hazo",12,20],["H6394","and Pildash",22,33],["H3044","and Jidlaph",35,46],["H1328","and Bethuel",48,59]]},"22:23":{"text":"And Bethuel begat Rebekah: these eight Milcah did bear to Nahor, Abraham's brother.","words":[["H1328","And Bethuel",0,11],["H3205","begat",12,17],["H7259","Rebekah",18,25],["H8083","these eight",27,38],["H4435","Milcah",39,45],["H3205","did bear",46,54],["H5152","to Nahor",55,63],["H0085","Abraham's",65,74],["H0251","brother",75,82]]},"22:24":{"text":"And his concubine, whose name was Reumah, she bare also Tebah, and Gaham, and Thahash, and Maachah.","words":[["H6370","And his concubine",0,17],["H8034","whose name",19,29],["H7208","was Reumah",30,40],["H3205","she bare",42,50],["H2875","also Tebah",51,61],["H1514","and Gaham",63,72],["H8477","and Thahash",74,85],["H4601","and Maachah",87,98]]},"23:1":{"text":"And Sarah was an hundred and seven and twenty years old: these were the years of the life of Sarah.","words":[["H8283","And Sarah",0,9],["H3967","was an hundred",10,24],["H8141","was an hundred",10,24],["H7651","and seven",25,34],["H8141","and seven",25,34],["H6242","and twenty",35,45],["H8141","years",46,51],["H2416","old",52,55],["H8141","these were the years",57,77],["H2416","of the life",78,89],["H8283","of Sarah",90,98]]},"23:2":{"text":"And Sarah died in Kirjatharba; the same is Hebron in the land of Canaan: and Abraham came to mourn for Sarah, and to weep for her.","words":[["H8283","And Sarah",0,9],["H4191","died",10,14],["H7153","in Kirjatharba",15,29],["H2275","the same is Hebron",31,49],["H0776","in the land",50,61],["H3667","of Canaan",62,71],["H0085","and Abraham",73,84],["H0935","came",85,89],["H5594","to mourn",90,98],["H8283","for Sarah",99,108],["H1058","and to weep",110,121]]},"23:3":{"text":"And Abraham stood up from before his dead, and spake unto the sons of Heth, saying,","words":[["H0085","And Abraham",0,11],["H6965","stood up",12,20],["H6440","from before",21,32],["H4191","his dead",33,41],["H1696","and spake",43,52],["H1121","unto the sons",53,66],["H2845","of Heth",67,74],["H0559","saying",76,82]]},"23:4":{"text":"I am a stranger and a sojourner with you: give me a possession of a buryingplace with you, that I may bury my dead out of my sight.","words":[["H1616","I am a stranger",0,15],["H8453","and a sojourner",16,31],["H5414","with you: give",32,46],["H0272","me a possession",47,62],["H6913","of a buryingplace",63,80],["H6912","with you, that I may bury",81,106],["H4191","my dead",107,114],["H6440","out of my sight",115,130]]},"23:5":{"text":"And the children of Heth answered Abraham, saying unto him,","words":[["H1121","And the children",0,16],["H2845","of Heth",17,24],["H6030","answered",25,33],["H0085","Abraham",34,41],["H0559","saying",43,49]]},"23:6":{"text":"Hear us, my lord: thou art a mighty prince among us: in the choice of our sepulchres bury thy dead; none of us shall withhold from thee his sepulchre, but that thou mayest bury thy dead.","words":[["H8085","Hear us",0,7],["H0113","my lord",9,16],["H0430","thou art a mighty",18,35],["H5387","prince",36,42],["H8432","among us",43,51],["H4005","in the choice",53,66],["H6913","of our sepulchres",67,84],["H6912","bury",85,89],["H4191","thy dead",90,98],["H3808","none",100,104],["H0376","none",100,104],["H3607","of us shall withhold",105,125],["H6913","from thee his sepulchre",126,149],["H6912","but that thou mayest bury",151,176],["H4191","thy dead",177,185]]},"23:7":{"text":"And Abraham stood up, and bowed himself to the people of the land, even to the children of Heth.","words":[["H0085","And Abraham",0,11],["H6965","stood up",12,20],["H7812","and bowed",22,31],["H5971","himself to the people",32,53],["H0776","of the land",54,65],["H1121","even to the children",67,87],["H2845","of Heth",88,95]]},"23:8":{"text":"And he communed with them, saying, If it be your mind that I should bury my dead out of my sight; hear me, and intreat for me to Ephron the son of Zohar,","words":[["H1696","And he communed",0,15],["H0559","with them, saying",16,33],["H3426","If it be",35,43],["H5315","your mind",44,53],["H6912","that I should bury",54,72],["H4191","my dead",73,80],["H6440","out of my sight",81,96],["H8085","hear",98,102],["H6293","me, and intreat",103,118],["H6085","for me to Ephron",119,135],["H1121","the son",136,143],["H6714","of Zohar",144,152]]},"23:9":{"text":"That he may give me the cave of Machpelah, which he hath, which is in the end of his field; for as much money as it is worth he shall give it me for a possession of a buryingplace amongst you.","words":[["H5414","That he may give",0,16],["H4631","me the cave",17,28],["H4375","of Machpelah",29,41],["H7097","which he hath, which is in the end",43,77],["H7704","of his field",78,90],["H4392","for as much",92,103],["H3701","money",104,109],["H4392","as it is worth",110,124],["H5414","he shall give it",125,141],["H0272","me for a possession",142,161],["H6913","of a buryingplace",162,179],["H8432","amongst you",180,191]]},"23:10":{"text":"And Ephron dwelt among the children of Heth: and Ephron the Hittite answered Abraham in the audience of the children of Heth, even of all that went in at the gate of his city, saying,","words":[["H6085","And Ephron",0,10],["H3427","dwelt",11,16],["H8432","among",17,22],["H1121","the children",23,35],["H2845","of Heth",36,43],["H6085","and Ephron",45,55],["H2850","the Hittite",56,67],["H6030","answered",68,76],["H0085","Abraham",77,84],["H0241","in the audience",85,100],["H1121","of the children",101,116],["H2845","of Heth",117,124],["H0935","even of all that went in",126,150],["H8179","at the gate",151,162],["H5892","of his city",163,174],["H0559","saying",176,182]]},"23:11":{"text":"Nay, my lord, hear me: the field give I thee, and the cave that is therein, I give it thee; in the presence of the sons of my people give I it thee: bury thy dead.","words":[["H3808","Nay",0,3],["H0113","my lord",5,12],["H8085","hear me",14,21],["H7704","the field",23,32],["H5414","give I",33,39],["H4631","thee, and the cave",40,58],["H5414","that is therein, I give it",59,85],["H5869","thee; in the presence",86,107],["H1121","of the sons",108,119],["H5971","of my people",120,132],["H5414","give",133,137],["H6912","I it thee: bury",138,153],["H4191","thy dead",154,162]]},"23:12":{"text":"And Abraham bowed down himself before the people of the land.","words":[["H0085","And Abraham",0,11],["H7812","bowed down",12,22],["H6440","himself before",23,37],["H5971","the people",38,48],["H0776","of the land",49,60]]},"23:13":{"text":"And he spake unto Ephron in the audience of the people of the land, saying, But if thou wilt give it, I pray thee, hear me: I will give thee money for the field; take it of me, and I will bury my dead there.","words":[["H1696","And he spake",0,12],["H6085","unto Ephron",13,24],["H0241","in the audience",25,40],["H5971","of the people",41,54],["H0776","of the land",55,66],["H0559","saying",68,74],["H3863","But if thou wilt give it, I pray thee",76,113],["H8085","hear",115,119],["H5414","me: I will give",120,135],["H3701","thee money",136,146],["H7704","for the field",147,160],["H3947","take",162,166],["H6912","it of me, and I will bury",167,192],["H4191","my dead",193,200]]},"23:14":{"text":"And Ephron answered Abraham, saying unto him,","words":[["H6085","And Ephron",0,10],["H6030","answered",11,19],["H0085","Abraham",20,27],["H0559","saying",29,35]]},"23:15":{"text":"My lord, hearken unto me: the land is worth four hundred shekels of silver; what is that betwixt me and thee? bury therefore thy dead.","words":[["H0113","My lord",0,7],["H8085","hearken",9,16],["H0776","unto me: the land",17,34],["H0702","is worth four",35,48],["H3967","hundred",49,56],["H8255","shekels",57,64],["H3701","of silver",65,74],["H0996","what is that betwixt",76,96],["H6912","me and thee? bury",97,114],["H4191","therefore thy dead",115,133]]},"23:16":{"text":"And Abraham hearkened unto Ephron; and Abraham weighed to Ephron the silver, which he had named in the audience of the sons of Heth, four hundred shekels of silver, current money with the merchant.","words":[["H0085","And Abraham",0,11],["H8085","hearkened",12,21],["H6085","unto Ephron",22,33],["H0085","and Abraham",35,46],["H8254","weighed",47,54],["H6085","to Ephron",55,64],["H3701","the silver",65,75],["H1696","which he had named",77,95],["H0241","in the audience",96,111],["H1121","of the sons",112,123],["H2845","of Heth",124,131],["H0702","four",133,137],["H3967","hundred",138,145],["H8255","shekels",146,153],["H3701","of silver",154,163],["H5674","current",165,172],["H5503","money with the merchant",173,196]]},"23:17":{"text":"And the field of Ephron, which was in Machpelah, which was before Mamre, the field, and the cave which was therein, and all the trees that were in the field, that were in all the borders round about, were made sure","words":[["H7704","And the field",0,13],["H6085","of Ephron",14,23],["H4375","which was in Machpelah",25,47],["H6440","which was before",49,65],["H4471","Mamre",66,71],["H7704","the field",73,82],["H4631","and the cave",84,96],["H6086","which was therein, and all the trees",97,133],["H7704","that were in the field",134,156],["H1366","that were in all the borders",158,186],["H5439","round about",187,198],["H6965","were made sure",200,214]]},"23:18":{"text":"Unto Abraham for a possession in the presence of the children of Heth, before all that went in at the gate of his city.","words":[["H0085","Unto Abraham",0,12],["H4736","for a possession",13,29],["H5869","in the presence",30,45],["H1121","of the children",46,61],["H2845","of Heth",62,69],["H0935","before all that went in",71,94],["H8179","at the gate",95,106],["H5892","of his city",107,118]]},"23:19":{"text":"And after this, Abraham buried Sarah his wife in the cave of the field of Machpelah before Mamre: the same is Hebron in the land of Canaan.","words":[["H0310","And after",0,9],["H3651","this",10,14],["H0085","Abraham",16,23],["H6912","buried",24,30],["H8283","Sarah",31,36],["H0802","his wife",37,45],["H4631","in the cave",46,57],["H7704","of the field",58,70],["H4375","of Machpelah",71,83],["H6440","before",84,90],["H4471","Mamre",91,96],["H2275","the same is Hebron",98,116],["H0776","in the land",117,128],["H3667","of Canaan",129,138]]},"23:20":{"text":"And the field, and the cave that is therein, were made sure unto Abraham for a possession of a buryingplace by the sons of Heth.","words":[["H7704","And the field",0,13],["H4631","and the cave",15,27],["H6965","that is therein, were made sure",28,59],["H0085","unto Abraham",60,72],["H0272","for a possession",73,89],["H6913","of a buryingplace",90,107],["H1121","by the sons",108,119],["H2845","of Heth",120,127]]},"24:1":{"text":"And Abraham was old, and well stricken in age: and the LORD had blessed Abraham in all things.","words":[["H0085","And Abraham",0,11],["H2204","was old",12,19],["H0935","and well stricken",21,38],["H3117","in age",39,45],["H3068","and the LORD",47,59],["H1288","had blessed",60,71],["H0085","Abraham",72,79]]},"24:2":{"text":"And Abraham said unto his eldest servant of his house, that ruled over all that he had, Put, I pray thee, thy hand under my thigh:","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H2205","unto his eldest",17,32],["H5650","servant",33,40],["H1004","of his house",41,53],["H4910","that ruled over",55,70],["H7760","all that he had, Put",71,91],["H3027","I pray thee, thy hand",93,114],["H3409","under my thigh",115,129]]},"24:3":{"text":"And I will make thee swear by the LORD, the God of heaven, and the God of the earth, that thou shalt not take a wife unto my son of the daughters of the Canaanites, among whom I dwell:","words":[["H7650","And I will make thee swear",0,26],["H3068","by the LORD",27,38],["H0430","the God",40,47],["H8064","of heaven",48,57],["H0430","and the God",59,70],["H0776","of the earth",71,83],["H3947","that thou shalt not take",85,109],["H0802","a wife",110,116],["H1121","unto my son",117,128],["H1323","of the daughters",129,145],["H3669","of the Canaanites",146,163],["H7130","among",165,170],["H3427","whom I dwell",171,183]]},"24:4":{"text":"But thou shalt go unto my country, and to my kindred, and take a wife unto my son Isaac.","words":[["H3212","But thou shalt go",0,17],["H0776","unto my country",18,33],["H4138","and to my kindred",35,52],["H3947","and take",54,62],["H0802","a wife",63,69],["H1121","unto my son",70,81],["H3327","Isaac",82,87]]},"24:5":{"text":"And the servant said unto him, Peradventure the woman will not be willing to follow me unto this land: must I needs bring thy son again unto the land from whence thou camest?","words":[["H5650","And the servant",0,15],["H0559","said",16,20],["H0802","unto him, Peradventure the woman",21,53],["H0014","will not be willing",54,73],["H3212","to follow",74,83],["H0310","me",84,86],["H0776","unto this land",87,101],["H7725","must I needs bring",103,121],["H1121","thy son",122,129],["H7725","again",130,135],["H0776","unto the land",136,149],["H3318","from whence thou camest",150,173]]},"24:6":{"text":"And Abraham said unto him, Beware thou that thou bring not my son thither again.","words":[["H0085","And Abraham",0,11],["H0559","said",12,16],["H8104","unto him, Beware",17,33],["H7725","thou that thou bring",34,54],["H6435","not",55,58],["H1121","my son",59,65],["H7725","thither again",66,79]]},"24:7":{"text":"The LORD God of heaven, which took me from my father's house, and from the land of my kindred, and which spake unto me, and that sware unto me, saying, Unto thy seed will I give this land; he shall send his angel before thee, and thou shalt take a wife unto my son from thence.","words":[["H3068","The LORD",0,8],["H0430","God",9,12],["H8064","of heaven",13,22],["H3947","which took me",24,37],["H0001","from my father's",38,54],["H1004","house",55,60],["H0776","and from the land",62,79],["H4138","of my kindred",80,93],["H1696","and which spake",95,110],["H7650","unto me, and that sware",111,134],["H0559","unto me, saying",135,150],["H2233","Unto thy seed",152,165],["H5414","will I give",166,177],["H0776","this land",178,187],["H7971","he shall send",189,202],["H4397","his angel",203,212],["H6440","before thee",213,224],["H3947","and thou shalt take",226,245],["H0802","a wife",246,252],["H1121","unto my son",253,264]]},"24:8":{"text":"And if the woman will not be willing to follow thee, then thou shalt be clear from this my oath: only bring not my son thither again.","words":[["H0802","And if the woman",0,16],["H0014","will not be willing",17,36],["H3212","to follow",37,46],["H0310","thee",47,51],["H5352","then thou shalt be clear",53,77],["H7621","from this my oath",78,95],["H7725","only bring",97,107],["H1121","not my son",108,118],["H7725","thither again",119,132]]},"24:9":{"text":"And the servant put his hand under the thigh of Abraham his master, and sware to him concerning that matter.","words":[["H5650","And the servant",0,15],["H7760","put",16,19],["H3027","his hand",20,28],["H3409","under the thigh",29,44],["H0085","of Abraham",45,55],["H0113","his master",56,66],["H7650","and sware",68,77],["H5921","to him concerning",78,95],["H2088","that",96,100],["H1697","matter",101,107]]},"24:10":{"text":"And the servant took ten camels of the camels of his master, and departed; for all the goods of his master were in his hand: and he arose, and went to Mesopotamia, unto the city of Nahor.","words":[["H5650","And the servant",0,15],["H3947","took",16,20],["H6235","ten",21,24],["H1581","camels",25,31],["H1581","of the camels",32,45],["H0113","of his master",46,59],["H3212","and departed",61,73],["H2898","for all the goods",75,92],["H0113","of his master",93,106],["H3027","were in his hand",107,123],["H6965","and he arose",125,137],["H3212","and went",139,147],["H0763","to Mesopotamia",148,162],["H5892","unto the city",164,177],["H5152","of Nahor",178,186]]},"24:11":{"text":"And he made his camels to kneel down without the city by a well of water at the time of the evening, even the time that women go out to draw water.","words":[["H1288","And he made",0,11],["H1581","his camels",12,22],["H1288","to kneel down",23,36],["H2351","without",37,44],["H5892","the city",45,53],["H0413","by",54,56],["H0875","a well",57,63],["H4325","of water",64,72],["H6256","at the time",73,84],["H6153","of the evening",85,99],["H6256","even the time",101,114],["H3318","that women go out",115,132],["H7579","to draw",133,140]]},"24:12":{"text":"And he said, O LORD God of my master Abraham, I pray thee, send me good speed this day, and shew kindness unto my master Abraham.","words":[["H0559","And he said",0,11],["H3068","O LORD",13,19],["H0430","God",20,23],["H0113","of my master",24,36],["H0085","Abraham",37,44],["H6440","I pray thee, send me",46,66],["H7136","good speed",67,77],["H3117","this day",78,86],["H6213","and shew",88,96],["H2617","kindness",97,105],["H5973","unto",106,110],["H0113","my master",111,120],["H0085","Abraham",121,128]]},"24:13":{"text":"Behold, I stand here by the well of water; and the daughters of the men of the city come out to draw water:","words":[["H5324","Behold, I stand",0,15],["H5869","here by the well",16,32],["H4325","of water",33,41],["H1323","and the daughters",43,60],["H0582","of the men",61,71],["H5892","of the city",72,83],["H3318","come out",84,92],["H7579","to draw",93,100],["H4325","water",101,106]]},"24:14":{"text":"And let it come to pass, that the damsel to whom I shall say, Let down thy pitcher, I pray thee, that I may drink; and she shall say, Drink, and I will give thy camels drink also: let the same be she that thou hast appointed for thy servant Isaac; and thereby shall I know that thou hast shewed kindness unto my master.","words":[["H5291","And let it come to pass, that the damsel",0,40],["H0559","to whom I shall say",41,60],["H5186","Let down",62,70],["H3537","thy pitcher",71,82],["H8354","I pray thee, that I may drink",84,113],["H0559","and she shall say",115,132],["H8354","Drink",134,139],["H8248","and I will give",141,156],["H1581","thy camels",157,167],["H8248","drink",168,173],["H3198","also: let the same be she that thou hast appointed",174,224],["H5650","for thy servant",225,240],["H3327","Isaac",241,246],["H3045","and thereby shall I know",248,272],["H6213","that thou hast shewed",273,294],["H2617","kindness",295,303],["H0113","unto my master",304,318]]},"24:15":{"text":"And it came to pass, before he had done speaking, that, behold, Rebekah came out, who was born to Bethuel, son of Milcah, the wife of Nahor, Abraham's brother, with her pitcher upon her shoulder.","words":[["H3615","And it came to pass, before he had done",0,39],["H1696","speaking",40,48],["H7259","that, behold, Rebekah",50,71],["H3318","came out",72,80],["H0834","who",82,85],["H3205","was born",86,94],["H1328","to Bethuel",95,105],["H1121","son",107,110],["H4435","of Milcah",111,120],["H0802","the wife",122,130],["H5152","of Nahor",131,139],["H0085","Abraham's",141,150],["H0251","brother",151,158],["H3537","with her pitcher",160,176],["H7926","upon her shoulder",177,194]]},"24:16":{"text":"And the damsel was very fair to look upon, a virgin, neither had any man known her: and she went down to the well, and filled her pitcher, and came up.","words":[["H5291","And the damsel",0,14],["H3966","was very",15,23],["H2896","fair",24,28],["H4758","to look upon",29,41],["H1330","a virgin",43,51],["H0376","neither had any man",53,72],["H3045","known",73,78],["H3381","her: and she went down",79,101],["H5869","to the well",102,113],["H4390","and filled",115,125],["H3537","her pitcher",126,137],["H5927","and came up",139,150]]},"24:17":{"text":"And the servant ran to meet her, and said, Let me, I pray thee, drink a little water of thy pitcher.","words":[["H5650","And the servant",0,15],["H7323","ran",16,19],["H7125","to meet her",20,31],["H0559","and said",33,41],["H1572","Let me, I pray thee, drink",43,69],["H4592","a little",70,78],["H4325","water",79,84],["H3537","of thy pitcher",85,99]]},"24:18":{"text":"And she said, Drink, my lord: and she hasted, and let down her pitcher upon her hand, and gave him drink.","words":[["H0559","And she said",0,12],["H8354","Drink",14,19],["H0113","my lord",21,28],["H4116","and she hasted",30,44],["H3381","and let down",46,58],["H3537","her pitcher",59,70],["H3027","upon her hand",71,84],["H8248","and gave him drink",86,104]]},"24:19":{"text":"And when she had done giving him drink, she said, I will draw water for thy camels also, until they have done drinking.","words":[["H3615","And when she had done",0,21],["H8248","giving him drink",22,38],["H0559","she said",40,48],["H7579","I will draw",50,61],["H1581","water for thy camels",62,82],["H3615","also, until they have done",83,109],["H8354","drinking",110,118]]},"24:20":{"text":"And she hasted, and emptied her pitcher into the trough, and ran again unto the well to draw water, and drew for all his camels.","words":[["H4116","And she hasted",0,14],["H6168","and emptied",16,27],["H3537","her pitcher",28,39],["H8268","into the trough",40,55],["H7323","and ran",57,64],["H0875","again unto the well",65,84],["H7579","to draw",85,92],["H7579","water, and drew",93,108],["H1581","for all his camels",109,127]]},"24:21":{"text":"And the man wondering at her held his peace, to wit whether the LORD had made his journey prosperous or not.","words":[["H0376","And the man",0,11],["H7583","wondering",12,21],["H2790","at her held his peace",22,43],["H3045","to wit",45,51],["H3068","whether the LORD",52,68],["H6743","had made",69,77],["H1870","his journey",78,89],["H6743","prosperous",90,100],["H0518","or",101,103]]},"24:22":{"text":"And it came to pass, as the camels had done drinking, that the man took a golden earring of half a shekel weight, and two bracelets for her hands of ten shekels weight of gold;","words":[["H1581","And it came to pass, as the camels",0,34],["H3615","had done",35,43],["H8354","drinking",44,52],["H0376","that the man",54,66],["H3947","took",67,71],["H2091","a golden",72,80],["H5141","earring",81,88],["H1235","of half a shekel",89,105],["H4948","weight",106,112],["H8147","and two",114,121],["H6781","bracelets",122,131],["H3027","for her hands",132,145],["H6235","of ten",146,152],["H4948","shekels weight",153,167],["H2091","of gold",168,175]]},"24:23":{"text":"And said, Whose daughter art thou? tell me, I pray thee: is there room in thy father's house for us to lodge in?","words":[["H0559","And said",0,8],["H4310","Whose",10,15],["H1323","daughter",16,24],["H0859","art thou",25,33],["H5046","tell",35,39],["H3426","me, I pray thee: is there",40,65],["H4725","room",66,70],["H0001","in thy father's",71,86],["H1004","house",87,92],["H3885","for us to lodge in",93,111]]},"24:24":{"text":"And she said unto him, I am the daughter of Bethuel the son of Milcah, which she bare unto Nahor.","words":[["H0559","And she said",0,12],["H1323","unto him, I am the daughter",13,40],["H1328","of Bethuel",41,51],["H1121","the son",52,59],["H4435","of Milcah",60,69],["H3205","which she bare",71,85],["H5152","unto Nahor",86,96]]},"24:25":{"text":"She said moreover unto him, We have both straw and provender enough, and room to lodge in.","words":[["H0559","She said",0,8],["H1571","moreover unto him, We have both",9,40],["H8401","straw",41,46],["H4554","and provender",47,60],["H7227","enough",61,67],["H1571","and",69,72],["H4725","room",73,77],["H3885","to lodge in",78,89]]},"24:26":{"text":"And the man bowed down his head, and worshipped the LORD.","words":[["H0376","And the man",0,11],["H6915","bowed down his head",12,31],["H7812","and worshipped",33,47],["H3068","the LORD",48,56]]},"24:27":{"text":"And he said, Blessed be the LORD God of my master Abraham, who hath not left destitute my master of his mercy and his truth: I being in the way, the LORD led me to the house of my master's brethren.","words":[["H0559","And he said",0,11],["H1288","Blessed",13,20],["H3068","be the LORD",21,32],["H0430","God",33,36],["H0113","of my master",37,49],["H0085","Abraham",50,57],["H5800","who hath not left destitute",59,86],["H5973","who hath not left destitute",59,86],["H0113","my master",87,96],["H2617","of his mercy",97,109],["H0571","and his truth",110,123],["H1870","I being in the way",125,143],["H3068","the LORD",145,153],["H5148","led me",154,160],["H1004","to the house",161,173],["H0113","of my master's",174,188],["H0251","brethren",189,197]]},"24:28":{"text":"And the damsel ran, and told them of her mother's house these things.","words":[["H5291","And the damsel",0,14],["H7323","ran",15,18],["H5046","and told",20,28],["H0517","them of her mother's",29,49],["H1004","house",50,55],["H1697","these things",56,68]]},"24:29":{"text":"And Rebekah had a brother, and his name was Laban: and Laban ran out unto the man, unto the well.","words":[["H7259","And Rebekah",0,11],["H0251","had a brother",12,25],["H8034","and his name",27,39],["H3837","was Laban",40,49],["H3837","and Laban",51,60],["H7323","ran",61,64],["H2351","out",65,68],["H0376","unto the man",69,81],["H5869","unto the well",83,96]]},"24:30":{"text":"And it came to pass, when he saw the earring and bracelets upon his sister's hands, and when he heard the words of Rebekah his sister, saying, Thus spake the man unto me; that he came unto the man; and, behold, he stood by the camels at the well.","words":[["H7200","And it came to pass, when he saw",0,32],["H5141","the earring",33,44],["H6781","and bracelets",45,58],["H0269","upon his sister's",59,76],["H3027","hands",77,82],["H8085","and when he heard",84,101],["H1697","the words",102,111],["H7259","of Rebekah",112,122],["H0269","his sister",123,133],["H0559","saying",135,141],["H3541","Thus",143,147],["H1696","spake",148,153],["H0376","the man",154,161],["H0935","unto me; that he came",162,183],["H0376","unto the man",184,196],["H5975","and, behold, he stood",198,219],["H5921","by",220,222],["H1581","the camels",223,233],["H5869","at the well",234,245]]},"24:31":{"text":"And he said, Come in, thou blessed of the LORD; wherefore standest thou without? for I have prepared the house, and room for the camels.","words":[["H0559","And he said",0,11],["H0935","Come in",13,20],["H1288","thou blessed",22,34],["H3068","of the LORD",35,46],["H5975","wherefore standest",48,66],["H2351","thou without",67,79],["H6437","for I have prepared",81,100],["H1004","the house",101,110],["H4725","and room",112,120],["H1581","for the camels",121,135]]},"24:32":{"text":"And the man came into the house: and he ungirded his camels, and gave straw and provender for the camels, and water to wash his feet, and the men's feet that were with him.","words":[["H0376","And the man",0,11],["H0935","came",12,16],["H1004","into the house",17,31],["H6605","and he ungirded",33,48],["H1581","his camels",49,59],["H5414","and gave",61,69],["H8401","straw",70,75],["H4554","and provender",76,89],["H1581","for the camels",90,104],["H4325","and water",106,115],["H7364","to wash",116,123],["H7272","his feet",124,132],["H0582","and the men's",134,147],["H7272","feet",148,152]]},"24:33":{"text":"And there was set meat before him to eat: but he said, I will not eat, until I have told mine errand. And he said, Speak on.","words":[["H7760","And there was set",0,17],["H3455","And there was set",0,17],["H6440","meat before him",18,33],["H0398","to eat",34,40],["H0559","but he said",42,53],["H0398","I will not eat",55,69],["H1696","until I have told",71,88],["H1697","mine errand",89,100],["H0559","And he said",102,113],["H1696","Speak on",115,123]]},"24:34":{"text":"And he said, I am Abraham's servant.","words":[["H0559","And he said",0,11],["H0085","I am Abraham's",13,27],["H5650","servant",28,35]]},"24:35":{"text":"And the LORD hath blessed my master greatly; and he is become great: and he hath given him flocks, and herds, and silver, and gold, and menservants, and maidservants, and camels, and asses.","words":[["H3068","And the LORD",0,12],["H1288","hath blessed",13,25],["H0113","my master",26,35],["H3966","greatly",36,43],["H1431","and he is become great",45,67],["H5414","and he hath given",69,86],["H6629","him flocks",87,97],["H1241","and herds",99,108],["H3701","and silver",110,120],["H2091","and gold",122,130],["H5650","and menservants",132,147],["H8198","and maidservants",149,165],["H1581","and camels",167,177],["H2543","and asses",179,188]]},"24:36":{"text":"And Sarah my master's wife bare a son to my master when she was old: and unto him hath he given all that he hath.","words":[["H8283","And Sarah",0,9],["H0113","my master's",10,21],["H0802","wife",22,26],["H3205","bare",27,31],["H1121","a son",32,37],["H0113","to my master",38,50],["H0310","when",51,55],["H2209","she was old",56,67],["H5414","and unto him hath he given",69,95]]},"24:37":{"text":"And my master made me swear, saying, Thou shalt not take a wife to my son of the daughters of the Canaanites, in whose land I dwell:","words":[["H0113","And my master",0,13],["H7650","made me swear",14,27],["H0559","saying",29,35],["H3947","Thou shalt not take",37,56],["H0802","a wife",57,63],["H1121","to my son",64,73],["H1323","of the daughters",74,90],["H3669","of the Canaanites",91,108],["H0776","in whose land",110,123],["H3427","I dwell",124,131]]},"24:38":{"text":"But thou shalt go unto my father's house, and to my kindred, and take a wife unto my son.","words":[["H0518","But",0,3],["H3212","thou shalt go",4,17],["H0001","unto my father's",18,34],["H1004","house",35,40],["H4940","and to my kindred",42,59],["H3947","and take",61,69],["H0802","a wife",70,76],["H1121","unto my son",77,88]]},"24:39":{"text":"And I said unto my master, Peradventure the woman will not follow me.","words":[["H0559","And I said",0,10],["H0113","unto my master",11,25],["H0802","Peradventure the woman",27,49],["H3212","will not follow",50,65],["H0310","will not follow",50,65]]},"24:40":{"text":"And he said unto me, The LORD, before whom I walk, will send his angel with thee, and prosper thy way; and thou shalt take a wife for my son of my kindred, and of my father's house:","words":[["H0559","And he said",0,11],["H3068","unto me, The LORD",12,29],["H6440","before",31,37],["H1980","whom I walk",38,49],["H7971","will send",51,60],["H4397","his angel",61,70],["H6743","with thee, and prosper",71,93],["H1870","thy way",94,101],["H3947","and thou shalt take",103,122],["H0802","a wife",123,129],["H1121","for my son",130,140],["H4940","of my kindred",141,154],["H0001","and of my father's",156,174],["H1004","house",175,180]]},"24:41":{"text":"Then shalt thou be clear from this my oath, when thou comest to my kindred; and if they give not thee one, thou shalt be clear from my oath.","words":[["H5352","Then shalt thou be clear",0,24],["H0423","from this my oath",25,42],["H0935","when thou comest",44,60],["H4940","to my kindred",61,74],["H5414","and if they give",76,92],["H5355","not thee one, thou shalt be clear",93,126],["H0423","from my oath",127,139]]},"24:42":{"text":"And I came this day unto the well, and said, O LORD God of my master Abraham, if now thou do prosper my way which I go:","words":[["H0935","And I came",0,10],["H3117","this day",11,19],["H5869","unto the well",20,33],["H0559","and said",35,43],["H3068","O LORD",45,51],["H0430","God",52,55],["H0113","of my master",56,68],["H0085","Abraham",69,76],["H3426","if now thou do",78,92],["H6743","prosper",93,100],["H1870","my way",101,107],["H1980","which I go",108,118]]},"24:43":{"text":"Behold, I stand by the well of water; and it shall come to pass, that when the virgin cometh forth to draw water, and I say to her, Give me, I pray thee, a little water of thy pitcher to drink;","words":[["H5324","Behold, I stand",0,15],["H5869","by the well",16,27],["H4325","of water",28,36],["H5959","and it shall come to pass, that when the virgin",38,85],["H3318","cometh forth",86,98],["H7579","to draw",99,106],["H0559","water, and I say",107,123],["H8248","to her, Give me",124,139],["H4592","I pray thee, a little",141,162],["H4325","water",163,168],["H3537","of thy pitcher",169,183],["H8248","to drink",184,192]]},"24:44":{"text":"And she say to me, Both drink thou, and I will also draw for thy camels: let the same be the woman whom the LORD hath appointed out for my master's son.","words":[["H0559","And she say",0,11],["H8354","to me, Both drink",12,29],["H7579","thou, and I will also draw",30,56],["H1581","for thy camels",57,71],["H0802","let the same be the woman",73,98],["H3068","whom the LORD",99,112],["H3198","hath appointed out",113,131],["H0113","for my master's",132,147],["H1121","son",148,151]]},"24:45":{"text":"And before I had done speaking in mine heart, behold, Rebekah came forth with her pitcher on her shoulder; and she went down unto the well, and drew water: and I said unto her, Let me drink, I pray thee.","words":[["H3615","And before I had done",0,21],["H1696","speaking",22,30],["H3820","in mine heart",31,44],["H7259","behold, Rebekah",46,61],["H3318","came forth",62,72],["H3537","with her pitcher",73,89],["H7926","on her shoulder",90,105],["H3381","and she went down",107,124],["H5869","unto the well",125,138],["H7579","and drew",140,148],["H0559","water: and I said",149,166],["H8248","unto her, Let me drink",167,189]]},"24:46":{"text":"And she made haste, and let down her pitcher from her shoulder, and said, Drink, and I will give thy camels drink also: so I drank, and she made the camels drink also.","words":[["H4116","And she made haste",0,18],["H3381","and let down",20,32],["H3537","her pitcher",33,44],["H0559","from her shoulder, and said",45,72],["H8354","Drink",74,79],["H8248","and I will give",81,96],["H1581","thy camels",97,107],["H8248","drink",108,113],["H8354","also: so I drank",114,130],["H8248","and she made",132,144],["H1581","the camels",145,155],["H8248","drink",156,161]]},"24:47":{"text":"And I asked her, and said, Whose daughter art thou? And she said, The daughter of Bethuel, Nahor's son, whom Milcah bare unto him: and I put the earring upon her face, and the bracelets upon her hands.","words":[["H7592","And I asked",0,11],["H0559","her, and said",12,25],["H1323","Whose daughter",27,41],["H0559","art thou? And she said",42,64],["H1323","The daughter",66,78],["H1328","of Bethuel",79,89],["H5152","Nahor's",91,98],["H1121","son",99,102],["H4435","whom Milcah",104,115],["H3205","bare",116,120],["H7760","unto him: and I put",121,140],["H5141","the earring",141,152],["H0639","upon her face",153,166],["H6781","and the bracelets",168,185],["H3027","upon her hands",186,200]]},"24:48":{"text":"And I bowed down my head, and worshipped the LORD, and blessed the LORD God of my master Abraham, which had led me in the right way to take my master's brother's daughter unto his son.","words":[["H6915","And I bowed down my head",0,24],["H7812","and worshipped",26,40],["H3068","the LORD",41,49],["H1288","and blessed",51,62],["H3068","the LORD",63,71],["H0430","God",72,75],["H0113","of my master",76,88],["H0085","Abraham",89,96],["H5148","which had led me",98,114],["H0571","in the right",115,127],["H1870","way",128,131],["H3947","to take",132,139],["H0113","my master's",140,151],["H0251","brother's",152,161],["H1323","daughter",162,170],["H1121","unto his son",171,183]]},"24:49":{"text":"And now if ye will deal kindly and truly with my master, tell me: and if not, tell me; that I may turn to the right hand, or to the left.","words":[["H3426","And now if ye will",0,18],["H6213","deal",19,23],["H2617","kindly",24,30],["H0571","and truly",31,40],["H0113","with my master",41,55],["H5046","tell",57,61],["H5046","me: and if not, tell",62,82],["H6437","me; that I may turn",83,102],["H3225","to the right hand",103,120],["H0176","or",122,124],["H8040","to the left",125,136]]},"24:50":{"text":"Then Laban and Bethuel answered and said, The thing proceedeth from the LORD: we cannot speak unto thee bad or good.","words":[["H3837","Then Laban",0,10],["H1328","and Bethuel",11,22],["H6030","answered",23,31],["H0559","and said",32,40],["H1697","The thing",42,51],["H3318","proceedeth",52,62],["H3068","from the LORD",63,76],["H3201","we cannot",78,87],["H1696","speak",88,93],["H7451","unto thee bad",94,107],["H0176","or",108,110],["H2896","good",111,115]]},"24:51":{"text":"Behold, Rebekah is before thee, take her, and go, and let her be thy master's son's wife, as the LORD hath spoken.","words":[["H7259","Behold, Rebekah",0,15],["H6440","is before thee",16,30],["H3947","take",32,36],["H3212","her, and go",37,48],["H0113","and let her be thy master's",50,77],["H1121","son's",78,83],["H0802","wife",84,88],["H3068","as the LORD",90,101],["H1696","hath spoken",102,113]]},"24:52":{"text":"And it came to pass, that, when Abraham's servant heard their words, he worshipped the LORD, bowing himself to the earth.","words":[["H0085","And it came to pass, that, when Abraham's",0,41],["H5650","servant",42,49],["H8085","heard",50,55],["H1697","their words",56,67],["H7812","he worshipped",69,82],["H3068","the LORD",83,91],["H0776","bowing himself to the earth",93,120]]},"24:53":{"text":"And the servant brought forth jewels of silver, and jewels of gold, and raiment, and gave them to Rebekah: he gave also to her brother and to her mother precious things.","words":[["H5650","And the servant",0,15],["H3318","brought forth",16,29],["H3627","jewels",30,36],["H3701","of silver",37,46],["H3627","and jewels",48,58],["H2091","of gold",59,66],["H0899","and raiment",68,79],["H5414","and gave",81,89],["H7259","them to Rebekah",90,105],["H5414","he gave",107,114],["H0251","also to her brother",115,134],["H0517","and to her mother",135,152],["H4030","precious things",153,168]]},"24:54":{"text":"And they did eat and drink, he and the men that were with him, and tarried all night; and they rose up in the morning, and he said, Send me away unto my master.","words":[["H0398","And they did eat",0,16],["H8354","and drink",17,26],["H0582","he and the men",28,42],["H3885","that were with him, and tarried all night",43,84],["H6965","and they rose up",86,102],["H1242","in the morning",103,117],["H0559","and he said",119,130],["H7971","Send me away",132,144],["H0113","unto my master",145,159]]},"24:55":{"text":"And her brother and her mother said, Let the damsel abide with us a few days, at the least ten; after that she shall go.","words":[["H0251","And her brother",0,15],["H0517","and her mother",16,30],["H0559","said",31,35],["H5291","Let the damsel",37,51],["H3427","abide",52,57],["H3117","with us a few days",58,76],["H0176","at the least",78,90],["H6218","ten",91,94],["H0310","after",96,101],["H3212","that she shall go",102,119]]},"24:56":{"text":"And he said unto them, Hinder me not, seeing the LORD hath prospered my way; send me away that I may go to my master.","words":[["H0559","And he said",0,11],["H0309","unto them, Hinder me",12,32],["H3068","not, seeing the LORD",33,53],["H6743","hath prospered",54,68],["H1870","my way",69,75],["H7971","send me away",77,89],["H3212","that I may go",90,103],["H0113","to my master",104,116]]},"24:57":{"text":"And they said, We will call the damsel, and enquire at her mouth.","words":[["H0559","And they said",0,13],["H7121","We will call",15,27],["H5291","the damsel",28,38],["H7592","and enquire",40,51],["H6310","at her mouth",52,64]]},"24:58":{"text":"And they called Rebekah, and said unto her, Wilt thou go with this man? And she said, I will go.","words":[["H7121","And they called",0,15],["H7259","Rebekah",16,23],["H0559","and said",25,33],["H3212","unto her, Wilt thou go",34,56],["H0376","with this man",57,70],["H0559","And she said",72,84],["H3212","I will go",86,95]]},"24:59":{"text":"And they sent away Rebekah their sister, and her nurse, and Abraham's servant, and his men.","words":[["H7971","And they sent away",0,18],["H7259","Rebekah",19,26],["H0269","their sister",27,39],["H3243","and her nurse",41,54],["H0085","and Abraham's",56,69],["H5650","servant",70,77],["H0582","and his men",79,90]]},"24:60":{"text":"And they blessed Rebekah, and said unto her, Thou art our sister, be thou the mother of thousands of millions, and let thy seed possess the gate of those which hate them.","words":[["H1288","And they blessed",0,16],["H7259","Rebekah",17,24],["H0559","and said",26,34],["H0859","unto her, Thou",35,49],["H0269","art our sister",50,64],["H1961","be thou",66,73],["H0505","the mother of thousands",74,97],["H7233","of millions",98,109],["H2233","and let thy seed",111,127],["H3423","possess",128,135],["H8179","the gate",136,144],["H8130","of those which hate",145,164]]},"24:61":{"text":"And Rebekah arose, and her damsels, and they rode upon the camels, and followed the man: and the servant took Rebekah, and went his way.","words":[["H7259","And Rebekah",0,11],["H6965","arose",12,17],["H5291","and her damsels",19,34],["H7392","and they rode",36,49],["H1581","upon the camels",50,65],["H3212","and followed",67,79],["H0310","and followed",67,79],["H0376","the man",80,87],["H5650","and the servant",89,104],["H3947","took",105,109],["H7259","Rebekah",110,117],["H3212","and went his way",119,135]]},"24:62":{"text":"And Isaac came from the way of the well Lahairoi; for he dwelt in the south country.","words":[["H3327","And Isaac",0,9],["H0935","came",10,14],["H0935","from the way",15,27],["H0883","of the well Lahairoi",28,48],["H3427","for he dwelt",50,62],["H5045","in the south",63,75],["H0776","country",76,83]]},"24:63":{"text":"And Isaac went out to meditate in the field at the eventide: and he lifted up his eyes, and saw, and, behold, the camels were coming.","words":[["H3327","And Isaac",0,9],["H3318","went out",10,18],["H7742","to meditate",19,30],["H7704","in the field",31,43],["H6437","at",44,46],["H6153","the eventide",47,59],["H5375","and he lifted up",61,77],["H5869","his eyes",78,86],["H7200","and saw",88,95],["H1581","and, behold, the camels",97,120],["H0935","were coming",121,132]]},"24:64":{"text":"And Rebekah lifted up her eyes, and when she saw Isaac, she lighted off the camel.","words":[["H7259","And Rebekah",0,11],["H5375","lifted up",12,21],["H5869","her eyes",22,30],["H7200","and when she saw",32,48],["H3327","Isaac",49,54],["H5307","she lighted",56,67],["H5921","off",68,71],["H1581","the camel",72,81]]},"24:65":{"text":"For she had said unto the servant, What man is this that walketh in the field to meet us? And the servant had said, It is my master: therefore she took a vail, and covered herself.","words":[["H0559","For she had said",0,16],["H5650","unto the servant",17,33],["H4310","What",35,39],["H0376","man",40,43],["H1976","is this",44,51],["H1980","that walketh",52,64],["H7704","in the field",65,77],["H7125","to meet us",78,88],["H5650","And the servant",90,105],["H0559","had said",106,114],["H0113","It is my master",116,131],["H3947","therefore she took",133,151],["H6809","a vail",152,158],["H3680","and covered herself",160,179]]},"24:66":{"text":"And the servant told Isaac all things that he had done.","words":[["H5650","And the servant",0,15],["H5608","told",16,20],["H3327","Isaac",21,26],["H1697","all things",27,37],["H6213","that he had done",38,54]]},"24:67":{"text":"And Isaac brought her into his mother Sarah's tent, and took Rebekah, and she became his wife; and he loved her: and Isaac was comforted after his mother's death.","words":[["H3327","And Isaac",0,9],["H0935","brought her",10,21],["H0517","into his mother",22,37],["H8283","Sarah's",38,45],["H0168","tent",46,50],["H3947","and took",52,60],["H7259","Rebekah",61,68],["H0802","and she became his wife",70,93],["H0157","and he loved",95,107],["H3327","her: and Isaac",108,122],["H5162","was comforted",123,136],["H0310","after",137,142],["H0517","his mother's",143,155]]},"25:1":{"text":"Then again Abraham took a wife, and her name was Keturah.","words":[["H3254","Then again",0,10],["H0085","Abraham",11,18],["H3947","took",19,23],["H0802","a wife",24,30],["H8034","and her name",32,44],["H6989","was Keturah",45,56]]},"25:2":{"text":"And she bare him Zimran, and Jokshan, and Medan, and Midian, and Ishbak, and Shuah.","words":[["H3205","And she bare",0,12],["H2175","him Zimran",13,23],["H3370","and Jokshan",25,36],["H4091","and Medan",38,47],["H4080","and Midian",49,59],["H3435","and Ishbak",61,71],["H7744","and Shuah",73,82]]},"25:3":{"text":"And Jokshan begat Sheba, and Dedan. And the sons of Dedan were Asshurim, and Letushim, and Leummim.","words":[["H3370","And Jokshan",0,11],["H3205","begat",12,17],["H7614","Sheba",18,23],["H1719","and Dedan",25,34],["H1121","And the sons",36,48],["H1719","of Dedan",49,57],["H0805","were Asshurim",58,71],["H3912","and Letushim",73,85],["H3817","and Leummim",87,98]]},"25:4":{"text":"And the sons of Midian; Ephah, and Epher, and Hanoch, and Abida, and Eldaah. All these were the children of Keturah.","words":[["H1121","And the sons",0,12],["H4080","of Midian",13,22],["H5891","Ephah",24,29],["H6081","and Epher",31,40],["H2585","and Hanoch",42,52],["H0028","and Abida",54,63],["H0420","and Eldaah",65,75],["H1121","All these were the children",77,104],["H6989","of Keturah",105,115]]},"25:5":{"text":"And Abraham gave all that he had unto Isaac.","words":[["H0085","And Abraham",0,11],["H5414","gave",12,16],["H3327","all that he had unto Isaac",17,43]]},"25:6":{"text":"But unto the sons of the concubines, which Abraham had, Abraham gave gifts, and sent them away from Isaac his son, while he yet lived, eastward, unto the east country.","words":[["H1121","But unto the sons",0,17],["H6370","of the concubines",18,35],["H0085","which Abraham",37,50],["H0085","had, Abraham",51,63],["H5414","gave",64,68],["H4979","gifts",69,74],["H7971","and sent them away",76,94],["H3327","from Isaac",95,105],["H1121","his son",106,113],["H2416","while he yet lived",115,133],["H6924","eastward",135,143],["H6924","unto the east",145,158],["H0776","country",159,166]]},"25:7":{"text":"And these are the days of the years of Abraham's life which he lived, an hundred threescore and fifteen years.","words":[["H3117","And these are the days",0,22],["H8141","of the years",23,35],["H0085","of Abraham's",36,48],["H2416","life",49,53],["H2425","which he lived",54,68],["H3967","an hundred",70,80],["H8141","an hundred",70,80],["H7657","threescore and fifteen",81,103],["H8141","threescore and fifteen",81,103],["H2568","threescore and fifteen",81,103],["H8141","years",104,109]]},"25:8":{"text":"Then Abraham gave up the ghost, and died in a good old age, an old man, and full of years; and was gathered to his people.","words":[["H0085","Then Abraham",0,12],["H1478","gave up the ghost",13,30],["H4191","and died",32,40],["H2896","in a good",41,50],["H7872","old age",51,58],["H2205","an old man",60,70],["H7649","and full",72,80],["H0622","of years; and was gathered",81,107],["H5971","to his people",108,121]]},"25:9":{"text":"And his sons Isaac and Ishmael buried him in the cave of Machpelah, in the field of Ephron the son of Zohar the Hittite, which is before Mamre;","words":[["H1121","And his sons",0,12],["H3327","Isaac",13,18],["H3458","and Ishmael",19,30],["H6912","buried",31,37],["H4631","him in the cave",38,53],["H4375","of Machpelah",54,66],["H7704","in the field",68,80],["H6085","of Ephron",81,90],["H1121","the son",91,98],["H6714","of Zohar",99,107],["H2850","the Hittite",108,119],["H6440","which is before",121,136],["H4471","Mamre",137,142]]},"25:10":{"text":"The field which Abraham purchased of the sons of Heth: there was Abraham buried, and Sarah his wife.","words":[["H7704","The field",0,9],["H0085","which Abraham",10,23],["H7069","purchased",24,33],["H1121","of the sons",34,45],["H2845","of Heth",46,53],["H0085","there was Abraham",55,72],["H6912","buried",73,79],["H8283","and Sarah",81,90],["H0802","his wife",91,99]]},"25:11":{"text":"And it came to pass after the death of Abraham, that God blessed his son Isaac; and Isaac dwelt by the well Lahairoi.","words":[["H0310","And it came to pass after",0,25],["H4194","the death",26,35],["H0085","of Abraham",36,46],["H0430","that God",48,56],["H1288","blessed",57,64],["H1121","his son",65,72],["H3327","Isaac",73,78],["H3327","and Isaac",80,89],["H3427","dwelt",90,95],["H5973","by",96,98],["H0883","the well Lahairoi",99,116]]},"25:12":{"text":"Now these are the generations of Ishmael, Abraham's son, whom Hagar the Egyptian, Sarah's handmaid, bare unto Abraham:","words":[["H8435","Now these are the generations",0,29],["H3458","of Ishmael",30,40],["H0085","Abraham's",42,51],["H1121","son",52,55],["H1904","whom Hagar",57,67],["H4713","the Egyptian",68,80],["H8283","Sarah's",82,89],["H8198","handmaid",90,98],["H3205","bare",100,104],["H0085","unto Abraham",105,117]]},"25:13":{"text":"And these are the names of the sons of Ishmael, by their names, according to their generations: the firstborn of Ishmael, Nebajoth; and Kedar, and Adbeel, and Mibsam,","words":[["H8034","And these are the names",0,23],["H1121","of the sons",24,35],["H3458","of Ishmael",36,46],["H8034","by their names",48,62],["H8435","according to their generations",64,94],["H1060","the firstborn",96,109],["H3458","of Ishmael",110,120],["H5032","Nebajoth",122,130],["H6938","and Kedar",132,141],["H0110","and Adbeel",143,153],["H4017","and Mibsam",155,165]]},"25:14":{"text":"And Mishma, and Dumah, and Massa,","words":[["H4927","And Mishma",0,10],["H1746","and Dumah",12,21],["H4854","and Massa",23,32]]},"25:15":{"text":"Hadar, and Tema, Jetur, Naphish, and Kedemah:","words":[["H2316","Hadar",0,5],["H8485","and Tema",7,15],["H3195","Jetur",17,22],["H5305","Naphish",24,31],["H6929","and Kedemah",33,44]]},"25:16":{"text":"These are the sons of Ishmael, and these are their names, by their towns, and by their castles; twelve princes according to their nations.","words":[["H1121","These are the sons",0,18],["H3458","of Ishmael",19,29],["H8034","and these are their names",31,56],["H2691","by their towns",58,72],["H2918","and by their castles",74,94],["H8147","twelve",96,102],["H6240","twelve",96,102],["H5387","princes",103,110],["H0523","according to their nations",111,137]]},"25:17":{"text":"And these are the years of the life of Ishmael, an hundred and thirty and seven years: and he gave up the ghost and died; and was gathered unto his people.","words":[["H8141","And these are the years",0,23],["H2416","of the life",24,35],["H3458","of Ishmael",36,46],["H3967","an hundred",48,58],["H8141","an hundred",48,58],["H7970","and thirty",59,69],["H8141","and thirty",59,69],["H7651","and seven",70,79],["H8141","years",80,85],["H1478","and he gave up the ghost",87,111],["H4191","and died",112,120],["H0622","and was gathered",122,138],["H5971","unto his people",139,154]]},"25:18":{"text":"And they dwelt from Havilah unto Shur, that is before Egypt, as thou goest toward Assyria: and he died in the presence of all his brethren.","words":[["H7931","And they dwelt",0,14],["H2341","from Havilah",15,27],["H7793","unto Shur",28,37],["H6440","that is before",39,53],["H4714","Egypt",54,59],["H0935","as thou goest",61,74],["H0804","toward Assyria",75,89],["H5307","and he died",91,102],["H6440","in the presence",103,118],["H0251","of all his brethren",119,138]]},"25:19":{"text":"And these are the generations of Isaac, Abraham's son: Abraham begat Isaac:","words":[["H8435","And these are the generations",0,29],["H3327","of Isaac",30,38],["H0085","Abraham's",40,49],["H1121","son",50,53],["H0085","Abraham",55,62],["H3205","begat",63,68],["H3327","Isaac",69,74]]},"25:20":{"text":"And Isaac was forty years old when he took Rebekah to wife, the daughter of Bethuel the Syrian of Padanaram, the sister to Laban the Syrian.","words":[["H3327","And Isaac",0,9],["H0705","was forty",10,19],["H8141","years",20,25],["H1121","old",26,29],["H3947","when he took",30,42],["H7259","Rebekah",43,50],["H0802","to wife",51,58],["H1323","the daughter",60,72],["H1328","of Bethuel",73,83],["H0761","the Syrian",84,94],["H6307","of Padanaram",95,107],["H0269","the sister",109,119],["H3837","to Laban",120,128],["H0761","the Syrian",129,139]]},"25:21":{"text":"And Isaac intreated the LORD for his wife, because she was barren: and the LORD was intreated of him, and Rebekah his wife conceived.","words":[["H3327","And Isaac",0,9],["H6279","intreated",10,19],["H3068","the LORD",20,28],["H5227","for",29,32],["H0802","his wife",33,41],["H6135","because she was barren",43,65],["H3068","and the LORD",67,79],["H6279","was intreated",80,93],["H7259","of him, and Rebekah",94,113],["H0802","his wife",114,122],["H2029","conceived",123,132]]},"25:22":{"text":"And the children struggled together within her; and she said, If it be so, why am I thus? And she went to enquire of the LORD.","words":[["H1121","And the children",0,16],["H7533","struggled together",17,35],["H7130","within her",36,46],["H0559","and she said",48,60],["H2088","If it be so, why am I thus",62,88],["H3212","And she went",90,102],["H1875","to enquire",103,113],["H3068","of the LORD",114,125]]},"25:23":{"text":"And the LORD said unto her, Two nations are in thy womb, and two manner of people shall be separated from thy bowels; and the one people shall be stronger than the other people; and the elder shall serve the younger.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H8147","unto her, Two",18,31],["H1471","nations",32,39],["H0990","are in thy womb",40,55],["H8147","and two manner",57,71],["H3816","of people",72,81],["H6504","shall be separated",82,100],["H4578","from thy bowels",101,116],["H3816","and the one people",118,136],["H0553","shall be stronger",137,154],["H3816","than the other people",155,176],["H7227","and the elder",178,191],["H5647","shall serve",192,203],["H6810","the younger",204,215]]},"25:24":{"text":"And when her days to be delivered were fulfilled, behold, there were twins in her womb.","words":[["H3117","And when her days",0,17],["H3205","to be delivered",18,33],["H4390","were fulfilled",34,48],["H8380","behold, there were twins",50,74],["H0990","in her womb",75,86]]},"25:25":{"text":"And the first came out red, all over like an hairy garment; and they called his name Esau.","words":[["H7223","And the first",0,13],["H3318","came out",14,22],["H0132","red",23,26],["H8181","all over like an hairy",28,50],["H0155","garment",51,58],["H7121","and they called",60,75],["H8034","his name",76,84],["H6215","Esau",85,89]]},"25:26":{"text":"And after that came his brother out, and his hand took hold on Esau's heel; and his name was called Jacob: and Isaac was threescore years old when she bare them.","words":[["H0310","And after",0,9],["H3318","that came",10,19],["H0251","his brother",20,31],["H3318","out",32,35],["H3027","and his hand",37,49],["H0270","took hold",50,59],["H6215","on Esau's",60,69],["H6119","heel",70,74],["H8034","and his name",76,88],["H7121","was called",89,99],["H3290","Jacob",100,105],["H3327","and Isaac",107,116],["H8346","was threescore",117,131],["H8141","years",132,137],["H1121","old",138,141],["H3205","when she bare",142,155]]},"25:27":{"text":"And the boys grew: and Esau was a cunning hunter, a man of the field; and Jacob was a plain man, dwelling in tents.","words":[["H5288","And the boys",0,12],["H1431","grew",13,17],["H6215","and Esau",19,27],["H3045","was a cunning",28,41],["H6718","hunter",42,48],["H0376","a man",50,55],["H7704","of the field",56,68],["H3290","and Jacob",70,79],["H8535","was a plain",80,91],["H0376","man",92,95],["H3427","dwelling",97,105],["H0168","in tents",106,114]]},"25:28":{"text":"And Isaac loved Esau, because he did eat of his venison: but Rebekah loved Jacob.","words":[["H3327","And Isaac",0,9],["H0157","loved",10,15],["H6215","Esau",16,20],["H6310","because he did eat",22,40],["H6718","of his venison",41,55],["H7259","but Rebekah",57,68],["H0157","loved",69,74],["H3290","Jacob",75,80]]},"25:29":{"text":"And Jacob sod pottage: and Esau came from the field, and he was faint:","words":[["H3290","And Jacob",0,9],["H2102","sod",10,13],["H5138","pottage",14,21],["H6215","and Esau",23,31],["H0935","came",32,36],["H7704","from the field",37,51],["H5889","and he was faint",53,69]]},"25:30":{"text":"And Esau said to Jacob, Feed me, I pray thee, with that same red pottage; for I am faint: therefore was his name called Edom.","words":[["H6215","And Esau",0,8],["H0559","said",9,13],["H3290","to Jacob",14,22],["H3938","Feed",24,28],["H4480","me, I pray thee, with",29,50],["H0122","that same",51,60],["H0122","red",61,64],["H5889","pottage; for I am faint",65,88],["H8034","therefore was his name",90,112],["H7121","called",113,119],["H0123","Edom",120,124]]},"25:31":{"text":"And Jacob said, Sell me this day thy birthright.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H4376","Sell",16,20],["H3117","me this day",21,32],["H1062","thy birthright",33,47]]},"25:32":{"text":"And Esau said, Behold, I am at the point to die: and what profit shall this birthright do to me?","words":[["H6215","And Esau",0,8],["H0559","said",9,13],["H1980","Behold, I am at the point",15,40],["H4191","to die",41,47],["H1062","and what profit shall this birthright",49,86]]},"25:33":{"text":"And Jacob said, Swear to me this day; and he sware unto him: and he sold his birthright unto Jacob.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H7650","Swear",16,21],["H3117","to me this day",22,36],["H7650","and he sware",38,50],["H4376","unto him: and he sold",51,72],["H1062","his birthright",73,87],["H3290","unto Jacob",88,98]]},"25:34":{"text":"Then Jacob gave Esau bread and pottage of lentiles; and he did eat and drink, and rose up, and went his way: thus Esau despised his birthright.","words":[["H3290","Then Jacob",0,10],["H5414","gave",11,15],["H6215","Esau",16,20],["H3899","bread",21,26],["H5138","and pottage",27,38],["H5742","of lentiles",39,50],["H0398","and he did eat",52,66],["H8354","and drink",67,76],["H6965","and rose up",78,89],["H3212","and went his way",91,107],["H6215","thus Esau",109,118],["H0959","despised",119,127],["H1062","his birthright",128,142]]},"26:1":{"text":"And there was a famine in the land, beside the first famine that was in the days of Abraham. And Isaac went unto Abimelech king of the Philistines unto Gerar.","words":[["H7458","And there was a famine",0,22],["H0776","in the land",23,34],["H0905","beside",36,42],["H7223","the first",43,52],["H7458","famine",53,59],["H3117","that was in the days",60,80],["H0085","of Abraham",81,91],["H3327","And Isaac",93,102],["H3212","went",103,107],["H0040","unto Abimelech",108,122],["H4428","king",123,127],["H6430","of the Philistines",128,146],["H1642","unto Gerar",147,157]]},"26:2":{"text":"And the LORD appeared unto him, and said, Go not down into Egypt; dwell in the land which I shall tell thee of:","words":[["H3068","And the LORD",0,12],["H7200","appeared",13,21],["H0559","unto him, and said",22,40],["H3381","Go not down",42,53],["H4714","into Egypt",54,64],["H7931","dwell",66,71],["H0776","in the land",72,83],["H0559","which I shall tell",84,102]]},"26:3":{"text":"Sojourn in this land, and I will be with thee, and will bless thee; for unto thee, and unto thy seed, I will give all these countries, and I will perform the oath which I sware unto Abraham thy father;","words":[["H1481","Sojourn",0,7],["H0776","in this land",8,20],["H1288","and I will be with thee, and will bless",22,61],["H2233","thee; for unto thee, and unto thy seed",62,100],["H5414","I will give",102,113],["H0411","all these",114,123],["H0776","countries",124,133],["H6965","and I will perform",135,153],["H7621","the oath",154,162],["H7650","which I sware",163,176],["H0085","unto Abraham",177,189],["H0001","thy father",190,200]]},"26:4":{"text":"And I will make thy seed to multiply as the stars of heaven, and will give unto thy seed all these countries; and in thy seed shall all the nations of the earth be blessed;","words":[["H7235","And I will make",0,15],["H2233","thy seed",16,24],["H7235","to multiply",25,36],["H3556","as the stars",37,49],["H8064","of heaven",50,59],["H5414","and will give",61,74],["H2233","unto thy seed",75,88],["H0411","all these",89,98],["H0776","countries",99,108],["H2233","and in thy seed",110,125],["H1471","shall all the nations",126,147],["H0776","of the earth",148,160],["H1288","be blessed",161,171]]},"26:5":{"text":"Because that Abraham obeyed my voice, and kept my charge, my commandments, my statutes, and my laws.","words":[["H6118","Because",0,7],["H0085","that Abraham",8,20],["H8085","obeyed",21,27],["H6963","my voice",28,36],["H8104","and kept",38,46],["H4931","my charge",47,56],["H4687","my commandments",58,73],["H2708","my statutes",75,86],["H8451","and my laws",88,99]]},"26:6":{"text":"And Isaac dwelt in Gerar:","words":[["H3327","And Isaac",0,9],["H3427","dwelt",10,15],["H1642","in Gerar",16,24]]},"26:7":{"text":"And the men of the place asked him of his wife; and he said, She is my sister: for he feared to say, She is my wife; lest, said he, the men of the place should kill me for Rebekah; because she was fair to look upon.","words":[["H0582","And the men",0,11],["H4725","of the place",12,24],["H7592","asked",25,30],["H0802","him of his wife",31,46],["H0559","and he said",48,59],["H0269","She is my sister",61,77],["H3372","for he feared",79,92],["H0559","to say",93,99],["H0802","She is my wife",101,115],["H0582","lest, said he, the men",117,139],["H4725","of the place",140,152],["H2026","should kill",153,164],["H7259","me for Rebekah",165,179],["H2896","because she was fair",181,201],["H4758","to look upon",202,214]]},"26:8":{"text":"And it came to pass, when he had been there a long time, that Abimelech king of the Philistines looked out at a window, and saw, and, behold, Isaac was sporting with Rebekah his wife.","words":[["H0748","And it came to pass, when he had been there a long",0,50],["H3117","time",51,55],["H0040","that Abimelech",57,71],["H4428","king",72,76],["H6430","of the Philistines",77,95],["H8259","looked out",96,106],["H1157","at",107,109],["H2474","a window",110,118],["H7200","and saw",120,127],["H3327","and, behold, Isaac",129,147],["H6711","was sporting",148,160],["H7259","with Rebekah",161,173],["H0802","his wife",174,182]]},"26:9":{"text":"And Abimelech called Isaac, and said, Behold, of a surety she is thy wife: and how saidst thou, She is my sister? And Isaac said unto him, Because I said, Lest I die for her.","words":[["H0040","And Abimelech",0,13],["H7121","called",14,20],["H3327","Isaac",21,26],["H0559","and said",28,36],["H0389","Behold, of a surety",38,57],["H0802","she is thy wife",58,73],["H0559","and how saidst",75,89],["H0269","thou, She is my sister",90,112],["H3327","And Isaac",114,123],["H0559","said",124,128],["H0559","unto him, Because I said",129,153],["H4191","Lest I die",155,165]]},"26:10":{"text":"And Abimelech said, What is this thou hast done unto us? one of the people might lightly have lien with thy wife, and thou shouldest have brought guiltiness upon us.","words":[["H0040","And Abimelech",0,13],["H0559","said",14,18],["H6213","What is this thou hast done",20,47],["H0259","unto us? one",48,60],["H5971","of the people",61,74],["H4592","might lightly",75,88],["H7901","have lien",89,98],["H0802","with thy wife",99,112],["H0935","and thou shouldest have brought",114,145],["H0817","guiltiness",146,156]]},"26:11":{"text":"And Abimelech charged all his people, saying, He that toucheth this man or his wife shall surely be put to death.","words":[["H0040","And Abimelech",0,13],["H6680","charged",14,21],["H5971","all his people",22,36],["H0559","saying",38,44],["H5060","He that toucheth",46,62],["H0376","this man",63,71],["H0802","or his wife",72,83],["H4191","shall surely",84,96],["H4191","be put to death",97,112]]},"26:12":{"text":"Then Isaac sowed in that land, and received in the same year an hundredfold: and the LORD blessed him.","words":[["H3327","Then Isaac",0,10],["H2232","sowed",11,16],["H0776","in that land",17,29],["H4672","and received",31,43],["H8141","in the same year",44,60],["H3967","an hundredfold",61,75],["H8180","an hundredfold",61,75],["H3068","and the LORD",77,89],["H1288","blessed",90,97]]},"26:13":{"text":"And the man waxed great, and went forward, and grew until he became very great:","words":[["H0376","And the man",0,11],["H1431","waxed great",12,23],["H3212","and went",25,33],["H1980","forward",34,41],["H1432","and grew",43,51],["H1431","until he became",52,67],["H3966","very",68,72],["H1431","great",73,78]]},"26:14":{"text":"For he had possession of flocks, and possession of herds, and great store of servants: and the Philistines envied him.","words":[["H4735","For he had possession",0,21],["H6629","of flocks",22,31],["H4735","and possession",33,47],["H1241","of herds",48,56],["H7227","and great store",58,73],["H5657","of servants",74,85],["H6430","and the Philistines",87,106],["H7065","envied",107,113]]},"26:15":{"text":"For all the wells which his father's servants had digged in the days of Abraham his father, the Philistines had stopped them, and filled them with earth.","words":[["H0875","For all the wells",0,17],["H0001","which his father's",18,36],["H5650","servants",37,45],["H2658","had digged",46,56],["H3117","in the days",57,68],["H0085","of Abraham",69,79],["H0001","his father",80,90],["H6430","the Philistines",92,107],["H5640","had stopped",108,119],["H4390","them, and filled",120,136],["H6083","them with earth",137,152]]},"26:16":{"text":"And Abimelech said unto Isaac, Go from us; for thou art much mightier than we.","words":[["H0040","And Abimelech",0,13],["H0559","said",14,18],["H3327","unto Isaac",19,29],["H3212","Go",31,33],["H3966","from us; for thou art much",34,60],["H6105","mightier",61,69]]},"26:17":{"text":"And Isaac departed thence, and pitched his tent in the valley of Gerar, and dwelt there.","words":[["H3327","And Isaac",0,9],["H3212","departed",10,18],["H2583","thence, and pitched his tent",19,47],["H5158","in the valley",48,61],["H1642","of Gerar",62,70],["H3427","and dwelt",72,81],["H8033","there",82,87]]},"26:18":{"text":"And Isaac digged again the wells of water, which they had digged in the days of Abraham his father; for the Philistines had stopped them after the death of Abraham: and he called their names after the names by which his father had called them.","words":[["H3327","And Isaac",0,9],["H2658","digged",10,16],["H7725","again",17,22],["H0875","the wells",23,32],["H4325","of water",33,41],["H2658","which they had digged",43,64],["H3117","in the days",65,76],["H0085","of Abraham",77,87],["H0001","his father",88,98],["H6430","for the Philistines",100,119],["H5640","had stopped",120,131],["H0310","them after",132,142],["H4194","the death",143,152],["H0085","of Abraham",153,163],["H7121","and he called",165,178],["H8034","their names",179,190],["H8034","after the names",191,206],["H0834","by which",207,215],["H0001","his father",216,226],["H7121","had called",227,237]]},"26:19":{"text":"And Isaac's servants digged in the valley, and found there a well of springing water.","words":[["H3327","And Isaac's",0,11],["H5650","servants",12,20],["H2658","digged",21,27],["H5158","in the valley",28,41],["H4672","and found",43,52],["H0875","there a well",53,65],["H2416","of springing",66,78],["H4325","water",79,84]]},"26:20":{"text":"And the herdmen of Gerar did strive with Isaac's herdmen, saying, The water is ours: and he called the name of the well Esek; because they strove with him.","words":[["H7462","And the herdmen",0,15],["H1642","of Gerar",16,24],["H7378","did strive",25,35],["H3327","with Isaac's",36,48],["H7462","herdmen",49,56],["H0559","saying",58,64],["H4325","The water",66,75],["H7121","is ours: and he called",76,98],["H8034","the name",99,107],["H0875","of the well",108,119],["H6230","Esek",120,124],["H6229","because they strove",126,145]]},"26:21":{"text":"And they digged another well, and strove for that also: and he called the name of it Sitnah.","words":[["H2658","And they digged",0,15],["H0312","another",16,23],["H0875","well",24,28],["H7378","and strove",30,40],["H7121","for that also: and he called",41,69],["H8034","the name of it",70,84],["H7856","Sitnah",85,91]]},"26:22":{"text":"And he removed from thence, and digged another well; and for that they strove not: and he called the name of it Rehoboth; and he said, For now the LORD hath made room for us, and we shall be fruitful in the land.","words":[["H6275","And he removed",0,14],["H2658","from thence, and digged",15,38],["H0312","another",39,46],["H0875","well",47,51],["H7378","and for that they strove",53,77],["H7121","not: and he called",78,96],["H8034","the name of it",97,111],["H7344","Rehoboth",112,120],["H0559","and he said",122,133],["H6258","For now",135,142],["H3068","the LORD",143,151],["H7337","hath made room",152,166],["H6509","for us, and we shall be fruitful",167,199],["H0776","in the land",200,211]]},"26:23":{"text":"And he went up from thence to Beersheba.","words":[["H5927","And he went up",0,14],["H0884","from thence to Beersheba",15,39]]},"26:24":{"text":"And the LORD appeared unto him the same night, and said, I am the God of Abraham thy father: fear not, for I am with thee, and will bless thee, and multiply thy seed for my servant Abraham's sake.","words":[["H3068","And the LORD",0,12],["H7200","appeared",13,21],["H3915","unto him the same night",22,45],["H0559","and said",47,55],["H0430","I am the God",57,69],["H0085","of Abraham",70,80],["H0001","thy father",81,91],["H3372","fear",93,97],["H0854","not, for I am with",98,116],["H1288","thee, and will bless",117,137],["H7235","thee, and multiply",138,156],["H2233","thy seed",157,165],["H5650","for my servant",166,180],["H0085","Abraham's",181,190]]},"26:25":{"text":"And he builded an altar there, and called upon the name of the LORD, and pitched his tent there: and there Isaac's servants digged a well.","words":[["H1129","And he builded",0,14],["H4196","an altar",15,23],["H7121","there, and called",24,41],["H8034","upon the name",42,55],["H3068","of the LORD",56,67],["H5186","and pitched",69,80],["H0168","his tent",81,89],["H3327","there: and there Isaac's",90,114],["H5650","servants",115,123],["H3738","digged",124,130],["H0875","a well",131,137]]},"26:26":{"text":"Then Abimelech went to him from Gerar, and Ahuzzath one of his friends, and Phichol the chief captain of his army.","words":[["H0040","Then Abimelech",0,14],["H1980","went",15,19],["H1642","to him from Gerar",20,37],["H0276","and Ahuzzath",39,51],["H4828","one of his friends",52,70],["H6369","and Phichol",72,83],["H8269","the chief captain",84,101],["H6635","of his army",102,113]]},"26:27":{"text":"And Isaac said unto them, Wherefore come ye to me, seeing ye hate me, and have sent me away from you?","words":[["H3327","And Isaac",0,9],["H0559","said",10,14],["H4069","unto them, Wherefore",15,35],["H0935","come",36,40],["H8130","ye to me, seeing ye hate",41,65],["H7971","me, and have sent me away",66,91]]},"26:28":{"text":"And they said, We saw certainly that the LORD was with thee: and we said, Let there be now an oath betwixt us, even betwixt us and thee, and let us make a covenant with thee;","words":[["H0559","And they said",0,13],["H7200","We saw",15,21],["H7200","certainly",22,31],["H3068","that the LORD",32,45],["H0559","was with thee: and we said",46,72],["H0423","Let there be now an oath",74,98],["H0996","betwixt",99,106],["H0996","us, even betwixt",107,123],["H3772","us and thee, and let us make",124,152],["H1285","a covenant",153,163]]},"26:29":{"text":"That thou wilt do us no hurt, as we have not touched thee, and as we have done unto thee nothing but good, and have sent thee away in peace: thou art now the blessed of the LORD.","words":[["H6213","That thou wilt do",0,17],["H7451","us no hurt",18,28],["H5060","as we have not touched",30,52],["H6213","thee, and as we have done",53,78],["H7535","unto thee nothing but",79,100],["H2896","good",101,105],["H7971","and have sent thee away",107,130],["H7965","in peace",131,139],["H6258","thou art now",141,153],["H1288","the blessed",154,165],["H3068","of the LORD",166,177]]},"26:30":{"text":"And he made them a feast, and they did eat and drink.","words":[["H6213","And he made",0,11],["H4960","them a feast",12,24],["H0398","and they did eat",26,42],["H8354","and drink",43,52]]},"26:31":{"text":"And they rose up betimes in the morning, and sware one to another: and Isaac sent them away, and they departed from him in peace.","words":[["H7925","And they rose up betimes",0,24],["H1242","in the morning",25,39],["H7650","and sware",41,50],["H0376","one",51,54],["H0251","to another",55,65],["H3327","and Isaac",67,76],["H7971","sent them away",77,91],["H3212","and they departed",93,110],["H7965","from him in peace",111,128]]},"26:32":{"text":"And it came to pass the same day, that Isaac's servants came, and told him concerning the well which they had digged, and said unto him, We have found water.","words":[["H3117","And it came to pass the same day",0,32],["H3327","that Isaac's",34,46],["H5650","servants",47,55],["H0935","came",56,60],["H5046","and told",62,70],["H0182","him concerning",71,85],["H0875","the well",86,94],["H2658","which they had digged",95,116],["H0559","and said",118,126],["H4672","unto him, We have found",127,150],["H4325","water",151,156]]},"26:33":{"text":"And he called it Shebah: therefore the name of the city is Beersheba unto this day.","words":[["H7121","And he called",0,13],["H7656","it Shebah",14,23],["H8034","therefore the name",25,43],["H5892","of the city",44,55],["H0884","is Beersheba",56,68],["H3117","unto this day",69,82]]},"26:34":{"text":"And Esau was forty years old when he took to wife Judith the daughter of Beeri the Hittite, and Bashemath the daughter of Elon the Hittite:","words":[["H6215","And Esau",0,8],["H0705","was forty",9,18],["H8141","years",19,24],["H1121","old",25,28],["H3947","when he took",29,41],["H0802","to wife",42,49],["H3067","Judith",50,56],["H1323","the daughter",57,69],["H0882","of Beeri",70,78],["H2850","the Hittite",79,90],["H1315","and Bashemath",92,105],["H1323","the daughter",106,118],["H0356","of Elon",119,126],["H2850","the Hittite",127,138]]},"26:35":{"text":"Which were a grief of mind unto Isaac and to Rebekah.","words":[["H4786","Which were a grief",0,18],["H7307","of mind",19,26],["H3327","unto Isaac",27,37],["H7259","and to Rebekah",38,52]]},"27:1":{"text":"And it came to pass, that when Isaac was old, and his eyes were dim, so that he could not see, he called Esau his eldest son, and said unto him, My son: and he said unto him, Behold, here am I.","words":[["H1961","And it came to pass",0,19],["H3327","that when Isaac",21,36],["H2204","was old",37,44],["H5869","and his eyes",46,58],["H3543","were dim",59,67],["H7200","so that he could not see",69,93],["H7121","he called",95,104],["H6215","Esau",105,109],["H1419","his eldest",110,120],["H1121","son",121,124],["H0559","and said",126,134],["H1121","unto him, My son",135,151],["H0559","and he said",153,164]]},"27:2":{"text":"And he said, Behold now, I am old, I know not the day of my death:","words":[["H0559","And he said",0,11],["H2204","Behold now, I am old",13,33],["H3045","I know",35,41],["H3117","not the day",42,53],["H4194","of my death",54,65]]},"27:3":{"text":"Now therefore take, I pray thee, thy weapons, thy quiver and thy bow, and go out to the field, and take me some venison;","words":[["H5375","Now therefore take",0,18],["H3627","I pray thee, thy weapons",20,44],["H8522","thy quiver",46,56],["H7198","and thy bow",57,68],["H3318","and go out",70,80],["H7704","to the field",81,93],["H6679","and take",95,103],["H6718","me some venison",104,119],["H6720","me some venison",104,119]]},"27:4":{"text":"And make me savoury meat, such as I love, and bring it to me, that I may eat; that my soul may bless thee before I die.","words":[["H6213","And make",0,8],["H4303","me savoury meat",9,24],["H0834","such as",26,33],["H0157","I love",34,40],["H0935","and bring",42,51],["H0398","it to me, that I may eat",52,76],["H5315","that my soul",78,90],["H1288","may bless",91,100],["H2962","thee before",101,112],["H4191","I die",113,118]]},"27:5":{"text":"And Rebekah heard when Isaac spake to Esau his son. And Esau went to the field to hunt for venison, and to bring it.","words":[["H7259","And Rebekah",0,11],["H8085","heard",12,17],["H3327","when Isaac",18,28],["H1696","spake",29,34],["H6215","to Esau",35,42],["H1121","his son",43,50],["H6215","And Esau",52,60],["H3212","went",61,65],["H7704","to the field",66,78],["H6679","to hunt",79,86],["H6718","for venison",87,98],["H0935","and to bring",100,112]]},"27:6":{"text":"And Rebekah spake unto Jacob her son, saying, Behold, I heard thy father speak unto Esau thy brother, saying,","words":[["H7259","And Rebekah",0,11],["H0559","spake",12,17],["H3290","unto Jacob",18,28],["H1121","her son",29,36],["H0559","saying",38,44],["H8085","Behold, I heard",46,61],["H0001","thy father",62,72],["H1696","speak",73,78],["H6215","unto Esau",79,88],["H0251","thy brother",89,100],["H0559","saying",102,108]]},"27:7":{"text":"Bring me venison, and make me savoury meat, that I may eat, and bless thee before the LORD before my death.","words":[["H0935","Bring",0,5],["H6718","me venison",6,16],["H6213","and make",18,26],["H4303","me savoury meat",27,42],["H0398","that I may eat",44,58],["H1288","and bless",60,69],["H6440","thee before",70,81],["H3068","the LORD",82,90],["H6440","before",91,97],["H4194","my death",98,106]]},"27:8":{"text":"Now therefore, my son, obey my voice according to that which I command thee.","words":[["H1121","Now therefore, my son",0,21],["H8085","obey",23,27],["H6963","my voice",28,36],["H0834","according to that which",37,60],["H6680","I command",61,70]]},"27:9":{"text":"Go now to the flock, and fetch me from thence two good kids of the goats; and I will make them savoury meat for thy father, such as he loveth:","words":[["H3212","Go",0,2],["H6629","now to the flock",3,19],["H3947","and fetch",21,30],["H8147","me from thence two",31,49],["H2896","good",50,54],["H1423","kids",55,59],["H5795","of the goats",60,72],["H6213","and I will make",74,89],["H4303","them savoury meat",90,107],["H0001","for thy father",108,122],["H0157","such as he loveth",124,141]]},"27:10":{"text":"And thou shalt bring it to thy father, that he may eat, and that he may bless thee before his death.","words":[["H0935","And thou shalt bring",0,20],["H0001","it to thy father",21,37],["H0398","that he may eat",39,54],["H0834","and that",56,64],["H1288","he may bless",65,77],["H6440","thee before",78,89],["H4194","his death",90,99]]},"27:11":{"text":"And Jacob said to Rebekah his mother, Behold, Esau my brother is a hairy man, and I am a smooth man:","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H7259","to Rebekah",15,25],["H0517","his mother",26,36],["H6215","Behold, Esau",38,50],["H0251","my brother",51,61],["H8163","is a hairy",62,72],["H0376","man",73,76],["H2509","and I am a smooth",78,95],["H0376","man",96,99]]},"27:12":{"text":"My father peradventure will feel me, and I shall seem to him as a deceiver; and I shall bring a curse upon me, and not a blessing.","words":[["H0001","My father",0,9],["H4959","peradventure will feel",10,32],["H5869","me, and I shall seem",33,53],["H8591","to him as a deceiver",54,74],["H0935","and I shall bring",76,93],["H7045","a curse",94,101],["H1293","upon me, and not a blessing",102,129]]},"27:13":{"text":"And his mother said unto him, Upon me be thy curse, my son: only obey my voice, and go fetch me them.","words":[["H0517","And his mother",0,14],["H0559","said",15,19],["H7045","unto him, Upon me be thy curse",20,50],["H1121","my son",52,58],["H8085","only obey",60,69],["H6963","my voice",70,78],["H3212","and go",80,86],["H3947","fetch",87,92]]},"27:14":{"text":"And he went, and fetched, and brought them to his mother: and his mother made savoury meat, such as his father loved.","words":[["H3212","And he went",0,11],["H3947","and fetched",13,24],["H0935","and brought",26,37],["H0517","them to his mother",38,56],["H0517","and his mother",58,72],["H6213","made",73,77],["H4303","savoury meat",78,90],["H0001","such as his father",92,110],["H0157","loved",111,116]]},"27:15":{"text":"And Rebekah took goodly raiment of her eldest son Esau, which were with her in the house, and put them upon Jacob her younger son:","words":[["H7259","And Rebekah",0,11],["H3947","took",12,16],["H2532","goodly",17,23],["H0899","raiment",24,31],["H1419","of her eldest",32,45],["H1121","son",46,49],["H6215","Esau",50,54],["H1004","which were with her in the house",56,88],["H3847","and put them upon",90,107],["H3290","Jacob",108,113],["H6996","her younger",114,125],["H1121","son",126,129]]},"27:16":{"text":"And she put the skins of the kids of the goats upon his hands, and upon the smooth of his neck:","words":[["H3847","And she put",0,11],["H5785","the skins",12,21],["H1423","of the kids",22,33],["H5795","of the goats",34,46],["H3027","upon his hands",47,61],["H2513","and upon the smooth",63,82],["H6677","of his neck",83,94]]},"27:17":{"text":"And she gave the savoury meat and the bread, which she had prepared, into the hand of her son Jacob.","words":[["H5414","And she gave",0,12],["H4303","the savoury meat",13,29],["H3899","and the bread",30,43],["H6213","which she had prepared",45,67],["H3027","into the hand",69,82],["H1121","of her son",83,93],["H3290","Jacob",94,99]]},"27:18":{"text":"And he came unto his father, and said, My father: and he said, Here am I; who art thou, my son?","words":[["H0935","And he came",0,11],["H0001","unto his father",12,27],["H0559","and said",29,37],["H0001","My father",39,48],["H0559","and he said",50,61],["H1121","Here am I; who art thou, my son",63,94]]},"27:19":{"text":"And Jacob said unto his father, I am Esau thy firstborn; I have done according as thou badest me: arise, I pray thee, sit and eat of my venison, that thy soul may bless me.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H0001","unto his father",15,30],["H6215","I am Esau",32,41],["H1060","thy firstborn",42,55],["H6213","I have done",57,68],["H1696","according as thou badest",69,93],["H6965","me: arise",94,103],["H3427","I pray thee, sit",105,121],["H0398","and eat",122,129],["H6718","of my venison",130,143],["H5315","that thy soul",145,158],["H1288","may bless",159,168]]},"27:20":{"text":"And Isaac said unto his son, How is it that thou hast found it so quickly, my son? And he said, Because the LORD thy God brought it to me.","words":[["H3327","And Isaac",0,9],["H0559","said",10,14],["H1121","unto his son",15,27],["H4672","How is it that thou hast found",29,59],["H4116","it so quickly",60,73],["H1121","my son",75,81],["H0559","And he said",83,94],["H3068","Because the LORD",96,112],["H0430","thy God",113,120],["H7136","brought",121,128],["H6440","it to me",129,137]]},"27:21":{"text":"And Isaac said unto Jacob, Come near, I pray thee, that I may feel thee, my son, whether thou be my very son Esau or not.","words":[["H3327","And Isaac",0,9],["H0559","said",10,14],["H3290","unto Jacob",15,25],["H5066","Come near",27,36],["H4184","I pray thee, that I may feel",38,66],["H1121","thee, my son",67,79],["H2088","whether thou be my very",81,104],["H1121","son",105,108],["H6215","Esau",109,113]]},"27:22":{"text":"And Jacob went near unto Isaac his father; and he felt him, and said, The voice is Jacob's voice, but the hands are the hands of Esau.","words":[["H3290","And Jacob",0,9],["H5066","went near",10,19],["H3327","unto Isaac",20,30],["H0001","his father",31,41],["H4959","and he felt",43,54],["H0559","him, and said",55,68],["H6963","The voice",70,79],["H3290","is Jacob's",80,90],["H6963","voice",91,96],["H3027","but the hands",98,111],["H3027","are the hands",112,125],["H6215","of Esau",126,133]]},"27:23":{"text":"And he discerned him not, because his hands were hairy, as his brother Esau's hands: so he blessed him.","words":[["H5234","And he discerned",0,16],["H3027","him not, because his hands",17,43],["H8163","were hairy",44,54],["H0251","as his brother",56,70],["H6215","Esau's",71,77],["H3027","hands",78,83],["H1288","so he blessed",85,98]]},"27:24":{"text":"And he said, Art thou my very son Esau? And he said, I am.","words":[["H0559","And he said",0,11],["H1121","Art thou my very son",13,33],["H6215","Esau",34,38],["H0559","And he said",40,51]]},"27:25":{"text":"And he said, Bring it near to me, and I will eat of my son's venison, that my soul may bless thee. And he brought it near to him, and he did eat: and he brought him wine, and he drank.","words":[["H0559","And he said",0,11],["H5066","Bring it near",13,26],["H0398","to me, and I will eat",27,48],["H1121","of my son's",49,60],["H6718","venison",61,68],["H5315","that my soul",70,82],["H1288","may bless",83,92],["H5066","thee. And he brought it near",93,121],["H0398","to him, and he did eat",122,144],["H0935","and he brought",146,160],["H3196","him wine",161,169],["H8354","and he drank",171,183]]},"27:26":{"text":"And his father Isaac said unto him, Come near now, and kiss me, my son.","words":[["H0001","And his father",0,14],["H3327","Isaac",15,20],["H0559","said",21,25],["H5066","unto him, Come near",26,45],["H5401","now, and kiss",46,59],["H1121","me, my son",60,70]]},"27:27":{"text":"And he came near, and kissed him: and he smelled the smell of his raiment, and blessed him, and said, See, the smell of my son is as the smell of a field which the LORD hath blessed:","words":[["H5066","And he came near",0,16],["H5401","and kissed",18,28],["H7306","him: and he smelled",29,48],["H7381","the smell",49,58],["H0899","of his raiment",59,73],["H1288","and blessed",75,86],["H0559","him, and said",87,100],["H7200","See",102,105],["H7381","the smell",107,116],["H1121","of my son",117,126],["H7381","is as the smell",127,142],["H7704","of a field",143,153],["H3068","which the LORD",154,168],["H1288","hath blessed",169,181]]},"27:28":{"text":"Therefore God give thee of the dew of heaven, and the fatness of the earth, and plenty of corn and wine:","words":[["H0430","Therefore God",0,13],["H5414","give",14,18],["H2919","thee of the dew",19,34],["H8064","of heaven",35,44],["H4924","and the fatness",46,61],["H0776","of the earth",62,74],["H7230","and plenty",76,86],["H1715","of corn",87,94],["H8492","and wine",95,103]]},"27:29":{"text":"Let people serve thee, and nations bow down to thee: be lord over thy brethren, and let thy mother's sons bow down to thee: cursed be every one that curseth thee, and blessed be he that blesseth thee.","words":[["H5971","Let people",0,10],["H5647","serve",11,16],["H3816","thee, and nations",17,34],["H7812","bow down",35,43],["H1933","to thee: be",44,55],["H1376","lord",56,60],["H0251","over thy brethren",61,78],["H0517","and let thy mother's",80,100],["H1121","sons",101,105],["H7812","bow down",106,114],["H0779","to thee: cursed",115,130],["H0779","be every one that curseth",131,156],["H1288","thee, and blessed",157,174],["H1288","be he that blesseth",175,194]]},"27:30":{"text":"And it came to pass, as soon as Isaac had made an end of blessing Jacob, and Jacob was yet scarce gone out from the presence of Isaac his father, that Esau his brother came in from his hunting.","words":[["H3327","And it came to pass, as soon as Isaac",0,37],["H3615","had made an end",38,53],["H1288","of blessing",54,65],["H3290","Jacob",66,71],["H3290","and Jacob",73,82],["H0389","was yet",83,90],["H3318","scarce",91,97],["H3318","gone out",98,106],["H6440","from the presence",107,124],["H3327","of Isaac",125,133],["H0001","his father",134,144],["H6215","that Esau",146,155],["H0251","his brother",156,167],["H0935","came in",168,175],["H6718","from his hunting",176,192]]},"27:31":{"text":"And he also had made savoury meat, and brought it unto his father, and said unto his father, Let my father arise, and eat of his son's venison, that thy soul may bless me.","words":[["H6213","And he also had made",0,20],["H4303","savoury meat",21,33],["H0935","and brought it",35,49],["H0001","unto his father",50,65],["H0559","and said",67,75],["H0001","unto his father",76,91],["H0001","Let my father",93,106],["H6965","arise",107,112],["H0398","and eat",114,121],["H1121","of his son's",122,134],["H6718","venison",135,142],["H5315","that thy soul",144,157],["H1288","may bless",158,167]]},"27:32":{"text":"And Isaac his father said unto him, Who art thou? And he said, I am thy son, thy firstborn Esau.","words":[["H3327","And Isaac",0,9],["H0001","his father",10,20],["H0559","said",21,25],["H0559","unto him, Who art thou? And he said",26,61],["H1121","I am thy son",63,75],["H1060","thy firstborn",77,90],["H6215","Esau",91,95]]},"27:33":{"text":"And Isaac trembled very exceedingly, and said, Who? where is he that hath taken venison, and brought it me, and I have eaten of all before thou camest, and have blessed him? yea, and he shall be blessed.","words":[["H3327","And Isaac",0,9],["H2729","trembled",10,18],["H1419","very",19,23],["H3966","exceedingly",24,35],["H2731","exceedingly",24,35],["H0559","and said",37,45],["H0645","Who? where",47,57],["H6679","is he that hath taken",58,79],["H6718","venison",80,87],["H0935","and brought",89,100],["H0398","it me, and I have eaten",101,124],["H0935","of all before thou camest",125,150],["H1288","and have blessed",152,168],["H1288","him? yea, and he shall be blessed",169,202]]},"27:34":{"text":"And when Esau heard the words of his father, he cried with a great and exceeding bitter cry, and said unto his father, Bless me, even me also, O my father.","words":[["H6215","And when Esau",0,13],["H8085","heard",14,19],["H1697","the words",20,29],["H0001","of his father",30,43],["H6817","he cried",45,53],["H1419","with a great",54,66],["H3966","and exceeding",67,80],["H4751","bitter",81,87],["H6818","cry",88,91],["H0559","and said",93,101],["H0001","unto his father",102,117],["H1288","Bless",119,124],["H0001","me, even me also, O my father",125,154]]},"27:35":{"text":"And he said, Thy brother came with subtilty, and hath taken away thy blessing.","words":[["H0559","And he said",0,11],["H0251","Thy brother",13,24],["H0935","came",25,29],["H4820","with subtilty",30,43],["H3947","and hath taken away",45,64],["H1293","thy blessing",65,77]]},"27:36":{"text":"And he said, Is not he rightly named Jacob? for he hath supplanted me these two times: he took away my birthright; and, behold, now he hath taken away my blessing. And he said, Hast thou not reserved a blessing for me?","words":[["H0559","And he said",0,11],["H3588","Is not he rightly",13,30],["H7121","named",31,36],["H8034","named",31,36],["H3290","Jacob",37,42],["H6117","for he hath supplanted me",44,69],["H2088","these",70,75],["H6471","two times",76,85],["H3947","he took away",87,99],["H1062","my birthright",100,113],["H3947","and, behold, now he hath taken away",115,150],["H1293","my blessing",151,162],["H0559","And he said",164,175],["H0680","Hast thou not reserved",177,199],["H1293","a blessing",200,210]]},"27:37":{"text":"And Isaac answered and said unto Esau, Behold, I have made him thy lord, and all his brethren have I given to him for servants; and with corn and wine have I sustained him: and what shall I do now unto thee, my son?","words":[["H3327","And Isaac",0,9],["H6030","answered",10,18],["H0559","and said",19,27],["H6215","unto Esau",28,37],["H7760","Behold, I have made",39,58],["H1376","him thy lord",59,71],["H0251","and all his brethren",73,93],["H5414","have I given",94,106],["H5650","to him for servants",107,126],["H1715","and with corn",128,141],["H8492","and wine",142,150],["H5564","have I sustained",151,167],["H6213","him: and what shall I do",168,192],["H0645","now",193,196],["H1121","unto thee, my son",197,214]]},"27:38":{"text":"And Esau said unto his father, Hast thou but one blessing, my father? bless me, even me also, O my father. And Esau lifted up his voice, and wept.","words":[["H6215","And Esau",0,8],["H0559","said",9,13],["H0001","unto his father",14,29],["H0259","Hast thou but one",31,48],["H1293","blessing",49,57],["H0001","my father",59,68],["H1288","bless",70,75],["H0001","me, even me also, O my father",76,105],["H6215","And Esau",107,115],["H5375","lifted up",116,125],["H6963","his voice",126,135],["H1058","and wept",137,145]]},"27:39":{"text":"And Isaac his father answered and said unto him, Behold, thy dwelling shall be the fatness of the earth, and of the dew of heaven from above;","words":[["H3327","And Isaac",0,9],["H0001","his father",10,20],["H6030","answered",21,29],["H0559","and said",30,38],["H4186","unto him, Behold, thy dwelling",39,69],["H4924","shall be the fatness",70,90],["H0776","of the earth",91,103],["H2919","and of the dew",105,119],["H8064","of heaven",120,129],["H5920","from above",130,140]]},"27:40":{"text":"And by thy sword shalt thou live, and shalt serve thy brother; and it shall come to pass when thou shalt have the dominion, that thou shalt break his yoke from off thy neck.","words":[["H2719","And by thy sword",0,16],["H2421","shalt thou live",17,32],["H5647","and shalt serve",34,49],["H0251","thy brother",50,61],["H7300","and it shall come to pass when thou shalt have the dominion",63,122],["H6561","that thou shalt break",124,145],["H5923","his yoke",146,154],["H6677","from off thy neck",155,172]]},"27:41":{"text":"And Esau hated Jacob because of the blessing wherewith his father blessed him: and Esau said in his heart, The days of mourning for my father are at hand; then will I slay my brother Jacob.","words":[["H6215","And Esau",0,8],["H7852","hated",9,14],["H3290","Jacob",15,20],["H5921","because",21,28],["H1293","of the blessing",29,44],["H0834","wherewith",45,54],["H0001","his father",55,65],["H1288","blessed him",66,77],["H6215","and Esau",79,87],["H0559","said",88,92],["H3820","in his heart",93,105],["H3117","The days",107,115],["H0060","of mourning",116,127],["H0001","for my father",128,141],["H7126","are at hand",142,153],["H2026","then will I slay",155,171],["H0251","my brother",172,182],["H3290","Jacob",183,188]]},"27:42":{"text":"And these words of Esau her elder son were told to Rebekah: and she sent and called Jacob her younger son, and said unto him, Behold, thy brother Esau, as touching thee, doth comfort himself, purposing to kill thee.","words":[["H1697","And these words",0,15],["H6215","of Esau",16,23],["H1419","her elder",24,33],["H1121","son",34,37],["H5046","were told",38,47],["H7259","to Rebekah",48,58],["H7971","and she sent",60,72],["H7121","and called",73,83],["H3290","Jacob",84,89],["H6996","her younger",90,101],["H1121","son",102,105],["H0559","and said",107,115],["H0251","unto him, Behold, thy brother",116,145],["H6215","Esau",146,150],["H5162","as touching thee, doth comfort",152,182],["H2026","himself, purposing to kill",183,209]]},"27:43":{"text":"Now therefore, my son, obey my voice; and arise, flee thou to Laban my brother to Haran;","words":[["H1121","Now therefore, my son",0,21],["H8085","obey",23,27],["H6963","my voice",28,36],["H6965","and arise",38,47],["H1272","flee",49,53],["H3837","thou to Laban",54,67],["H0251","my brother",68,78],["H2771","to Haran",79,87]]},"27:44":{"text":"And tarry with him a few days, until thy brother's fury turn away;","words":[["H3427","And tarry",0,9],["H0259","with him a few",10,24],["H3117","days",25,29],["H0834","until",31,36],["H0251","thy brother's",37,50],["H2534","fury",51,55],["H7725","turn away",56,65]]},"27:45":{"text":"Until thy brother's anger turn away from thee, and he forget that which thou hast done to him: then I will send, and fetch thee from thence: why should I be deprived also of you both in one day?","words":[["H0251","Until thy brother's",0,19],["H0639","anger",20,25],["H7725","turn away",26,35],["H7911","from thee, and he forget",36,60],["H6213","that which thou hast done",61,86],["H7971","to him: then I will send",87,111],["H3947","and fetch",113,122],["H4100","thee from thence: why",123,144],["H7921","should I be deprived",145,165],["H8147","also of you both",166,182],["H0259","in one",183,189],["H3117","day",190,193]]},"27:46":{"text":"And Rebekah said to Isaac, I am weary of my life because of the daughters of Heth: if Jacob take a wife of the daughters of Heth, such as these which are of the daughters of the land, what good shall my life do me?","words":[["H7259","And Rebekah",0,11],["H0559","said",12,16],["H3327","to Isaac",17,25],["H6973","I am weary",27,37],["H2416","of my life",38,48],["H6440","because",49,56],["H1323","of the daughters",57,73],["H2845","of Heth",74,81],["H3290","if Jacob",83,91],["H3947","take",92,96],["H0802","a wife",97,103],["H1323","of the daughters",104,120],["H2845","of Heth",121,128],["H1323","such as these which are of the daughters",130,170],["H0776","of the land",171,182],["H4100","what good",184,193],["H2416","shall my life",194,207]]},"28:1":{"text":"And Isaac called Jacob, and blessed him, and charged him, and said unto him, Thou shalt not take a wife of the daughters of Canaan.","words":[["H3327","And Isaac",0,9],["H7121","called",10,16],["H3290","Jacob",17,22],["H1288","and blessed",24,35],["H6680","him, and charged",36,52],["H0559","him, and said",53,66],["H3947","unto him, Thou shalt not take",67,96],["H0802","a wife",97,103],["H1323","of the daughters",104,120],["H3667","of Canaan",121,130]]},"28:2":{"text":"Arise, go to Padanaram, to the house of Bethuel thy mother's father; and take thee a wife from thence of the daughters of Laban thy mother's brother.","words":[["H6965","Arise",0,5],["H3212","go",7,9],["H6307","to Padanaram",10,22],["H1004","to the house",24,36],["H1328","of Bethuel",37,47],["H0517","thy mother's",48,60],["H0001","father",61,67],["H3947","and take",69,77],["H0802","thee a wife",78,89],["H1323","from thence of the daughters",90,118],["H3837","of Laban",119,127],["H0517","thy mother's",128,140],["H0251","brother",141,148]]},"28:3":{"text":"And God Almighty bless thee, and make thee fruitful, and multiply thee, that thou mayest be a multitude of people;","words":[["H0410","And God",0,7],["H7706","Almighty",8,16],["H1288","bless",17,22],["H6509","thee, and make thee fruitful",23,51],["H7235","and multiply",53,65],["H6951","thee, that thou mayest be a multitude",66,103],["H5971","of people",104,113]]},"28:4":{"text":"And give thee the blessing of Abraham, to thee, and to thy seed with thee; that thou mayest inherit the land wherein thou art a stranger, which God gave unto Abraham.","words":[["H5414","And give",0,8],["H1293","thee the blessing",9,26],["H0085","of Abraham",27,37],["H2233","to thee, and to thy seed",39,63],["H3423","with thee; that thou mayest inherit",64,99],["H0776","the land",100,108],["H4033","wherein thou art a stranger",109,136],["H0430","which God",138,147],["H5414","gave",148,152],["H0085","unto Abraham",153,165]]},"28:5":{"text":"And Isaac sent away Jacob: and he went to Padanaram unto Laban, son of Bethuel the Syrian, the brother of Rebekah, Jacob's and Esau's mother.","words":[["H3327","And Isaac",0,9],["H7971","sent away",10,19],["H3290","Jacob",20,25],["H3212","and he went",27,38],["H6307","to Padanaram",39,51],["H3837","unto Laban",52,62],["H1121","son",64,67],["H1328","of Bethuel",68,78],["H0761","the Syrian",79,89],["H0251","the brother",91,102],["H7259","of Rebekah",103,113],["H3290","Jacob's",115,122],["H6215","and Esau's",123,133],["H0517","mother",134,140]]},"28:6":{"text":"When Esau saw that Isaac had blessed Jacob, and sent him away to Padanaram, to take him a wife from thence; and that as he blessed him he gave him a charge, saying, Thou shalt not take a wife of the daughters of Canaan;","words":[["H6215","When Esau",0,9],["H7200","saw",10,13],["H3327","that Isaac",14,24],["H1288","had blessed",25,36],["H3290","Jacob",37,42],["H7971","and sent him away",44,61],["H6307","to Padanaram",62,74],["H3947","to take",76,83],["H0802","him a wife",84,94],["H1288","from thence; and that as he blessed",95,130],["H6680","him he gave him a charge",131,155],["H0559","saying",157,163],["H3947","Thou shalt not take",165,184],["H0802","a wife",185,191],["H1323","of the daughters",192,208],["H3667","of Canaan",209,218]]},"28:7":{"text":"And that Jacob obeyed his father and his mother, and was gone to Padanaram;","words":[["H3290","And that Jacob",0,14],["H8085","obeyed",15,21],["H0001","his father",22,32],["H0517","and his mother",33,47],["H3212","and was gone",49,61],["H6307","to Padanaram",62,74]]},"28:8":{"text":"And Esau seeing that the daughters of Canaan pleased not Isaac his father;","words":[["H6215","And Esau",0,8],["H7200","seeing",9,15],["H1323","that the daughters",16,34],["H3667","of Canaan",35,44],["H5869","pleased",45,52],["H7451","not",53,56],["H3327","Isaac",57,62],["H0001","his father",63,73]]},"28:9":{"text":"Then went Esau unto Ishmael, and took unto the wives which he had Mahalath the daughter of Ishmael Abraham's son, the sister of Nebajoth, to be his wife.","words":[["H3212","Then went",0,9],["H6215","Esau",10,14],["H3458","unto Ishmael",15,27],["H3947","and took",29,37],["H0802","unto the wives",38,52],["H4258","which he had Mahalath",53,74],["H1323","the daughter",75,87],["H3458","of Ishmael",88,98],["H0085","Abraham's",99,108],["H1121","son",109,112],["H0269","the sister",114,124],["H5032","of Nebajoth",125,136],["H0802","to be his wife",138,152]]},"28:10":{"text":"And Jacob went out from Beersheba, and went toward Haran.","words":[["H3290","And Jacob",0,9],["H3318","went out",10,18],["H0884","from Beersheba",19,33],["H3212","and went",35,43],["H2771","toward Haran",44,56]]},"28:11":{"text":"And he lighted upon a certain place, and tarried there all night, because the sun was set; and he took of the stones of that place, and put them for his pillows, and lay down in that place to sleep.","words":[["H6293","And he lighted",0,14],["H4725","upon a certain place",15,35],["H3885","and tarried there all night",37,64],["H8121","because the sun",66,81],["H0935","was set",82,89],["H3947","and he took",91,102],["H0068","of the stones",103,116],["H4725","of that place",117,130],["H7760","and put",132,139],["H4763","them for his pillows",140,160],["H7901","and lay down",162,174],["H4725","in that place",175,188],["H7901","to sleep",189,197]]},"28:12":{"text":"And he dreamed, and behold a ladder set up on the earth, and the top of it reached to heaven: and behold the angels of God ascending and descending on it.","words":[["H2492","And he dreamed",0,14],["H5551","and behold a ladder",16,35],["H5324","set up",36,42],["H0776","on the earth",43,55],["H7218","and the top of it",57,74],["H5060","reached",75,82],["H8064","to heaven",83,92],["H4397","and behold the angels",94,115],["H0430","of God",116,122],["H5927","ascending",123,132],["H3381","and descending",133,147]]},"28:13":{"text":"And, behold, the LORD stood above it, and said, I am the LORD God of Abraham thy father, and the God of Isaac: the land whereon thou liest, to thee will I give it, and to thy seed;","words":[["H3068","And, behold, the LORD",0,21],["H5324","stood",22,27],["H0559","above it, and said",28,46],["H3068","I am the LORD",48,61],["H0430","God",62,65],["H0085","of Abraham",66,76],["H0001","thy father",77,87],["H0430","and the God",89,100],["H3327","of Isaac",101,109],["H0776","the land",111,119],["H7901","whereon thou liest",120,138],["H5414","to thee will I give it",140,162],["H2233","and to thy seed",164,179]]},"28:14":{"text":"And thy seed shall be as the dust of the earth, and thou shalt spread abroad to the west, and to the east, and to the north, and to the south: and in thee and in thy seed shall all the families of the earth be blessed.","words":[["H2233","And thy seed",0,12],["H6083","shall be as the dust",13,33],["H0776","of the earth",34,46],["H6555","and thou shalt spread abroad",48,76],["H3220","to the west",77,88],["H6924","and to the east",90,105],["H6828","and to the north",107,123],["H5045","and to the south",125,141],["H2233","and in thee and in thy seed",143,170],["H4940","shall all the families",171,193],["H0127","of the earth",194,206],["H1288","be blessed",207,217]]},"28:15":{"text":"And, behold, I am with thee, and will keep thee in all places whither thou goest, and will bring thee again into this land; for I will not leave thee, until I have done that which I have spoken to thee of.","words":[["H8104","And, behold, I am with thee, and will keep",0,42],["H0834","thee in all places whither",43,69],["H3212","thou goest",70,80],["H7725","and will bring thee again",82,107],["H0127","into this land",108,122],["H5800","for I will not leave",124,144],["H0834","thee, until",145,156],["H6213","I have done",157,168],["H1696","that which I have spoken",169,193]]},"28:16":{"text":"And Jacob awaked out of his sleep, and he said, Surely the LORD is in this place; and I knew it not.","words":[["H3290","And Jacob",0,9],["H3364","awaked",10,16],["H8142","out of his sleep",17,33],["H0559","and he said",35,46],["H0403","Surely",48,54],["H3068","the LORD",55,63],["H3426","is",64,66],["H4725","in this place",67,80],["H3045","and I knew",82,92]]},"28:17":{"text":"And he was afraid, and said, How dreadful is this place! this is none other but the house of God, and this is the gate of heaven.","words":[["H3372","And he was afraid",0,17],["H0559","and said",19,27],["H3372","How dreadful",29,41],["H4725","is this place",42,55],["H1004","this is none other but the house",57,89],["H0430","of God",90,96],["H8179","and this is the gate",98,118],["H8064","of heaven",119,128]]},"28:18":{"text":"And Jacob rose up early in the morning, and took the stone that he had put for his pillows, and set it up for a pillar, and poured oil upon the top of it.","words":[["H3290","And Jacob",0,9],["H7925","rose up early",10,23],["H1242","in the morning",24,38],["H3947","and took",40,48],["H0068","the stone",49,58],["H7760","that he had put",59,74],["H4763","for his pillows",75,90],["H7760","and set it up",92,105],["H4676","for a pillar",106,118],["H3332","and poured",120,130],["H8081","oil",131,134],["H7218","upon the top of it",135,153]]},"28:19":{"text":"And he called the name of that place Bethel: but the name of that city was called Luz at the first.","words":[["H7121","And he called",0,13],["H8034","the name",14,22],["H4725","of that place",23,36],["H1008","Bethel",37,43],["H0199","but",45,48],["H8034","the name",49,57],["H5892","of that city",58,70],["H3870","was called Luz",71,85],["H7223","at the first",86,98]]},"28:20":{"text":"And Jacob vowed a vow, saying, If God will be with me, and will keep me in this way that I go, and will give me bread to eat, and raiment to put on,","words":[["H3290","And Jacob",0,9],["H5087","vowed",10,15],["H5088","a vow",16,21],["H0559","saying",23,29],["H0430","If God",31,37],["H8104","will be with me, and will keep me",38,71],["H1870","in this way",72,83],["H1980","that I go",84,93],["H5414","and will give",95,108],["H3899","me bread",109,117],["H0398","to eat",118,124],["H0899","and raiment",126,137],["H3847","to put on",138,147]]},"28:21":{"text":"So that I come again to my father's house in peace; then shall the LORD be my God:","words":[["H7725","So that I come again",0,20],["H0001","to my father's",21,35],["H1004","house",36,41],["H7965","in peace",42,50],["H3068","then shall the LORD",52,71],["H0430","be my God",72,81]]},"28:22":{"text":"And this stone, which I have set for a pillar, shall be God's house: and of all that thou shalt give me I will surely give the tenth unto thee.","words":[["H0068","And this stone",0,14],["H7760","which I have set",16,32],["H4676","for a pillar",33,45],["H0430","shall be God's",47,61],["H1004","house",62,67],["H5414","and of all that thou shalt give",69,100],["H6237","me I will surely",101,117],["H6237","give the tenth",118,132]]},"29:1":{"text":"Then Jacob went on his journey, and came into the land of the people of the east.","words":[["H3290","Then Jacob",0,10],["H5375","went on",11,18],["H7272","his journey",19,30],["H3212","and came",32,40],["H0776","into the land",41,54],["H1121","of the people",55,68],["H6924","of the east",69,80]]},"29:2":{"text":"And he looked, and behold a well in the field, and, lo, there were three flocks of sheep lying by it; for out of that well they watered the flocks: and a great stone was upon the well's mouth.","words":[["H7200","And he looked",0,13],["H0875","and behold a well",15,32],["H7704","in the field",33,45],["H7969","and, lo, there were three",47,72],["H5739","flocks",73,79],["H6629","of sheep",80,88],["H7257","lying",89,94],["H0875","by it; for out of that well",95,122],["H8248","they watered",123,135],["H5739","the flocks",136,146],["H1419","and a great",148,159],["H0068","stone",160,165],["H0875","was upon the well's",166,185],["H6310","mouth",186,191]]},"29:3":{"text":"And thither were all the flocks gathered: and they rolled the stone from the well's mouth, and watered the sheep, and put the stone again upon the well's mouth in his place.","words":[["H5739","And thither were all the flocks",0,31],["H0622","gathered",32,40],["H1556","and they rolled",42,57],["H0068","the stone",58,67],["H0875","from the well's",68,83],["H6310","mouth",84,89],["H8248","and watered",91,102],["H6629","the sheep",103,112],["H7725","and put",114,121],["H0068","the stone",122,131],["H7725","again",132,137],["H0875","upon the well's",138,153],["H6310","mouth",154,159],["H4725","in his place",160,172]]},"29:4":{"text":"And Jacob said unto them, My brethren, whence be ye? And they said, Of Haran are we.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H0251","unto them, My brethren",15,37],["H0370","whence",39,45],["H0559","be ye? And they said",46,66],["H2771","Of Haran",68,76]]},"29:5":{"text":"And he said unto them, Know ye Laban the son of Nahor? And they said, We know him.","words":[["H0559","And he said",0,11],["H3045","unto them, Know",12,27],["H3837","ye Laban",28,36],["H1121","the son",37,44],["H5152","of Nahor",45,53],["H0559","And they said",55,68],["H3045","We know",70,77]]},"29:6":{"text":"And he said unto them, Is he well? And they said, He is well: and, behold, Rachel his daughter cometh with the sheep.","words":[["H0559","And he said",0,11],["H7965","unto them, Is he well",12,33],["H0559","And they said",35,48],["H7965","He is well",50,60],["H7354","and, behold, Rachel",62,81],["H1323","his daughter",82,94],["H0935","cometh",95,101],["H6629","with the sheep",102,116]]},"29:7":{"text":"And he said, Lo, it is yet high day, neither is it time that the cattle should be gathered together: water ye the sheep, and go and feed them.","words":[["H0559","And he said",0,11],["H2005","Lo",13,15],["H1419","it is yet high",17,31],["H3117","day",32,35],["H6256","neither is it time",37,55],["H4735","that the cattle",56,71],["H0622","should be gathered together",72,99],["H8248","water",101,106],["H6629","ye the sheep",107,119],["H3212","and go",121,127],["H7462","and feed",128,136]]},"29:8":{"text":"And they said, We cannot, until all the flocks be gathered together, and till they roll the stone from the well's mouth; then we water the sheep.","words":[["H0559","And they said",0,13],["H3201","We cannot",15,24],["H5739","until all the flocks",26,46],["H0622","be gathered together",47,67],["H1556","and till they roll",69,87],["H0068","the stone",88,97],["H0875","from the well's",98,113],["H6310","mouth",114,119],["H8248","then we water",121,134],["H6629","the sheep",135,144]]},"29:9":{"text":"And while he yet spake with them, Rachel came with her father's sheep: for she kept them.","words":[["H5750","And while he yet",0,16],["H1696","spake",17,22],["H7354","with them, Rachel",23,40],["H0935","came",41,45],["H0001","with her father's",46,63],["H6629","sheep",64,69],["H7462","for she kept them",71,88]]},"29:10":{"text":"And it came to pass, when Jacob saw Rachel the daughter of Laban his mother's brother, and the sheep of Laban his mother's brother, that Jacob went near, and rolled the stone from the well's mouth, and watered the flock of Laban his mother's brother.","words":[["H3290","And it came to pass, when Jacob",0,31],["H7200","saw",32,35],["H7354","Rachel",36,42],["H1323","the daughter",43,55],["H3837","of Laban",56,64],["H0517","his mother's",65,77],["H0251","brother",78,85],["H6629","and the sheep",87,100],["H3837","of Laban",101,109],["H0517","his mother's",110,122],["H0251","brother",123,130],["H3290","that Jacob",132,142],["H5066","went near",143,152],["H1556","and rolled",154,164],["H0068","the stone",165,174],["H0875","from the well's",175,190],["H6310","mouth",191,196],["H8248","and watered",198,209],["H6629","the flock",210,219],["H3837","of Laban",220,228],["H0517","his mother's",229,241],["H0251","brother",242,249]]},"29:11":{"text":"And Jacob kissed Rachel, and lifted up his voice, and wept.","words":[["H3290","And Jacob",0,9],["H5401","kissed",10,16],["H7354","Rachel",17,23],["H5375","and lifted up",25,38],["H6963","his voice",39,48],["H1058","and wept",50,58]]},"29:12":{"text":"And Jacob told Rachel that he was her father's brother, and that he was Rebekah's son: and she ran and told her father.","words":[["H3290","And Jacob",0,9],["H5046","told",10,14],["H7354","Rachel",15,21],["H0001","that he was her father's",22,46],["H0251","brother",47,54],["H7259","and that he was Rebekah's",56,81],["H1121","son",82,85],["H7323","and she ran",87,98],["H5046","and told",99,107],["H0001","her father",108,118]]},"29:13":{"text":"And it came to pass, when Laban heard the tidings of Jacob his sister's son, that he ran to meet him, and embraced him, and kissed him, and brought him to his house. And he told Laban all these things.","words":[["H3837","And it came to pass, when Laban",0,31],["H8085","heard",32,37],["H8088","the tidings",38,49],["H3290","of Jacob",50,58],["H0269","his sister's",59,71],["H1121","son",72,75],["H7323","that he ran",77,88],["H7125","to meet",89,96],["H2263","him, and embraced",97,114],["H5401","him, and kissed",115,130],["H0935","him, and brought",131,147],["H1004","him to his house",148,164],["H5608","And he told",166,177],["H3837","Laban",178,183],["H1697","all these things",184,200]]},"29:14":{"text":"And Laban said to him, Surely thou art my bone and my flesh. And he abode with him the space of a month.","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H0389","to him, Surely",15,29],["H6106","thou art my bone",30,46],["H1320","and my flesh",47,59],["H3427","And he abode",61,73],["H3117","with him the space",74,92],["H2320","of a month",93,103]]},"29:15":{"text":"And Laban said unto Jacob, Because thou art my brother, shouldest thou therefore serve me for nought? tell me, what shall thy wages be?","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H3290","unto Jacob",15,25],["H0251","Because thou art my brother",27,54],["H5647","shouldest thou therefore serve",56,86],["H2600","me for nought",87,100],["H5046","tell",102,106],["H4909","me, what shall thy wages",107,131]]},"29:16":{"text":"And Laban had two daughters: the name of the elder was Leah, and the name of the younger was Rachel.","words":[["H3837","And Laban",0,9],["H8147","had two",10,17],["H1323","daughters",18,27],["H8034","the name",29,37],["H1419","of the elder",38,50],["H3812","was Leah",51,59],["H8034","and the name",61,73],["H6996","of the younger",74,88],["H7354","was Rachel",89,99]]},"29:17":{"text":"Leah was tender eyed; but Rachel was beautiful and well favoured.","words":[["H3812","Leah",0,4],["H7390","was tender",5,15],["H5869","eyed",16,20],["H7354","but Rachel",22,32],["H3303","was beautiful",33,46],["H8389","was beautiful",33,46],["H3303","and well",47,55],["H4758","favoured",56,64]]},"29:18":{"text":"And Jacob loved Rachel; and said, I will serve thee seven years for Rachel thy younger daughter.","words":[["H3290","And Jacob",0,9],["H0157","loved",10,15],["H7354","Rachel",16,22],["H0559","and said",24,32],["H5647","I will serve",34,46],["H7651","thee seven",47,57],["H8141","years",58,63],["H7354","for Rachel",64,74],["H6996","thy younger",75,86],["H1323","daughter",87,95]]},"29:19":{"text":"And Laban said, It is better that I give her to thee, than that I should give her to another man: abide with me.","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H2896","It is better",16,28],["H5414","that I give",29,40],["H5414","her to thee, than that I should give",41,77],["H0312","her to another",78,92],["H0376","man",93,96],["H3427","abide",98,103]]},"29:20":{"text":"And Jacob served seven years for Rachel; and they seemed unto him but a few days, for the love he had to her.","words":[["H3290","And Jacob",0,9],["H5647","served",10,16],["H7651","seven",17,22],["H8141","years",23,28],["H7354","for Rachel",29,39],["H5869","and they seemed",41,56],["H0259","unto him but a few",57,75],["H3117","days",76,80],["H0160","for the love he had",82,101]]},"29:21":{"text":"And Jacob said unto Laban, Give me my wife, for my days are fulfilled, that I may go in unto her.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H3837","unto Laban",15,25],["H3051","Give",27,31],["H0802","me my wife",32,42],["H3117","for my days",44,55],["H4390","are fulfilled",56,69],["H0935","that I may go in",71,87]]},"29:22":{"text":"And Laban gathered together all the men of the place, and made a feast.","words":[["H3837","And Laban",0,9],["H0622","gathered together",10,27],["H0582","all the men",28,39],["H4725","of the place",40,52],["H6213","and made",54,62],["H4960","a feast",63,70]]},"29:23":{"text":"And it came to pass in the evening, that he took Leah his daughter, and brought her to him; and he went in unto her.","words":[["H6153","And it came to pass in the evening",0,34],["H3947","that he took",36,48],["H3812","Leah",49,53],["H1323","his daughter",54,66],["H0935","and brought",68,79],["H0935","her to him; and he went in",80,106]]},"29:24":{"text":"And Laban gave unto his daughter Leah Zilpah his maid for an handmaid.","words":[["H3837","And Laban",0,9],["H5414","gave",10,14],["H1323","unto his daughter",15,32],["H3812","Leah",33,37],["H2153","Zilpah",38,44],["H8198","his maid",45,53],["H8198","for an handmaid",54,69]]},"29:25":{"text":"And it came to pass, that in the morning, behold, it was Leah: and he said to Laban, What is this thou hast done unto me? did not I serve with thee for Rachel? wherefore then hast thou beguiled me?","words":[["H1242","And it came to pass, that in the morning",0,40],["H3812","behold, it was Leah",42,61],["H0559","and he said",63,74],["H3837","to Laban",75,83],["H6213","What is this thou hast done",85,112],["H5647","unto me? did not I serve",113,137],["H7354","with thee for Rachel",138,158],["H7411","wherefore then hast thou beguiled",160,193]]},"29:26":{"text":"And Laban said, It must not be so done in our country, to give the younger before the firstborn.","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H6213","It must not be so done",16,38],["H4725","in our country",39,53],["H5414","to give",55,62],["H6810","the younger",63,74],["H6440","before",75,81],["H1067","the firstborn",82,95]]},"29:27":{"text":"Fulfil her week, and we will give thee this also for the service which thou shalt serve with me yet seven other years.","words":[["H4390","Fulfil",0,6],["H2063","her",7,10],["H7620","week",11,15],["H5414","and we will give",17,33],["H5656","thee this also for the service",34,64],["H5647","which thou shalt serve",65,87],["H7651","with me yet seven",88,105],["H0312","other",106,111],["H8141","years",112,117]]},"29:28":{"text":"And Jacob did so, and fulfilled her week: and he gave him Rachel his daughter to wife also.","words":[["H3290","And Jacob",0,9],["H6213","did",10,13],["H4390","so, and fulfilled",14,31],["H7620","her week",32,40],["H5414","and he gave",42,53],["H7354","him Rachel",54,64],["H1323","his daughter",65,77],["H0802","to wife",78,85]]},"29:29":{"text":"And Laban gave to Rachel his daughter Bilhah his handmaid to be her maid.","words":[["H3837","And Laban",0,9],["H5414","gave",10,14],["H7354","to Rachel",15,24],["H1323","his daughter",25,37],["H1090","Bilhah",38,44],["H8198","his handmaid",45,57],["H8198","to be her maid",58,72]]},"29:30":{"text":"And he went in also unto Rachel, and he loved also Rachel more than Leah, and served with him yet seven other years.","words":[["H0935","And he went in",0,14],["H7354","also unto Rachel",15,31],["H0157","and he loved",33,45],["H7354","also Rachel",46,57],["H3812","more than Leah",58,72],["H5647","and served",74,84],["H7651","with him yet seven",85,103],["H0312","other",104,109],["H8141","years",110,115]]},"29:31":{"text":"And when the LORD saw that Leah was hated, he opened her womb: but Rachel was barren.","words":[["H3068","And when the LORD",0,17],["H7200","saw",18,21],["H3812","that Leah",22,31],["H8130","was hated",32,41],["H6605","he opened",43,52],["H7358","her womb",53,61],["H7354","but Rachel",63,73],["H6135","was barren",74,84]]},"29:32":{"text":"And Leah conceived, and bare a son, and she called his name Reuben: for she said, Surely the LORD hath looked upon my affliction; now therefore my husband will love me.","words":[["H3812","And Leah",0,8],["H2029","conceived",9,18],["H3205","and bare",20,28],["H1121","a son",29,34],["H7121","and she called",36,50],["H8034","his name",51,59],["H7205","Reuben",60,66],["H3588","for",68,71],["H0559","she said",72,80],["H3588","Surely",82,88],["H3068","the LORD",89,97],["H7200","hath looked",98,109],["H6040","upon my affliction",110,128],["H3588","now therefore",130,143],["H0376","my husband",144,154],["H0157","will love",155,164]]},"29:33":{"text":"And she conceived again, and bare a son; and said, Because the LORD hath heard that I was hated, he hath therefore given me this son also: and she called his name Simeon.","words":[["H2029","And she conceived",0,17],["H3205","again, and bare",18,33],["H1121","a son",34,39],["H0559","and said",41,49],["H3068","Because the LORD",51,67],["H8085","hath heard",68,78],["H8130","that I was hated",79,95],["H5414","he hath therefore given",97,120],["H7121","me this son also: and she called",121,153],["H8034","his name",154,162],["H8095","Simeon",163,169]]},"29:34":{"text":"And she conceived again, and bare a son; and said, Now this time will my husband be joined unto me, because I have born him three sons: therefore was his name called Levi.","words":[["H2029","And she conceived again",0,23],["H3205","and bare",25,33],["H1121","a son",34,39],["H0559","and said",41,49],["H6471","Now this time",51,64],["H0376","will my husband",65,80],["H3867","be joined",81,90],["H3205","unto me, because I have born",91,119],["H7969","him three",120,129],["H1121","sons",130,134],["H8034","therefore was his name",136,158],["H7121","called",159,165],["H3878","Levi",166,170]]},"29:35":{"text":"And she conceived again, and bare a son: and she said, Now will I praise the LORD: therefore she called his name Judah; and left bearing.","words":[["H2029","And she conceived",0,17],["H3205","again, and bare",18,33],["H1121","a son",34,39],["H0559","and she said",41,53],["H6471","Now",55,58],["H3034","will I praise",59,72],["H3068","the LORD",73,81],["H7121","therefore she called",83,103],["H8034","his name",104,112],["H3063","Judah",113,118],["H5975","and left",120,128],["H3205","bearing",129,136]]},"30:1":{"text":"And when Rachel saw that she bare Jacob no children, Rachel envied her sister; and said unto Jacob, Give me children, or else I die.","words":[["H7354","And when Rachel",0,15],["H7200","saw",16,19],["H3205","that she bare",20,33],["H3290","Jacob",34,39],["H7354","no children, Rachel",40,59],["H7065","envied",60,66],["H0269","her sister",67,77],["H0559","and said",79,87],["H3290","unto Jacob",88,98],["H3051","Give",100,104],["H1121","me children",105,116],["H0369","or else",118,125],["H4191","I die",126,131]]},"30:2":{"text":"And Jacob's anger was kindled against Rachel: and he said, Am I in God's stead, who hath withheld from thee the fruit of the womb?","words":[["H3290","And Jacob's",0,11],["H0639","anger",12,17],["H2734","was kindled",18,29],["H7354","against Rachel",30,44],["H0559","and he said",46,57],["H0430","Am I in God's",59,72],["H4513","stead, who hath withheld",73,97],["H6529","from thee the fruit",98,117],["H0990","of the womb",118,129]]},"30:3":{"text":"And she said, Behold my maid Bilhah, go in unto her; and she shall bear upon my knees, that I may also have children by her.","words":[["H0559","And she said",0,12],["H0519","Behold my maid",14,28],["H1090","Bilhah",29,35],["H0935","go in",37,42],["H3205","unto her; and she shall bear",43,71],["H1290","upon my knees",72,85],["H1129","that I may also have children",87,116]]},"30:4":{"text":"And she gave him Bilhah her handmaid to wife: and Jacob went in unto her.","words":[["H5414","And she gave",0,12],["H1090","him Bilhah",13,23],["H8198","her handmaid",24,36],["H0802","to wife",37,44],["H3290","and Jacob",46,55],["H0935","went in",56,63]]},"30:5":{"text":"And Bilhah conceived, and bare Jacob a son.","words":[["H1090","And Bilhah",0,10],["H2029","conceived",11,20],["H3205","and bare",22,30],["H3290","Jacob",31,36],["H1121","a son",37,42]]},"30:6":{"text":"And Rachel said, God hath judged me, and hath also heard my voice, and hath given me a son: therefore called she his name Dan.","words":[["H7354","And Rachel",0,10],["H0559","said",11,15],["H0430","God",17,20],["H1777","hath judged",21,32],["H8085","me, and hath also heard",33,56],["H6963","my voice",57,65],["H5414","and hath given",67,81],["H1121","me a son",82,90],["H7121","therefore called",92,108],["H8034","she his name",109,121],["H1835","Dan",122,125]]},"30:7":{"text":"And Bilhah Rachel's maid conceived again, and bare Jacob a second son.","words":[["H1090","And Bilhah",0,10],["H7354","Rachel's",11,19],["H8198","maid",20,24],["H2029","conceived",25,34],["H3205","again, and bare",35,50],["H3290","Jacob",51,56],["H8145","a second",57,65],["H1121","son",66,69]]},"30:8":{"text":"And Rachel said, With great wrestlings have I wrestled with my sister, and I have prevailed: and she called his name Naphtali.","words":[["H7354","And Rachel",0,10],["H0559","said",11,15],["H0430","With great",17,27],["H5319","wrestlings",28,38],["H6617","have I wrestled",39,54],["H0269","with my sister",55,69],["H3201","and I have prevailed",71,91],["H7121","and she called",93,107],["H8034","his name",108,116],["H5321","Naphtali",117,125]]},"30:9":{"text":"When Leah saw that she had left bearing, she took Zilpah her maid, and gave her Jacob to wife.","words":[["H3812","When Leah",0,9],["H7200","saw",10,13],["H5975","that she had left",14,31],["H3205","bearing",32,39],["H3947","she took",41,49],["H2153","Zilpah",50,56],["H8198","her maid",57,65],["H5414","and gave",67,75],["H3290","her Jacob",76,85],["H0802","to wife",86,93]]},"30:10":{"text":"And Zilpah Leah's maid bare Jacob a son.","words":[["H2153","And Zilpah",0,10],["H3812","Leah's",11,17],["H8198","maid",18,22],["H3205","bare",23,27],["H3290","Jacob",28,33],["H1121","a son",34,39]]},"30:11":{"text":"And Leah said, A troop cometh: and she called his name Gad.","words":[["H3812","And Leah",0,8],["H0559","said",9,13],["H1409","A troop",15,22],["H0935","cometh",23,29],["H7121","and she called",31,45],["H8034","his name",46,54],["H1410","Gad",55,58]]},"30:12":{"text":"And Zilpah Leah's maid bare Jacob a second son.","words":[["H2153","And Zilpah",0,10],["H3812","Leah's",11,17],["H8198","maid",18,22],["H3205","bare",23,27],["H3290","Jacob",28,33],["H8145","a second",34,42],["H1121","son",43,46]]},"30:13":{"text":"And Leah said, Happy am I, for the daughters will call me blessed: and she called his name Asher.","words":[["H3812","And Leah",0,8],["H0559","said",9,13],["H0837","Happy am I",15,25],["H1323","for the daughters",27,44],["H0833","will call me blessed",45,65],["H7121","and she called",67,81],["H8034","his name",82,90],["H0836","Asher",91,96]]},"30:14":{"text":"And Reuben went in the days of wheat harvest, and found mandrakes in the field, and brought them unto his mother Leah. Then Rachel said to Leah, Give me, I pray thee, of thy son's mandrakes.","words":[["H7205","And Reuben",0,10],["H3212","went in",11,18],["H3117","the days",19,27],["H2406","of wheat",28,36],["H7105","harvest",37,44],["H4672","and found",46,55],["H1736","mandrakes",56,65],["H7704","in the field",66,78],["H0935","and brought",80,91],["H0517","them unto his mother",92,112],["H3812","Leah",113,117],["H7354","Then Rachel",119,130],["H0559","said",131,135],["H3812","to Leah",136,143],["H5414","Give me",145,152],["H1121","I pray thee, of thy son's",154,179],["H1736","mandrakes",180,189]]},"30:15":{"text":"And she said unto her, Is it a small matter that thou hast taken my husband? and wouldest thou take away my son's mandrakes also? And Rachel said, Therefore he shall lie with thee to night for thy son's mandrakes.","words":[["H0559","And she said",0,12],["H4592","unto her, Is it a small matter",13,43],["H3947","that thou hast taken",44,64],["H0376","my husband",65,75],["H3947","and wouldest thou take away",77,104],["H1121","my son's",105,113],["H1736","mandrakes",114,123],["H7354","also? And Rachel",124,140],["H0559","said",141,145],["H7901","Therefore he shall lie",147,169],["H3915","with thee to night",170,188],["H8478","for",189,192],["H1121","thy son's",193,202],["H1736","mandrakes",203,212]]},"30:16":{"text":"And Jacob came out of the field in the evening, and Leah went out to meet him, and said, Thou must come in unto me; for surely I have hired thee with my son's mandrakes. And he lay with her that night.","words":[["H3290","And Jacob",0,9],["H0935","came",10,14],["H7704","out of the field",15,31],["H6153","in the evening",32,46],["H3812","and Leah",48,56],["H3318","went out",57,65],["H7125","to meet",66,73],["H0559","him, and said",74,87],["H0935","Thou must come in",89,106],["H7936","unto me; for surely",107,126],["H7936","I have hired",127,139],["H1121","thee with my son's",140,158],["H1736","mandrakes",159,168],["H7901","And he lay",170,180],["H3915","with her that night",181,200]]},"30:17":{"text":"And God hearkened unto Leah, and she conceived, and bare Jacob the fifth son.","words":[["H0430","And God",0,7],["H8085","hearkened",8,17],["H3812","unto Leah",18,27],["H2029","and she conceived",29,46],["H3205","and bare",48,56],["H3290","Jacob",57,62],["H2549","the fifth",63,72],["H1121","son",73,76]]},"30:18":{"text":"And Leah said, God hath given me my hire, because I have given my maiden to my husband: and she called his name Issachar.","words":[["H3812","And Leah",0,8],["H0559","said",9,13],["H0430","God",15,18],["H5414","hath given",19,29],["H7939","me my hire",30,40],["H0834","because",42,49],["H5414","I have given",50,62],["H8198","my maiden",63,72],["H0376","to my husband",73,86],["H7121","and she called",88,102],["H8034","his name",103,111],["H3485","Issachar",112,120]]},"30:19":{"text":"And Leah conceived again, and bare Jacob the sixth son.","words":[["H3812","And Leah",0,8],["H2029","conceived",9,18],["H3205","again, and bare",19,34],["H3290","Jacob",35,40],["H8345","the sixth",41,50],["H1121","son",51,54]]},"30:20":{"text":"And Leah said, God hath endued me with a good dowry; now will my husband dwell with me, because I have born him six sons: and she called his name Zebulun.","words":[["H3812","And Leah",0,8],["H0559","said",9,13],["H0430","God",15,18],["H2064","hath endued",19,30],["H2896","me with a good",31,45],["H2065","dowry",46,51],["H6471","now",53,56],["H0376","will my husband",57,72],["H2082","dwell",73,78],["H3205","with me, because I have born",79,107],["H8337","him six",108,115],["H1121","sons",116,120],["H7121","and she called",122,136],["H8034","his name",137,145],["H2074","Zebulun",146,153]]},"30:21":{"text":"And afterwards she bare a daughter, and called her name Dinah.","words":[["H0310","And afterwards",0,14],["H3205","she bare",15,23],["H1323","a daughter",24,34],["H7121","and called",36,46],["H8034","her name",47,55],["H1783","Dinah",56,61]]},"30:22":{"text":"And God remembered Rachel, and God hearkened to her, and opened her womb.","words":[["H0430","And God",0,7],["H2142","remembered",8,18],["H7354","Rachel",19,25],["H0430","and God",27,34],["H8085","hearkened",35,44],["H6605","to her, and opened",45,63],["H7358","her womb",64,72]]},"30:23":{"text":"And she conceived, and bare a son; and said, God hath taken away my reproach:","words":[["H2029","And she conceived",0,17],["H3205","and bare",19,27],["H1121","a son",28,33],["H0559","and said",35,43],["H0430","God",45,48],["H0622","hath taken away",49,64],["H2781","my reproach",65,76]]},"30:24":{"text":"And she called his name Joseph; and said, The LORD shall add to me another son.","words":[["H7121","And she called",0,14],["H8034","his name",15,23],["H3130","Joseph",24,30],["H0559","and said",32,40],["H3068","The LORD",42,50],["H3254","shall add",51,60],["H0312","to me another",61,74],["H1121","son",75,78]]},"30:25":{"text":"And it came to pass, when Rachel had born Joseph, that Jacob said unto Laban, Send me away, that I may go unto mine own place, and to my country.","words":[["H7354","And it came to pass, when Rachel",0,32],["H3205","had born",33,41],["H3130","Joseph",42,48],["H3290","that Jacob",50,60],["H0559","said",61,65],["H3837","unto Laban",66,76],["H7971","Send me away",78,90],["H3212","that I may go",92,105],["H4725","unto mine own place",106,125],["H0776","and to my country",127,144]]},"30:26":{"text":"Give me my wives and my children, for whom I have served thee, and let me go: for thou knowest my service which I have done thee.","words":[["H5414","Give",0,4],["H0802","me my wives",5,16],["H3206","and my children",17,32],["H2004","for",34,37],["H5647","whom I have served",38,56],["H3212","thee, and let me go",57,76],["H3045","for thou knowest",78,94],["H5656","my service",95,105],["H5647","which I have done",106,123]]},"30:27":{"text":"And Laban said unto him, I pray thee, if I have found favour in thine eyes, tarry: for I have learned by experience that the LORD hath blessed me for thy sake.","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H4672","unto him, I pray thee, if I have found",15,53],["H2580","favour",54,60],["H5869","in thine eyes",61,74],["H5172","tarry: for I have learned by experience",76,115],["H3068","that the LORD",116,129],["H1288","hath blessed",130,142],["H1558","me for thy sake",143,158]]},"30:28":{"text":"And he said, Appoint me thy wages, and I will give it.","words":[["H0559","And he said",0,11],["H5344","Appoint",13,20],["H7939","me thy wages",21,33],["H5414","and I will give",35,50]]},"30:29":{"text":"And he said unto him, Thou knowest how I have served thee, and how thy cattle was with me.","words":[["H0559","And he said",0,11],["H3045","unto him, Thou knowest",12,34],["H0834","how",35,38],["H5647","I have served",39,52],["H0834","thee, and how",53,66],["H4735","thy cattle",67,77]]},"30:30":{"text":"For it was little which thou hadst before I came, and it is now increased unto a multitude; and the LORD hath blessed thee since my coming: and now when shall I provide for mine own house also?","words":[["H4592","For it was little",0,17],["H6440","which thou hadst before I",18,43],["H6555","came, and it is now increased",44,73],["H7230","unto a multitude",74,90],["H3068","and the LORD",92,104],["H1288","hath blessed",105,117],["H7272","thee since my coming",118,138],["H4970","and now when",140,152],["H6213","shall I provide",153,168],["H1004","for mine own house",169,187]]},"30:31":{"text":"And he said, What shall I give thee? And Jacob said, Thou shalt not give me any thing: if thou wilt do this thing for me, I will again feed and keep thy flock:","words":[["H0559","And he said",0,11],["H5414","What shall I give thee",13,35],["H3290","And Jacob",37,46],["H0559","said",47,51],["H5414","Thou shalt not give",53,72],["H3972","me any thing",73,85],["H6213","if thou wilt do",87,102],["H1697","this thing",103,113],["H7725","for me, I will again",114,134],["H7462","feed",135,139],["H8104","and keep",140,148],["H6629","thy flock",149,158]]},"30:32":{"text":"I will pass through all thy flock to day, removing from thence all the speckled and spotted cattle, and all the brown cattle among the sheep, and the spotted and speckled among the goats: and of such shall be my hire.","words":[["H5674","I will pass",0,11],["H6629","through all thy flock",12,33],["H3117","to day",34,40],["H5493","removing",42,50],["H5348","from thence all the speckled",51,79],["H2921","and spotted",80,91],["H7716","cattle",92,98],["H2345","and all the brown",100,117],["H7716","cattle",118,124],["H3775","among the sheep",125,140],["H2921","and the spotted",142,157],["H5348","and speckled",158,170],["H5795","among the goats",171,186],["H7939","and of such shall be my hire",188,216]]},"30:33":{"text":"So shall my righteousness answer for me in time to come, when it shall come for my hire before thy face: every one that is not speckled and spotted among the goats, and brown among the sheep, that shall be counted stolen with me.","words":[["H6666","So shall my righteousness",0,25],["H6030","answer",26,32],["H3117","for me in time",33,47],["H4279","to come",48,55],["H0935","when it shall come",57,75],["H7939","for my hire",76,87],["H6440","before thy face",88,103],["H3605","every one",105,114],["H5348","that is not speckled",115,135],["H2921","and spotted",136,147],["H5795","among the goats",148,163],["H2345","and brown",165,174],["H3775","among the sheep",175,190],["H1589","that shall be counted stolen",192,220]]},"30:34":{"text":"And Laban said, Behold, I would it might be according to thy word.","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H3863","Behold, I would it might be",16,43],["H1697","according to thy word",44,65]]},"30:35":{"text":"And he removed that day the he goats that were ringstraked and spotted, and all the she goats that were speckled and spotted, and every one that had some white in it, and all the brown among the sheep, and gave them into the hand of his sons.","words":[["H5493","And he removed",0,14],["H3117","that day",15,23],["H8495","the he goats",24,36],["H6124","that were ringstraked",37,58],["H2921","and spotted",59,70],["H5795","and all the she goats",72,93],["H5348","that were speckled",94,112],["H2921","and spotted",113,124],["H3836","and every one that had some white",126,159],["H2345","in it, and all the brown",160,184],["H3775","among the sheep",185,200],["H5414","and gave",202,210],["H3027","them into the hand",211,229],["H1121","of his sons",230,241]]},"30:36":{"text":"And he set three days' journey betwixt himself and Jacob: and Jacob fed the rest of Laban's flocks.","words":[["H7760","And he set",0,10],["H7969","three",11,16],["H3117","days'",17,22],["H1870","journey",23,30],["H3290","betwixt himself and Jacob",31,56],["H3290","and Jacob",58,67],["H7462","fed",68,71],["H3498","the rest",72,80],["H3837","of Laban's",81,91],["H6629","flocks",92,98]]},"30:37":{"text":"And Jacob took him rods of green poplar, and of the hazel and chesnut tree; and pilled white strakes in them, and made the white appear which was in the rods.","words":[["H3290","And Jacob",0,9],["H3947","took",10,14],["H4731","him rods",15,23],["H3892","of green",24,32],["H3839","poplar",33,39],["H3869","and of the hazel",41,57],["H6196","and chesnut tree",58,74],["H6478","and pilled",76,86],["H3836","white",87,92],["H6479","strakes",93,100],["H3836","in them, and made the white",101,128],["H4286","appear",129,135],["H4731","which was in the rods",136,157]]},"30:38":{"text":"And he set the rods which he had pilled before the flocks in the gutters in the watering troughs when the flocks came to drink, that they should conceive when they came to drink.","words":[["H3322","And he set",0,10],["H4731","the rods",11,19],["H6478","which he had pilled",20,39],["H5227","before",40,46],["H6629","the flocks",47,57],["H7298","in the gutters",58,72],["H4325","in the watering",73,88],["H8268","troughs",89,96],["H6629","when the flocks",97,112],["H0935","came",113,117],["H8354","to drink",118,126],["H3179","that they should conceive",128,153],["H0935","when they came",154,168],["H8354","to drink",169,177]]},"30:39":{"text":"And the flocks conceived before the rods, and brought forth cattle ringstraked, speckled, and spotted.","words":[["H6629","And the flocks",0,14],["H3179","conceived",15,24],["H4731","before the rods",25,40],["H3205","and brought forth",42,59],["H6629","cattle",60,66],["H6124","ringstraked",67,78],["H5348","speckled",80,88],["H2921","and spotted",90,101]]},"30:40":{"text":"And Jacob did separate the lambs, and set the faces of the flocks toward the ringstraked, and all the brown in the flock of Laban; and he put his own flocks by themselves, and put them not unto Laban's cattle.","words":[["H3290","And Jacob",0,9],["H6504","did separate",10,22],["H3775","the lambs",23,32],["H5414","and set",34,41],["H6440","the faces",42,51],["H6629","of the flocks",52,65],["H0413","toward",66,72],["H6124","the ringstraked",73,88],["H2345","and all the brown",90,107],["H6629","in the flock",108,120],["H3837","of Laban",121,129],["H7896","and he put",131,141],["H5739","his own flocks",142,156],["H7896","by themselves, and put",157,179],["H3837","them not unto Laban's",180,201],["H6629","cattle",202,208]]},"30:41":{"text":"And it came to pass, whensoever the stronger cattle did conceive, that Jacob laid the rods before the eyes of the cattle in the gutters, that they might conceive among the rods.","words":[["H7194","And it came to pass, whensoever the stronger",0,44],["H6629","cattle",45,51],["H3179","did conceive",52,64],["H3290","that Jacob",66,76],["H7760","laid",77,81],["H4731","the rods",82,90],["H5869","before the eyes",91,106],["H6629","of the cattle",107,120],["H7298","in the gutters",121,135],["H3179","that they might conceive",137,161],["H4731","among the rods",162,176]]},"30:42":{"text":"But when the cattle were feeble, he put them not in: so the feebler were Laban's, and the stronger Jacob's.","words":[["H6629","But when the cattle",0,19],["H5848","were feeble",20,31],["H7760","he put them not in",33,51],["H5848","so the feebler",53,67],["H3837","were Laban's",68,80],["H7194","and the stronger",82,98],["H3290","Jacob's",99,106]]},"30:43":{"text":"And the man increased exceedingly, and had much cattle, and maidservants, and menservants, and camels, and asses.","words":[["H0376","And the man",0,11],["H6555","increased",12,21],["H3966","exceedingly",22,33],["H3966","exceedingly",22,33],["H7227","and had much",35,47],["H6629","cattle",48,54],["H8198","and maidservants",56,72],["H5650","and menservants",74,89],["H1581","and camels",91,101],["H2543","and asses",103,112]]},"31:1":{"text":"And he heard the words of Laban's sons, saying, Jacob hath taken away all that was our father's; and of that which was our father's hath he gotten all this glory.","words":[["H8085","And he heard",0,12],["H1697","the words",13,22],["H3837","of Laban's",23,33],["H1121","sons",34,38],["H0559","saying",40,46],["H3290","Jacob",48,53],["H3947","hath taken away",54,69],["H0001","all that was our father's",70,95],["H0001","and of that which was our father's",97,131],["H6213","hath he gotten",132,146],["H3519","all this glory",147,161]]},"31:2":{"text":"And Jacob beheld the countenance of Laban, and, behold, it was not toward him as before.","words":[["H3290","And Jacob",0,9],["H7200","beheld",10,16],["H6440","the countenance",17,32],["H3837","of Laban",33,41],["H8543","and, behold, it was not toward him as",43,80],["H8032","before",81,87]]},"31:3":{"text":"And the LORD said unto Jacob, Return unto the land of thy fathers, and to thy kindred; and I will be with thee.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H3290","unto Jacob",18,28],["H7725","Return",30,36],["H0776","unto the land",37,50],["H0001","of thy fathers",51,65],["H4138","and to thy kindred",67,85]]},"31:4":{"text":"And Jacob sent and called Rachel and Leah to the field unto his flock,","words":[["H3290","And Jacob",0,9],["H7971","sent",10,14],["H7121","and called",15,25],["H7354","Rachel",26,32],["H3812","and Leah",33,41],["H7704","to the field",42,54],["H6629","unto his flock",55,69]]},"31:5":{"text":"And said unto them, I see your father's countenance, that it is not toward me as before; but the God of my father hath been with me.","words":[["H0559","And said",0,8],["H7200","unto them, I see",9,25],["H0001","your father's",26,39],["H6440","countenance",40,51],["H8543","that it is not toward me as",53,80],["H8032","before",81,87],["H0430","but the God",89,100],["H0001","of my father",101,113],["H1961","hath been",114,123]]},"31:6":{"text":"And ye know that with all my power I have served your father.","words":[["H0859","And ye",0,6],["H3045","know",7,11],["H3581","that with all my power",12,34],["H5647","I have served",35,48],["H0001","your father",49,60]]},"31:7":{"text":"And your father hath deceived me, and changed my wages ten times; but God suffered him not to hurt me.","words":[["H0001","And your father",0,15],["H2048","hath deceived",16,29],["H2498","me, and changed",30,45],["H4909","my wages",46,54],["H6235","ten",55,58],["H4489","times",59,64],["H0430","but God",66,73],["H5414","suffered him",74,86],["H7489","not to hurt",87,98],["H5978","me",99,101]]},"31:8":{"text":"If he said thus, The speckled shall be thy wages; then all the cattle bare speckled: and if he said thus, The ringstraked shall be thy hire; then bare all the cattle ringstraked.","words":[["H0559","If he said",0,10],["H5348","thus, The speckled",11,29],["H7939","shall be thy wages",30,48],["H6629","then all the cattle",50,69],["H3205","bare",70,74],["H5348","speckled",75,83],["H0559","and if he said",85,99],["H6124","thus, The ringstraked",100,121],["H7939","shall be thy hire",122,139],["H3205","then bare",141,150],["H6629","all the cattle",151,165],["H6124","ringstraked",166,177]]},"31:9":{"text":"Thus God hath taken away the cattle of your father, and given them to me.","words":[["H0430","Thus God",0,8],["H5337","hath taken away",9,24],["H4735","the cattle",25,35],["H0001","of your father",36,50],["H5414","and given",52,61]]},"31:10":{"text":"And it came to pass at the time that the cattle conceived, that I lifted up mine eyes, and saw in a dream, and, behold, the rams which leaped upon the cattle were ringstraked, speckled, and grisled.","words":[["H6256","And it came to pass at the time",0,31],["H6629","that the cattle",32,47],["H3179","conceived",48,57],["H5375","that I lifted up",59,75],["H5869","mine eyes",76,85],["H7200","and saw",87,94],["H2472","in a dream",95,105],["H6260","and, behold, the rams",107,128],["H5927","which leaped",129,141],["H6629","upon the cattle",142,157],["H6124","were ringstraked",158,174],["H5348","speckled",176,184],["H1261","and grisled",186,197]]},"31:11":{"text":"And the angel of God spake unto me in a dream, saying, Jacob: And I said, Here am I.","words":[["H4397","And the angel",0,13],["H0430","of God",14,20],["H0559","spake",21,26],["H2472","unto me in a dream",27,45],["H3290","saying, Jacob",47,60],["H0559","And I said",62,72]]},"31:12":{"text":"And he said, Lift up now thine eyes, and see, all the rams which leap upon the cattle are ringstraked, speckled, and grisled: for I have seen all that Laban doeth unto thee.","words":[["H0559","And he said",0,11],["H5375","Lift up",13,20],["H5869","now thine eyes",21,35],["H7200","and see",37,44],["H6260","all the rams",46,58],["H5927","which leap",59,69],["H6629","upon the cattle",70,85],["H6124","are ringstraked",86,101],["H5348","speckled",103,111],["H1261","and grisled",113,124],["H7200","for I have seen",126,141],["H3837","all that Laban",142,156],["H6213","doeth",157,162]]},"31:13":{"text":"I am the God of Bethel, where thou anointedst the pillar, and where thou vowedst a vow unto me: now arise, get thee out from this land, and return unto the land of thy kindred.","words":[["H0410","I am the God",0,12],["H1008","of Bethel",13,22],["H4886","where thou anointedst",24,45],["H4676","the pillar",46,56],["H5087","and where thou vowedst",58,80],["H5088","a vow",81,86],["H6965","unto me: now arise",87,105],["H3318","get thee out",107,119],["H0776","from this land",120,134],["H7725","and return",136,146],["H0776","unto the land",147,160],["H4138","of thy kindred",161,175]]},"31:14":{"text":"And Rachel and Leah answered and said unto him, Is there yet any portion or inheritance for us in our father's house?","words":[["H7354","And Rachel",0,10],["H3812","and Leah",11,19],["H6030","answered",20,28],["H0559","and said",29,37],["H2506","unto him, Is there yet any portion",38,72],["H5159","or inheritance",73,87],["H0001","for us in our father's",88,110],["H1004","house",111,116]]},"31:15":{"text":"Are we not counted of him strangers? for he hath sold us, and hath quite devoured also our money.","words":[["H2803","Are we not counted",0,18],["H5237","of him strangers",19,35],["H4376","for he hath sold",37,53],["H0398","us, and hath quite",54,72],["H0398","devoured",73,81],["H3701","also our money",82,96]]},"31:16":{"text":"For all the riches which God hath taken from our father, that is ours, and our children's: now then, whatsoever God hath said unto thee, do.","words":[["H6239","For all the riches",0,18],["H0430","which God",19,28],["H5337","hath taken",29,39],["H0001","from our father",40,55],["H1121","that is ours, and our children's",57,89],["H0430","now then, whatsoever God",91,115],["H0559","hath said",116,125],["H6213","unto thee, do",126,139]]},"31:17":{"text":"Then Jacob rose up, and set his sons and his wives upon camels;","words":[["H3290","Then Jacob",0,10],["H6965","rose up",11,18],["H5375","and set",20,27],["H1121","his sons",28,36],["H0802","and his wives",37,50],["H1581","upon camels",51,62]]},"31:18":{"text":"And he carried away all his cattle, and all his goods which he had gotten, the cattle of his getting, which he had gotten in Padanaram, for to go to Isaac his father in the land of Canaan.","words":[["H5090","And he carried away",0,19],["H4735","all his cattle",20,34],["H7399","and all his goods",36,53],["H7408","which he had gotten",54,73],["H4735","the cattle",75,85],["H7075","of his getting",86,100],["H7408","which he had gotten",102,121],["H6307","in Padanaram",122,134],["H0935","for to go",136,145],["H3327","to Isaac",146,154],["H0001","his father",155,165],["H0776","in the land",166,177],["H3667","of Canaan",178,187]]},"31:19":{"text":"And Laban went to shear his sheep: and Rachel had stolen the images that were her father's.","words":[["H3837","And Laban",0,9],["H1980","went",10,14],["H1494","to shear",15,23],["H6629","his sheep",24,33],["H7354","and Rachel",35,45],["H1589","had stolen",46,56],["H8655","the images",57,67],["H0001","that were her father's",68,90]]},"31:20":{"text":"And Jacob stole away unawares to Laban the Syrian, in that he told him not that he fled.","words":[["H3290","And Jacob",0,9],["H1589","stole away",10,20],["H3820","unawares",21,29],["H3837","to Laban",30,38],["H0761","the Syrian",39,49],["H5921","in that",51,58],["H5046","he told",59,66],["H1097","him not",67,74],["H1272","that he fled",75,87]]},"31:21":{"text":"So he fled with all that he had; and he rose up, and passed over the river, and set his face toward the mount Gilead.","words":[["H1272","So he fled",0,10],["H6965","with all that he had; and he rose up",11,47],["H5674","and passed over",49,64],["H5104","the river",65,74],["H7760","and set",76,83],["H6440","his face",84,92],["H2022","toward the mount",93,109],["H1568","Gilead",110,116]]},"31:22":{"text":"And it was told Laban on the third day that Jacob was fled.","words":[["H5046","And it was told",0,15],["H3837","Laban",16,21],["H7992","on the third",22,34],["H3117","day",35,38],["H3290","that Jacob",39,49],["H1272","was fled",50,58]]},"31:23":{"text":"And he took his brethren with him, and pursued after him seven days' journey; and they overtook him in the mount Gilead.","words":[["H3947","And he took",0,11],["H0251","his brethren",12,24],["H7291","with him, and pursued",25,46],["H0310","after him",47,56],["H7651","seven",57,62],["H3117","days'",63,68],["H1870","journey",69,76],["H1692","and they overtook",78,95],["H2022","him in the mount",96,112],["H1568","Gilead",113,119]]},"31:24":{"text":"And God came to Laban the Syrian in a dream by night, and said unto him, Take heed that thou speak not to Jacob either good or bad.","words":[["H0430","And God",0,7],["H0935","came",8,12],["H3837","to Laban",13,21],["H0761","the Syrian",22,32],["H2472","in a dream",33,43],["H3915","by night",44,52],["H0559","and said",54,62],["H8104","unto him, Take heed",63,82],["H1696","that thou speak",83,98],["H5973","not to",99,105],["H3290","Jacob",106,111],["H2896","either good",112,123],["H5704","or",124,126],["H7451","bad",127,130]]},"31:25":{"text":"Then Laban overtook Jacob. Now Jacob had pitched his tent in the mount: and Laban with his brethren pitched in the mount of Gilead.","words":[["H3837","Then Laban",0,10],["H5381","overtook",11,19],["H3290","Jacob",20,25],["H3290","Now Jacob",27,36],["H8628","had pitched",37,48],["H0168","his tent",49,57],["H2022","in the mount",58,70],["H3837","and Laban",72,81],["H0251","with his brethren",82,99],["H8628","pitched",100,107],["H2022","in the mount",108,120],["H1568","of Gilead",121,130]]},"31:26":{"text":"And Laban said to Jacob, What hast thou done, that thou hast stolen away unawares to me, and carried away my daughters, as captives taken with the sword?","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H3290","to Jacob",15,23],["H6213","What hast thou done",25,44],["H1589","that thou hast stolen away",46,72],["H3824","unawares",73,81],["H5090","to me, and carried away",82,105],["H1323","my daughters",106,118],["H7617","as captives",120,131],["H2719","taken with the sword",132,152]]},"31:27":{"text":"Wherefore didst thou flee away secretly, and steal away from me; and didst not tell me, that I might have sent thee away with mirth, and with songs, with tabret, and with harp?","words":[["H1272","Wherefore didst thou flee away",0,30],["H2244","secretly",31,39],["H1589","and steal away",41,55],["H5046","from me; and didst not tell",56,83],["H7971","me, that I might have sent thee away",84,120],["H8057","with mirth",121,131],["H7892","and with songs",133,147],["H8596","with tabret",149,160],["H3658","and with harp",162,175]]},"31:28":{"text":"And hast not suffered me to kiss my sons and my daughters? thou hast now done foolishly in so doing.","words":[["H5203","And hast not suffered",0,21],["H5401","me to kiss",22,32],["H1121","my sons",33,40],["H1323","and my daughters",41,57],["H5528","thou hast now done foolishly",59,87],["H6213","in so doing",88,99]]},"31:29":{"text":"It is in the power of my hand to do you hurt: but the God of your father spake unto me yesternight, saying, Take thou heed that thou speak not to Jacob either good or bad.","words":[["H3426","It is",0,5],["H0410","in the power",6,18],["H3027","of my hand",19,29],["H6213","to do",30,35],["H7451","you hurt",36,44],["H0430","but the God",46,57],["H0001","of your father",58,72],["H0559","spake",73,78],["H0570","unto me yesternight",79,98],["H0559","saying",100,106],["H8104","Take thou heed",108,122],["H1696","that thou speak not",123,142],["H3290","to Jacob",143,151],["H2896","either good",152,163],["H7451","or bad",164,170]]},"31:30":{"text":"And now, though thou wouldest needs be gone, because thou sore longedst after thy father's house, yet wherefore hast thou stolen my gods?","words":[["H1980","And now, though thou wouldest needs",0,35],["H1980","be gone",36,43],["H3700","because thou sore",45,62],["H3700","longedst",63,71],["H0001","after thy father's",72,90],["H1004","house",91,96],["H1589","yet wherefore hast thou stolen",98,128],["H0430","my gods",129,136]]},"31:31":{"text":"And Jacob answered and said to Laban, Because I was afraid: for I said, Peradventure thou wouldest take by force thy daughters from me.","words":[["H3290","And Jacob",0,9],["H6030","answered",10,18],["H0559","and said",19,27],["H3837","to Laban",28,36],["H3372","Because I was afraid",38,58],["H0559","for I said",60,70],["H6435","Peradventure",72,84],["H1497","thou wouldest take by force",85,112],["H1323","thy daughters",113,126]]},"31:32":{"text":"With whomsoever thou findest thy gods, let him not live: before our brethren discern thou what is thine with me, and take it to thee. For Jacob knew not that Rachel had stolen them.","words":[["H0834","With whomsoever",0,15],["H4672","thou findest",16,28],["H0430","thy gods",29,37],["H2421","let him not live",39,55],["H5048","before",57,63],["H0251","our brethren",64,76],["H5234","discern",77,84],["H3947","thou what is thine with me, and take",85,121],["H3290","it to thee. For Jacob",122,143],["H3045","knew",144,148],["H7354","not that Rachel",149,164],["H1589","had stolen",165,175]]},"31:33":{"text":"And Laban went into Jacob's tent, and into Leah's tent, and into the two maidservants' tents; but he found them not. Then went he out of Leah's tent, and entered into Rachel's tent.","words":[["H3837","And Laban",0,9],["H0935","went",10,14],["H3290","into Jacob's",15,27],["H0168","tent",28,32],["H3812","and into Leah's",34,49],["H0168","tent",50,54],["H8147","and into the two",56,72],["H0519","maidservants'",73,86],["H0168","tents",87,92],["H4672","but he found",94,106],["H3318","them not. Then went he out",107,133],["H3812","of Leah's",134,143],["H0168","tent",144,148],["H0935","and entered",150,161],["H7354","into Rachel's",162,175],["H0168","tent",176,180]]},"31:34":{"text":"Now Rachel had taken the images, and put them in the camel's furniture, and sat upon them. And Laban searched all the tent, but found them not.","words":[["H7354","Now Rachel",0,10],["H3947","had taken",11,20],["H8655","the images",21,31],["H7760","and put",33,40],["H1581","them in the camel's",41,60],["H3733","furniture",61,70],["H3427","and sat",72,79],["H3837","upon them. And Laban",80,100],["H4959","searched",101,109],["H0168","all the tent",110,122],["H4672","but found",124,133]]},"31:35":{"text":"And she said to her father, Let it not displease my lord that I cannot rise up before thee; for the custom of women is upon me. And he searched, but found not the images.","words":[["H0559","And she said",0,12],["H0001","to her father",13,26],["H2734","Let it not displease",28,48],["H5869","Let it not displease",28,48],["H0113","my lord",49,56],["H3201","that I cannot",57,70],["H6965","rise up",71,78],["H6440","before thee",79,90],["H1870","for the custom",92,106],["H0802","of women",107,115],["H2664","is upon me. And he searched",116,143],["H4672","but found",145,154],["H8655","not the images",155,169]]},"31:36":{"text":"And Jacob was wroth, and chode with Laban: and Jacob answered and said to Laban, What is my trespass? what is my sin, that thou hast so hotly pursued after me?","words":[["H3290","And Jacob",0,9],["H2734","was wroth",10,19],["H7378","and chode",21,30],["H3837","with Laban",31,41],["H3290","and Jacob",43,52],["H6030","answered",53,61],["H0559","and said",62,70],["H3837","to Laban",71,79],["H6588","What is my trespass",81,100],["H2403","what is my sin",102,116],["H1814","that thou hast so hotly pursued",118,149],["H0310","after me",150,158]]},"31:37":{"text":"Whereas thou hast searched all my stuff, what hast thou found of all thy household stuff? set it here before my brethren and thy brethren, that they may judge betwixt us both.","words":[["H3588","Whereas",0,7],["H4959","thou hast searched",8,26],["H3627","all my stuff",27,39],["H4672","what hast thou found",41,61],["H1004","of all thy household",62,82],["H3627","stuff",83,88],["H7760","set",90,93],["H3541","it here",94,101],["H0251","before my brethren",102,120],["H0251","and thy brethren",121,137],["H3198","that they may judge",139,158],["H0996","betwixt",159,166],["H8147","us both",167,174]]},"31:38":{"text":"This twenty years have I been with thee; thy ewes and thy she goats have not cast their young, and the rams of thy flock have I not eaten.","words":[["H6242","This twenty",0,11],["H8141","years",12,17],["H7353","have I been with thee; thy ewes",18,49],["H5795","and thy she goats",50,67],["H7921","have not cast their young",68,93],["H0352","and the rams",95,107],["H6629","of thy flock",108,120],["H0398","have I not eaten",121,137]]},"31:39":{"text":"That which was torn of beasts I brought not unto thee; I bare the loss of it; of my hand didst thou require it, whether stolen by day, or stolen by night.","words":[["H2966","That which was torn",0,19],["H0935","of beasts I brought",20,39],["H2398","not unto thee; I bare the loss",40,70],["H3027","of it; of my hand",71,88],["H1245","didst thou require",89,107],["H1589","it, whether stolen",108,126],["H3117","by day",127,133],["H1589","or stolen",135,144],["H3915","by night",145,153]]},"31:40":{"text":"Thus I was; in the day the drought consumed me, and the frost by night; and my sleep departed from mine eyes.","words":[["H3117","Thus I was; in the day",0,22],["H2721","the drought",23,34],["H0398","consumed",35,43],["H7140","me, and the frost",44,61],["H3915","by night",62,70],["H8142","and my sleep",72,84],["H5074","departed",85,93],["H5869","from mine eyes",94,108]]},"31:41":{"text":"Thus have I been twenty years in thy house; I served thee fourteen years for thy two daughters, and six years for thy cattle: and thou hast changed my wages ten times.","words":[["H6242","Thus have I been twenty",0,23],["H8141","years",24,29],["H1004","in thy house",30,42],["H5647","I served thee",44,57],["H0702","fourteen",58,66],["H6240","fourteen",58,66],["H8141","years",67,72],["H8147","for thy two",73,84],["H1323","daughters",85,94],["H8337","and six",96,103],["H8141","years",104,109],["H6629","for thy cattle",110,124],["H2498","and thou hast changed",126,147],["H4909","my wages",148,156],["H6235","ten",157,160],["H4489","times",161,166]]},"31:42":{"text":"Except the God of my father, the God of Abraham, and the fear of Isaac, had been with me, surely thou hadst sent me away now empty. God hath seen mine affliction and the labour of my hands, and rebuked thee yesternight.","words":[["H3884","Except",0,6],["H0430","the God",7,14],["H0001","of my father",15,27],["H0430","the God",29,36],["H0085","of Abraham",37,47],["H6343","and the fear",49,61],["H3327","of Isaac",62,70],["H7971","had been with me, surely thou hadst sent me away",72,120],["H7387","now empty",121,130],["H0430","God",132,135],["H7200","hath seen",136,145],["H6040","mine affliction",146,161],["H3018","and the labour",162,176],["H3709","of my hands",177,188],["H3198","and rebuked",190,201],["H0570","thee yesternight",202,218]]},"31:43":{"text":"And Laban answered and said unto Jacob, These daughters are my daughters, and these children are my children, and these cattle are my cattle, and all that thou seest is mine: and what can I do this day unto these my daughters, or unto their children which they have born?","words":[["H3837","And Laban",0,9],["H6030","answered",10,18],["H0559","and said",19,27],["H3290","unto Jacob",28,38],["H1323","These daughters",40,55],["H1323","are my daughters",56,72],["H1121","and these children",74,92],["H1121","are my children",93,108],["H6629","and these cattle",110,126],["H6629","are my cattle",127,140],["H7200","and all that thou seest",142,165],["H6213","is mine: and what can I do",166,192],["H3117","this day",193,201],["H1323","unto these my daughters",202,225],["H0176","or",227,229],["H1121","unto their children",230,249],["H3205","which they have born",250,270]]},"31:44":{"text":"Now therefore come thou, let us make a covenant, I and thou; and let it be for a witness between me and thee.","words":[["H3212","Now therefore come thou",0,23],["H3772","let us make",25,36],["H1285","a covenant",37,47],["H5707","I and thou; and let it be for a witness",49,88]]},"31:45":{"text":"And Jacob took a stone, and set it up for a pillar.","words":[["H3290","And Jacob",0,9],["H3947","took",10,14],["H0068","a stone",15,22],["H7311","and set it up",24,37],["H4676","for a pillar",38,50]]},"31:46":{"text":"And Jacob said unto his brethren, Gather stones; and they took stones, and made an heap: and they did eat there upon the heap.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H0251","unto his brethren",15,32],["H3950","Gather",34,40],["H0068","stones",41,47],["H3947","and they took",49,62],["H0068","stones",63,69],["H6213","and made",71,79],["H1530","an heap",80,87],["H0398","and they did eat",89,105],["H1530","there upon the heap",106,125]]},"31:47":{"text":"And Laban called it Jegarsahadutha: but Jacob called it Galeed.","words":[["H3837","And Laban",0,9],["H7121","called",10,16],["H3026","it Jegarsahadutha",17,34],["H3290","but Jacob",36,45],["H7121","called",46,52],["H1567","it Galeed",53,62]]},"31:48":{"text":"And Laban said, This heap is a witness between me and thee this day. Therefore was the name of it called Galeed;","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H1530","This heap",16,25],["H5707","is a witness",26,38],["H3117","between me and thee this day",39,67],["H8034","Therefore was the name",69,91],["H7121","of it called",92,104],["H1567","Galeed",105,111]]},"31:49":{"text":"And Mizpah; for he said, The LORD watch between me and thee, when we are absent one from another.","words":[["H4709","And Mizpah",0,10],["H0834","for",12,15],["H0559","he said",16,23],["H3068","The LORD",25,33],["H6822","watch",34,39],["H5641","between me and thee, when we are absent",40,79],["H0376","one",80,83],["H7453","from another",84,96]]},"31:50":{"text":"If thou shalt afflict my daughters, or if thou shalt take other wives beside my daughters, no man is with us; see, God is witness betwixt me and thee.","words":[["H6031","If thou shalt afflict",0,21],["H1323","my daughters",22,34],["H3947","or if thou shalt take",36,57],["H0802","other wives",58,69],["H5921","beside",70,76],["H1323","my daughters",77,89],["H0376","no man",91,97],["H7200","is with us; see",98,113],["H0430","God",115,118],["H5707","is witness",119,129]]},"31:51":{"text":"And Laban said to Jacob, Behold this heap, and behold this pillar, which I have cast betwixt me and thee;","words":[["H3837","And Laban",0,9],["H0559","said",10,14],["H3290","to Jacob",15,23],["H1530","Behold this heap",25,41],["H4676","and behold this pillar",43,65],["H3384","which I have cast",67,84]]},"31:52":{"text":"This heap be witness, and this pillar be witness, that I will not pass over this heap to thee, and that thou shalt not pass over this heap and this pillar unto me, for harm.","words":[["H1530","This heap",0,9],["H5707","be witness",10,20],["H4676","and this pillar",22,37],["H5713","be witness",38,48],["H5674","that I will not pass over",50,75],["H1530","this heap",76,85],["H5674","to thee, and that thou shalt not pass over",86,128],["H1530","this heap",129,138],["H4676","and this pillar",139,154],["H7451","unto me, for harm",155,172]]},"31:53":{"text":"The God of Abraham, and the God of Nahor, the God of their father, judge betwixt us. And Jacob sware by the fear of his father Isaac.","words":[["H0430","The God",0,7],["H0085","of Abraham",8,18],["H0430","and the God",20,31],["H5152","of Nahor",32,40],["H0430","the God",42,49],["H0001","of their father",50,65],["H8199","judge",67,72],["H3290","betwixt us. And Jacob",73,94],["H7650","sware",95,100],["H6343","by the fear",101,112],["H0001","of his father",113,126],["H3327","Isaac",127,132]]},"31:54":{"text":"Then Jacob offered sacrifice upon the mount, and called his brethren to eat bread: and they did eat bread, and tarried all night in the mount.","words":[["H3290","Then Jacob",0,10],["H2076","offered",11,18],["H2077","sacrifice",19,28],["H2022","upon the mount",29,43],["H7121","and called",45,55],["H0251","his brethren",56,68],["H0398","to eat",69,75],["H3899","bread",76,81],["H0398","and they did eat",83,99],["H3899","bread",100,105],["H3885","and tarried all night",107,128],["H2022","in the mount",129,141]]},"31:55":{"text":"And early in the morning Laban rose up, and kissed his sons and his daughters, and blessed them: and Laban departed, and returned unto his place.","words":[["H7925","And early",0,9],["H1242","in the morning",10,24],["H3837","Laban",25,30],["H7925","rose up",31,38],["H5401","and kissed",40,50],["H1121","his sons",51,59],["H1323","and his daughters",60,77],["H1288","and blessed",79,90],["H3837","them: and Laban",91,106],["H3212","departed",107,115],["H7725","and returned",117,129],["H4725","unto his place",130,144]]},"32:1":{"text":"And Jacob went on his way, and the angels of God met him.","words":[["H3290","And Jacob",0,9],["H1980","went",10,14],["H1870","on his way",15,25],["H4397","and the angels",27,41],["H0430","of God",42,48],["H6293","met",49,52]]},"32:2":{"text":"And when Jacob saw them, he said, This is God's host: and he called the name of that place Mahanaim.","words":[["H3290","And when Jacob",0,14],["H7200","saw them",15,23],["H0559","he said",25,32],["H0430","This is God's",34,47],["H4264","host",48,52],["H7121","and he called",54,67],["H8034","the name",68,76],["H4725","of that place",77,90],["H4266","Mahanaim",91,99]]},"32:3":{"text":"And Jacob sent messengers before him to Esau his brother unto the land of Seir, the country of Edom.","words":[["H3290","And Jacob",0,9],["H7971","sent",10,14],["H4397","messengers",15,25],["H6440","before him",26,36],["H6215","to Esau",37,44],["H0251","his brother",45,56],["H0776","unto the land",57,70],["H8165","of Seir",71,78],["H7704","the country",80,91],["H0123","of Edom",92,99]]},"32:4":{"text":"And he commanded them, saying, Thus shall ye speak unto my lord Esau; Thy servant Jacob saith thus, I have sojourned with Laban, and stayed there until now:","words":[["H6680","And he commanded",0,16],["H0559","them, saying",17,29],["H0559","Thus shall ye speak",31,50],["H0113","unto my lord",51,63],["H6215","Esau",64,68],["H5650","Thy servant",70,81],["H3290","Jacob",82,87],["H0559","saith",88,93],["H1481","thus, I have sojourned",94,116],["H3837","with Laban",117,127],["H0309","and stayed there",129,145]]},"32:5":{"text":"And I have oxen, and asses, flocks, and menservants, and womenservants: and I have sent to tell my lord, that I may find grace in thy sight.","words":[["H7794","And I have oxen",0,15],["H2543","and asses",17,26],["H6629","flocks",28,34],["H5650","and menservants",36,51],["H8198","and womenservants",53,70],["H7971","and I have sent",72,87],["H5046","to tell",88,95],["H0113","my lord",96,103],["H4672","that I may find",105,120],["H2580","grace",121,126],["H5869","in thy sight",127,139]]},"32:6":{"text":"And the messengers returned to Jacob, saying, We came to thy brother Esau, and also he cometh to meet thee, and four hundred men with him.","words":[["H4397","And the messengers",0,18],["H7725","returned",19,27],["H3290","to Jacob",28,36],["H0559","saying",38,44],["H0935","We came",46,53],["H0251","to thy brother",54,68],["H6215","Esau",69,73],["H1980","and also he cometh",75,93],["H7125","to meet thee",94,106],["H3967","and four hundred",108,124],["H0376","men",125,128]]},"32:7":{"text":"Then Jacob was greatly afraid and distressed: and he divided the people that was with him, and the flocks, and herds, and the camels, into two bands;","words":[["H3290","Then Jacob",0,10],["H3966","was greatly",11,22],["H3372","afraid",23,29],["H3334","and distressed",30,44],["H2673","and he divided",46,60],["H5971","the people",61,71],["H6629","that was with him, and the flocks",72,105],["H1241","and herds",107,116],["H1581","and the camels",118,132],["H8147","into two",134,142],["H4264","bands",143,148]]},"32:8":{"text":"And said, If Esau come to the one company, and smite it, then the other company which is left shall escape.","words":[["H0559","And said",0,8],["H6215","If Esau",10,17],["H0935","come",18,22],["H0259","to the one",23,33],["H4264","company",34,41],["H5221","and smite it",43,55],["H4264","then the other company",57,79],["H7604","which is left",80,93],["H6413","shall escape",94,106]]},"32:9":{"text":"And Jacob said, O God of my father Abraham, and God of my father Isaac, the LORD which saidst unto me, Return unto thy country, and to thy kindred, and I will deal well with thee:","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H0430","O God",16,21],["H0001","of my father",22,34],["H0085","Abraham",35,42],["H0430","and God",44,51],["H0001","of my father",52,64],["H3327","Isaac",65,70],["H3068","the LORD",72,80],["H0559","which saidst",81,93],["H7725","unto me, Return",94,109],["H0776","unto thy country",110,126],["H4138","and to thy kindred",128,146],["H3190","and I will deal well",148,168]]},"32:10":{"text":"I am not worthy of the least of all the mercies, and of all the truth, which thou hast shewed unto thy servant; for with my staff I passed over this Jordan; and now I am become two bands.","words":[["H6994","I am not worthy of the least",0,28],["H2617","of all the mercies",29,47],["H0571","and of all the truth",49,69],["H6213","which thou hast shewed",71,93],["H5650","unto thy servant",94,110],["H4731","for with my staff",112,129],["H5674","I passed over",130,143],["H3383","this Jordan",144,155],["H8147","and now I am become two",157,180],["H4264","bands",181,186]]},"32:11":{"text":"Deliver me, I pray thee, from the hand of my brother, from the hand of Esau: for I fear him, lest he will come and smite me, and the mother with the children.","words":[["H5337","Deliver me",0,10],["H3027","I pray thee, from the hand",12,38],["H0251","of my brother",39,52],["H3027","from the hand",54,67],["H6215","of Esau",68,75],["H3373","for I fear",77,87],["H0935","him, lest he will come",88,110],["H5221","and smite me",111,123],["H0517","and the mother",125,139],["H5921","with",140,144],["H1121","the children",145,157]]},"32:12":{"text":"And thou saidst, I will surely do thee good, and make thy seed as the sand of the sea, which cannot be numbered for multitude.","words":[["H0559","And thou saidst",0,15],["H3190","I will surely",17,30],["H3190","do thee good",31,43],["H7760","and make",45,53],["H2233","thy seed",54,62],["H2344","as the sand",63,74],["H3220","of the sea",75,85],["H5608","which cannot be numbered",87,111],["H7230","for multitude",112,125]]},"32:13":{"text":"And he lodged there that same night; and took of that which came to his hand a present for Esau his brother;","words":[["H3885","And he lodged",0,13],["H3915","there that same night",14,35],["H3947","and took",37,45],["H0935","of that which came",46,64],["H3027","to his hand",65,76],["H4503","a present",77,86],["H6215","for Esau",87,95],["H0251","his brother",96,107]]},"32:14":{"text":"Two hundred she goats, and twenty he goats, two hundred ewes, and twenty rams,","words":[["H3967","Two hundred",0,11],["H5795","she goats",12,21],["H6242","and twenty",23,33],["H8495","he goats",34,42],["H3967","two hundred",44,55],["H7353","ewes",56,60],["H6242","and twenty",62,72],["H0352","rams",73,77]]},"32:15":{"text":"Thirty milch camels with their colts, forty kine, and ten bulls, twenty she asses, and ten foals.","words":[["H7970","Thirty",0,6],["H3243","milch",7,12],["H1581","camels",13,19],["H1121","with their colts",20,36],["H0705","forty",38,43],["H6510","kine",44,48],["H6235","and ten",50,57],["H6499","bulls",58,63],["H6242","twenty",65,71],["H0860","she asses",72,81],["H6235","and ten",83,90],["H5895","foals",91,96]]},"32:16":{"text":"And he delivered them into the hand of his servants, every drove by themselves; and said unto his servants, Pass over before me, and put a space betwixt drove and drove.","words":[["H5414","And he delivered",0,16],["H3027","them into the hand",17,35],["H5650","of his servants",36,51],["H5739","every drove",53,64],["H0559","by themselves; and said",65,88],["H5650","unto his servants",89,106],["H5674","Pass over",108,117],["H6440","before me",118,127],["H7760","and put",129,136],["H7305","a space",137,144],["H0996","betwixt",145,152],["H5739","drove",153,158],["H0996","and",159,162],["H5739","drove",163,168]]},"32:17":{"text":"And he commanded the foremost, saying, When Esau my brother meeteth thee, and asketh thee, saying, Whose art thou? and whither goest thou? and whose are these before thee?","words":[["H6680","And he commanded",0,16],["H7223","the foremost",17,29],["H0559","saying",31,37],["H6215","When Esau",39,48],["H0251","my brother",49,59],["H6298","meeteth thee",60,72],["H7592","and asketh thee",74,89],["H0559","saying",91,97],["H3212","Whose art thou? and whither goest",99,132],["H6440","thou? and whose are these before",133,165]]},"32:18":{"text":"Then thou shalt say, They be thy servant Jacob's; it is a present sent unto my lord Esau: and, behold, also he is behind us.","words":[["H0559","Then thou shalt say",0,19],["H5650","They be thy servant",21,40],["H3290","Jacob's",41,48],["H4503","it is a present",50,65],["H7971","sent",66,70],["H0113","unto my lord",71,83],["H6215","Esau",84,88],["H0310","and, behold, also he is behind us",90,123]]},"32:19":{"text":"And so commanded he the second, and the third, and all that followed the droves, saying, On this manner shall ye speak unto Esau, when ye find him.","words":[["H1571","And so",0,6],["H6680","commanded he",7,19],["H8145","the second",20,30],["H7992","and the third",32,45],["H1980","and all that followed",47,68],["H0310","and all that followed",47,68],["H5739","the droves",69,79],["H0559","saying",81,87],["H1697","On this manner",89,103],["H1696","shall ye speak",104,118],["H6215","unto Esau",119,128],["H4672","when ye find",130,142]]},"32:20":{"text":"And say ye moreover, Behold, thy servant Jacob is behind us. For he said, I will appease him with the present that goeth before me, and afterward I will see his face; peradventure he will accept of me.","words":[["H0559","And say ye",0,10],["H1571","moreover",11,19],["H5650","Behold, thy servant",21,40],["H3290","Jacob",41,46],["H0310","is behind us",47,59],["H0559","For he said",61,72],["H3722","I will appease",74,88],["H6440","him",89,92],["H4503","with the present",93,109],["H1980","that goeth",110,120],["H6440","before me",121,130],["H0310","and afterward",132,145],["H7200","I will see",146,156],["H6440","his face",157,165],["H5375","peradventure he will accept",167,194],["H6440","of me",195,200]]},"32:21":{"text":"So went the present over before him: and himself lodged that night in the company.","words":[["H5674","So went",0,7],["H4503","the present",8,19],["H5674","over",20,24],["H6440","before him",25,35],["H3885","and himself lodged",37,55],["H3915","that night",56,66],["H4264","in the company",67,81]]},"32:22":{"text":"And he rose up that night, and took his two wives, and his two womenservants, and his eleven sons, and passed over the ford Jabbok.","words":[["H6965","And he rose up",0,14],["H3915","that night",15,25],["H3947","and took",27,35],["H8147","his two",36,43],["H0802","wives",44,49],["H8147","and his two",51,62],["H8198","womenservants",63,76],["H6240","and his eleven",78,92],["H0259","and his eleven",78,92],["H3206","sons",93,97],["H5674","and passed over",99,114],["H4569","the ford",115,123],["H2999","Jabbok",124,130]]},"32:23":{"text":"And he took them, and sent them over the brook, and sent over that he had.","words":[["H3947","And he took them",0,16],["H5674","and sent them over",18,36],["H5158","the brook",37,46],["H5674","and sent over",48,61]]},"32:24":{"text":"And Jacob was left alone; and there wrestled a man with him until the breaking of the day.","words":[["H3290","And Jacob",0,9],["H3498","was left",10,18],["H0079","alone; and there wrestled",19,44],["H0376","a man",45,50],["H5927","with him until the breaking",51,78],["H7837","of the day",79,89]]},"32:25":{"text":"And when he saw that he prevailed not against him, he touched the hollow of his thigh; and the hollow of Jacob's thigh was out of joint, as he wrestled with him.","words":[["H7200","And when he saw",0,15],["H3201","that he prevailed",16,33],["H5060","not against him, he touched",34,61],["H3409","the hollow of his thigh",62,85],["H3709","and the hollow",87,101],["H3290","of Jacob's",102,112],["H3409","thigh",113,118],["H3363","was out of joint",119,135],["H0079","as he wrestled",137,151]]},"32:26":{"text":"And he said, Let me go, for the day breaketh. And he said, I will not let thee go, except thou bless me.","words":[["H0559","And he said",0,11],["H7971","Let me go",13,22],["H7837","for the day",24,35],["H5927","breaketh",36,44],["H0559","And he said",46,57],["H7971","I will not let thee go",59,81],["H0518","except",83,89],["H1288","thou bless",90,100]]},"32:27":{"text":"And he said unto him, What is thy name? And he said, Jacob.","words":[["H0559","And he said",0,11],["H8034","unto him, What is thy name",12,38],["H0559","And he said",40,51],["H3290","Jacob",53,58]]},"32:28":{"text":"And he said, Thy name shall be called no more Jacob, but Israel: for as a prince hast thou power with God and with men, and hast prevailed.","words":[["H0559","And he said",0,11],["H8034","Thy name",13,21],["H0559","shall be called",22,37],["H3290","no more Jacob",38,51],["H3478","but Israel",53,63],["H8280","for as a prince hast thou power",65,96],["H0430","with God",97,105],["H0582","and with men",106,118],["H3201","and hast prevailed",120,138]]},"32:29":{"text":"And Jacob asked him, and said, Tell me, I pray thee, thy name. And he said, Wherefore is it that thou dost ask after my name? And he blessed him there.","words":[["H3290","And Jacob",0,9],["H7592","asked",10,15],["H0559","him, and said",16,29],["H5046","Tell",31,35],["H8034","me, I pray thee, thy name",36,61],["H0559","And he said",63,74],["H2088","Wherefore is it",76,91],["H7592","that thou dost ask",92,110],["H8034","after my name",111,124],["H1288","And he blessed",126,140]]},"32:30":{"text":"And Jacob called the name of the place Peniel: for I have seen God face to face, and my life is preserved.","words":[["H3290","And Jacob",0,9],["H7121","called",10,16],["H8034","the name",17,25],["H4725","of the place",26,38],["H6439","Peniel",39,45],["H7200","for I have seen",47,62],["H0430","God",63,66],["H6440","face",67,71],["H6440","to face",72,79],["H5315","and my life",81,92],["H5337","is preserved",93,105]]},"32:31":{"text":"And as he passed over Penuel the sun rose upon him, and he halted upon his thigh.","words":[["H5674","And as he passed over",0,21],["H6439","Penuel",22,28],["H8121","the sun",29,36],["H2224","rose",37,41],["H6760","upon him, and he halted",42,65],["H3409","upon his thigh",66,80]]},"32:32":{"text":"Therefore the children of Israel eat not of the sinew which shrank, which is upon the hollow of the thigh, unto this day: because he touched the hollow of Jacob's thigh in the sinew that shrank.","words":[["H1121","Therefore the children",0,22],["H3478","of Israel",23,32],["H0398","eat",33,36],["H1517","not of the sinew",37,53],["H5384","which shrank",54,66],["H3709","which is upon the hollow",68,92],["H3409","of the thigh",93,105],["H3117","unto this day",107,120],["H5060","because he touched",122,140],["H3709","the hollow",141,151],["H3290","of Jacob's",152,162],["H3409","thigh",163,168],["H1517","in the sinew",169,181],["H5384","that shrank",182,193]]},"33:1":{"text":"And Jacob lifted up his eyes, and looked, and, behold, Esau came, and with him four hundred men. And he divided the children unto Leah, and unto Rachel, and unto the two handmaids.","words":[["H3290","And Jacob",0,9],["H5375","lifted up",10,19],["H5869","his eyes",20,28],["H7200","and looked",30,40],["H6215","and, behold, Esau",42,59],["H0935","came",60,64],["H0702","and with him four",66,83],["H3967","hundred",84,91],["H0376","men",92,95],["H2673","And he divided",97,111],["H3206","the children",112,124],["H3812","unto Leah",125,134],["H7354","and unto Rachel",136,151],["H8147","and unto the two",153,169],["H8198","handmaids",170,179]]},"33:2":{"text":"And he put the handmaids and their children foremost, and Leah and her children after, and Rachel and Joseph hindermost.","words":[["H7760","And he put",0,10],["H8198","the handmaids",11,24],["H3206","and their children",25,43],["H7223","foremost",44,52],["H3812","and Leah",54,62],["H3206","and her children",63,79],["H0314","after",80,85],["H7354","and Rachel",87,97],["H3130","and Joseph",98,108],["H0314","hindermost",109,119]]},"33:3":{"text":"And he passed over before them, and bowed himself to the ground seven times, until he came near to his brother.","words":[["H5674","And he passed over",0,18],["H6440","before them",19,30],["H7812","and bowed himself",32,49],["H0776","to the ground",50,63],["H7651","seven",64,69],["H6471","times",70,75],["H5066","until he came near",77,95],["H0251","to his brother",96,110]]},"33:4":{"text":"And Esau ran to meet him, and embraced him, and fell on his neck, and kissed him: and they wept.","words":[["H6215","And Esau",0,8],["H7323","ran",9,12],["H7125","to meet him",13,24],["H2263","and embraced",26,38],["H5307","him, and fell",39,52],["H6677","on his neck",53,64],["H5401","and kissed him",66,80],["H1058","and they wept",82,95]]},"33:5":{"text":"And he lifted up his eyes, and saw the women and the children; and said, Who are those with thee? And he said, The children which God hath graciously given thy servant.","words":[["H5375","And he lifted up",0,16],["H5869","his eyes",17,25],["H7200","and saw",27,34],["H0802","the women",35,44],["H3206","and the children",45,61],["H0559","and said",63,71],["H0428","Who are those",73,86],["H0559","with thee? And he said",87,109],["H3206","The children",111,123],["H0430","which God",124,133],["H2603","hath graciously given",134,155],["H5650","thy servant",156,167]]},"33:6":{"text":"Then the handmaidens came near, they and their children, and they bowed themselves.","words":[["H8198","Then the handmaidens",0,20],["H5066","came near",21,30],["H3206","they and their children",32,55],["H7812","and they bowed themselves",57,82]]},"33:7":{"text":"And Leah also with her children came near, and bowed themselves: and after came Joseph near and Rachel, and they bowed themselves.","words":[["H3812","And Leah",0,8],["H3206","also with her children",9,31],["H5066","came near",32,41],["H7812","and bowed themselves",43,63],["H0310","and after",65,74],["H5066","came",75,79],["H3130","Joseph",80,86],["H5066","near",87,91],["H7354","and Rachel",92,102],["H7812","and they bowed",104,118]]},"33:8":{"text":"And he said, What meanest thou by all this drove which I met? And he said, These are to find grace in the sight of my lord.","words":[["H0559","And he said",0,11],["H4264","What meanest thou by all this drove",13,48],["H6298","which I met",49,60],["H0559","And he said",62,73],["H4672","These are to find",75,92],["H2580","grace",93,98],["H5869","in the sight",99,111],["H0113","of my lord",112,122]]},"33:9":{"text":"And Esau said, I have enough, my brother; keep that thou hast unto thyself.","words":[["H6215","And Esau",0,8],["H0559","said",9,13],["H3426","I have",15,21],["H7227","enough",22,28],["H0251","my brother",30,40]]},"33:10":{"text":"And Jacob said, Nay, I pray thee, if now I have found grace in thy sight, then receive my present at my hand: for therefore I have seen thy face, as though I had seen the face of God, and thou wast pleased with me.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H4672","Nay, I pray thee, if now I have found",16,53],["H2580","grace",54,59],["H5869","in thy sight",60,72],["H3947","then receive",74,86],["H4503","my present",87,97],["H3027","at my hand",98,108],["H7200","for therefore I have seen",110,135],["H6440","thy face",136,144],["H7200","as though I had seen",146,166],["H6440","the face",167,175],["H0430","of God",176,182],["H7521","and thou wast pleased with me",184,213]]},"33:11":{"text":"Take, I pray thee, my blessing that is brought to thee; because God hath dealt graciously with me, and because I have enough. And he urged him, and he took it.","words":[["H3947","Take",0,4],["H1293","I pray thee, my blessing",6,30],["H0935","that is brought",31,46],["H0430","to thee; because God",47,67],["H2603","hath dealt graciously with me",68,97],["H3605","and because",99,110],["H3426","I have",111,117],["H3605","enough",118,124],["H6484","And he urged",126,138],["H3947","him, and he took",139,155]]},"33:12":{"text":"And he said, Let us take our journey, and let us go, and I will go before thee.","words":[["H0559","And he said",0,11],["H5265","Let us take our journey",13,36],["H3212","and let us go",38,51],["H3212","and I will go",53,66]]},"33:13":{"text":"And he said unto him, My lord knoweth that the children are tender, and the flocks and herds with young are with me: and if men should overdrive them one day, all the flock will die.","words":[["H0559","And he said",0,11],["H0113","unto him, My lord",12,29],["H3045","knoweth",30,37],["H3206","that the children",38,55],["H7390","are tender",56,66],["H6629","and the flocks",68,82],["H1241","and herds",83,92],["H5763","with young",93,103],["H1849","are with me: and if men should overdrive",104,144],["H0259","them one",145,153],["H3117","day",154,157],["H6629","all the flock",159,172],["H4191","will die",173,181]]},"33:14":{"text":"Let my lord, I pray thee, pass over before his servant: and I will lead on softly, according as the cattle that goeth before me and the children be able to endure, until I come unto my lord unto Seir.","words":[["H0113","Let my lord",0,11],["H5674","I pray thee, pass over",13,35],["H6440","before",36,42],["H5650","his servant",43,54],["H5095","and I will lead on",56,74],["H0328","softly",75,81],["H7272","according as",83,95],["H4399","the cattle",96,106],["H6440","that goeth before me",107,127],["H3206","and the children",128,144],["H7272","be able to endure",145,162],["H0935","until I come",164,176],["H0113","unto my lord",177,189],["H8165","unto Seir",190,199]]},"33:15":{"text":"And Esau said, Let me now leave with thee some of the folk that are with me. And he said, What needeth it? let me find grace in the sight of my lord.","words":[["H6215","And Esau",0,8],["H0559","said",9,13],["H3322","Let me now leave",15,31],["H5971","with thee some of the folk",32,58],["H0559","that are with me. And he said",59,88],["H4100","What",90,94],["H4672","needeth it? let me find",95,118],["H2580","grace",119,124],["H5869","in the sight",125,137],["H0113","of my lord",138,148]]},"33:16":{"text":"So Esau returned that day on his way unto Seir.","words":[["H6215","So Esau",0,7],["H7725","returned",8,16],["H3117","that day",17,25],["H1870","on his way",26,36],["H8165","unto Seir",37,46]]},"33:17":{"text":"And Jacob journeyed to Succoth, and built him an house, and made booths for his cattle: therefore the name of the place is called Succoth.","words":[["H3290","And Jacob",0,9],["H5265","journeyed",10,19],["H5523","to Succoth",20,30],["H1129","and built",32,41],["H1004","him an house",42,54],["H6213","and made",56,64],["H5521","booths",65,71],["H4735","for his cattle",72,86],["H8034","therefore the name",88,106],["H4725","of the place",107,119],["H7121","is called",120,129],["H5523","Succoth",130,137]]},"33:18":{"text":"And Jacob came to Shalem, a city of Shechem, which is in the land of Canaan, when he came from Padanaram; and pitched his tent before the city.","words":[["H3290","And Jacob",0,9],["H0935","came",10,14],["H8004","to Shalem",15,24],["H5892","a city",26,32],["H7927","of Shechem",33,43],["H0776","which is in the land",45,65],["H3667","of Canaan",66,75],["H0935","when he came",77,89],["H6307","from Padanaram",90,104],["H2583","and pitched his tent",106,126],["H6440","before",127,133],["H5892","the city",134,142]]},"33:19":{"text":"And he bought a parcel of a field, where he had spread his tent, at the hand of the children of Hamor, Shechem's father, for an hundred pieces of money.","words":[["H7069","And he bought",0,13],["H2513","a parcel",14,22],["H7704","of a field",23,33],["H5186","where he had spread",35,54],["H0168","his tent",55,63],["H3027","at the hand",65,76],["H1121","of the children",77,92],["H2544","of Hamor",93,101],["H7927","Shechem's",103,112],["H0001","father",113,119],["H3967","for an hundred",121,135],["H7192","pieces of money",136,151]]},"33:20":{"text":"And he erected there an altar, and called it Elelohe-Israel.","words":[["H5324","And he erected",0,14],["H4196","there an altar",15,29],["H7121","and called it",31,44],["H0415","Elelohe-Israel",45,59]]},"34:1":{"text":"And Dinah the daughter of Leah, which she bare unto Jacob, went out to see the daughters of the land.","words":[["H1783","And Dinah",0,9],["H1323","the daughter",10,22],["H3812","of Leah",23,30],["H3205","which she bare",32,46],["H3290","unto Jacob",47,57],["H3318","went out",59,67],["H7200","to see",68,74],["H1323","the daughters",75,88],["H0776","of the land",89,100]]},"34:2":{"text":"And when Shechem the son of Hamor the Hivite, prince of the country, saw her, he took her, and lay with her, and defiled her.","words":[["H7927","And when Shechem",0,16],["H1121","the son",17,24],["H2544","of Hamor",25,33],["H2340","the Hivite",34,44],["H5387","prince",46,52],["H0776","of the country",53,67],["H7200","saw",69,72],["H3947","her, he took",73,85],["H7901","her, and lay",86,98],["H6031","with her, and defiled her",99,124]]},"34:3":{"text":"And his soul clave unto Dinah the daughter of Jacob, and he loved the damsel, and spake kindly unto the damsel.","words":[["H5315","And his soul",0,12],["H1692","clave",13,18],["H1783","unto Dinah",19,29],["H1323","the daughter",30,42],["H3290","of Jacob",43,51],["H0157","and he loved",53,65],["H5291","the damsel",66,76],["H1696","and spake",78,87],["H3820","kindly",88,94],["H5291","unto the damsel",95,110]]},"34:4":{"text":"And Shechem spake unto his father Hamor, saying, Get me this damsel to wife.","words":[["H7927","And Shechem",0,11],["H0559","spake",12,17],["H0001","unto his father",18,33],["H2544","Hamor",34,39],["H0559","saying",41,47],["H3947","Get",49,52],["H3207","me this damsel",53,67],["H0802","to wife",68,75]]},"34:5":{"text":"And Jacob heard that he had defiled Dinah his daughter: now his sons were with his cattle in the field: and Jacob held his peace until they were come.","words":[["H3290","And Jacob",0,9],["H8085","heard",10,15],["H2930","that he had defiled",16,35],["H1783","Dinah",36,41],["H1323","his daughter",42,54],["H1121","now his sons",56,68],["H4735","were with his cattle",69,89],["H7704","in the field",90,102],["H3290","and Jacob",104,113],["H2790","held his peace",114,128],["H0935","until they were come",129,149]]},"34:6":{"text":"And Hamor the father of Shechem went out unto Jacob to commune with him.","words":[["H2544","And Hamor",0,9],["H0001","the father",10,20],["H7927","of Shechem",21,31],["H3318","went out",32,40],["H3290","unto Jacob",41,51],["H1696","to commune",52,62],["H0854","with",63,67]]},"34:7":{"text":"And the sons of Jacob came out of the field when they heard it: and the men were grieved, and they were very wroth, because he had wrought folly in Israel in lying with Jacob's daughter; which thing ought not to be done.","words":[["H1121","And the sons",0,12],["H3290","of Jacob",13,21],["H0935","came",22,26],["H7704","out of the field",27,43],["H8085","when they heard",44,59],["H0582","it: and the men",60,75],["H6087","were grieved",76,88],["H3966","and they were very",90,108],["H2734","wroth",109,114],["H6213","because he had wrought",116,138],["H5039","folly",139,144],["H3478","in Israel",145,154],["H7901","in lying",155,163],["H3290","with Jacob's",164,176],["H1323","daughter",177,185],["H6213","which thing ought not to be done",187,219]]},"34:8":{"text":"And Hamor communed with them, saying, The soul of my son Shechem longeth for your daughter: I pray you give her him to wife.","words":[["H2544","And Hamor",0,9],["H1696","communed",10,18],["H0559","with them, saying",19,36],["H5315","The soul",38,46],["H1121","of my son",47,56],["H7927","Shechem",57,64],["H2836","longeth",65,72],["H1323","for your daughter",73,90],["H5414","I pray you give",92,107],["H0802","her him to wife",108,123]]},"34:9":{"text":"And make ye marriages with us, and give your daughters unto us, and take our daughters unto you.","words":[["H2859","And make ye marriages",0,21],["H5414","with us, and give",22,39],["H1323","your daughters",40,54],["H3947","unto us, and take",55,72],["H1323","our daughters",73,86]]},"34:10":{"text":"And ye shall dwell with us: and the land shall be before you; dwell and trade ye therein, and get you possessions therein.","words":[["H3427","And ye shall dwell",0,18],["H0776","with us: and the land",19,40],["H1961","shall be",41,49],["H6440","before you",50,60],["H3427","dwell",62,67],["H5503","and trade",68,77],["H0270","ye therein, and get you possessions",78,113]]},"34:11":{"text":"And Shechem said unto her father and unto her brethren, Let me find grace in your eyes, and what ye shall say unto me I will give.","words":[["H7927","And Shechem",0,11],["H0559","said",12,16],["H0001","unto her father",17,32],["H0251","and unto her brethren",33,54],["H4672","Let me find",56,67],["H2580","grace",68,73],["H5869","in your eyes",74,86],["H0559","and what ye shall say",88,109],["H5414","unto me I will give",110,129]]},"34:12":{"text":"Ask me never so much dowry and gift, and I will give according as ye shall say unto me: but give me the damsel to wife.","words":[["H7235","Ask",0,3],["H3966","me never so much",4,20],["H4119","dowry",21,26],["H4976","and gift",27,35],["H5414","and I will give",37,52],["H0559","according as ye shall say",53,78],["H5414","unto me: but give",79,96],["H5291","me the damsel",97,110],["H0802","to wife",111,118]]},"34:13":{"text":"And the sons of Jacob answered Shechem and Hamor his father deceitfully, and said, because he had defiled Dinah their sister:","words":[["H1121","And the sons",0,12],["H3290","of Jacob",13,21],["H6030","answered",22,30],["H7927","Shechem",31,38],["H2544","and Hamor",39,48],["H0001","his father",49,59],["H4820","deceitfully",60,71],["H1696","and said",73,81],["H2930","because he had defiled",83,105],["H1783","Dinah",106,111],["H0269","their sister",112,124]]},"34:14":{"text":"And they said unto them, We cannot do this thing, to give our sister to one that is uncircumcised; for that were a reproach unto us:","words":[["H0559","And they said",0,13],["H3808","unto them, We cannot",14,34],["H3201","unto them, We cannot",14,34],["H6213","do",35,37],["H1697","this thing",38,48],["H5414","to give",50,57],["H0269","our sister",58,68],["H0376","to one",69,75],["H6190","that is uncircumcised",76,97],["H2781","for that were a reproach",99,123]]},"34:15":{"text":"But in this will we consent unto you: If ye will be as we be, that every male of you be circumcised;","words":[["H2063","But in this",0,11],["H0225","will we consent",12,27],["H2145","unto you: If ye will be as we be, that every male",28,77],["H4135","of you be circumcised",78,99]]},"34:16":{"text":"Then will we give our daughters unto you, and we will take your daughters to us, and we will dwell with you, and we will become one people.","words":[["H5414","Then will we give",0,17],["H1323","our daughters",18,31],["H3947","unto you, and we will take",32,58],["H1323","your daughters",59,73],["H3427","to us, and we will dwell",74,98],["H0259","with you, and we will become one",99,131],["H5971","people",132,138]]},"34:17":{"text":"But if ye will not hearken unto us, to be circumcised; then will we take our daughter, and we will be gone.","words":[["H8085","But if ye will not hearken",0,26],["H4135","unto us, to be circumcised",27,53],["H3947","then will we take",55,72],["H1323","our daughter",73,85],["H1980","and we will be gone",87,106]]},"34:18":{"text":"And their words pleased Hamor, and Shechem Hamor's son.","words":[["H1697","And their words",0,15],["H3190","pleased",16,23],["H5869","pleased",16,23],["H2544","Hamor",24,29],["H7927","and Shechem",31,42],["H2544","Hamor's",43,50],["H1121","son",51,54]]},"34:19":{"text":"And the young man deferred not to do the thing, because he had delight in Jacob's daughter: and he was more honourable than all the house of his father.","words":[["H5288","And the young man",0,17],["H0309","deferred",18,26],["H6213","not to do",27,36],["H1697","the thing",37,46],["H2654","because he had delight",48,70],["H3290","in Jacob's",71,81],["H1323","daughter",82,90],["H3513","and he was more honourable",92,118],["H1004","than all the house",119,137],["H0001","of his father",138,151]]},"34:20":{"text":"And Hamor and Shechem his son came unto the gate of their city, and communed with the men of their city, saying,","words":[["H2544","And Hamor",0,9],["H7927","and Shechem",10,21],["H1121","his son",22,29],["H0935","came",30,34],["H8179","unto the gate",35,48],["H5892","of their city",49,62],["H1696","and communed",64,76],["H0582","with the men",77,89],["H5892","of their city",90,103],["H0559","saying",105,111]]},"34:21":{"text":"These men are peaceable with us; therefore let them dwell in the land, and trade therein; for the land, behold, it is large enough for them; let us take their daughters to us for wives, and let us give them our daughters.","words":[["H0582","These men",0,9],["H8003","are peaceable",10,23],["H0854","with",24,28],["H3427","us; therefore let them dwell",29,57],["H0776","in the land",58,69],["H5503","and trade",71,80],["H0776","therein; for the land",81,102],["H7342","behold, it is large",104,123],["H3027","enough",124,130],["H6440","for them",131,139],["H3947","let us take",141,152],["H1323","their daughters",153,168],["H0802","to us for wives",169,184],["H5414","and let us give",186,201],["H1323","them our daughters",202,220]]},"34:22":{"text":"Only herein will the men consent unto us for to dwell with us, to be one people, if every male among us be circumcised, as they are circumcised.","words":[["H2063","Only herein",0,11],["H0582","will the men",12,24],["H0225","consent",25,32],["H3427","unto us for to dwell",33,53],["H0259","with us, to be one",54,72],["H5971","people",73,79],["H2145","if every male",81,94],["H4135","among us be circumcised",95,118],["H4135","as they are circumcised",120,143]]},"34:23":{"text":"Shall not their cattle and their substance and every beast of theirs be ours? only let us consent unto them, and they will dwell with us.","words":[["H4735","Shall not their cattle",0,22],["H7075","and their substance",23,42],["H0929","and every beast",43,58],["H0225","of theirs be ours? only let us consent",59,97],["H3427","unto them, and they will dwell",98,128]]},"34:24":{"text":"And unto Hamor and unto Shechem his son hearkened all that went out of the gate of his city; and every male was circumcised, all that went out of the gate of his city.","words":[["H2544","And unto Hamor",0,14],["H7927","and unto Shechem",15,31],["H1121","his son",32,39],["H8085","hearkened",40,49],["H3318","all that went out",50,67],["H8179","of the gate",68,79],["H5892","of his city",80,91],["H2145","and every male",93,107],["H4135","was circumcised",108,123],["H3318","all that went out",125,142],["H8179","of the gate",143,154],["H5892","of his city",155,166]]},"34:25":{"text":"And it came to pass on the third day, when they were sore, that two of the sons of Jacob, Simeon and Levi, Dinah's brethren, took each man his sword, and came upon the city boldly, and slew all the males.","words":[["H7992","And it came to pass on the third",0,32],["H3117","day",33,36],["H3510","when they were sore",38,57],["H8147","that two",59,67],["H1121","of the sons",68,79],["H3290","of Jacob",80,88],["H8095","Simeon",90,96],["H3878","and Levi",97,105],["H1783","Dinah's",107,114],["H0251","brethren",115,123],["H3947","took",125,129],["H0376","each man",130,138],["H2719","his sword",139,148],["H0935","and came",150,158],["H5892","upon the city",159,172],["H0983","boldly",173,179],["H2026","and slew",181,189],["H2145","all the males",190,203]]},"34:26":{"text":"And they slew Hamor and Shechem his son with the edge of the sword, and took Dinah out of Shechem's house, and went out.","words":[["H2026","And they slew",0,13],["H2544","Hamor",14,19],["H7927","and Shechem",20,31],["H1121","his son",32,39],["H6310","with the edge",40,53],["H2719","of the sword",54,66],["H3947","and took",68,76],["H1783","Dinah",77,82],["H3947","out",83,86],["H7927","of Shechem's",87,99],["H1004","house",100,105],["H3318","and went out",107,119]]},"34:27":{"text":"The sons of Jacob came upon the slain, and spoiled the city, because they had defiled their sister.","words":[["H1121","The sons",0,8],["H3290","of Jacob",9,17],["H0935","came",18,22],["H2491","upon the slain",23,37],["H0962","and spoiled",39,50],["H5892","the city",51,59],["H2930","because they had defiled",61,85],["H0269","their sister",86,98]]},"34:28":{"text":"They took their sheep, and their oxen, and their asses, and that which was in the city, and that which was in the field,","words":[["H3947","They took",0,9],["H6629","their sheep",10,21],["H1241","and their oxen",23,37],["H2543","and their asses",39,54],["H5892","and that which was in the city",56,86],["H7704","and that which was in the field",88,119]]},"34:29":{"text":"And all their wealth, and all their little ones, and their wives took they captive, and spoiled even all that was in the house.","words":[["H2428","And all their wealth",0,20],["H2945","and all their little ones",22,47],["H0802","and their wives",49,64],["H7617","took they captive",65,82],["H0962","and spoiled",84,95],["H1004","even all that was in the house",96,126]]},"34:30":{"text":"And Jacob said to Simeon and Levi, Ye have troubled me to make me to stink among the inhabitants of the land, among the Canaanites and the Perizzites: and I being few in number, they shall gather themselves together against me, and slay me; and I shall be destroyed, I and my house.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H8095","to Simeon",15,24],["H3878","and Levi",25,33],["H5916","Ye have troubled",35,51],["H0887","me to make me to stink",52,74],["H3427","among the inhabitants",75,96],["H0776","of the land",97,108],["H3669","among the Canaanites",110,130],["H6522","and the Perizzites",131,149],["H4962","and I being few",151,166],["H4557","in number",167,176],["H0622","they shall gather themselves together",178,215],["H5221","against me, and slay me",216,239],["H8045","and I shall be destroyed",241,265],["H1004","I and my house",267,281]]},"34:31":{"text":"And they said, Should he deal with our sister as with an harlot?","words":[["H0559","And they said",0,13],["H6213","Should he deal",15,29],["H0269","with our sister",30,45],["H2181","as with an harlot",46,63]]},"35:1":{"text":"And God said unto Jacob, Arise, go up to Bethel, and dwell there: and make there an altar unto God, that appeared unto thee when thou fleddest from the face of Esau thy brother.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H3290","unto Jacob",13,23],["H6965","Arise",25,30],["H5927","go up",32,37],["H1008","to Bethel",38,47],["H3427","and dwell",49,58],["H6213","there: and make",59,74],["H4196","there an altar",75,89],["H0410","unto God",90,98],["H7200","that appeared",100,113],["H1272","unto thee when thou fleddest",114,142],["H6440","from the face",143,156],["H6215","of Esau",157,164],["H0251","thy brother",165,176]]},"35:2":{"text":"Then Jacob said unto his household, and to all that were with him, Put away the strange gods that are among you, and be clean, and change your garments:","words":[["H3290","Then Jacob",0,10],["H0559","said",11,15],["H1004","unto his household",16,34],["H5493","and to all that were with him, Put away",36,75],["H5236","the strange",76,87],["H0430","gods",88,92],["H8432","that are among you",93,111],["H2891","and be clean",113,125],["H2498","and change",127,137],["H8071","your garments",138,151]]},"35:3":{"text":"And let us arise, and go up to Bethel; and I will make there an altar unto God, who answered me in the day of my distress, and was with me in the way which I went.","words":[["H6965","And let us arise",0,16],["H5927","and go up",18,27],["H1008","to Bethel",28,37],["H6213","and I will make",39,54],["H4196","there an altar",55,69],["H0410","unto God",70,78],["H6030","who answered",80,92],["H3117","me in the day",93,106],["H6869","of my distress",107,121],["H1870","and was with me in the way",123,149],["H1980","which I went",150,162]]},"35:4":{"text":"And they gave unto Jacob all the strange gods which were in their hand, and all their earrings which were in their ears; and Jacob hid them under the oak which was by Shechem.","words":[["H5414","And they gave",0,13],["H3290","unto Jacob",14,24],["H5236","all the strange",25,40],["H0430","gods",41,45],["H3027","which were in their hand",46,70],["H5141","and all their earrings",72,94],["H0241","which were in their ears",95,119],["H3290","and Jacob",121,130],["H2934","hid",131,134],["H0424","them under the oak",135,153],["H7927","which was by Shechem",154,174]]},"35:5":{"text":"And they journeyed: and the terror of God was upon the cities that were round about them, and they did not pursue after the sons of Jacob.","words":[["H5265","And they journeyed",0,18],["H2847","and the terror",20,34],["H0430","of God",35,41],["H5892","was upon the cities",42,61],["H5439","that were round about",62,83],["H7291","them, and they did not pursue",84,113],["H0310","after",114,119],["H1121","the sons",120,128],["H3290","of Jacob",129,137]]},"35:6":{"text":"So Jacob came to Luz, which is in the land of Canaan, that is, Bethel, he and all the people that were with him.","words":[["H3290","So Jacob",0,8],["H0935","came",9,13],["H3870","to Luz",14,20],["H0776","which is in the land",22,42],["H3667","of Canaan",43,52],["H1008","that is, Bethel",54,69],["H5971","he and all the people",71,92]]},"35:7":{"text":"And he built there an altar, and called the place Elbethel: because there God appeared unto him, when he fled from the face of his brother.","words":[["H1129","And he built",0,12],["H4196","there an altar",13,27],["H7121","and called",29,39],["H4725","the place",40,49],["H0416","Elbethel",50,58],["H0430","because there God",60,77],["H1540","appeared",78,86],["H1272","unto him, when he fled",87,109],["H6440","from the face",110,123],["H0251","of his brother",124,138]]},"35:8":{"text":"But Deborah Rebekah's nurse died, and she was buried beneath Bethel under an oak: and the name of it was called Allonbachuth.","words":[["H1683","But Deborah",0,11],["H7259","Rebekah's",12,21],["H3243","nurse",22,27],["H4191","died",28,32],["H6912","and she was buried",34,52],["H1008","beneath Bethel",53,67],["H0437","under an oak",68,80],["H8034","and the name",82,94],["H7121","of it was called",95,111],["H0439","Allonbachuth",112,124]]},"35:9":{"text":"And God appeared unto Jacob again, when he came out of Padanaram, and blessed him.","words":[["H0430","And God",0,7],["H7200","appeared",8,16],["H3290","unto Jacob",17,27],["H0935","again, when he came",28,47],["H6307","out of Padanaram",48,64],["H1288","and blessed",66,77]]},"35:10":{"text":"And God said unto him, Thy name is Jacob: thy name shall not be called any more Jacob, but Israel shall be thy name: and he called his name Israel.","words":[["H0430","And God",0,7],["H0559","said",8,12],["H8034","unto him, Thy name",13,31],["H3290","is Jacob",32,40],["H8034","thy name",42,50],["H7121","shall not be called",51,70],["H3290","any more Jacob",71,85],["H3478","but Israel",87,97],["H8034","shall be thy name",98,115],["H7121","and he called",117,130],["H8034","his name",131,139],["H3478","Israel",140,146]]},"35:11":{"text":"And God said unto him, I am God Almighty: be fruitful and multiply; a nation and a company of nations shall be of thee, and kings shall come out of thy loins;","words":[["H0430","And God",0,7],["H0559","said",8,12],["H0410","unto him, I am God",13,31],["H7706","Almighty",32,40],["H6509","be fruitful",42,53],["H7235","and multiply",54,66],["H1471","a nation",68,76],["H6951","and a company",77,90],["H1471","of nations",91,101],["H4428","shall be of thee, and kings",102,129],["H3318","shall come",130,140],["H2504","out of thy loins",141,157]]},"35:12":{"text":"And the land which I gave Abraham and Isaac, to thee I will give it, and to thy seed after thee will I give the land.","words":[["H0776","And the land",0,12],["H5414","which I gave",13,25],["H0085","Abraham",26,33],["H3327","and Isaac",34,43],["H5414","to thee I will give it",45,67],["H2233","and to thy seed",69,84],["H0310","after thee",85,95],["H5414","will I give",96,107],["H0776","the land",108,116]]},"35:13":{"text":"And God went up from him in the place where he talked with him.","words":[["H0430","And God",0,7],["H5927","went up",8,15],["H4725","from him in the place",16,37],["H1696","where he talked",38,53]]},"35:14":{"text":"And Jacob set up a pillar in the place where he talked with him, even a pillar of stone: and he poured a drink offering thereon, and he poured oil thereon.","words":[["H3290","And Jacob",0,9],["H5324","set up",10,16],["H4676","a pillar",17,25],["H4725","in the place",26,38],["H1696","where he talked",39,54],["H4678","with him, even a pillar",55,78],["H0068","of stone",79,87],["H5258","and he poured",89,102],["H5262","a drink offering",103,119],["H3332","thereon, and he poured",120,142],["H8081","oil",143,146]]},"35:15":{"text":"And Jacob called the name of the place where God spake with him, Bethel.","words":[["H3290","And Jacob",0,9],["H7121","called",10,16],["H8034","the name",17,25],["H4725","of the place",26,38],["H0430","where God",39,48],["H1696","spake",49,54],["H1008","with him, Bethel",55,71]]},"35:16":{"text":"And they journeyed from Bethel; and there was but a little way to come to Ephrath: and Rachel travailed, and she had hard labour.","words":[["H5265","And they journeyed",0,18],["H1008","from Bethel",19,30],["H5750","and there was but",32,49],["H3530","a little",50,58],["H0776","way",59,62],["H0935","to come",63,70],["H0672","to Ephrath",71,81],["H7354","and Rachel",83,93],["H3205","travailed",94,103],["H7185","and she had hard",105,121],["H3205","labour",122,128]]},"35:17":{"text":"And it came to pass, when she was in hard labour, that the midwife said unto her, Fear not; thou shalt have this son also.","words":[["H7185","And it came to pass, when she was in hard",0,41],["H3205","labour",42,48],["H3205","that the midwife",50,66],["H0559","said",67,71],["H3372","unto her, Fear",72,86],["H1121","not; thou shalt have this son",87,116]]},"35:18":{"text":"And it came to pass, as her soul was in departing, (for she died) that she called his name Benoni: but his father called him Benjamin.","words":[["H5315","And it came to pass, as her soul",0,32],["H3318","was in departing",33,49],["H4191","(for she died",51,64],["H7121","that she called",66,81],["H8034","his name",82,90],["H1126","Benoni",91,97],["H0001","but his father",99,113],["H7121","called",114,120],["H1144","him Benjamin",121,133]]},"35:19":{"text":"And Rachel died, and was buried in the way to Ephrath, which is Bethlehem.","words":[["H7354","And Rachel",0,10],["H4191","died",11,15],["H6912","and was buried",17,31],["H1870","in the way",32,42],["H0672","to Ephrath",43,53],["H1035","which is Bethlehem",55,73]]},"35:20":{"text":"And Jacob set a pillar upon her grave: that is the pillar of Rachel's grave unto this day.","words":[["H3290","And Jacob",0,9],["H5324","set",10,13],["H4676","a pillar",14,22],["H6900","upon her grave",23,37],["H4678","that is the pillar",39,57],["H7354","of Rachel's",58,69],["H6900","grave",70,75],["H3117","unto this day",76,89]]},"35:21":{"text":"And Israel journeyed, and spread his tent beyond the tower of Edar.","words":[["H3478","And Israel",0,10],["H5265","journeyed",11,20],["H5186","and spread",22,32],["H0168","his tent",33,41],["H1973","beyond",42,48],["H4026","the tower",49,58],["H4029","of Edar",59,66]]},"35:22":{"text":"And it came to pass, when Israel dwelt in that land, that Reuben went and lay with Bilhah his father's concubine: and Israel heard it. Now the sons of Jacob were twelve:","words":[["H3478","And it came to pass, when Israel",0,32],["H7931","dwelt",33,38],["H0776","in that land",39,51],["H7205","that Reuben",53,64],["H3212","went",65,69],["H7901","and lay",70,77],["H1090","with Bilhah",78,89],["H0001","his father's",90,102],["H6370","concubine",103,112],["H3478","and Israel",114,124],["H8085","heard",125,130],["H1121","it. Now the sons",131,147],["H3290","of Jacob",148,156],["H8147","were twelve",157,168],["H6240","were twelve",157,168]]},"35:23":{"text":"The sons of Leah; Reuben, Jacob's firstborn, and Simeon, and Levi, and Judah, and Issachar, and Zebulun:","words":[["H1121","The sons",0,8],["H3812","of Leah",9,16],["H7205","Reuben",18,24],["H3290","Jacob's",26,33],["H1060","firstborn",34,43],["H8095","and Simeon",45,55],["H3878","and Levi",57,65],["H3063","and Judah",67,76],["H3485","and Issachar",78,90],["H2074","and Zebulun",92,103]]},"35:24":{"text":"The sons of Rachel; Joseph, and Benjamin:","words":[["H1121","The sons",0,8],["H7354","of Rachel",9,18],["H3130","Joseph",20,26],["H1144","and Benjamin",28,40]]},"35:25":{"text":"And the sons of Bilhah, Rachel's handmaid; Dan, and Naphtali:","words":[["H1121","And the sons",0,12],["H1090","of Bilhah",13,22],["H7354","Rachel's",24,32],["H8198","handmaid",33,41],["H1835","Dan",43,46],["H5321","and Naphtali",48,60]]},"35:26":{"text":"And the sons of Zilpah, Leah's handmaid; Gad, and Asher: these are the sons of Jacob, which were born to him in Padanaram.","words":[["H1121","And the sons",0,12],["H2153","of Zilpah",13,22],["H3812","Leah's",24,30],["H8198","handmaid",31,39],["H1410","Gad",41,44],["H0836","and Asher",46,55],["H1121","these are the sons",57,75],["H3290","of Jacob",76,84],["H3205","which were born",86,101],["H6307","to him in Padanaram",102,121]]},"35:27":{"text":"And Jacob came unto Isaac his father unto Mamre, unto the city of Arbah, which is Hebron, where Abraham and Isaac sojourned.","words":[["H3290","And Jacob",0,9],["H0935","came",10,14],["H3327","unto Isaac",15,25],["H0001","his father",26,36],["H4471","unto Mamre",37,47],["H7153","unto the city of Arbah",49,71],["H2275","which is Hebron",73,88],["H0085","where Abraham",90,103],["H3327","and Isaac",104,113],["H1481","sojourned",114,123]]},"35:28":{"text":"And the days of Isaac were an hundred and fourscore years.","words":[["H3117","And the days",0,12],["H3327","of Isaac",13,21],["H3967","were an hundred",22,37],["H8141","were an hundred",22,37],["H8084","and fourscore",38,51],["H8141","years",52,57]]},"35:29":{"text":"And Isaac gave up the ghost, and died, and was gathered unto his people, being old and full of days: and his sons Esau and Jacob buried him.","words":[["H3327","And Isaac",0,9],["H1478","gave up the ghost",10,27],["H4191","and died",29,37],["H0622","and was gathered",39,55],["H5971","unto his people",56,71],["H2205","being old",73,82],["H7649","and full",83,91],["H3117","of days",92,99],["H1121","and his sons",101,113],["H6215","Esau",114,118],["H3290","and Jacob",119,128],["H6912","buried",129,135]]},"36:1":{"text":"Now these are the generations of Esau, who is Edom.","words":[["H8435","Now these are the generations",0,29],["H6215","of Esau",30,37],["H0123","who is Edom",39,50]]},"36:2":{"text":"Esau took his wives of the daughters of Canaan; Adah the daughter of Elon the Hittite, and Aholibamah the daughter of Anah the daughter of Zibeon the Hivite;","words":[["H6215","Esau",0,4],["H3947","took",5,9],["H0802","his wives",10,19],["H1323","of the daughters",20,36],["H3667","of Canaan",37,46],["H5711","Adah",48,52],["H1323","the daughter",53,65],["H0356","of Elon",66,73],["H2850","the Hittite",74,85],["H0173","and Aholibamah",87,101],["H1323","the daughter",102,114],["H6034","of Anah",115,122],["H1323","the daughter",123,135],["H6649","of Zibeon",136,145],["H2340","the Hivite",146,156]]},"36:3":{"text":"And Bashemath Ishmael's daughter, sister of Nebajoth.","words":[["H1315","And Bashemath",0,13],["H3458","Ishmael's",14,23],["H1323","daughter",24,32],["H0269","sister",34,40],["H5032","of Nebajoth",41,52]]},"36:4":{"text":"And Adah bare to Esau Eliphaz; and Bashemath bare Reuel;","words":[["H5711","And Adah",0,8],["H3205","bare",9,13],["H6215","to Esau",14,21],["H0464","Eliphaz",22,29],["H1315","and Bashemath",31,44],["H3205","bare",45,49],["H7467","Reuel",50,55]]},"36:5":{"text":"And Aholibamah bare Jeush, and Jaalam, and Korah: these are the sons of Esau, which were born unto him in the land of Canaan.","words":[["H0173","And Aholibamah",0,14],["H3205","bare",15,19],["H3274","Jeush",20,25],["H3281","and Jaalam",27,37],["H7141","and Korah",39,48],["H1121","these are the sons",50,68],["H6215","of Esau",69,76],["H3205","which were born",78,93],["H0776","unto him in the land",94,114],["H3667","of Canaan",115,124]]},"36:6":{"text":"And Esau took his wives, and his sons, and his daughters, and all the persons of his house, and his cattle, and all his beasts, and all his substance, which he had got in the land of Canaan; and went into the country from the face of his brother Jacob.","words":[["H6215","And Esau",0,8],["H3947","took",9,13],["H0802","his wives",14,23],["H1121","and his sons",25,37],["H1323","and his daughters",39,56],["H5315","and all the persons",58,77],["H1004","of his house",78,90],["H4735","and his cattle",92,106],["H0929","and all his beasts",108,126],["H7075","and all his substance",128,149],["H7408","which he had got",151,167],["H0776","in the land",168,179],["H3667","of Canaan",180,189],["H3212","and went",191,199],["H0776","into the country",200,216],["H6440","from the face",217,230],["H0251","of his brother",231,245],["H3290","Jacob",246,251]]},"36:7":{"text":"For their riches were more than that they might dwell together; and the land wherein they were strangers could not bear them because of their cattle.","words":[["H7399","For their riches",0,16],["H7227","were more",17,26],["H3427","than that they might dwell",27,53],["H3162","together",54,62],["H0776","and the land",64,76],["H4033","wherein they were strangers",77,104],["H3201","could",105,110],["H5375","not bear",111,119],["H6440","them because",120,132],["H4735","of their cattle",133,148]]},"36:8":{"text":"Thus dwelt Esau in mount Seir: Esau is Edom.","words":[["H3427","Thus dwelt",0,10],["H6215","Esau",11,15],["H2022","in mount",16,24],["H8165","Seir",25,29],["H6215","Esau",31,35],["H0123","is Edom",36,43]]},"36:9":{"text":"And these are the generations of Esau the father of the Edomites in mount Seir:","words":[["H8435","And these are the generations",0,29],["H6215","of Esau",30,37],["H0001","the father",38,48],["H0123","of the Edomites",49,64],["H2022","in mount",65,73],["H8165","Seir",74,78]]},"36:10":{"text":"These are the names of Esau's sons; Eliphaz the son of Adah the wife of Esau, Reuel the son of Bashemath the wife of Esau.","words":[["H8034","These are the names",0,19],["H6215","of Esau's",20,29],["H1121","sons",30,34],["H0464","Eliphaz",36,43],["H1121","the son",44,51],["H5711","of Adah",52,59],["H0802","the wife",60,68],["H6215","of Esau",69,76],["H7467","Reuel",78,83],["H1121","the son",84,91],["H1315","of Bashemath",92,104],["H0802","the wife",105,113],["H6215","of Esau",114,121]]},"36:11":{"text":"And the sons of Eliphaz were Teman, Omar, Zepho, and Gatam, and Kenaz.","words":[["H1121","And the sons",0,12],["H0464","of Eliphaz",13,23],["H8487","were Teman",24,34],["H0201","Omar",36,40],["H6825","Zepho",42,47],["H1609","and Gatam",49,58],["H7073","and Kenaz",60,69]]},"36:12":{"text":"And Timna was concubine to Eliphaz Esau's son; and she bare to Eliphaz Amalek: these were the sons of Adah Esau's wife.","words":[["H8555","And Timna",0,9],["H6370","was concubine",10,23],["H0464","to Eliphaz",24,34],["H6215","Esau's",35,41],["H1121","son",42,45],["H3205","and she bare",47,59],["H0464","to Eliphaz",60,70],["H6002","Amalek",71,77],["H1121","these were the sons",79,98],["H5711","of Adah",99,106],["H6215","Esau's",107,113],["H0802","wife",114,118]]},"36:13":{"text":"And these are the sons of Reuel; Nahath, and Zerah, Shammah, and Mizzah: these were the sons of Bashemath Esau's wife.","words":[["H1121","And these are the sons",0,22],["H7467","of Reuel",23,31],["H5184","Nahath",33,39],["H2226","and Zerah",41,50],["H8048","Shammah",52,59],["H4199","and Mizzah",61,71],["H1121","these were the sons",73,92],["H1315","of Bashemath",93,105],["H6215","Esau's",106,112],["H0802","wife",113,117]]},"36:14":{"text":"And these were the sons of Aholibamah, the daughter of Anah the daughter of Zibeon, Esau's wife: and she bare to Esau Jeush, and Jaalam, and Korah.","words":[["H1121","And these were the sons",0,23],["H0173","of Aholibamah",24,37],["H1323","the daughter",39,51],["H6034","of Anah",52,59],["H1323","the daughter",60,72],["H6649","of Zibeon",73,82],["H6215","Esau's",84,90],["H0802","wife",91,95],["H3205","and she bare",97,109],["H6215","to Esau",110,117],["H3274","Jeush",118,123],["H3281","and Jaalam",125,135],["H7141","and Korah",137,146]]},"36:15":{"text":"These were dukes of the sons of Esau: the sons of Eliphaz the firstborn son of Esau; duke Teman, duke Omar, duke Zepho, duke Kenaz,","words":[["H0441","These were dukes",0,16],["H1121","of the sons",17,28],["H6215","of Esau",29,36],["H1121","the sons",38,46],["H0464","of Eliphaz",47,57],["H1060","the firstborn",58,71],["H6215","son of Esau",72,83],["H0441","duke",85,89],["H8487","Teman",90,95],["H0441","duke",97,101],["H0201","Omar",102,106],["H0441","duke",108,112],["H6825","Zepho",113,118],["H0441","duke",120,124],["H7073","Kenaz",125,130]]},"36:16":{"text":"Duke Korah, duke Gatam, and duke Amalek: these are the dukes that came of Eliphaz in the land of Edom; these were the sons of Adah.","words":[["H0441","Duke",0,4],["H7141","Korah",5,10],["H0441","duke",12,16],["H1609","Gatam",17,22],["H0441","and duke",24,32],["H6002","Amalek",33,39],["H0441","these are the dukes",41,60],["H0464","that came of Eliphaz",61,81],["H0776","in the land",82,93],["H0123","of Edom",94,101],["H1121","these were the sons",103,122],["H5711","of Adah",123,130]]},"36:17":{"text":"And these are the sons of Reuel Esau's son; duke Nahath, duke Zerah, duke Shammah, duke Mizzah: these are the dukes that came of Reuel in the land of Edom; these are the sons of Bashemath Esau's wife.","words":[["H1121","And these are the sons",0,22],["H7467","of Reuel",23,31],["H6215","Esau's",32,38],["H1121","son",39,42],["H0441","duke",44,48],["H5184","Nahath",49,55],["H0441","duke",57,61],["H2226","Zerah",62,67],["H0441","duke",69,73],["H8048","Shammah",74,81],["H0441","duke",83,87],["H4199","Mizzah",88,94],["H0441","these are the dukes",96,115],["H7467","that came of Reuel",116,134],["H0776","in the land",135,146],["H0123","of Edom",147,154],["H1121","these are the sons",156,174],["H1315","of Bashemath",175,187],["H6215","Esau's",188,194],["H0802","wife",195,199]]},"36:18":{"text":"And these are the sons of Aholibamah Esau's wife; duke Jeush, duke Jaalam, duke Korah: these were the dukes that came of Aholibamah the daughter of Anah, Esau's wife.","words":[["H1121","And these are the sons",0,22],["H0173","of Aholibamah",23,36],["H6215","Esau's",37,43],["H0802","wife",44,48],["H0441","duke",50,54],["H3266","Jeush",55,60],["H0441","duke",62,66],["H3281","Jaalam",67,73],["H0441","duke",75,79],["H7141","Korah",80,85],["H0441","these were the dukes",87,107],["H0173","that came of Aholibamah",108,131],["H1323","the daughter",132,144],["H6034","of Anah",145,152],["H6215","Esau's",154,160],["H0802","wife",161,165]]},"36:19":{"text":"These are the sons of Esau, who is Edom, and these are their dukes.","words":[["H1121","These are the sons",0,18],["H6215","of Esau",19,26],["H0123","who is Edom",28,39],["H0441","and these are their dukes",41,66]]},"36:20":{"text":"These are the sons of Seir the Horite, who inhabited the land; Lotan, and Shobal, and Zibeon, and Anah,","words":[["H1121","These are the sons",0,18],["H8165","of Seir",19,26],["H2752","the Horite",27,37],["H3427","who inhabited",39,52],["H0776","the land",53,61],["H3877","Lotan",63,68],["H7732","and Shobal",70,80],["H6649","and Zibeon",82,92],["H6034","and Anah",94,102]]},"36:21":{"text":"And Dishon, and Ezer, and Dishan: these are the dukes of the Horites, the children of Seir in the land of Edom.","words":[["H1787","And Dishon",0,10],["H0687","and Ezer",12,20],["H1789","and Dishan",22,32],["H0441","these are the dukes",34,53],["H2752","of the Horites",54,68],["H1121","the children",70,82],["H8165","of Seir",83,90],["H0776","in the land",91,102],["H0123","of Edom",103,110]]},"36:22":{"text":"And the children of Lotan were Hori and Hemam; and Lotan's sister was Timna.","words":[["H1121","And the children",0,16],["H3877","of Lotan",17,25],["H2753","were Hori",26,35],["H1967","and Hemam",36,45],["H3877","and Lotan's",47,58],["H0269","sister",59,65],["H8555","was Timna",66,75]]},"36:23":{"text":"And the children of Shobal were these; Alvan, and Manahath, and Ebal, Shepho, and Onam.","words":[["H1121","And the children",0,16],["H7732","of Shobal",17,26],["H5935","were these; Alvan",27,44],["H4506","and Manahath",46,58],["H5858","and Ebal",60,68],["H8195","Shepho",70,76],["H0208","and Onam",78,86]]},"36:24":{"text":"And these are the children of Zibeon; both Ajah, and Anah: this was that Anah that found the mules in the wilderness, as he fed the asses of Zibeon his father.","words":[["H1121","And these are the children",0,26],["H6649","of Zibeon",27,36],["H0345","both Ajah",38,47],["H6034","and Anah",49,57],["H6034","this was that Anah",59,77],["H4672","that found",78,88],["H3222","the mules",89,98],["H4057","in the wilderness",99,116],["H7462","as he fed",118,127],["H2543","the asses",128,137],["H6649","of Zibeon",138,147],["H0001","his father",148,158]]},"36:25":{"text":"And the children of Anah were these; Dishon, and Aholibamah the daughter of Anah.","words":[["H1121","And the children",0,16],["H6034","of Anah",17,24],["H1787","were these; Dishon",25,43],["H0173","and Aholibamah",45,59],["H1323","the daughter",60,72],["H6034","of Anah",73,80]]},"36:26":{"text":"And these are the children of Dishon; Hemdan, and Eshban, and Ithran, and Cheran.","words":[["H1121","And these are the children",0,26],["H1787","of Dishon",27,36],["H2533","Hemdan",38,44],["H0790","and Eshban",46,56],["H3506","and Ithran",58,68],["H3763","and Cheran",70,80]]},"36:27":{"text":"The children of Ezer are these; Bilhan, and Zaavan, and Akan.","words":[["H1121","The children",0,12],["H0687","of Ezer",13,20],["H1092","are these; Bilhan",21,38],["H2190","and Zaavan",40,50],["H6130","and Akan",52,60]]},"36:28":{"text":"The children of Dishan are these; Uz, and Aran.","words":[["H1121","The children",0,12],["H1789","of Dishan",13,22],["H5780","are these; Uz",23,36],["H0765","and Aran",38,46]]},"36:29":{"text":"These are the dukes that came of the Horites; duke Lotan, duke Shobal, duke Zibeon, duke Anah,","words":[["H0441","These are the dukes",0,19],["H2752","that came of the Horites",20,44],["H0441","duke",46,50],["H3877","Lotan",51,56],["H0441","duke",58,62],["H7732","Shobal",63,69],["H0441","duke",71,75],["H6649","Zibeon",76,82],["H0441","duke",84,88],["H6034","Anah",89,93]]},"36:30":{"text":"Duke Dishon, duke Ezer, duke Dishan: these are the dukes that came of Hori, among their dukes in the land of Seir.","words":[["H0441","Duke",0,4],["H1787","Dishon",5,11],["H0441","duke",13,17],["H0687","Ezer",18,22],["H0441","duke",24,28],["H1789","Dishan",29,35],["H0441","these are the dukes",37,56],["H2753","that came of Hori",57,74],["H0441","among their dukes",76,93],["H0776","in the land",94,105],["H8165","of Seir",106,113]]},"36:31":{"text":"And these are the kings that reigned in the land of Edom, before there reigned any king over the children of Israel.","words":[["H4428","And these are the kings",0,23],["H4427","that reigned",24,36],["H0776","in the land",37,48],["H0123","of Edom",49,56],["H6440","before",58,64],["H4427","there reigned",65,78],["H4428","any king",79,87],["H1121","over the children",88,105],["H3478","of Israel",106,115]]},"36:32":{"text":"And Bela the son of Beor reigned in Edom: and the name of his city was Dinhabah.","words":[["H1106","And Bela",0,8],["H1121","the son",9,16],["H1160","of Beor",17,24],["H4427","reigned",25,32],["H0123","in Edom",33,40],["H8034","and the name",42,54],["H5892","of his city",55,66],["H1838","was Dinhabah",67,79]]},"36:33":{"text":"And Bela died, and Jobab the son of Zerah of Bozrah reigned in his stead.","words":[["H1106","And Bela",0,8],["H4191","died",9,13],["H3103","and Jobab",15,24],["H1121","the son",25,32],["H2226","of Zerah",33,41],["H1224","of Bozrah",42,51],["H4427","reigned",52,59]]},"36:34":{"text":"And Jobab died, and Husham of the land of Temani reigned in his stead.","words":[["H3103","And Jobab",0,9],["H4191","died",10,14],["H2367","and Husham",16,26],["H0776","of the land",27,38],["H8489","of Temani",39,48],["H4427","reigned",49,56]]},"36:35":{"text":"And Husham died, and Hadad the son of Bedad, who smote Midian in the field of Moab, reigned in his stead: and the name of his city was Avith.","words":[["H2367","And Husham",0,10],["H4191","died",11,15],["H1908","and Hadad",17,26],["H1121","the son",27,34],["H0911","of Bedad",35,43],["H5221","who smote",45,54],["H4080","Midian",55,61],["H7704","in the field",62,74],["H4124","of Moab",75,82],["H4427","reigned",84,91],["H8034","in his stead: and the name",92,118],["H5892","of his city",119,130],["H5762","was Avith",131,140]]},"36:36":{"text":"And Hadad died, and Samlah of Masrekah reigned in his stead.","words":[["H1908","And Hadad",0,9],["H4191","died",10,14],["H8072","and Samlah",16,26],["H4957","of Masrekah",27,38],["H4427","reigned",39,46]]},"36:37":{"text":"And Samlah died, and Saul of Rehoboth by the river reigned in his stead.","words":[["H8072","And Samlah",0,10],["H4191","died",11,15],["H7586","and Saul",17,25],["H7344","of Rehoboth",26,37],["H5104","by the river",38,50],["H4427","reigned",51,58]]},"36:38":{"text":"And Saul died, and Baalhanan the son of Achbor reigned in his stead.","words":[["H7586","And Saul",0,8],["H4191","died",9,13],["H1177","and Baalhanan",15,28],["H1121","the son",29,36],["H5907","of Achbor",37,46],["H4427","reigned",47,54]]},"36:39":{"text":"And Baalhanan the son of Achbor died, and Hadar reigned in his stead: and the name of his city was Pau; and his wife's name was Mehetabel, the daughter of Matred, the daughter of Mezahab.","words":[["H1177","And Baalhanan",0,13],["H1121","the son",14,21],["H5907","of Achbor",22,31],["H4191","died",32,36],["H1924","and Hadar",38,47],["H4427","reigned",48,55],["H8034","in his stead: and the name",56,82],["H5892","of his city",83,94],["H6464","was Pau",95,102],["H0802","and his wife's",104,118],["H8034","name",119,123],["H4105","was Mehetabel",124,137],["H1323","the daughter",139,151],["H4308","of Matred",152,161],["H1323","the daughter",163,175],["H4314","of Mezahab",176,186]]},"36:40":{"text":"And these are the names of the dukes that came of Esau, according to their families, after their places, by their names; duke Timnah, duke Alvah, duke Jetheth,","words":[["H8034","And these are the names",0,23],["H0441","of the dukes",24,36],["H6215","that came of Esau",37,54],["H4940","according to their families",56,83],["H4725","after their places",85,103],["H8034","by their names",105,119],["H0441","duke",121,125],["H8555","Timnah",126,132],["H0441","duke",134,138],["H5933","Alvah",139,144],["H0441","duke",146,150],["H3509","Jetheth",151,158]]},"36:41":{"text":"Duke Aholibamah, duke Elah, duke Pinon,","words":[["H0441","Duke",0,4],["H0173","Aholibamah",5,15],["H0441","duke",17,21],["H0425","Elah",22,26],["H0441","duke",28,32],["H6373","Pinon",33,38]]},"36:42":{"text":"Duke Kenaz, duke Teman, duke Mibzar,","words":[["H0441","Duke",0,4],["H7073","Kenaz",5,10],["H0441","duke",12,16],["H8487","Teman",17,22],["H0441","duke",24,28],["H4014","Mibzar",29,35]]},"36:43":{"text":"Duke Magdiel, duke Iram: these be the dukes of Edom, according to their habitations in the land of their possession: he is Esau the father of the Edomites.","words":[["H0441","Duke",0,4],["H4025","Magdiel",5,12],["H0441","duke",14,18],["H5902","Iram",19,23],["H0441","these be the dukes",25,43],["H0123","of Edom",44,51],["H4186","according to their habitations",53,83],["H0776","in the land",84,95],["H0272","of their possession",96,115],["H6215","he is Esau",117,127],["H0001","the father",128,138],["H0123","of the Edomites",139,154]]},"37:1":{"text":"And Jacob dwelt in the land wherein his father was a stranger, in the land of Canaan.","words":[["H3290","And Jacob",0,9],["H3427","dwelt",10,15],["H0776","in the land",16,27],["H0001","wherein his father",28,46],["H4033","was a stranger",47,61],["H0776","in the land",63,74],["H3667","of Canaan",75,84]]},"37:2":{"text":"These are the generations of Jacob. Joseph, being seventeen years old, was feeding the flock with his brethren; and the lad was with the sons of Bilhah, and with the sons of Zilpah, his father's wives: and Joseph brought unto his father their evil report.","words":[["H8435","These are the generations",0,25],["H3290","of Jacob",26,34],["H3130","Joseph",36,42],["H6240","being seventeen",44,59],["H7651","being seventeen",44,59],["H8141","years",60,65],["H1121","old",66,69],["H7462","was feeding",71,82],["H6629","the flock",83,92],["H0251","with his brethren",93,110],["H5288","and the lad",112,123],["H1121","was with the sons",124,141],["H1090","of Bilhah",142,151],["H1121","and with the sons",153,170],["H2153","of Zilpah",171,180],["H0001","his father's",182,194],["H0802","wives",195,200],["H3130","and Joseph",202,212],["H0935","brought",213,220],["H0001","unto his father",221,236],["H7451","their evil",237,247],["H1681","report",248,254]]},"37:3":{"text":"Now Israel loved Joseph more than all his children, because he was the son of his old age: and he made him a coat of many colours.","words":[["H3478","Now Israel",0,10],["H0157","loved",11,16],["H3130","Joseph",17,23],["H1121","more than all his children",24,50],["H1121","because he was the son",52,74],["H2208","of his old age",75,89],["H6213","and he made",91,102],["H3801","him a coat",103,113],["H6446","of many colours",114,129]]},"37:4":{"text":"And when his brethren saw that their father loved him more than all his brethren, they hated him, and could not speak peaceably unto him.","words":[["H0251","And when his brethren",0,21],["H7200","saw",22,25],["H0001","that their father",26,43],["H0157","loved",44,49],["H0251","him more than all his brethren",50,80],["H8130","they hated",82,92],["H3201","him, and could",93,107],["H1696","not speak",108,117],["H7965","peaceably",118,127]]},"37:5":{"text":"And Joseph dreamed a dream, and he told it his brethren: and they hated him yet the more.","words":[["H3130","And Joseph",0,10],["H2492","dreamed",11,18],["H2472","a dream",19,26],["H5046","and he told",28,39],["H0251","it his brethren",40,55],["H8130","and they hated",57,71],["H3254","him yet the more",72,88]]},"37:6":{"text":"And he said unto them, Hear, I pray you, this dream which I have dreamed:","words":[["H0559","And he said",0,11],["H8085","unto them, Hear",12,27],["H2472","I pray you, this dream",29,51],["H2492","which I have dreamed",52,72]]},"37:7":{"text":"For, behold, we were binding sheaves in the field, and, lo, my sheaf arose, and also stood upright; and, behold, your sheaves stood round about, and made obeisance to my sheaf.","words":[["H0481","For, behold, we were binding",0,28],["H8432","For, behold, we were binding",0,28],["H0485","sheaves",29,36],["H7704","in the field",37,49],["H0485","and, lo, my sheaf",51,68],["H6965","arose",69,74],["H5324","and also stood upright",76,98],["H0485","and, behold, your sheaves",100,125],["H5437","stood round about",126,143],["H7812","and made obeisance",145,163],["H0485","to my sheaf",164,175]]},"37:8":{"text":"And his brethren said to him, Shalt thou indeed reign over us? or shalt thou indeed have dominion over us? And they hated him yet the more for his dreams, and for his words.","words":[["H0251","And his brethren",0,16],["H0559","said",17,21],["H4427","to him, Shalt thou indeed",22,47],["H4427","reign",48,53],["H4910","over us? or shalt thou indeed",54,83],["H4910","have dominion",84,97],["H8130","over us? And they hated",98,121],["H3254","him yet the more",122,138],["H2472","for his dreams",139,153],["H1697","and for his words",155,172]]},"37:9":{"text":"And he dreamed yet another dream, and told it his brethren, and said, Behold, I have dreamed a dream more; and, behold, the sun and the moon and the eleven stars made obeisance to me.","words":[["H2492","And he dreamed",0,14],["H0312","yet another",15,26],["H2472","dream",27,32],["H5608","and told",34,42],["H0251","it his brethren",43,58],["H0559","and said",60,68],["H2492","Behold, I have dreamed",70,92],["H2472","a dream",93,100],["H8121","more; and, behold, the sun",101,127],["H3394","and the moon",128,140],["H6240","and the eleven",141,155],["H0259","and the eleven",141,155],["H3556","stars",156,161],["H7812","made obeisance",162,176]]},"37:10":{"text":"And he told it to his father, and to his brethren: and his father rebuked him, and said unto him, What is this dream that thou hast dreamed? Shall I and thy mother and thy brethren indeed come to bow down ourselves to thee to the earth?","words":[["H5608","And he told",0,11],["H0001","it to his father",12,28],["H0251","and to his brethren",30,49],["H0001","and his father",51,65],["H1605","rebuked",66,73],["H0559","him, and said",74,87],["H2472","unto him, What is this dream",88,116],["H2492","that thou hast dreamed",117,139],["H0517","Shall I and thy mother",141,163],["H0251","and thy brethren",164,180],["H0935","indeed",181,187],["H0935","come",188,192],["H7812","to bow down",193,204],["H0776","ourselves to thee to the earth",205,235]]},"37:11":{"text":"And his brethren envied him; but his father observed the saying.","words":[["H0251","And his brethren",0,16],["H7065","envied",17,23],["H0001","him; but his father",24,43],["H8104","observed",44,52],["H1697","the saying",53,63]]},"37:12":{"text":"And his brethren went to feed their father's flock in Shechem.","words":[["H0251","And his brethren",0,16],["H3212","went",17,21],["H7462","to feed",22,29],["H0001","their father's",30,44],["H6629","flock",45,50],["H7927","in Shechem",51,61]]},"37:13":{"text":"And Israel said unto Joseph, Do not thy brethren feed the flock in Shechem? come, and I will send thee unto them. And he said to him, Here am I.","words":[["H3478","And Israel",0,10],["H0559","said",11,15],["H3130","unto Joseph",16,27],["H0251","Do not thy brethren",29,48],["H7462","feed",49,53],["H7927","the flock in Shechem",54,74],["H3212","come",76,80],["H7971","and I will send thee",82,102],["H0559","unto them. And he said",103,125]]},"37:14":{"text":"And he said to him, Go, I pray thee, see whether it be well with thy brethren, and well with the flocks; and bring me word again. So he sent him out of the vale of Hebron, and he came to Shechem.","words":[["H0559","And he said",0,11],["H3212","to him, Go",12,22],["H7200","I pray thee, see",24,40],["H7965","whether it be well",41,59],["H0251","with thy brethren",60,77],["H7965","and well",79,87],["H6629","with the flocks",88,103],["H7725","and bring",105,114],["H1697","me word",115,122],["H7725","again",123,128],["H7971","So he sent",130,140],["H6010","him out of the vale",141,160],["H2275","of Hebron",161,170],["H0935","and he came",172,183],["H7927","to Shechem",184,194]]},"37:15":{"text":"And a certain man found him, and, behold, he was wandering in the field: and the man asked him, saying, What seekest thou?","words":[["H0376","And a certain man",0,17],["H4672","found him",18,27],["H8582","and, behold, he was wandering",29,58],["H7704","in the field",59,71],["H0376","and the man",73,84],["H7592","asked him",85,94],["H0559","saying",96,102],["H1245","What seekest",104,116]]},"37:16":{"text":"And he said, I seek my brethren: tell me, I pray thee, where they feed their flocks.","words":[["H0559","And he said",0,11],["H1245","I seek",13,19],["H0251","my brethren",20,31],["H5046","tell",33,37],["H0375","me, I pray thee, where",38,60],["H7462","they feed",61,70]]},"37:17":{"text":"And the man said, They are departed hence; for I heard them say, Let us go to Dothan. And Joseph went after his brethren, and found them in Dothan.","words":[["H0376","And the man",0,11],["H0559","said",12,16],["H5265","They are departed",18,35],["H2088","hence",36,41],["H8085","for I heard",43,54],["H0559","them say",55,63],["H3212","Let us go",65,74],["H1886","to Dothan",75,84],["H3130","And Joseph",86,96],["H3212","went",97,101],["H0310","after",102,107],["H0251","his brethren",108,120],["H4672","and found",122,131],["H1886","them in Dothan",132,146]]},"37:18":{"text":"And when they saw him afar off, even before he came near unto them, they conspired against him to slay him.","words":[["H7200","And when they saw",0,17],["H7350","him afar off",18,30],["H7126","even before he came near",32,56],["H5230","unto them, they conspired",57,82],["H4191","against him to slay",83,102]]},"37:19":{"text":"And they said one to another, Behold, this dreamer cometh.","words":[["H0559","And they said",0,13],["H0376","one",14,17],["H0251","to another",18,28],["H1976","Behold, this",30,42],["H1167","dreamer",43,50],["H2472","dreamer",43,50],["H0935","cometh",51,57]]},"37:20":{"text":"Come now therefore, and let us slay him, and cast him into some pit, and we will say, Some evil beast hath devoured him: and we shall see what will become of his dreams.","words":[["H3212","Come",0,4],["H2026","now therefore, and let us slay",5,35],["H7993","him, and cast",36,49],["H0259","him into some",50,63],["H0953","pit",64,67],["H0559","and we will say",69,84],["H7451","Some evil",86,95],["H2416","beast",96,101],["H0398","hath devoured",102,115],["H7200","him: and we shall see",116,137],["H2472","what will become of his dreams",138,168]]},"37:21":{"text":"And Reuben heard it, and he delivered him out of their hands; and said, Let us not kill him.","words":[["H7205","And Reuben",0,10],["H8085","heard",11,16],["H5337","it, and he delivered",17,37],["H3027","him out of their hands",38,60],["H0559","and said",62,70],["H5221","Let us not kill",72,87],["H5315","Let us not kill",72,87]]},"37:22":{"text":"And Reuben said unto them, Shed no blood, but cast him into this pit that is in the wilderness, and lay no hand upon him; that he might rid him out of their hands, to deliver him to his father again.","words":[["H7205","And Reuben",0,10],["H0559","said",11,15],["H8210","unto them, Shed",16,31],["H1818","no blood",32,40],["H7993","but cast",42,50],["H0953","him into this pit",51,68],["H4057","that is in the wilderness",69,94],["H7971","and lay",96,103],["H3027","no hand",104,111],["H5337","upon him; that he might rid",112,139],["H3027","him out of their hands",140,162],["H7725","to deliver",164,174],["H0001","him to his father",175,192],["H7725","again",193,198]]},"37:23":{"text":"And it came to pass, when Joseph was come unto his brethren, that they stript Joseph out of his coat, his coat of many colours that was on him;","words":[["H3130","And it came to pass, when Joseph",0,32],["H0935","was come",33,41],["H0251","unto his brethren",42,59],["H6584","that they stript",61,77],["H0853","",-1,-1],["H3130","Joseph",78,84],["H0854","out of",85,91],["H3801","his coat",92,100],["H3801","his coat",102,110],["H6446","of many colours",111,126]]},"37:24":{"text":"And they took him, and cast him into a pit: and the pit was empty, there was no water in it.","words":[["H3947","And they took",0,13],["H7993","him, and cast",14,27],["H0953","him into a pit",28,42],["H0953","and the pit",44,55],["H7386","was empty",56,65],["H4325","there was no water",67,85]]},"37:25":{"text":"And they sat down to eat bread: and they lifted up their eyes and looked, and, behold, a company of Ishmeelites came from Gilead with their camels bearing spicery and balm and myrrh, going to carry it down to Egypt.","words":[["H3427","And they sat down",0,17],["H0398","to eat",18,24],["H3899","bread",25,30],["H5375","and they lifted up",32,50],["H5869","their eyes",51,61],["H7200","and looked",62,72],["H0736","and, behold, a company",74,96],["H3459","of Ishmeelites",97,111],["H0935","came",112,116],["H1568","from Gilead",117,128],["H1581","with their camels",129,146],["H5375","bearing",147,154],["H5219","spicery",155,162],["H6875","and balm",163,171],["H3910","and myrrh",172,181],["H1980","going",183,188],["H3381","to carry it down",189,205],["H4714","to Egypt",206,214]]},"37:26":{"text":"And Judah said unto his brethren, What profit is it if we slay our brother, and conceal his blood?","words":[["H3063","And Judah",0,9],["H0559","said",10,14],["H0251","unto his brethren",15,32],["H1215","What profit",34,45],["H2026","is it if we slay",46,62],["H0251","our brother",63,74],["H3680","and conceal",76,87],["H1818","his blood",88,97]]},"37:27":{"text":"Come, and let us sell him to the Ishmeelites, and let not our hand be upon him; for he is our brother and our flesh. And his brethren were content.","words":[["H3212","Come",0,4],["H4376","and let us sell",6,21],["H3459","him to the Ishmeelites",22,44],["H3027","and let not our hand",46,66],["H0251","be upon him; for he is our brother",67,101],["H1320","and our flesh",102,115],["H0251","And his brethren",117,133],["H8085","were content",134,146]]},"37:28":{"text":"Then there passed by Midianites merchantmen; and they drew and lifted up Joseph out of the pit, and sold Joseph to the Ishmeelites for twenty pieces of silver: and they brought Joseph into Egypt.","words":[["H5674","Then there passed",0,17],["H4084","by Midianites",18,31],["H0582","merchantmen",32,43],["H5503","merchantmen",32,43],["H4900","and they drew",45,58],["H5927","and lifted up",59,72],["H3130","Joseph",73,79],["H0953","out of the pit",80,94],["H4376","and sold",96,104],["H3130","Joseph",105,111],["H3459","to the Ishmeelites",112,130],["H6242","for twenty",131,141],["H3701","pieces of silver",142,158],["H0935","and they brought",160,176],["H3130","Joseph",177,183],["H4714","into Egypt",184,194]]},"37:29":{"text":"And Reuben returned unto the pit; and, behold, Joseph was not in the pit; and he rent his clothes.","words":[["H7205","And Reuben",0,10],["H7725","returned",11,19],["H0953","unto the pit",20,32],["H3130","and, behold, Joseph",34,53],["H0953","was not in the pit",54,72],["H7167","and he rent",74,85],["H0899","his clothes",86,97]]},"37:30":{"text":"And he returned unto his brethren, and said, The child is not; and I, whither shall I go?","words":[["H7725","And he returned",0,15],["H0251","unto his brethren",16,33],["H0559","and said",35,43],["H3206","The child",45,54],["H0575","is not; and I, whither",55,77],["H0935","shall I go",78,88]]},"37:31":{"text":"And they took Joseph's coat, and killed a kid of the goats, and dipped the coat in the blood;","words":[["H3947","And they took",0,13],["H3130","Joseph's",14,22],["H3801","coat",23,27],["H7819","and killed",29,39],["H8163","a kid",40,45],["H5795","of the goats",46,58],["H2881","and dipped",60,70],["H3801","the coat",71,79],["H1818","in the blood",80,92]]},"37:32":{"text":"And they sent the coat of many colours, and they brought it to their father; and said, This have we found: know now whether it be thy son's coat or no.","words":[["H7971","And they sent",0,13],["H3801","the coat",14,22],["H6446","of many colours",23,38],["H0935","and they brought",40,56],["H0001","it to their father",57,75],["H0559","and said",77,85],["H4672","This have we found",87,105],["H5234","know",107,111],["H1121","now whether it be thy son's",112,139],["H3801","coat",140,144]]},"37:33":{"text":"And he knew it, and said, It is my son's coat; an evil beast hath devoured him; Joseph is without doubt rent in pieces.","words":[["H5234","And he knew it",0,14],["H0559","and said",16,24],["H1121","It is my son's",26,40],["H3801","coat",41,45],["H7451","an evil",47,54],["H2416","beast",55,60],["H0398","hath devoured",61,74],["H3130","him; Joseph",75,86],["H2963","is without doubt",87,103],["H2963","rent in pieces",104,118]]},"37:34":{"text":"And Jacob rent his clothes, and put sackcloth upon his loins, and mourned for his son many days.","words":[["H3290","And Jacob",0,9],["H7167","rent",10,14],["H8071","his clothes",15,26],["H7760","and put",28,35],["H8242","sackcloth",36,45],["H4975","upon his loins",46,60],["H0056","and mourned",62,73],["H1121","for his son",74,85],["H7227","many",86,90],["H3117","days",91,95]]},"37:35":{"text":"And all his sons and all his daughters rose up to comfort him; but he refused to be comforted; and he said, For I will go down into the grave unto my son mourning. Thus his father wept for him.","words":[["H1121","And all his sons",0,16],["H1323","and all his daughters",17,38],["H6965","rose up",39,46],["H5162","to comfort",47,57],["H3985","him; but he refused",58,77],["H5162","to be comforted",78,93],["H0559","and he said",95,106],["H3381","For I will go down",108,126],["H7585","into the grave",127,141],["H1121","unto my son",142,153],["H0057","mourning",154,162],["H0001","Thus his father",164,179],["H1058","wept",180,184]]},"37:36":{"text":"And the Midianites sold him into Egypt unto Potiphar, an officer of Pharaoh's, and captain of the guard.","words":[["H4092","And the Midianites",0,18],["H4376","sold",19,23],["H4714","him into Egypt",24,38],["H6318","unto Potiphar",39,52],["H5631","an officer",54,64],["H6547","of Pharaoh's",65,77],["H8269","and captain",79,90],["H2876","of the guard",91,103]]},"38:1":{"text":"And it came to pass at that time, that Judah went down from his brethren, and turned in to a certain Adullamite, whose name was Hirah.","words":[["H6256","And it came to pass at that time",0,32],["H3063","that Judah",34,44],["H3381","went down",45,54],["H0251","from his brethren",55,72],["H5186","and turned",74,84],["H0376","in to a certain",85,100],["H5726","Adullamite",101,111],["H8034","whose name",113,123],["H2437","was Hirah",124,133]]},"38:2":{"text":"And Judah saw there a daughter of a certain Canaanite, whose name was Shuah; and he took her, and went in unto her.","words":[["H3063","And Judah",0,9],["H7200","saw",10,13],["H1323","there a daughter",14,30],["H0376","of a certain",31,43],["H3669","Canaanite",44,53],["H8034","whose name",55,65],["H7770","was Shuah",66,75],["H3947","and he took her",77,92],["H0935","and went in",94,105]]},"38:3":{"text":"And she conceived, and bare a son; and he called his name Er.","words":[["H2029","And she conceived",0,17],["H3205","and bare",19,27],["H1121","a son",28,33],["H7121","and he called",35,48],["H8034","his name",49,57],["H6147","Er",58,60]]},"38:4":{"text":"And she conceived again, and bare a son; and she called his name Onan.","words":[["H2029","And she conceived",0,17],["H3205","again, and bare",18,33],["H1121","a son",34,39],["H7121","and she called",41,55],["H8034","his name",56,64],["H0209","Onan",65,69]]},"38:5":{"text":"And she yet again conceived, and bare a son; and called his name Shelah: and he was at Chezib, when she bare him.","words":[["H3254","And she yet again conceived",0,27],["H3205","and bare",29,37],["H1121","a son",38,43],["H7121","and called",45,55],["H8034","his name",56,64],["H7956","Shelah",65,71],["H3580","and he was at Chezib",73,93],["H3205","when she bare",95,108]]},"38:6":{"text":"And Judah took a wife for Er his firstborn, whose name was Tamar.","words":[["H3063","And Judah",0,9],["H3947","took",10,14],["H0802","a wife",15,21],["H6147","for Er",22,28],["H1060","his firstborn",29,42],["H8034","whose name",44,54],["H8559","was Tamar",55,64]]},"38:7":{"text":"And Er, Judah's firstborn, was wicked in the sight of the LORD; and the LORD slew him.","words":[["H6147","And Er",0,6],["H3063","Judah's",8,15],["H1060","firstborn",16,25],["H7451","was wicked",27,37],["H5869","in the sight",38,50],["H3068","of the LORD",51,62],["H3068","and the LORD",64,76],["H4191","slew",77,81]]},"38:8":{"text":"And Judah said unto Onan, Go in unto thy brother's wife, and marry her, and raise up seed to thy brother.","words":[["H3063","And Judah",0,9],["H0559","said",10,14],["H0209","unto Onan",15,24],["H0935","Go in",26,31],["H0251","unto thy brother's",32,50],["H0802","wife",51,55],["H2992","and marry",57,66],["H6965","her, and raise up",67,84],["H2233","seed",85,89],["H0251","to thy brother",90,104]]},"38:9":{"text":"And Onan knew that the seed should not be his; and it came to pass, when he went in unto his brother's wife, that he spilled it on the ground, lest that he should give seed to his brother.","words":[["H0209","And Onan",0,8],["H3045","knew",9,13],["H2233","that the seed",14,27],["H0518","should not be his; and it came to pass, when",28,72],["H0935","he went in",73,83],["H0251","unto his brother's",84,102],["H0802","wife",103,107],["H7843","that he spilled",109,124],["H0776","it on the ground",125,141],["H1115","lest",143,147],["H5414","that he should give",148,167],["H2233","seed",168,172],["H0251","to his brother",173,187]]},"38:10":{"text":"And the thing which he did displeased the LORD: wherefore he slew him also.","words":[["H0834","And the thing which",0,19],["H6213","he did",20,26],["H3415","displeased",27,37],["H5869","displeased",27,37],["H3068","the LORD",38,46],["H4191","wherefore he slew",48,65]]},"38:11":{"text":"Then said Judah to Tamar his daughter in law, Remain a widow at thy father's house, till Shelah my son be grown: for he said, Lest peradventure he die also, as his brethren did. And Tamar went and dwelt in her father's house.","words":[["H0559","Then said",0,9],["H3063","Judah",10,15],["H8559","to Tamar",16,24],["H3618","his daughter in law",25,44],["H3427","Remain",46,52],["H0490","a widow",53,60],["H0001","at thy father's",61,76],["H1004","house",77,82],["H7956","till Shelah",84,95],["H1121","my son",96,102],["H1431","be grown",103,111],["H0559","for he said",113,124],["H4191","Lest peradventure he die",126,150],["H0251","also, as his brethren",151,172],["H8559","did. And Tamar",173,187],["H3212","went",188,192],["H3427","and dwelt",193,202],["H0001","in her father's",203,218],["H1004","house",219,224]]},"38:12":{"text":"And in process of time the daughter of Shuah Judah's wife died; and Judah was comforted, and went up unto his sheepshearers to Timnath, he and his friend Hirah the Adullamite.","words":[["H7235","And in process",0,14],["H3117","of time",15,22],["H1323","the daughter",23,35],["H7770","of Shuah",36,44],["H3063","Judah's",45,52],["H0802","wife",53,57],["H4191","died",58,62],["H3063","and Judah",64,73],["H5162","was comforted",74,87],["H5927","and went up",89,100],["H1494","unto his sheepshearers",101,123],["H6629","unto his sheepshearers",101,123],["H8553","to Timnath",124,134],["H7453","he and his friend",136,153],["H2437","Hirah",154,159],["H5726","the Adullamite",160,174]]},"38:13":{"text":"And it was told Tamar, saying, Behold thy father in law goeth up to Timnath to shear his sheep.","words":[["H5046","And it was told",0,15],["H8559","Tamar",16,21],["H0559","saying",23,29],["H2524","Behold thy father in law",31,55],["H5927","goeth up",56,64],["H8553","to Timnath",65,75],["H1494","to shear",76,84],["H6629","his sheep",85,94]]},"38:14":{"text":"And she put her widow's garments off from her, and covered her with a vail, and wrapped herself, and sat in an open place, which is by the way to Timnath; for she saw that Shelah was grown, and she was not given unto him to wife.","words":[["H5493","And she put",0,11],["H0491","her widow's",12,23],["H0899","garments",24,32],["H5493","off",33,36],["H3680","from her, and covered her",37,62],["H6809","with a vail",63,74],["H5968","and wrapped herself",76,95],["H3427","and sat in",97,107],["H5869","an open",108,115],["H6607","place",116,121],["H1870","which is by the way",123,142],["H8553","to Timnath",143,153],["H7200","for she saw",155,166],["H7956","that Shelah",167,178],["H1431","was grown",179,188],["H5414","and she was not given",190,211],["H0802","unto him to wife",212,228]]},"38:15":{"text":"When Judah saw her, he thought her to be an harlot; because she had covered her face.","words":[["H3063","When Judah",0,10],["H7200","saw her",11,18],["H2803","he thought",20,30],["H2181","her to be an harlot",31,50],["H3680","because she had covered",52,75],["H6440","her face",76,84]]},"38:16":{"text":"And he turned unto her by the way, and said, Go to, I pray thee, let me come in unto thee; (for he knew not that she was his daughter in law.) And she said, What wilt thou give me, that thou mayest come in unto me?","words":[["H5186","And he turned",0,13],["H1870","unto her by the way",14,33],["H0559","and said",35,43],["H3051","Go to",45,50],["H0935","I pray thee, let me come in",52,79],["H3045","unto thee; (for he knew",80,103],["H3618","not that she was his daughter in law",104,140],["H0559",") And she said",141,155],["H5414","What wilt thou give",157,176],["H0935","me, that thou mayest come in",177,205]]},"38:17":{"text":"And he said, I will send thee a kid from the flock. And she said, Wilt thou give me a pledge, till thou send it?","words":[["H0559","And he said",0,11],["H7971","I will send",13,24],["H5795","thee a kid",25,35],["H1423","thee a kid",25,35],["H6629","from the flock",36,50],["H0559","And she said",52,64],["H5414","Wilt thou give",66,80],["H6162","me a pledge",81,92],["H7971","till thou send",94,108]]},"38:18":{"text":"And he said, What pledge shall I give thee? And she said, Thy signet, and thy bracelets, and thy staff that is in thine hand. And he gave it her, and came in unto her, and she conceived by him.","words":[["H0559","And he said",0,11],["H0834","What",13,17],["H6162","pledge",18,24],["H5414","shall I give",25,37],["H0559","thee? And she said",38,56],["H2368","Thy signet",58,68],["H6616","and thy bracelets",70,87],["H4294","and thy staff",89,102],["H3027","that is in thine hand",103,124],["H5414","And he gave",126,137],["H0935","it her, and came in",138,157],["H2029","unto her, and she conceived",158,185]]},"38:19":{"text":"And she arose, and went away, and laid by her vail from her, and put on the garments of her widowhood.","words":[["H6965","And she arose",0,13],["H3212","and went away",15,28],["H5493","and laid by",30,41],["H6809","her vail",42,50],["H3847","from her, and put on",51,71],["H0899","the garments",72,84],["H0491","of her widowhood",85,101]]},"38:20":{"text":"And Judah sent the kid by the hand of his friend the Adullamite, to receive his pledge from the woman's hand: but he found her not.","words":[["H3063","And Judah",0,9],["H7971","sent",10,14],["H1423","the kid",15,22],["H5795","the kid",15,22],["H3027","by the hand",23,34],["H7453","of his friend",35,48],["H5726","the Adullamite",49,63],["H3947","to receive",65,75],["H6162","his pledge",76,86],["H0802","from the woman's",87,103],["H3027","hand",104,108],["H4672","but he found her",110,126]]},"38:21":{"text":"Then he asked the men of that place, saying, Where is the harlot, that was openly by the way side? And they said, There was no harlot in this place.","words":[["H7592","Then he asked",0,13],["H0582","the men",14,21],["H4725","of that place",22,35],["H0559","saying",37,43],["H6948","Where is the harlot",45,64],["H5869","that was openly",66,81],["H1870","by the way side",82,97],["H0559","And they said",99,112],["H6948","There was no harlot",114,133],["H2088","in this",134,141]]},"38:22":{"text":"And he returned to Judah, and said, I cannot find her; and also the men of the place said, that there was no harlot in this place.","words":[["H7725","And he returned",0,15],["H3063","to Judah",16,24],["H0559","and said",26,34],["H3808","I cannot",36,44],["H4672","find",45,49],["H0582","her; and also the men",50,71],["H4725","of the place",72,84],["H0559","said",85,89],["H6948","that there was no harlot",91,115]]},"38:23":{"text":"And Judah said, Let her take it to her, lest we be shamed: behold, I sent this kid, and thou hast not found her.","words":[["H3063","And Judah",0,9],["H0559","said",10,14],["H3947","Let her take",16,28],["H0937","it to her, lest we be shamed",29,57],["H7971","behold, I sent",59,73],["H1423","this kid",74,82],["H4672","and thou hast not found",84,107]]},"38:24":{"text":"And it came to pass about three months after, that it was told Judah, saying, Tamar thy daughter in law hath played the harlot; and also, behold, she is with child by whoredom. And Judah said, Bring her forth, and let her be burnt.","words":[["H7969","And it came to pass about three",0,31],["H2320","months",32,38],["H5046","after, that it was told",39,62],["H3063","Judah",63,68],["H0559","saying",70,76],["H8559","Tamar",78,83],["H3618","thy daughter in law",84,103],["H2181","hath played the harlot",104,126],["H2030","and also, behold, she is with child",128,163],["H2183","by whoredom",164,175],["H3063","And Judah",177,186],["H0559","said",187,191],["H3318","Bring her forth",193,208],["H8313","and let her be burnt",210,230]]},"38:25":{"text":"When she was brought forth, she sent to her father in law, saying, By the man, whose these are, am I with child: and she said, Discern, I pray thee, whose are these, the signet, and bracelets, and staff.","words":[["H3318","When she was brought forth",0,26],["H7971","she sent",28,36],["H2524","to her father in law",37,57],["H0559","saying",59,65],["H0376","By the man",67,77],["H2030","whose these are, am I with child",79,111],["H0559","and she said",113,125],["H5234","Discern",127,134],["H2858","I pray thee, whose are these, the signet",136,176],["H6616","and bracelets",178,191],["H4294","and staff",193,202]]},"38:26":{"text":"And Judah acknowledged them, and said, She hath been more righteous than I; because that I gave her not to Shelah my son. And he knew her again no more.","words":[["H3063","And Judah",0,9],["H5234","acknowledged",10,22],["H0559","them, and said",23,37],["H6663","She hath been more righteous",39,67],["H5414","than I; because that I gave",68,95],["H7956","her not to Shelah",96,113],["H1121","my son",114,120],["H3045","And he knew her",122,137],["H3254","again",138,143]]},"38:27":{"text":"And it came to pass in the time of her travail, that, behold, twins were in her womb.","words":[["H6256","And it came to pass in the time",0,31],["H3205","of her travail",32,46],["H8380","that, behold, twins",48,67],["H0990","were in her womb",68,84]]},"38:28":{"text":"And it came to pass, when she travailed, that the one put out his hand: and the midwife took and bound upon his hand a scarlet thread, saying, This came out first.","words":[["H3205","And it came to pass, when she travailed",0,39],["H5414","that the one put out",41,61],["H3027","his hand",62,70],["H3205","and the midwife",72,87],["H3947","took",88,92],["H7194","and bound",93,102],["H3027","upon his hand",103,116],["H8144","a scarlet thread",117,133],["H0559","saying",135,141],["H3318","This came out",143,156],["H7223","first",157,162]]},"38:29":{"text":"And it came to pass, as he drew back his hand, that, behold, his brother came out: and she said, How hast thou broken forth? this breach be upon thee: therefore his name was called Pharez.","words":[["H7725","And it came to pass, as he drew back",0,36],["H3027","his hand",37,45],["H0251","that, behold, his brother",47,72],["H3318","came out",73,81],["H0559","and she said",83,95],["H6555","How hast thou broken forth",97,123],["H6556","this breach",125,136],["H8034","be upon thee: therefore his name",137,169],["H7121","was called",170,180],["H6557","Pharez",181,187]]},"38:30":{"text":"And afterward came out his brother, that had the scarlet thread upon his hand: and his name was called Zarah.","words":[["H0310","And afterward",0,13],["H3318","came out",14,22],["H0251","his brother",23,34],["H8144","that had the scarlet thread",36,63],["H3027","upon his hand",64,77],["H8034","and his name",79,91],["H7121","was called",92,102],["H2226","Zarah",103,108]]},"39:1":{"text":"And Joseph was brought down to Egypt; and Potiphar, an officer of Pharaoh, captain of the guard, an Egyptian, bought him of the hands of the Ishmeelites, which had brought him down thither.","words":[["H3130","And Joseph",0,10],["H3381","was brought down",11,27],["H4714","to Egypt",28,36],["H6318","and Potiphar",38,50],["H5631","an officer",52,62],["H6547","of Pharaoh",63,73],["H8269","captain",75,82],["H2876","of the guard",83,95],["H0376","an Egyptian",97,108],["H4713","an Egyptian",97,108],["H7069","bought",110,116],["H3027","him of the hands",117,133],["H3459","of the Ishmeelites",134,152],["H3381","which had brought him down",154,180]]},"39:2":{"text":"And the LORD was with Joseph, and he was a prosperous man; and he was in the house of his master the Egyptian.","words":[["H3068","And the LORD",0,12],["H3130","was with Joseph",13,28],["H6743","and he was a prosperous",30,53],["H0376","man",54,57],["H1004","and he was in the house",59,82],["H0113","of his master",83,96],["H4713","the Egyptian",97,109]]},"39:3":{"text":"And his master saw that the LORD was with him, and that the LORD made all that he did to prosper in his hand.","words":[["H0113","And his master",0,14],["H7200","saw",15,18],["H3068","that the LORD",19,32],["H3068","was with him, and that the LORD",33,64],["H6213","made all that he did",65,85],["H6743","to prosper",86,96],["H3027","in his hand",97,108]]},"39:4":{"text":"And Joseph found grace in his sight, and he served him: and he made him overseer over his house, and all that he had he put into his hand.","words":[["H3130","And Joseph",0,10],["H4672","found",11,16],["H2580","grace",17,22],["H5869","in his sight",23,35],["H8334","and he served",37,50],["H6485","him: and he made him overseer",51,80],["H1004","over his house",81,95],["H3426","and all that he had",97,116],["H5414","he put",117,123],["H3027","into his hand",124,137]]},"39:5":{"text":"And it came to pass from the time that he had made him overseer in his house, and over all that he had, that the LORD blessed the Egyptian's house for Joseph's sake; and the blessing of the LORD was upon all that he had in the house, and in the field.","words":[["H0227","And it came to pass from the time",0,33],["H6485","that he had made him overseer",34,63],["H1004","in his house",64,76],["H3426","and over all that he had",78,102],["H3068","that the LORD",104,117],["H1288","blessed",118,125],["H4713","the Egyptian's",126,140],["H1004","house",141,146],["H3130","for Joseph's",147,159],["H1558","sake",160,164],["H1293","and the blessing",166,182],["H3068","of the LORD",183,194],["H3426","was upon all that he had",195,219],["H1004","in the house",220,232],["H7704","and in the field",234,250]]},"39:6":{"text":"And he left all that he had in Joseph's hand; and he knew not ought he had, save the bread which he did eat. And Joseph was a goodly person, and well favoured.","words":[["H5800","And he left",0,11],["H3130","all that he had in Joseph's",12,39],["H3027","hand",40,44],["H3045","and he knew",46,57],["H3972","not ought",58,67],["H0518","he had, save",68,80],["H3899","the bread",81,90],["H0398","which he did eat",91,107],["H3130","And Joseph",109,119],["H8389","was a goodly",120,132],["H3303","person, and well",133,149],["H4758","favoured",150,158]]},"39:7":{"text":"And it came to pass after these things, that his master's wife cast her eyes upon Joseph; and she said, Lie with me.","words":[["H0310","And it came to pass after",0,25],["H1697","these things",26,38],["H0113","that his master's",40,57],["H0802","wife",58,62],["H5375","cast",63,67],["H5869","her eyes",68,76],["H3130","upon Joseph",77,88],["H0559","and she said",90,102],["H7901","Lie",104,107]]},"39:8":{"text":"But he refused, and said unto his master's wife, Behold, my master wotteth not what is with me in the house, and he hath committed all that he hath to my hand;","words":[["H3985","But he refused",0,14],["H0559","and said",16,24],["H0113","unto his master's",25,42],["H0802","wife",43,47],["H0113","Behold, my master",49,66],["H3045","wotteth",67,74],["H1004","not what is with me in the house",75,107],["H5414","and he hath committed",109,130],["H3426","all that he hath",131,147],["H3027","to my hand",148,158]]},"39:9":{"text":"There is none greater in this house than I; neither hath he kept back any thing from me but thee, because thou art his wife: how then can I do this great wickedness, and sin against God?","words":[["H1419","There is none greater",0,21],["H1004","in this house",22,35],["H3808","than I; neither",36,51],["H2820","hath he kept back",52,69],["H3972","any thing",70,79],["H0834","from me but thee, because",80,105],["H0859","thou",106,110],["H0802","art his wife",111,123],["H6213","how then can I do",125,142],["H1419","this great",143,153],["H7451","wickedness",154,164],["H2398","and sin",166,173],["H0430","against God",174,185]]},"39:10":{"text":"And it came to pass, as she spake to Joseph day by day, that he hearkened not unto her, to lie by her, or to be with her.","words":[["H1696","And it came to pass, as she spake",0,33],["H3130","to Joseph",34,43],["H3117","day",44,47],["H3117","by day",48,54],["H8085","that he hearkened",56,73],["H7901","not unto her, to lie",74,94],["H0681","by her",95,101]]},"39:11":{"text":"And it came to pass about this time, that Joseph went into the house to do his business; and there was none of the men of the house there within.","words":[["H3117","And it came to pass about this time",0,35],["H0935","that Joseph went",37,53],["H1004","into the house",54,68],["H6213","to do",69,74],["H4399","his business",75,87],["H0376","and there was none of the men",89,118],["H0582","and there was none of the men",89,118],["H1004","of the house",119,131]]},"39:12":{"text":"And she caught him by his garment, saying, Lie with me: and he left his garment in her hand, and fled, and got him out.","words":[["H8610","And she caught",0,14],["H0899","him by his garment",15,33],["H0559","saying",35,41],["H7901","Lie",43,46],["H5800","with me: and he left",47,67],["H0899","his garment",68,79],["H3027","in her hand",80,91],["H5127","and fled",93,101],["H3318","and got",103,110],["H2351","him out",111,118]]},"39:13":{"text":"And it came to pass, when she saw that he had left his garment in her hand, and was fled forth,","words":[["H7200","And it came to pass, when she saw",0,33],["H5800","that he had left",34,50],["H0899","his garment",51,62],["H3027","in her hand",63,74],["H5127","and was fled",76,88],["H2351","forth",89,94]]},"39:14":{"text":"That she called unto the men of her house, and spake unto them, saying, See, he hath brought in an Hebrew unto us to mock us; he came in unto me to lie with me, and I cried with a loud voice:","words":[["H7121","That she called",0,15],["H0582","unto the men",16,28],["H1004","of her house",29,41],["H0559","and spake",43,52],["H0559","unto them, saying",53,70],["H7200","See",72,75],["H0935","he hath brought in",77,95],["H0376","an Hebrew",96,105],["H5680","an Hebrew",96,105],["H6711","unto us to mock",106,121],["H0935","us; he came in",122,136],["H7901","unto me to lie",137,151],["H7121","with me, and I cried",152,172],["H1419","with a loud",173,184],["H6963","voice",185,190]]},"39:15":{"text":"And it came to pass, when he heard that I lifted up my voice and cried, that he left his garment with me, and fled, and got him out.","words":[["H8085","And it came to pass, when he heard",0,34],["H7311","that I lifted up",35,51],["H6963","my voice",52,60],["H7121","and cried",61,70],["H5800","that he left",72,84],["H0899","his garment",85,96],["H0681","with me",97,104],["H5127","and fled",106,114],["H3318","and got him",116,127],["H2351","out",128,131]]},"39:16":{"text":"And she laid up his garment by her, until his lord came home.","words":[["H3240","And she laid up",0,15],["H0899","his garment",16,27],["H0681","by her",28,34],["H0113","until his lord",36,50],["H0935","came",51,55],["H1004","home",56,60]]},"39:17":{"text":"And she spake unto him according to these words, saying, The Hebrew servant, which thou hast brought unto us, came in unto me to mock me:","words":[["H1696","And she spake",0,13],["H1697","unto him according to these words",14,47],["H0559","saying",49,55],["H5680","The Hebrew",57,67],["H5650","servant",68,75],["H0935","which thou hast brought",77,100],["H0935","unto us, came in",101,117],["H6711","unto me to mock",118,133]]},"39:18":{"text":"And it came to pass, as I lifted up my voice and cried, that he left his garment with me, and fled out.","words":[["H7311","And it came to pass, as I lifted up",0,35],["H6963","my voice",36,44],["H7121","and cried",45,54],["H5800","that he left",56,68],["H0899","his garment",69,80],["H0681","with me",81,88],["H5127","and fled",90,98],["H2351","out",99,102]]},"39:19":{"text":"And it came to pass, when his master heard the words of his wife, which she spake unto him, saying, After this manner did thy servant to me; that his wrath was kindled.","words":[["H0113","And it came to pass, when his master",0,36],["H8085","heard",37,42],["H1697","the words",43,52],["H0802","of his wife",53,64],["H1696","which she spake",66,81],["H0559","unto him, saying",82,98],["H1697","After this manner",100,117],["H6213","did",118,121],["H5650","thy servant",122,133],["H0639","to me; that his wrath",134,155],["H2734","was kindled",156,167]]},"39:20":{"text":"And Joseph's master took him, and put him into the prison, a place where the king's prisoners were bound: and he was there in the prison.","words":[["H3130","And Joseph's",0,12],["H0113","master",13,19],["H3947","took",20,24],["H5414","him, and put him",25,41],["H1004","into the prison",42,57],["H5470","into the prison",42,57],["H4725","a place",59,66],["H4428","where the king's",67,83],["H0615","prisoners",84,93],["H0631","were bound",94,104],["H1004","and he was there in the prison",106,136],["H5470","and he was there in the prison",106,136]]},"39:21":{"text":"But the LORD was with Joseph, and shewed him mercy, and gave him favour in the sight of the keeper of the prison.","words":[["H3068","But the LORD",0,12],["H3130","was with Joseph",13,28],["H5186","and shewed",30,40],["H2617","him mercy",41,50],["H5414","and gave",52,60],["H2580","him favour",61,71],["H5869","in the sight",72,84],["H8269","of the keeper",85,98],["H1004","of the prison",99,112],["H5470","of the prison",99,112]]},"39:22":{"text":"And the keeper of the prison committed to Joseph's hand all the prisoners that were in the prison; and whatsoever they did there, he was the doer of it.","words":[["H8269","And the keeper",0,14],["H1004","of the prison",15,28],["H5470","of the prison",15,28],["H5414","committed",29,38],["H3130","to Joseph's",39,50],["H3027","hand",51,55],["H0615","all the prisoners",56,73],["H1004","that were in the prison",74,97],["H5470","that were in the prison",74,97],["H6213","and whatsoever they did",99,122],["H6213","there, he was the doer",123,145]]},"39:23":{"text":"The keeper of the prison looked not to any thing that was under his hand; because the LORD was with him, and that which he did, the LORD made it to prosper.","words":[["H8269","The keeper",0,10],["H1004","of the prison",11,24],["H5470","of the prison",11,24],["H7200","looked",25,31],["H3972","not to any thing",32,48],["H3027","that was under his hand",49,72],["H3068","because the LORD",74,90],["H6213","was with him, and that which he did",91,126],["H3068","the LORD",128,136],["H6743","made it to prosper",137,155]]},"40:1":{"text":"And it came to pass after these things, that the butler of the king of Egypt and his baker had offended their lord the king of Egypt.","words":[["H0310","And it came to pass after",0,25],["H1697","these things",26,38],["H8248","that the butler",40,55],["H4428","of the king",56,67],["H4714","of Egypt",68,76],["H0644","and his baker",77,90],["H2398","had offended",91,103],["H0113","their lord",104,114],["H4428","the king",115,123],["H4714","of Egypt",124,132]]},"40:2":{"text":"And Pharaoh was wroth against two of his officers, against the chief of the butlers, and against the chief of the bakers.","words":[["H6547","And Pharaoh",0,11],["H7107","was wroth",12,21],["H5921","against",22,29],["H8147","two",30,33],["H5631","of his officers",34,49],["H8269","against the chief",51,68],["H8248","of the butlers",69,83],["H8269","and against the chief",85,106],["H0644","of the bakers",107,120]]},"40:3":{"text":"And he put them in ward in the house of the captain of the guard, into the prison, the place where Joseph was bound.","words":[["H5414","And he put",0,10],["H4929","them in ward",11,23],["H1004","in the house",24,36],["H8269","of the captain",37,51],["H2876","of the guard",52,64],["H1004","into the prison",66,81],["H5470","into the prison",66,81],["H4725","the place",83,92],["H3130","where Joseph",93,105],["H0631","was bound",106,115]]},"40:4":{"text":"And the captain of the guard charged Joseph with them, and he served them: and they continued a season in ward.","words":[["H8269","And the captain",0,15],["H2876","of the guard",16,28],["H6485","charged",29,36],["H3130","Joseph",37,43],["H8334","with them, and he served",44,68],["H3117","them: and they continued a season",69,102],["H4929","in ward",103,110]]},"40:5":{"text":"And they dreamed a dream both of them, each man his dream in one night, each man according to the interpretation of his dream, the butler and the baker of the king of Egypt, which were bound in the prison.","words":[["H2492","And they dreamed",0,16],["H2472","a dream",17,24],["H8147","both of them",25,37],["H0376","each man",39,47],["H2472","his dream",48,57],["H0259","in one",58,64],["H3915","night",65,70],["H0376","each man",72,80],["H6623","according to the interpretation",81,112],["H2472","of his dream",113,125],["H8248","the butler",127,137],["H0644","and the baker",138,151],["H4428","of the king",152,163],["H4714","of Egypt",164,172],["H0631","which were bound",174,190],["H1004","in the prison",191,204],["H5470","in the prison",191,204]]},"40:6":{"text":"And Joseph came in unto them in the morning, and looked upon them, and, behold, they were sad.","words":[["H3130","And Joseph",0,10],["H0935","came in",11,18],["H1242","unto them in the morning",19,43],["H7200","and looked",45,55],["H2196","upon them, and, behold, they were sad",56,93]]},"40:7":{"text":"And he asked Pharaoh's officers that were with him in the ward of his lord's house, saying, Wherefore look ye so sadly to day?","words":[["H7592","And he asked",0,12],["H6547","Pharaoh's",13,22],["H5631","officers",23,31],["H4929","that were with him in the ward",32,62],["H0113","of his lord's",63,76],["H1004","house",77,82],["H0559","saying",84,90],["H6440","Wherefore look",92,106],["H7451","ye so sadly",107,118],["H3117","to day",119,125]]},"40:8":{"text":"And they said unto him, We have dreamed a dream, and there is no interpreter of it. And Joseph said unto them, Do not interpretations belong to God? tell me them, I pray you.","words":[["H0559","And they said",0,13],["H2492","unto him, We have dreamed",14,39],["H2472","a dream",40,47],["H6622","and there is no interpreter",49,76],["H3130","of it. And Joseph",77,94],["H0559","said",95,99],["H6623","unto them, Do not interpretations",100,133],["H0430","belong to God",134,147],["H5608","tell me",149,156]]},"40:9":{"text":"And the chief butler told his dream to Joseph, and said to him, In my dream, behold, a vine was before me;","words":[["H8269","And the chief",0,13],["H8248","butler",14,20],["H5608","told",21,25],["H2472","his dream",26,35],["H3130","to Joseph",36,45],["H0559","and said",47,55],["H2472","to him, In my dream",56,75],["H1612","behold, a vine",77,91],["H6440","was before me",92,105]]},"40:10":{"text":"And in the vine were three branches: and it was as though it budded, and her blossoms shot forth; and the clusters thereof brought forth ripe grapes:","words":[["H1612","And in the vine",0,15],["H7969","were three",16,26],["H8299","branches",27,35],["H6524","and it was as though it budded",37,67],["H5322","and her blossoms",69,85],["H5927","shot forth",86,96],["H0811","and the clusters",98,114],["H1310","thereof brought forth ripe",115,141],["H6025","grapes",142,148]]},"40:11":{"text":"And Pharaoh's cup was in my hand: and I took the grapes, and pressed them into Pharaoh's cup, and I gave the cup into Pharaoh's hand.","words":[["H6547","And Pharaoh's",0,13],["H3563","cup",14,17],["H3027","was in my hand",18,32],["H3947","and I took",34,44],["H6025","the grapes",45,55],["H7818","and pressed",57,68],["H6547","them into Pharaoh's",69,88],["H3563","cup",89,92],["H5414","and I gave",94,104],["H3563","the cup",105,112],["H6547","into Pharaoh's",113,127],["H3709","hand",128,132]]},"40:12":{"text":"And Joseph said unto him, This is the interpretation of it: The three branches are three days:","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H6623","unto him, This is the interpretation",16,52],["H7969","of it: The three",53,69],["H8299","branches",70,78],["H7969","are three",79,88],["H3117","days",89,93]]},"40:13":{"text":"Yet within three days shall Pharaoh lift up thine head, and restore thee unto thy place: and thou shalt deliver Pharaoh's cup into his hand, after the former manner when thou wast his butler.","words":[["H5750","Yet",0,3],["H7969","within three",4,16],["H3117","days",17,21],["H6547","shall Pharaoh",22,35],["H5375","lift up",36,43],["H7218","thine head",44,54],["H7725","and restore",56,67],["H3653","thee unto thy place",68,87],["H5414","and thou shalt deliver",89,111],["H6547","Pharaoh's",112,121],["H3563","cup",122,125],["H3027","into his hand",126,139],["H7223","after the former",141,157],["H4941","manner",158,164],["H8248","when thou wast his butler",165,190]]},"40:14":{"text":"But think on me when it shall be well with thee, and shew kindness, I pray thee, unto me, and make mention of me unto Pharaoh, and bring me out of this house:","words":[["H2142","But think",0,9],["H3190","on me when it shall be well",10,37],["H6213","with thee, and shew",38,57],["H2617","kindness",58,66],["H2142","I pray thee, unto me, and make mention",68,106],["H6547","of me unto Pharaoh",107,125],["H3318","and bring me",127,139],["H1004","out of this house",140,157]]},"40:15":{"text":"For indeed I was stolen away out of the land of the Hebrews: and here also have I done nothing that they should put me into the dungeon.","words":[["H1589","For indeed I was stolen away",0,28],["H0776","out of the land",29,44],["H5680","of the Hebrews",45,59],["H6213","and here also have I done",61,86],["H3972","nothing",87,94],["H7760","that they should put",95,115],["H0953","me into the dungeon",116,135]]},"40:16":{"text":"When the chief baker saw that the interpretation was good, he said unto Joseph, I also was in my dream, and, behold, I had three white baskets on my head:","words":[["H8269","When the chief",0,14],["H0644","baker",15,20],["H7200","saw",21,24],["H6622","that the interpretation",25,48],["H2896","was good",49,57],["H0559","he said",59,66],["H3130","unto Joseph",67,78],["H0637","I also",80,86],["H2472","was in my dream",87,102],["H7969","and, behold, I had three",104,128],["H2751","white",129,134],["H5536","baskets",135,142],["H7218","on my head",143,153]]},"40:17":{"text":"And in the uppermost basket there was of all manner of bakemeats for Pharaoh; and the birds did eat them out of the basket upon my head.","words":[["H5945","And in the uppermost",0,20],["H5536","basket",21,27],["H3978","there was of all manner",28,51],["H4639","of bakemeats",52,64],["H0644","of bakemeats",52,64],["H6547","for Pharaoh",65,76],["H5775","and the birds",78,91],["H0398","did eat",92,99],["H5536","them out of the basket",100,122],["H5921","upon",123,127],["H7218","my head",128,135]]},"40:18":{"text":"And Joseph answered and said, This is the interpretation thereof: The three baskets are three days:","words":[["H3130","And Joseph",0,10],["H6030","answered",11,19],["H0559","and said",20,28],["H6623","This is the interpretation",30,56],["H7969","thereof: The three",57,75],["H5536","baskets",76,83],["H7969","are three",84,93],["H3117","days",94,98]]},"40:19":{"text":"Yet within three days shall Pharaoh lift up thy head from off thee, and shall hang thee on a tree; and the birds shall eat thy flesh from off thee.","words":[["H7969","Yet within three",0,16],["H3117","days",17,21],["H6547","shall Pharaoh",22,35],["H5375","lift up",36,43],["H7218","thy head",44,52],["H8518","from off thee, and shall hang",53,82],["H6086","thee on a tree",83,97],["H5775","and the birds",99,112],["H0398","shall eat",113,122],["H1320","thy flesh",123,132]]},"40:20":{"text":"And it came to pass the third day, which was Pharaoh's birthday, that he made a feast unto all his servants: and he lifted up the head of the chief butler and of the chief baker among his servants.","words":[["H7992","And it came to pass the third",0,29],["H3117","day",30,33],["H6547","which was Pharaoh's",35,54],["H3117","birthday",55,63],["H3205","birthday",55,63],["H6213","that he made",65,77],["H4960","a feast",78,85],["H5650","unto all his servants",86,107],["H5375","and he lifted up",109,125],["H7218","the head",126,134],["H8269","of the chief",135,147],["H8248","butler",148,154],["H8269","and of the chief",155,171],["H0644","baker",172,177],["H8432","among",178,183],["H5650","his servants",184,196]]},"40:21":{"text":"And he restored the chief butler unto his butlership again; and he gave the cup into Pharaoh's hand:","words":[["H7725","And he restored",0,15],["H8269","the chief",16,25],["H8248","butler",26,32],["H4945","unto his butlership",33,52],["H7725","again",53,58],["H5414","and he gave",60,71],["H3563","the cup",72,79],["H6547","into Pharaoh's",80,94],["H3709","hand",95,99]]},"40:22":{"text":"But he hanged the chief baker: as Joseph had interpreted to them.","words":[["H8518","But he hanged",0,13],["H8269","the chief",14,23],["H0644","baker",24,29],["H3130","as Joseph",31,40],["H6622","had interpreted",41,56]]},"40:23":{"text":"Yet did not the chief butler remember Joseph, but forgat him.","words":[["H8269","Yet did not the chief",0,21],["H8248","butler",22,28],["H2142","remember",29,37],["H3130","Joseph",38,44],["H7911","but forgat",46,56]]},"41:1":{"text":"And it came to pass at the end of two full years, that Pharaoh dreamed: and, behold, he stood by the river.","words":[["H7093","And it came to pass at the end",0,30],["H3117","of two full",31,42],["H8141","years",43,48],["H6547","that Pharaoh",50,62],["H2492","dreamed",63,70],["H5975","and, behold, he stood",72,93],["H2975","by the river",94,106]]},"41:2":{"text":"And, behold, there came up out of the river seven well favoured kine and fatfleshed; and they fed in a meadow.","words":[["H5927","And, behold, there came up",0,26],["H2975","out of the river",27,43],["H7651","seven",44,49],["H3303","well",50,54],["H4758","favoured",55,63],["H6510","kine",64,68],["H1277","and fatfleshed",69,83],["H1320","and fatfleshed",69,83],["H7462","and they fed",85,97],["H0260","in a meadow",98,109]]},"41:3":{"text":"And, behold, seven other kine came up after them out of the river, ill favoured and leanfleshed; and stood by the other kine upon the brink of the river.","words":[["H7651","And, behold, seven",0,18],["H0312","other",19,24],["H6510","kine",25,29],["H5927","came up",30,37],["H0310","after them",38,48],["H2975","out of the river",49,65],["H7451","ill",67,70],["H4758","favoured",71,79],["H1851","and leanfleshed",80,95],["H1320","and leanfleshed",80,95],["H5975","and stood",97,106],["H0681","by",107,109],["H6510","the other kine",110,124],["H8193","upon the brink",125,139],["H2975","of the river",140,152]]},"41:4":{"text":"And the ill favoured and leanfleshed kine did eat up the seven well favoured and fat kine. So Pharaoh awoke.","words":[["H7451","And the ill",0,11],["H4758","favoured",12,20],["H1851","and leanfleshed",21,36],["H1320","and leanfleshed",21,36],["H6510","kine",37,41],["H0398","did eat up",42,52],["H7651","the seven",53,62],["H3303","well",63,67],["H4758","favoured",68,76],["H1277","and fat",77,84],["H6510","kine",85,89],["H6547","So Pharaoh",91,101],["H3364","awoke",102,107]]},"41:5":{"text":"And he slept and dreamed the second time: and, behold, seven ears of corn came up upon one stalk, rank and good.","words":[["H3462","And he slept",0,12],["H2492","and dreamed",13,24],["H8145","the second time",25,40],["H7651","and, behold, seven",42,60],["H7641","ears of corn",61,73],["H5927","came up",74,81],["H0259","upon one",82,90],["H7070","stalk",91,96],["H1277","rank",98,102],["H2896","and good",103,111]]},"41:6":{"text":"And, behold, seven thin ears and blasted with the east wind sprung up after them.","words":[["H7651","And, behold, seven",0,18],["H1851","thin",19,23],["H7641","ears",24,28],["H7710","and blasted",29,40],["H6921","with the east wind",41,59],["H6779","sprung up",60,69],["H0310","after them",70,80]]},"41:7":{"text":"And the seven thin ears devoured the seven rank and full ears. And Pharaoh awoke, and, behold, it was a dream.","words":[["H1851","And the seven thin",0,18],["H7641","ears",19,23],["H1104","devoured",24,32],["H7651","the seven",33,42],["H1277","rank",43,47],["H4392","and full",48,56],["H7641","ears",57,61],["H6547","And Pharaoh",63,74],["H3364","awoke",75,80],["H2472","and, behold, it was a dream",82,109]]},"41:8":{"text":"And it came to pass in the morning that his spirit was troubled; and he sent and called for all the magicians of Egypt, and all the wise men thereof: and Pharaoh told them his dream; but there was none that could interpret them unto Pharaoh.","words":[["H1242","And it came to pass in the morning",0,34],["H7307","that his spirit",35,50],["H6470","was troubled",51,63],["H7971","and he sent",65,76],["H7121","and called",77,87],["H2748","for all the magicians",88,109],["H4714","of Egypt",110,118],["H2450","and all the wise men",120,140],["H6547","thereof: and Pharaoh",141,161],["H5608","told",162,166],["H2472","them his dream",167,181],["H6622","but there was none that could interpret",183,222],["H6547","them unto Pharaoh",223,240]]},"41:9":{"text":"Then spake the chief butler unto Pharaoh, saying, I do remember my faults this day:","words":[["H1696","Then spake",0,10],["H8269","the chief",11,20],["H8248","butler",21,27],["H6547","unto Pharaoh",28,40],["H0559","saying",42,48],["H2142","I do remember",50,63],["H2399","my faults",64,73],["H3117","this day",74,82]]},"41:10":{"text":"Pharaoh was wroth with his servants, and put me in ward in the captain of the guard's house, both me and the chief baker:","words":[["H6547","Pharaoh",0,7],["H7107","was wroth",8,17],["H5650","with his servants",18,35],["H5414","and put",37,44],["H4929","me in ward",45,55],["H8269","in the captain",56,70],["H2876","of the guard's",71,85],["H1004","house",86,91],["H8269","both me and the chief",93,114],["H0644","baker",115,120]]},"41:11":{"text":"And we dreamed a dream in one night, I and he; we dreamed each man according to the interpretation of his dream.","words":[["H2492","And we dreamed",0,14],["H2472","a dream",15,22],["H0259","in one",23,29],["H3915","night",30,35],["H2492","I and he; we dreamed",37,57],["H0376","each man",58,66],["H6623","according to the interpretation",67,98],["H2472","of his dream",99,111]]},"41:12":{"text":"And there was there with us a young man, an Hebrew, servant to the captain of the guard; and we told him, and he interpreted to us our dreams; to each man according to his dream he did interpret.","words":[["H5288","And there was there with us a young man",0,39],["H5680","an Hebrew",41,50],["H5650","servant",52,59],["H8269","to the captain",60,74],["H2876","of the guard",75,87],["H5608","and we told",89,100],["H6622","him, and he interpreted",101,124],["H2472","to us our dreams",125,141],["H0376","to each man",143,154],["H2472","according to his dream",155,177],["H6622","he did interpret",178,194]]},"41:13":{"text":"And it came to pass, as he interpreted to us, so it was; me he restored unto mine office, and him he hanged.","words":[["H6622","And it came to pass, as he interpreted",0,38],["H7725","to us, so it was; me he restored",39,71],["H3653","unto mine office",72,88],["H8518","and him he hanged",90,107]]},"41:14":{"text":"Then Pharaoh sent and called Joseph, and they brought him hastily out of the dungeon: and he shaved himself, and changed his raiment, and came in unto Pharaoh.","words":[["H6547","Then Pharaoh",0,12],["H7971","sent",13,17],["H7121","and called",18,28],["H3130","Joseph",29,35],["H7323","and they brought him hastily",37,65],["H0953","out of the dungeon",66,84],["H1548","and he shaved",86,99],["H2498","himself, and changed",100,120],["H8071","his raiment",121,132],["H0935","and came in",134,145],["H6547","unto Pharaoh",146,158]]},"41:15":{"text":"And Pharaoh said unto Joseph, I have dreamed a dream, and there is none that can interpret it: and I have heard say of thee, that thou canst understand a dream to interpret it.","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H3130","unto Joseph",17,28],["H2492","I have dreamed",30,44],["H2472","a dream",45,52],["H6622","and there is none that can interpret",54,90],["H8085","it: and I have heard",91,111],["H0559","say",112,115],["H8085","of thee, that thou canst understand",116,151],["H2472","a dream",152,159],["H6622","to interpret",160,172]]},"41:16":{"text":"And Joseph answered Pharaoh, saying, It is not in me: God shall give Pharaoh an answer of peace.","words":[["H3130","And Joseph",0,10],["H6030","answered",11,19],["H6547","Pharaoh",20,27],["H0559","saying",29,35],["H1107","It is not in me",37,52],["H0430","God",54,57],["H6030","shall give",58,68],["H6547","Pharaoh",69,76],["H6030","an answer",77,86],["H7965","of peace",87,95]]},"41:17":{"text":"And Pharaoh said unto Joseph, In my dream, behold, I stood upon the bank of the river:","words":[["H6547","And Pharaoh",0,11],["H1696","said",12,16],["H3130","unto Joseph",17,28],["H2472","In my dream",30,41],["H5975","behold, I stood",43,58],["H8193","upon the bank",59,72],["H2975","of the river",73,85]]},"41:18":{"text":"And, behold, there came up out of the river seven kine, fatfleshed and well favoured; and they fed in a meadow:","words":[["H5927","And, behold, there came up",0,26],["H2975","out of the river",27,43],["H7651","seven",44,49],["H6510","kine",50,54],["H1277","fatfleshed",56,66],["H1320","fatfleshed",56,66],["H3303","and well",67,75],["H8389","favoured",76,84],["H7462","and they fed",86,98],["H0260","in a meadow",99,110]]},"41:19":{"text":"And, behold, seven other kine came up after them, poor and very ill favoured and leanfleshed, such as I never saw in all the land of Egypt for badness:","words":[["H7651","And, behold, seven",0,18],["H0312","other",19,24],["H6510","kine",25,29],["H5927","came up",30,37],["H0310","after them",38,48],["H1803","poor",50,54],["H3966","and very",55,63],["H7451","ill",64,67],["H8389","favoured",68,76],["H7534","and leanfleshed",77,92],["H1320","and leanfleshed",77,92],["H2007","such",94,98],["H3808","as I never",99,109],["H7200","saw",110,113],["H0776","in all the land",114,129],["H4714","of Egypt",130,138],["H7455","for badness",139,150]]},"41:20":{"text":"And the lean and the ill favoured kine did eat up the first seven fat kine:","words":[["H7534","And the lean",0,12],["H7451","and the ill favoured",13,33],["H6510","kine",34,38],["H0398","did eat up",39,49],["H7223","the first",50,59],["H7651","seven",60,65],["H1277","fat",66,69],["H6510","kine",70,74]]},"41:21":{"text":"And when they had eaten them up, it could not be known that they had eaten them; but they were still ill favoured, as at the beginning. So I awoke.","words":[["H0935","And when they had eaten them up",0,31],["H7130","And when they had eaten them up",0,31],["H3045","it could not be known",33,54],["H0935","that they had eaten them",55,79],["H7130","that they had eaten them",55,79],["H4758","but they were still",81,100],["H7451","ill favoured",101,113],["H8462","as at the beginning",115,134],["H3364","So I awoke",136,146]]},"41:22":{"text":"And I saw in my dream, and, behold, seven ears came up in one stalk, full and good:","words":[["H7200","And I saw",0,9],["H2472","in my dream",10,21],["H7651","and, behold, seven",23,41],["H7641","ears",42,46],["H5927","came up",47,54],["H0259","in one",55,61],["H7070","stalk",62,67],["H4392","full",69,73],["H2896","and good",74,82]]},"41:23":{"text":"And, behold, seven ears, withered, thin, and blasted with the east wind, sprung up after them:","words":[["H7651","And, behold, seven",0,18],["H7641","ears",19,23],["H6798","withered",25,33],["H1851","thin",35,39],["H7710","and blasted",41,52],["H6921","with the east wind",53,71],["H6779","sprung up",73,82],["H0310","after them",83,93]]},"41:24":{"text":"And the thin ears devoured the seven good ears: and I told this unto the magicians; but there was none that could declare it to me.","words":[["H1851","And the thin",0,12],["H7641","ears",13,17],["H1104","devoured",18,26],["H7651","the seven",27,36],["H2896","good",37,41],["H7641","ears",42,46],["H0559","and I told",48,58],["H2748","this unto the magicians",59,82],["H5046","but there was none that could declare",84,121]]},"41:25":{"text":"And Joseph said unto Pharaoh, The dream of Pharaoh is one: God hath shewed Pharaoh what he is about to do.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H6547","unto Pharaoh",16,28],["H2472","The dream",30,39],["H6547","of Pharaoh",40,50],["H0259","is one",51,57],["H0430","God",59,62],["H5046","hath shewed",63,74],["H6547","Pharaoh",75,82],["H6213","what he is about to do",83,105]]},"41:26":{"text":"The seven good kine are seven years; and the seven good ears are seven years: the dream is one.","words":[["H7651","The seven",0,9],["H2896","good",10,14],["H6510","kine",15,19],["H7651","are seven",20,29],["H8141","years",30,35],["H7651","and the seven",37,50],["H2896","good",51,55],["H7641","ears",56,60],["H7651","are seven",61,70],["H8141","years",71,76],["H2472","the dream",78,87],["H0259","is one",88,94]]},"41:27":{"text":"And the seven thin and ill favoured kine that came up after them are seven years; and the seven empty ears blasted with the east wind shall be seven years of famine.","words":[["H7651","And the seven",0,13],["H7534","thin",14,18],["H7451","and ill favoured",19,35],["H6510","kine",36,40],["H5927","that came up",41,53],["H0310","after them",54,64],["H7651","are seven",65,74],["H8141","years",75,80],["H7651","and the seven",82,95],["H7386","empty",96,101],["H7641","ears",102,106],["H7710","blasted",107,114],["H6921","with the east wind",115,133],["H7651","shall be seven",134,148],["H8141","years",149,154],["H7458","of famine",155,164]]},"41:28":{"text":"This is the thing which I have spoken unto Pharaoh: What God is about to do he sheweth unto Pharaoh.","words":[["H1697","This is the thing",0,17],["H1696","which I have spoken",18,37],["H6547","unto Pharaoh",38,50],["H0430","What God",52,60],["H6213","is about to do",61,75],["H7200","he sheweth",76,86],["H6547","unto Pharaoh",87,99]]},"41:29":{"text":"Behold, there come seven years of great plenty throughout all the land of Egypt:","words":[["H0935","Behold, there come",0,18],["H7651","seven",19,24],["H8141","years",25,30],["H1419","of great",31,39],["H7647","plenty",40,46],["H0776","throughout all the land",47,70],["H4714","of Egypt",71,79]]},"41:30":{"text":"And there shall arise after them seven years of famine; and all the plenty shall be forgotten in the land of Egypt; and the famine shall consume the land;","words":[["H6965","And there shall arise",0,21],["H0310","after them",22,32],["H7651","seven",33,38],["H8141","years",39,44],["H7458","of famine",45,54],["H7647","and all the plenty",56,74],["H7911","shall be forgotten",75,93],["H0776","in the land",94,105],["H4714","of Egypt",106,114],["H7458","and the famine",116,130],["H3615","shall consume",131,144],["H0776","the land",145,153]]},"41:31":{"text":"And the plenty shall not be known in the land by reason of that famine following; for it shall be very grievous.","words":[["H7647","And the plenty",0,14],["H3045","shall not be known",15,33],["H0776","in the land",34,45],["H6440","by reason",46,55],["H7458","of that famine",56,70],["H0310","following",71,80],["H3651","following",71,80],["H3966","for it shall be very",82,102],["H3515","grievous",103,111]]},"41:32":{"text":"And for that the dream was doubled unto Pharaoh twice; it is because the thing is established by God, and God will shortly bring it to pass.","words":[["H2472","And for that the dream",0,22],["H8138","was doubled",23,34],["H6547","unto Pharaoh",35,47],["H6471","twice",48,53],["H1697","it is because the thing",55,78],["H3559","is established",79,93],["H5973","by",94,96],["H0430","God",97,100],["H0430","and God",102,109],["H4116","will shortly",110,122],["H6213","bring it to pass",123,139]]},"41:33":{"text":"Now therefore let Pharaoh look out a man discreet and wise, and set him over the land of Egypt.","words":[["H6547","Now therefore let Pharaoh",0,25],["H7200","look out",26,34],["H0376","a man",35,40],["H0995","discreet",41,49],["H2450","and wise",50,58],["H7896","and set",60,67],["H0776","him over the land",68,85],["H4714","of Egypt",86,94]]},"41:34":{"text":"Let Pharaoh do this, and let him appoint officers over the land, and take up the fifth part of the land of Egypt in the seven plenteous years.","words":[["H6547","Let Pharaoh",0,11],["H6213","do",12,14],["H6485","this, and let him appoint",15,40],["H6496","officers",41,49],["H0776","over the land",50,63],["H2567","and take up the fifth part",65,91],["H0776","of the land",92,103],["H4714","of Egypt",104,112],["H7651","in the seven",113,125],["H7647","plenteous",126,135],["H8141","years",136,141]]},"41:35":{"text":"And let them gather all the food of those good years that come, and lay up corn under the hand of Pharaoh, and let them keep food in the cities.","words":[["H6908","And let them gather",0,19],["H0400","all the food",20,32],["H2896","of those good",33,46],["H8141","years",47,52],["H0935","that come",53,62],["H6651","and lay up",64,74],["H1250","corn",75,79],["H3027","under the hand",80,94],["H6547","of Pharaoh",95,105],["H8104","and let them keep",107,124],["H0400","food",125,129],["H5892","in the cities",130,143]]},"41:36":{"text":"And that food shall be for store to the land against the seven years of famine, which shall be in the land of Egypt; that the land perish not through the famine.","words":[["H0400","And that food",0,13],["H6487","shall be for store",14,32],["H0776","to the land",33,44],["H7651","against the seven",45,62],["H8141","years",63,68],["H7458","of famine",69,78],["H0776","which shall be in the land",80,106],["H4714","of Egypt",107,115],["H0776","that the land",117,130],["H3772","perish",131,137],["H7458","not through the famine",138,160]]},"41:37":{"text":"And the thing was good in the eyes of Pharaoh, and in the eyes of all his servants.","words":[["H1697","And the thing",0,13],["H3190","was good",14,22],["H5869","in the eyes",23,34],["H6547","of Pharaoh",35,45],["H5869","and in the eyes",47,62],["H5650","of all his servants",63,82]]},"41:38":{"text":"And Pharaoh said unto his servants, Can we find such a one as this is, a man in whom the Spirit of God is?","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H5650","unto his servants",17,34],["H4672","Can we find",36,47],["H2088","such a one as this",48,66],["H0376","is, a man",67,76],["H0834","in whom",77,84],["H7307","the Spirit",85,95],["H0430","of God",96,102]]},"41:39":{"text":"And Pharaoh said unto Joseph, Forasmuch as God hath shewed thee all this, there is none so discreet and wise as thou art:","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H3130","unto Joseph",17,28],["H0310","Forasmuch",30,39],["H0430","as God",40,46],["H3045","hath shewed",47,58],["H0995","thee all this, there is none so discreet",59,99],["H2450","and wise",100,108]]},"41:40":{"text":"Thou shalt be over my house, and according unto thy word shall all my people be ruled: only in the throne will I be greater than thou.","words":[["H1961","Thou shalt be",0,13],["H1004","over my house",14,27],["H6310","and according unto thy word",29,56],["H5971","shall all my people",57,76],["H5401","be ruled",77,85],["H3678","only in the throne",87,105],["H1431","will I be greater",106,123]]},"41:41":{"text":"And Pharaoh said unto Joseph, See, I have set thee over all the land of Egypt.","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H3130","unto Joseph",17,28],["H7200","See",30,33],["H5414","I have set",35,45],["H0776","thee over all the land",46,68],["H4714","of Egypt",69,77]]},"41:42":{"text":"And Pharaoh took off his ring from his hand, and put it upon Joseph's hand, and arrayed him in vestures of fine linen, and put a gold chain about his neck;","words":[["H6547","And Pharaoh",0,11],["H5493","took off",12,20],["H2885","his ring",21,29],["H3027","from his hand",30,43],["H5414","and put",45,52],["H3130","it upon Joseph's",53,69],["H3027","hand",70,74],["H3847","and arrayed",76,87],["H0899","him in vestures",88,103],["H8336","of fine linen",104,117],["H7760","and put",119,126],["H2091","a gold",127,133],["H7242","chain",134,139],["H6677","about his neck",140,154]]},"41:43":{"text":"And he made him to ride in the second chariot which he had; and they cried before him, Bow the knee: and he made him ruler over all the land of Egypt.","words":[["H7392","And he made him to ride",0,23],["H4932","in the second",24,37],["H4818","chariot",38,45],["H7121","which he had; and they cried",46,74],["H6440","before him",75,85],["H0086","Bow the knee",87,99],["H5414","and he made",101,112],["H0776","him ruler over all the land",113,140],["H4714","of Egypt",141,149]]},"41:44":{"text":"And Pharaoh said unto Joseph, I am Pharaoh, and without thee shall no man lift up his hand or foot in all the land of Egypt.","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H3130","unto Joseph",17,28],["H6547","I am Pharaoh",30,42],["H1107","and without",44,55],["H0376","thee shall no man",56,73],["H7311","lift up",74,81],["H3027","his hand",82,90],["H7272","or foot",91,98],["H0776","in all the land",99,114],["H4714","of Egypt",115,123]]},"41:45":{"text":"And Pharaoh called Joseph's name Zaphnathpaaneah; and he gave him to wife Asenath the daughter of Potipherah priest of On. And Joseph went out over all the land of Egypt.","words":[["H6547","And Pharaoh",0,11],["H7121","called",12,18],["H3130","Joseph's",19,27],["H8034","name",28,32],["H6847","Zaphnathpaaneah",33,48],["H5414","and he gave",50,61],["H0802","him to wife",62,73],["H0621","Asenath",74,81],["H1323","the daughter",82,94],["H6319","of Potipherah",95,108],["H3548","priest",109,115],["H0204","of On",116,121],["H3130","And Joseph",123,133],["H3318","went out",134,142],["H0776","over all the land",143,160],["H4714","of Egypt",161,169]]},"41:46":{"text":"And Joseph was thirty years old when he stood before Pharaoh king of Egypt. And Joseph went out from the presence of Pharaoh, and went throughout all the land of Egypt.","words":[["H3130","And Joseph",0,10],["H7970","was thirty",11,21],["H8141","years",22,27],["H1121","old",28,31],["H5975","when he stood",32,45],["H6440","before",46,52],["H6547","Pharaoh",53,60],["H4428","king",61,65],["H4714","of Egypt",66,74],["H3130","And Joseph",76,86],["H3318","went out",87,95],["H6440","from the presence",96,113],["H6547","of Pharaoh",114,124],["H5674","and went throughout",126,145],["H0776","all the land",146,158],["H4714","of Egypt",159,167]]},"41:47":{"text":"And in the seven plenteous years the earth brought forth by handfuls.","words":[["H7651","And in the seven",0,16],["H7647","plenteous",17,26],["H8141","years",27,32],["H0776","the earth",33,42],["H6213","brought forth",43,56],["H7062","by handfuls",57,68]]},"41:48":{"text":"And he gathered up all the food of the seven years, which were in the land of Egypt, and laid up the food in the cities: the food of the field, which was round about every city, laid he up in the same.","words":[["H6908","And he gathered up",0,18],["H0400","all the food",19,31],["H7651","of the seven",32,44],["H8141","years",45,50],["H0776","which were in the land",52,74],["H4714","of Egypt",75,83],["H5414","and laid up",85,96],["H0400","the food",97,105],["H5892","in the cities",106,119],["H0400","the food",121,129],["H7704","of the field",130,142],["H5439","which was round about",144,165],["H5892","every city",166,176],["H5414","laid he up",178,188],["H8432","in the same",189,200]]},"41:49":{"text":"And Joseph gathered corn as the sand of the sea, very much, until he left numbering; for it was without number.","words":[["H3130","And Joseph",0,10],["H6651","gathered",11,19],["H1250","corn",20,24],["H2344","as the sand",25,36],["H3220","of the sea",37,47],["H3966","very",49,53],["H7235","much",54,58],["H2308","until he left",60,73],["H5608","numbering",74,83],["H0369","for it was without",85,103],["H4557","number",104,110]]},"41:50":{"text":"And unto Joseph were born two sons before the years of famine came, which Asenath the daughter of Potipherah priest of On bare unto him.","words":[["H3130","And unto Joseph",0,15],["H3205","were born",16,25],["H8147","two",26,29],["H1121","sons",30,34],["H8141","before the years",35,51],["H7458","of famine",52,61],["H0935","came",62,66],["H0621","which Asenath",68,81],["H1323","the daughter",82,94],["H6319","of Potipherah",95,108],["H3548","priest",109,115],["H0204","of On",116,121],["H3205","bare",122,126]]},"41:51":{"text":"And Joseph called the name of the firstborn Manasseh: For God, said he, hath made me forget all my toil, and all my father's house.","words":[["H3130","And Joseph",0,10],["H7121","called",11,17],["H8034","the name",18,26],["H1060","of the firstborn",27,43],["H4519","Manasseh",44,52],["H0430","For God",54,61],["H5382","said he, hath made me forget",63,91],["H5999","all my toil",92,103],["H0001","and all my father's",105,124],["H1004","house",125,130]]},"41:52":{"text":"And the name of the second called he Ephraim: For God hath caused me to be fruitful in the land of my affliction.","words":[["H8034","And the name",0,12],["H8145","of the second",13,26],["H7121","called",27,33],["H0669","he Ephraim",34,44],["H0430","For God",46,53],["H6509","hath caused me to be fruitful",54,83],["H0776","in the land",84,95],["H6040","of my affliction",96,112]]},"41:53":{"text":"And the seven years of plenteousness, that was in the land of Egypt, were ended.","words":[["H7651","And the seven",0,13],["H8141","years",14,19],["H7647","of plenteousness",20,36],["H0776","that was in the land",38,58],["H4714","of Egypt",59,67],["H3615","were ended",69,79]]},"41:54":{"text":"And the seven years of dearth began to come, according as Joseph had said: and the dearth was in all lands; but in all the land of Egypt there was bread.","words":[["H7651","And the seven",0,13],["H8141","years",14,19],["H7458","of dearth",20,29],["H2490","began",30,35],["H0935","to come",36,43],["H3130","according as Joseph",45,64],["H0559","had said",65,73],["H7458","and the dearth",75,89],["H0776","was in all lands",90,106],["H0776","but in all the land",108,127],["H4714","of Egypt",128,136],["H3899","there was bread",137,152]]},"41:55":{"text":"And when all the land of Egypt was famished, the people cried to Pharaoh for bread: and Pharaoh said unto all the Egyptians, Go unto Joseph; what he saith to you, do.","words":[["H0776","And when all the land",0,21],["H4714","of Egypt",22,30],["H7456","was famished",31,43],["H5971","the people",45,55],["H6817","cried",56,61],["H6547","to Pharaoh",62,72],["H3899","for bread",73,82],["H6547","and Pharaoh",84,95],["H0559","said",96,100],["H4714","unto all the Egyptians",101,123],["H3212","Go",125,127],["H3130","unto Joseph",128,139],["H0559","what he saith",141,154],["H6213","to you, do",155,165]]},"41:56":{"text":"And the famine was over all the face of the earth: And Joseph opened all the storehouses, and sold unto the Egyptians; and the famine waxed sore in the land of Egypt.","words":[["H7458","And the famine",0,14],["H6440","was over all the face",15,36],["H0776","of the earth",37,49],["H3130","And Joseph",51,61],["H6605","opened",62,68],["H7666","all the storehouses, and sold",69,98],["H4714","unto the Egyptians",99,117],["H7458","and the famine",119,133],["H2388","waxed sore",134,144],["H0776","in the land",145,156],["H4714","of Egypt",157,165]]},"41:57":{"text":"And all countries came into Egypt to Joseph for to buy corn; because that the famine was so sore in all lands.","words":[["H0776","And all countries",0,17],["H0935","came",18,22],["H4714","into Egypt",23,33],["H3130","to Joseph",34,43],["H7666","for to buy",44,54],["H7458","corn; because that the famine",55,84],["H2388","was so sore",85,96],["H0776","in all lands",97,109]]},"42:1":{"text":"Now when Jacob saw that there was corn in Egypt, Jacob said unto his sons, Why do ye look one upon another?","words":[["H3290","Now when Jacob",0,14],["H7200","saw",15,18],["H3426","that there was",19,33],["H7668","corn",34,38],["H4714","in Egypt",39,47],["H3290","Jacob",49,54],["H0559","said",55,59],["H1121","unto his sons",60,73],["H7200","Why do ye look",75,89]]},"42:2":{"text":"And he said, Behold, I have heard that there is corn in Egypt: get you down thither, and buy for us from thence; that we may live, and not die.","words":[["H0559","And he said",0,11],["H8085","Behold, I have heard",13,33],["H3426","that there is",34,47],["H7668","corn",48,52],["H4714","in Egypt",53,61],["H3381","get you down",63,75],["H7666","thither, and buy",76,92],["H2421","for us from thence; that we may live",93,129],["H4191","and not die",131,142]]},"42:3":{"text":"And Joseph's ten brethren went down to buy corn in Egypt.","words":[["H3130","And Joseph's",0,12],["H6235","ten",13,16],["H0251","brethren",17,25],["H3381","went down",26,35],["H7666","to buy",36,42],["H1250","corn",43,47],["H4714","in Egypt",48,56]]},"42:4":{"text":"But Benjamin, Joseph's brother, Jacob sent not with his brethren; for he said, Lest peradventure mischief befall him.","words":[["H1144","But Benjamin",0,12],["H3130","Joseph's",14,22],["H0251","brother",23,30],["H3290","Jacob",32,37],["H7971","sent",38,42],["H0251","not with his brethren",43,64],["H0559","for he said",66,77],["H6435","Lest peradventure",79,96],["H0611","mischief",97,105],["H7122","befall him",106,116]]},"42:5":{"text":"And the sons of Israel came to buy corn among those that came: for the famine was in the land of Canaan.","words":[["H1121","And the sons",0,12],["H3478","of Israel",13,22],["H0935","came",23,27],["H7666","to buy",28,34],["H8432","corn among",35,45],["H0935","those that came",46,61],["H7458","for the famine",63,77],["H0776","was in the land",78,93],["H3667","of Canaan",94,103]]},"42:6":{"text":"And Joseph was the governor over the land, and he it was that sold to all the people of the land: and Joseph's brethren came, and bowed down themselves before him with their faces to the earth.","words":[["H3130","And Joseph",0,10],["H7989","was the governor",11,27],["H0776","over the land",28,41],["H7666","and he it was that sold",43,66],["H5971","to all the people",67,84],["H0776","of the land",85,96],["H3130","and Joseph's",98,110],["H0251","brethren",111,119],["H0935","came",120,124],["H7812","and bowed down",126,140],["H0639","themselves before him with their faces",141,179],["H0776","to the earth",180,192]]},"42:7":{"text":"And Joseph saw his brethren, and he knew them, but made himself strange unto them, and spake roughly unto them; and he said unto them, Whence come ye? And they said, From the land of Canaan to buy food.","words":[["H3130","And Joseph",0,10],["H7200","saw",11,14],["H0251","his brethren",15,27],["H5234","and he knew",29,40],["H5234","them, but made himself strange",41,71],["H1696","unto them, and spake",72,92],["H7186","roughly",93,100],["H0559","unto them; and he said",101,123],["H0370","unto them, Whence",124,141],["H0935","come",142,146],["H0559","ye? And they said",147,164],["H0776","From the land",166,179],["H3667","of Canaan",180,189],["H7666","to buy",190,196],["H0400","food",197,201]]},"42:8":{"text":"And Joseph knew his brethren, but they knew not him.","words":[["H3130","And Joseph",0,10],["H5234","knew",11,15],["H0251","his brethren",16,28],["H5234","but they knew",30,43]]},"42:9":{"text":"And Joseph remembered the dreams which he dreamed of them, and said unto them, Ye are spies; to see the nakedness of the land ye are come.","words":[["H3130","And Joseph",0,10],["H2142","remembered",11,21],["H2472","the dreams",22,32],["H2492","which he dreamed",33,49],["H0559","of them, and said",50,67],["H7270","unto them, Ye are spies",68,91],["H7200","to see",93,99],["H6172","the nakedness",100,113],["H0776","of the land",114,125],["H0935","ye are come",126,137]]},"42:10":{"text":"And they said unto him, Nay, my lord, but to buy food are thy servants come.","words":[["H0559","And they said",0,13],["H0113","unto him, Nay, my lord",14,36],["H7666","but to buy",38,48],["H0400","food",49,53],["H5650","are thy servants",54,70],["H0935","come",71,75]]},"42:11":{"text":"We are all one man's sons; we are true men, thy servants are no spies.","words":[["H5168","We",0,2],["H0259","are all one",3,14],["H0376","man's",15,20],["H1121","sons",21,25],["H3651","we are true",27,38],["H5650","men, thy servants",39,56],["H7270","are no spies",57,69]]},"42:12":{"text":"And he said unto them, Nay, but to see the nakedness of the land ye are come.","words":[["H0559","And he said",0,11],["H7200","unto them, Nay, but to see",12,38],["H6172","the nakedness",39,52],["H0776","of the land",53,64],["H0935","ye are come",65,76]]},"42:13":{"text":"And they said, Thy servants are twelve brethren, the sons of one man in the land of Canaan; and, behold, the youngest is this day with our father, and one is not.","words":[["H0559","And they said",0,13],["H5650","Thy servants",15,27],["H8147","are twelve",28,38],["H6240","are twelve",28,38],["H0251","brethren",39,47],["H1121","the sons",49,57],["H0259","of one",58,64],["H0376","man",65,68],["H0776","in the land",69,80],["H3667","of Canaan",81,90],["H6996","and, behold, the youngest",92,117],["H3117","is this day",118,129],["H0001","with our father",130,145],["H0259","and one",147,154]]},"42:14":{"text":"And Joseph said unto them, That is it that I spake unto you, saying, Ye are spies:","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H1696","unto them, That is it that I spake",16,50],["H0559","unto you, saying",51,67],["H7270","Ye are spies",69,81]]},"42:15":{"text":"Hereby ye shall be proved: By the life of Pharaoh ye shall not go forth hence, except your youngest brother come hither.","words":[["H2063","Hereby",0,6],["H0974","ye shall be proved",7,25],["H2416","By the life",27,38],["H6547","of Pharaoh",39,49],["H3318","ye shall not go forth",50,71],["H6996","hence, except your youngest",72,99],["H0251","brother",100,107],["H0935","come",108,112]]},"42:16":{"text":"Send one of you, and let him fetch your brother, and ye shall be kept in prison, that your words may be proved, whether there be any truth in you: or else by the life of Pharaoh surely ye are spies.","words":[["H7971","Send",0,4],["H0259","one",5,8],["H3947","of you, and let him fetch",9,34],["H0251","your brother",35,47],["H0631","and ye shall be kept in prison",49,79],["H1697","that your words",81,96],["H0974","may be proved",97,110],["H0571","whether there be any truth",112,138],["H0854","in",139,141],["H3808","you: or else",142,154],["H2416","by the life",155,166],["H6547","of Pharaoh",167,177],["H7270","surely ye are spies",178,197]]},"42:17":{"text":"And he put them all together into ward three days.","words":[["H0622","And he put them all together",0,28],["H4929","into ward",29,38],["H7969","three",39,44],["H3117","days",45,49]]},"42:18":{"text":"And Joseph said unto them the third day, This do, and live; for I fear God:","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H7992","unto them the third",16,35],["H3117","day",36,39],["H6213","This do",41,48],["H2421","and live",50,58],["H3373","for I fear",60,70],["H0430","God",71,74]]},"42:19":{"text":"If ye be true men, let one of your brethren be bound in the house of your prison: go ye, carry corn for the famine of your houses:","words":[["H3651","If ye be true",0,13],["H0259","men, let one",14,26],["H0251","of your brethren",27,43],["H0631","be bound",44,52],["H1004","in the house",53,65],["H4929","of your prison",66,80],["H3212","go",82,84],["H0935","ye, carry",85,94],["H7668","corn",95,99],["H7459","for the famine",100,114],["H1004","of your houses",115,129]]},"42:20":{"text":"But bring your youngest brother unto me; so shall your words be verified, and ye shall not die. And they did so.","words":[["H0935","But bring",0,9],["H6996","your youngest",10,23],["H0251","brother",24,31],["H1697","unto me; so shall your words",32,60],["H0539","be verified",61,72],["H4191","and ye shall not die",74,94],["H6213","And they did",96,108]]},"42:21":{"text":"And they said one to another, We are verily guilty concerning our brother, in that we saw the anguish of his soul, when he besought us, and we would not hear; therefore is this distress come upon us.","words":[["H0559","And they said",0,13],["H0376","one",14,17],["H0251","to another",18,28],["H0061","We are verily",30,43],["H0818","guilty",44,50],["H0251","concerning our brother",51,73],["H0834","in that",75,82],["H7200","we saw",83,89],["H6869","the anguish",90,101],["H5315","of his soul",102,113],["H2603","when he besought",115,131],["H8085","us, and we would not hear",132,157],["H6869","therefore is this distress",159,185],["H0935","come",186,190]]},"42:22":{"text":"And Reuben answered them, saying, Spake I not unto you, saying, Do not sin against the child; and ye would not hear? therefore, behold, also his blood is required.","words":[["H7205","And Reuben",0,10],["H6030","answered",11,19],["H0559","them, saying",20,32],["H0559","Spake I",34,41],["H0559","not unto you, saying",42,62],["H2398","Do not sin",64,74],["H3206","against the child",75,92],["H8085","and ye would not hear",94,115],["H1818","therefore, behold, also his blood",117,150],["H1875","is required",151,162]]},"42:23":{"text":"And they knew not that Joseph understood them; for he spake unto them by an interpreter.","words":[["H3045","And they knew",0,13],["H3130","not that Joseph",14,29],["H8085","understood",30,40],["H3887","them; for he spake unto them by an interpreter",41,87]]},"42:24":{"text":"And he turned himself about from them, and wept; and returned to them again, and communed with them, and took from them Simeon, and bound him before their eyes.","words":[["H5437","And he turned himself about",0,27],["H1058","from them, and wept",28,47],["H7725","and returned to them again",49,75],["H1696","and communed",77,89],["H3947","with them, and took",90,109],["H8095","from them Simeon",110,126],["H0631","and bound",128,137],["H5869","him before their eyes",138,159]]},"42:25":{"text":"Then Joseph commanded to fill their sacks with corn, and to restore every man's money into his sack, and to give them provision for the way: and thus did he unto them.","words":[["H3130","Then Joseph",0,11],["H6680","commanded",12,21],["H4390","to fill",22,29],["H3627","their sacks",30,41],["H1250","with corn",42,51],["H7725","and to restore",53,67],["H0376","every man's",68,79],["H3701","money",80,85],["H8242","into his sack",86,99],["H5414","and to give",101,112],["H6720","them provision",113,127],["H1870","for the way",128,139],["H3651","and thus",141,149],["H6213","did he",150,156]]},"42:26":{"text":"And they laded their asses with the corn, and departed thence.","words":[["H5375","And they laded",0,14],["H2543","their asses",15,26],["H7668","with the corn",27,40],["H3212","and departed",42,54]]},"42:27":{"text":"And as one of them opened his sack to give his ass provender in the inn, he espied his money; for, behold, it was in his sack's mouth.","words":[["H0259","And as one",0,10],["H6605","of them opened",11,25],["H8242","his sack",26,34],["H5414","to give",35,42],["H2543","his ass",43,50],["H4554","provender",51,60],["H4411","in the inn",61,71],["H7200","he espied",73,82],["H3701","his money",83,92],["H0572","for, behold, it was in his sack's",94,127],["H6310","mouth",128,133]]},"42:28":{"text":"And he said unto his brethren, My money is restored; and, lo, it is even in my sack: and their heart failed them, and they were afraid, saying one to another, What is this that God hath done unto us?","words":[["H0559","And he said",0,11],["H0251","unto his brethren",12,29],["H3701","My money",31,39],["H7725","is restored",40,51],["H2009","and, lo",53,60],["H0572","it is even in my sack",62,83],["H3820","and their heart",85,100],["H3318","failed",101,107],["H2729","them, and they were afraid",108,134],["H0559","saying",136,142],["H0376","one",143,146],["H0251","to another",147,157],["H0430","What is this that God",159,180],["H6213","hath done",181,190]]},"42:29":{"text":"And they came unto Jacob their father unto the land of Canaan, and told him all that befell unto them; saying,","words":[["H0935","And they came",0,13],["H3290","unto Jacob",14,24],["H0001","their father",25,37],["H0776","unto the land",38,51],["H3667","of Canaan",52,61],["H5046","and told",63,71],["H7136","him all that befell",72,91],["H0559","unto them; saying",92,109]]},"42:30":{"text":"The man, who is the lord of the land, spake roughly to us, and took us for spies of the country.","words":[["H0376","The man",0,7],["H0113","who is the lord",9,24],["H0776","of the land",25,36],["H1696","spake",38,43],["H7186","roughly",44,51],["H5414","to us, and took",52,67],["H7270","us for spies",68,80],["H0776","of the country",81,95]]},"42:31":{"text":"And we said unto him, We are true men; we are no spies:","words":[["H0559","And we said",0,11],["H3651","unto him, We are true",12,33],["H7270","men; we are no spies",34,54]]},"42:32":{"text":"We be twelve brethren, sons of our father; one is not, and the youngest is this day with our father in the land of Canaan.","words":[["H6240","We be twelve",0,12],["H8147","We be twelve",0,12],["H0251","brethren",13,21],["H1121","sons",23,27],["H0001","of our father",28,41],["H0259","one",43,46],["H6996","is not, and the youngest",47,71],["H3117","is this day",72,83],["H0001","with our father",84,99],["H0776","in the land",100,111],["H3667","of Canaan",112,121]]},"42:33":{"text":"And the man, the lord of the country, said unto us, Hereby shall I know that ye are true men; leave one of your brethren here with me, and take food for the famine of your households, and be gone:","words":[["H0376","And the man",0,11],["H0113","the lord",13,21],["H0776","of the country",22,36],["H0559","said",38,42],["H3045","unto us, Hereby shall I know",43,71],["H3651","that ye are true",72,88],["H3240","men; leave",89,99],["H0259","one",100,103],["H0251","of your brethren",104,120],["H3947","here with me, and take",121,143],["H7459","food for the famine",144,163],["H1004","of your households",164,182],["H3212","and be gone",184,195]]},"42:34":{"text":"And bring your youngest brother unto me: then shall I know that ye are no spies, but that ye are true men: so will I deliver you your brother, and ye shall traffick in the land.","words":[["H0935","And bring",0,9],["H6996","your youngest",10,23],["H0251","brother",24,31],["H3045","unto me: then shall I know",32,58],["H7270","that ye are no spies",59,79],["H3651","but that ye are true",81,101],["H5414","men: so will I deliver",102,124],["H0251","you your brother",125,141],["H5503","and ye shall traffick",143,164],["H0776","in the land",165,176]]},"42:35":{"text":"And it came to pass as they emptied their sacks, that, behold, every man's bundle of money was in his sack: and when both they and their father saw the bundles of money, they were afraid.","words":[["H7324","And it came to pass as they emptied",0,35],["H8242","their sacks",36,47],["H0376","that, behold, every man's",49,74],["H6872","bundle",75,81],["H3701","of money",82,90],["H8242","was in his sack",91,106],["H0001","and when both they and their father",108,143],["H7200","saw",144,147],["H6872","the bundles",148,159],["H3701","of money",160,168],["H3372","they were afraid",170,186]]},"42:36":{"text":"And Jacob their father said unto them, Me have ye bereaved of my children: Joseph is not, and Simeon is not, and ye will take Benjamin away: all these things are against me.","words":[["H3290","And Jacob",0,9],["H0001","their father",10,22],["H0559","said",23,27],["H7921","unto them, Me have ye bereaved",28,58],["H3130","of my children: Joseph",59,81],["H8095","is not, and Simeon",82,100],["H3947","is not, and ye will take",101,125],["H1144","Benjamin",126,134]]},"42:37":{"text":"And Reuben spake unto his father, saying, Slay my two sons, if I bring him not to thee: deliver him into my hand, and I will bring him to thee again.","words":[["H7205","And Reuben",0,10],["H0559","spake",11,16],["H0001","unto his father",17,32],["H0559","saying",34,40],["H4191","Slay",42,46],["H8147","my two",47,53],["H1121","sons",54,58],["H0935","if I bring",60,70],["H5414","him not to thee: deliver",71,95],["H3027","him into my hand",96,112],["H7725","and I will bring him to thee again",114,148]]},"42:38":{"text":"And he said, My son shall not go down with you; for his brother is dead, and he is left alone: if mischief befall him by the way in the which ye go, then shall ye bring down my gray hairs with sorrow to the grave.","words":[["H0559","And he said",0,11],["H1121","My son",13,19],["H3381","shall not go down",20,37],["H0251","with you; for his brother",38,63],["H4191","is dead",64,71],["H7604","and he is left",73,87],["H0611","alone: if mischief",88,106],["H7122","befall",107,113],["H1870","him by the way",114,128],["H3212","in the which ye go",129,147],["H3381","then shall ye bring down",149,173],["H7872","my gray hairs",174,187],["H3015","with sorrow",188,199],["H7585","to the grave",200,212]]},"43:1":{"text":"And the famine was sore in the land.","words":[["H7458","And the famine",0,14],["H3515","was sore",15,23],["H0776","in the land",24,35]]},"43:2":{"text":"And it came to pass, when they had eaten up the corn which they had brought out of Egypt, their father said unto them, Go again, buy us a little food.","words":[["H3615","And it came to pass, when they had eaten up",0,43],["H0398","And it came to pass, when they had eaten up",0,43],["H7668","the corn",44,52],["H0935","which they had brought out",53,79],["H4714","of Egypt",80,88],["H0001","their father",90,102],["H0559","said",103,107],["H7725","unto them, Go again",108,127],["H7666","buy",129,132],["H4592","us a little",133,144],["H0400","food",145,149]]},"43:3":{"text":"And Judah spake unto him, saying, The man did solemnly protest unto us, saying, Ye shall not see my face, except your brother be with you.","words":[["H3063","And Judah",0,9],["H0559","spake",10,15],["H0559","unto him, saying",16,32],["H0376","The man",34,41],["H5749","did solemnly",42,54],["H5749","protest",55,62],["H0559","unto us, saying",63,78],["H7200","Ye shall not see",80,96],["H6440","my face",97,104],["H1115","except",106,112],["H0251","your brother",113,125]]},"43:4":{"text":"If thou wilt send our brother with us, we will go down and buy thee food:","words":[["H3426","If thou wilt",0,12],["H7971","send",13,17],["H0251","our brother",18,29],["H3381","with us, we will go down",30,54],["H7666","and buy",55,62],["H0400","thee food",63,72]]},"43:5":{"text":"But if thou wilt not send him, we will not go down: for the man said unto us, Ye shall not see my face, except your brother be with you.","words":[["H7971","But if thou wilt not send",0,25],["H3381","him, we will not go down",26,50],["H0376","for the man",52,63],["H0559","said",64,68],["H7200","unto us, Ye shall not see",69,94],["H6440","my face",95,102],["H0251","except your brother",104,123]]},"43:6":{"text":"And Israel said, Wherefore dealt ye so ill with me, as to tell the man whether ye had yet a brother?","words":[["H3478","And Israel",0,10],["H0559","said",11,15],["H7489","Wherefore dealt ye so ill",17,42],["H5046","with me, as to tell",43,62],["H0376","the man",63,70],["H0251","whether ye had yet a brother",71,99]]},"43:7":{"text":"And they said, The man asked us straitly of our state, and of our kindred, saying, Is your father yet alive? have ye another brother? and we told him according to the tenor of these words: could we certainly know that he would say, Bring your brother down?","words":[["H0559","And they said",0,13],["H0376","The man",15,22],["H7592","asked",23,28],["H7592","us straitly",29,40],["H4138","of our state, and of our kindred",41,73],["H0559","saying",75,81],["H0001","Is your father",83,97],["H2416","yet alive",98,107],["H3426","have ye",109,116],["H0251","another brother",117,132],["H5046","and we told",134,145],["H5921","him according",146,159],["H6310","to the tenor",160,172],["H1697","of these words",173,187],["H3045","could we certainly",189,207],["H3045","know",208,212],["H0559","that he would say",213,230],["H3381","Bring",232,237],["H0251","your brother",238,250],["H3381","down",251,255]]},"43:8":{"text":"And Judah said unto Israel his father, Send the lad with me, and we will arise and go; that we may live, and not die, both we, and thou, and also our little ones.","words":[["H3063","And Judah",0,9],["H0559","said",10,14],["H3478","unto Israel",15,26],["H0001","his father",27,37],["H7971","Send",39,43],["H5288","the lad",44,51],["H6965","with me, and we will arise",52,78],["H3212","and go",79,85],["H2421","that we may live",87,103],["H4191","and not die",105,116],["H2945","both we, and thou, and also our little ones",118,161]]},"43:9":{"text":"I will be surety for him; of my hand shalt thou require him: if I bring him not unto thee, and set him before thee, then let me bear the blame for ever:","words":[["H6148","I will be surety",0,16],["H3027","for him; of my hand",17,36],["H1245","shalt thou require",37,55],["H0518","him: if",56,63],["H0935","I bring",64,71],["H0518","him not",72,79],["H3322","unto thee, and set",80,98],["H6440","him before thee",99,114],["H2398","then let me bear the blame",116,142],["H3117","for ever",143,151]]},"43:10":{"text":"For except we had lingered, surely now we had returned this second time.","words":[["H3884","For except",0,10],["H4102","we had lingered",11,26],["H7725","surely now we had returned",28,54],["H6471","this second time",55,71]]},"43:11":{"text":"And their father Israel said unto them, If it must be so now, do this; take of the best fruits in the land in your vessels, and carry down the man a present, a little balm, and a little honey, spices, and myrrh, nuts, and almonds:","words":[["H0001","And their father",0,16],["H3478","Israel",17,23],["H0559","said",24,28],["H0645","unto them, If it must be so now",29,60],["H6213","do",62,64],["H3947","this; take",65,75],["H2173","of the best fruits",76,94],["H0776","in the land",95,106],["H3627","in your vessels",107,122],["H3381","and carry down",124,138],["H0376","the man",139,146],["H4503","a present",147,156],["H4592","a little",158,166],["H6875","balm",167,171],["H4592","and a little",173,185],["H1706","honey",186,191],["H5219","spices",193,199],["H3910","and myrrh",201,210],["H0992","nuts",212,216],["H8247","and almonds",218,229]]},"43:12":{"text":"And take double money in your hand; and the money that was brought again in the mouth of your sacks, carry it again in your hand; peradventure it was an oversight:","words":[["H3947","And take",0,8],["H4932","double",9,15],["H3701","money",16,21],["H3027","in your hand",22,34],["H3701","and the money",36,49],["H7725","that was brought again",50,72],["H6310","in the mouth",73,85],["H0572","of your sacks",86,99],["H7725","carry it again",101,115],["H3027","in your hand",116,128],["H4870","peradventure it was an oversight",130,162]]},"43:13":{"text":"Take also your brother, and arise, go again unto the man:","words":[["H3947","Take",0,4],["H0251","also your brother",5,22],["H6965","and arise",24,33],["H7725","go again",35,43],["H0376","unto the man",44,56]]},"43:14":{"text":"And God Almighty give you mercy before the man, that he may send away your other brother, and Benjamin. If I be bereaved of my children, I am bereaved.","words":[["H0410","And God",0,7],["H7706","Almighty",8,16],["H5414","give",17,21],["H7356","you mercy",22,31],["H6440","before",32,38],["H0376","the man",39,46],["H7971","that he may send away",48,69],["H0312","your other",70,80],["H0251","brother",81,88],["H1144","and Benjamin",90,102],["H0834","If",104,106],["H7921","I be bereaved",107,120],["H7921","of my children, I am bereaved",121,150]]},"43:15":{"text":"And the men took that present, and they took double money in their hand, and Benjamin; and rose up, and went down to Egypt, and stood before Joseph.","words":[["H0582","And the men",0,11],["H3947","took",12,16],["H2063","that",17,21],["H4503","present",22,29],["H3947","and they took",31,44],["H4932","double",45,51],["H3701","money",52,57],["H3027","in their hand",58,71],["H1144","and Benjamin",73,85],["H6965","and rose up",87,98],["H3381","and went down",100,113],["H4714","to Egypt",114,122],["H5975","and stood",124,133],["H6440","before",134,140],["H3130","Joseph",141,147]]},"43:16":{"text":"And when Joseph saw Benjamin with them, he said to the ruler of his house, Bring these men home, and slay, and make ready; for these men shall dine with me at noon.","words":[["H3130","And when Joseph",0,15],["H7200","saw",16,19],["H1144","Benjamin",20,28],["H0854","with",29,33],["H0559","them, he said",34,47],["H1004","to the ruler of his house",48,73],["H0935","Bring",75,80],["H0582","these men",81,90],["H1004","home",91,95],["H2873","and slay",97,105],["H2874","and slay",97,105],["H3559","and make ready",107,121],["H0582","for these men",123,136],["H0398","shall dine",137,147],["H6672","with me at noon",148,163]]},"43:17":{"text":"And the man did as Joseph bade; and the man brought the men into Joseph's house.","words":[["H0376","And the man",0,11],["H6213","did",12,15],["H3130","as Joseph",16,25],["H0559","bade",26,30],["H0376","and the man",32,43],["H0935","brought",44,51],["H0582","the men",52,59],["H3130","into Joseph's",60,73],["H1004","house",74,79]]},"43:18":{"text":"And the men were afraid, because they were brought into Joseph's house; and they said, Because of the money that was returned in our sacks at the first time are we brought in; that he may seek occasion against us, and fall upon us, and take us for bondmen, and our asses.","words":[["H0582","And the men",0,11],["H3372","were afraid",12,23],["H0935","because they were brought",25,50],["H3130","into Joseph's",51,64],["H1004","house",65,70],["H0559","and they said",72,85],["H1697","Because",87,94],["H3701","of the money",95,107],["H7725","that was returned",108,125],["H0572","in our sacks",126,138],["H8462","at the first time",139,156],["H0935","are we brought in",157,174],["H1556","that he may seek occasion",176,201],["H5307","against us, and fall",202,222],["H3947","upon us, and take",223,240],["H5650","us for bondmen",241,255],["H2543","and our asses",257,270]]},"43:19":{"text":"And they came near to the steward of Joseph's house, and they communed with him at the door of the house,","words":[["H5066","And they came near",0,18],["H0376","to the steward",19,33],["H3130","of Joseph's",34,45],["H1004","house",46,51],["H1696","and they communed",53,70],["H6607","with him at the door",71,91],["H1004","of the house",92,104]]},"43:20":{"text":"And said, O sir, we came indeed down at the first time to buy food:","words":[["H0559","And said",0,8],["H0994","O",10,11],["H0113","sir",12,15],["H3381","we came indeed",17,31],["H3381","down",32,36],["H8462","at the first time",37,54],["H7666","to buy",55,61],["H0400","food",62,66]]},"43:21":{"text":"And it came to pass, when we came to the inn, that we opened our sacks, and, behold, every man's money was in the mouth of his sack, our money in full weight: and we have brought it again in our hand.","words":[["H0935","And it came to pass, when we came",0,33],["H4411","to the inn",34,44],["H6605","that we opened",46,60],["H0572","our sacks",61,70],["H0376","and, behold, every man's",72,96],["H3701","money",97,102],["H6310","was in the mouth",103,119],["H0572","of his sack",120,131],["H3701","our money",133,142],["H4948","in full weight",143,157],["H7725","and we have brought it again",159,187],["H3027","in our hand",188,199]]},"43:22":{"text":"And other money have we brought down in our hands to buy food: we cannot tell who put our money in our sacks.","words":[["H0312","And other",0,9],["H3701","money",10,15],["H3381","have we brought down",16,36],["H3027","in our hands",37,49],["H7666","to buy",50,56],["H0400","food",57,61],["H3045","we cannot tell",63,77],["H7760","who put",78,85],["H3701","our money",86,95],["H0572","in our sacks",96,108]]},"43:23":{"text":"And he said, Peace be to you, fear not: your God, and the God of your father, hath given you treasure in your sacks: I had your money. And he brought Simeon out unto them.","words":[["H0559","And he said",0,11],["H7965","Peace",13,18],["H3372","be to you, fear",19,34],["H0430","not: your God",35,48],["H0430","and the God",50,61],["H0001","of your father",62,76],["H5414","hath given",78,88],["H4301","you treasure",89,101],["H0572","in your sacks",102,115],["H0935","I had",117,122],["H3701","your money",123,133],["H3318","And he brought",135,149],["H8095","Simeon",150,156]]},"43:24":{"text":"And the man brought the men into Joseph's house, and gave them water, and they washed their feet; and he gave their asses provender.","words":[["H0376","And the man",0,11],["H0935","brought",12,19],["H0582","the men",20,27],["H3130","into Joseph's",28,41],["H1004","house",42,47],["H5414","and gave",49,57],["H4325","them water",58,68],["H7364","and they washed",70,85],["H7272","their feet",86,96],["H5414","and he gave",98,109],["H2543","their asses",110,121],["H4554","provender",122,131]]},"43:25":{"text":"And they made ready the present against Joseph came at noon: for they heard that they should eat bread there.","words":[["H3559","And they made ready",0,19],["H4503","the present",20,31],["H5704","against",32,39],["H3130","Joseph",40,46],["H0935","came",47,51],["H6672","at noon",52,59],["H8085","for they heard",61,75],["H0398","that they should eat",76,96],["H3899","bread",97,102]]},"43:26":{"text":"And when Joseph came home, they brought him the present which was in their hand into the house, and bowed themselves to him to the earth.","words":[["H3130","And when Joseph",0,15],["H0935","came",16,20],["H1004","home",21,25],["H0935","they brought",27,39],["H4503","him the present",40,55],["H3027","which was in their hand",56,79],["H1004","into the house",80,94],["H7812","and bowed",96,105],["H0776","themselves to him to the earth",106,136]]},"43:27":{"text":"And he asked them of their welfare, and said, Is your father well, the old man of whom ye spake? Is he yet alive?","words":[["H7592","And he asked",0,12],["H7965","them of their welfare",13,34],["H0559","and said",36,44],["H0001","Is your father",46,60],["H7965","well",61,65],["H2205","the old man",67,78],["H0559","of whom ye spake",79,95],["H2416","Is he yet alive",97,112]]},"43:28":{"text":"And they answered, Thy servant our father is in good health, he is yet alive. And they bowed down their heads, and made obeisance.","words":[["H0559","And they answered",0,17],["H5650","Thy servant",19,30],["H0001","our father",31,41],["H7965","is in good health",42,59],["H2416","he is yet alive",61,76],["H6915","And they bowed down their heads",78,109],["H7812","and made obeisance",111,129]]},"43:29":{"text":"And he lifted up his eyes, and saw his brother Benjamin, his mother's son, and said, Is this your younger brother, of whom ye spake unto me? And he said, God be gracious unto thee, my son.","words":[["H5375","And he lifted up",0,16],["H5869","his eyes",17,25],["H7200","and saw",27,34],["H0251","his brother",35,46],["H1144","Benjamin",47,55],["H0517","his mother's",57,69],["H1121","son",70,73],["H0559","and said",75,83],["H6996","Is this your younger",85,105],["H0251","brother",106,113],["H0559","of whom ye spake",115,131],["H0559","unto me? And he said",132,152],["H0430","God",154,157],["H2603","be gracious",158,169],["H1121","unto thee, my son",170,187]]},"43:30":{"text":"And Joseph made haste; for his bowels did yearn upon his brother: and he sought where to weep; and he entered into his chamber, and wept there.","words":[["H3130","And Joseph",0,10],["H4116","made haste",11,21],["H7356","for his bowels",23,37],["H3648","did yearn",38,47],["H0251","upon his brother",48,64],["H1245","and he sought",66,79],["H1058","where to weep",80,93],["H0935","and he entered",95,109],["H2315","into his chamber",110,126],["H1058","and wept",128,136]]},"43:31":{"text":"And he washed his face, and went out, and refrained himself, and said, Set on bread.","words":[["H7364","And he washed",0,13],["H6440","his face",14,22],["H3318","and went out",24,36],["H0662","and refrained",38,51],["H0559","himself, and said",52,69],["H7760","Set on",71,77],["H3899","bread",78,83]]},"43:32":{"text":"And they set on for him by himself, and for them by themselves, and for the Egyptians, which did eat with him, by themselves: because the Egyptians might not eat bread with the Hebrews; for that is an abomination unto the Egyptians.","words":[["H7760","And they set on",0,15],["H4713","for him by himself, and for them by themselves, and for the Egyptians",16,85],["H0398","which did eat",87,100],["H4713","with him, by themselves: because the Egyptians",101,147],["H3201","might",148,153],["H0398","not eat",154,161],["H3899","bread",162,167],["H5680","with the Hebrews",168,184],["H8441","for that is an abomination",186,212],["H4714","unto the Egyptians",213,231]]},"43:33":{"text":"And they sat before him, the firstborn according to his birthright, and the youngest according to his youth: and the men marvelled one at another.","words":[["H3427","And they sat",0,12],["H6440","before him",13,23],["H1060","the firstborn",25,38],["H1062","according to his birthright",39,66],["H6810","and the youngest",68,84],["H6812","according to his youth",85,107],["H0582","and the men",109,120],["H8539","marvelled",121,130],["H0376","one",131,134],["H7453","at another",135,145]]},"43:34":{"text":"And he took and sent messes unto them from before him: but Benjamin's mess was five times so much as any of theirs. And they drank, and were merry with him.","words":[["H5375","And he took",0,11],["H4864","and sent messes",12,27],["H6440","unto them from before him",28,53],["H1144","but Benjamin's",55,69],["H4864","mess",70,74],["H2568","was five",75,83],["H3027","times",84,89],["H7235","so much as",90,100],["H8354","any of theirs. And they drank",101,130],["H7937","and were merry",132,146]]},"44:1":{"text":"And he commanded the steward of his house, saying, Fill the men's sacks with food, as much as they can carry, and put every man's money in his sack's mouth.","words":[["H6680","And he commanded",0,16],["H1004","the steward of his house",17,41],["H0559","saying",43,49],["H4390","Fill",51,55],["H0582","the men's",56,65],["H0572","sacks",66,71],["H0400","with food",72,81],["H0834","as much as",83,93],["H3201","they can",94,102],["H5375","carry",103,108],["H7760","and put",110,117],["H0376","every man's",118,129],["H3701","money",130,135],["H0572","in his sack's",136,149],["H6310","mouth",150,155]]},"44:2":{"text":"And put my cup, the silver cup, in the sack's mouth of the youngest, and his corn money. And he did according to the word that Joseph had spoken.","words":[["H7760","And put",0,7],["H1375","my cup",8,14],["H3701","the silver",16,26],["H1375","cup",27,30],["H0572","in the sack's",32,45],["H6310","mouth",46,51],["H6996","of the youngest",52,67],["H7668","and his corn",69,81],["H3701","money",82,87],["H6213","And he did",89,99],["H1697","according to the word",100,121],["H3130","that Joseph",122,133],["H1696","had spoken",134,144]]},"44:3":{"text":"As soon as the morning was light, the men were sent away, they and their asses.","words":[["H1242","As soon as the morning",0,22],["H0215","was light",23,32],["H0582","the men",34,41],["H7971","were sent away",42,56],["H2543","they and their asses",58,78]]},"44:4":{"text":"And when they were gone out of the city, and not yet far off, Joseph said unto his steward, Up, follow after the men; and when thou dost overtake them, say unto them, Wherefore have ye rewarded evil for good?","words":[["H3318","And when they were gone out",0,27],["H5892","of the city",28,39],["H7368","and not yet far off",41,60],["H3130","Joseph",62,68],["H0559","said",69,73],["H1004","unto his steward",74,90],["H6965","Up",92,94],["H7291","follow",96,102],["H0310","after",103,108],["H0582","the men",109,116],["H5381","and when thou dost overtake",118,145],["H0559","them, say",146,155],["H7999","unto them, Wherefore have ye rewarded",156,193],["H7451","evil",194,198],["H2896","for good",199,207]]},"44:5":{"text":"Is not this it in which my lord drinketh, and whereby indeed he divineth? ye have done evil in so doing.","words":[["H0113","Is not this it in which my lord",0,31],["H8354","drinketh",32,40],["H5172","and whereby indeed",42,60],["H5172","he divineth",61,72],["H7489","ye have done evil",74,91],["H6213","in so doing",92,103]]},"44:6":{"text":"And he overtook them, and he spake unto them these same words.","words":[["H5381","And he overtook",0,15],["H1696","them, and he spake",16,34],["H0428","unto them these same",35,55],["H1697","words",56,61]]},"44:7":{"text":"And they said unto him, Wherefore saith my lord these words? God forbid that thy servants should do according to this thing:","words":[["H0559","And they said",0,13],["H1696","unto him, Wherefore saith",14,39],["H0113","my lord",40,47],["H1697","these words",48,59],["H2486","God forbid",61,71],["H5650","that thy servants",72,89],["H6213","should do",90,99],["H1697","according to this thing",100,123]]},"44:8":{"text":"Behold, the money, which we found in our sacks' mouths, we brought again unto thee out of the land of Canaan: how then should we steal out of thy lord's house silver or gold?","words":[["H3701","Behold, the money",0,17],["H4672","which we found",19,33],["H0572","in our sacks'",34,47],["H6310","mouths",48,54],["H7725","we brought again",56,72],["H0776","unto thee out of the land",73,98],["H3667","of Canaan",99,108],["H1589","how then should we steal",110,134],["H0113","out of thy lord's",135,152],["H1004","house",153,158],["H3701","silver",159,165],["H2091","or gold",166,173]]},"44:9":{"text":"With whomsoever of thy servants it be found, both let him die, and we also will be my lord's bondmen.","words":[["H5650","With whomsoever of thy servants",0,31],["H4672","it be found",32,43],["H4191","both let him die",45,61],["H0113","and we also will be my lord's",63,92],["H5650","bondmen",93,100]]},"44:10":{"text":"And he said, Now also let it be according unto your words: he with whom it is found shall be my servant; and ye shall be blameless.","words":[["H0559","And he said",0,11],["H1697","Now also let it be according unto your words",13,57],["H3651","",-1,-1],["H4672","he with whom it is found",59,83],["H5650","shall be my servant",84,103],["H5355","and ye shall be blameless",105,130]]},"44:11":{"text":"Then they speedily took down every man his sack to the ground, and opened every man his sack.","words":[["H4116","Then they speedily",0,18],["H3381","took down",19,28],["H0376","every man",29,38],["H0572","his sack",39,47],["H0776","to the ground",48,61],["H6605","and opened",63,73],["H0376","every man",74,83],["H0572","his sack",84,92]]},"44:12":{"text":"And he searched, and began at the eldest, and left at the youngest: and the cup was found in Benjamin's sack.","words":[["H2664","And he searched",0,15],["H2490","and began",17,26],["H1419","at the eldest",27,40],["H3615","and left",42,50],["H6996","at the youngest",51,66],["H1375","and the cup",68,79],["H4672","was found",80,89],["H1144","in Benjamin's",90,103],["H0572","sack",104,108]]},"44:13":{"text":"Then they rent their clothes, and laded every man his ass, and returned to the city.","words":[["H7167","Then they rent",0,14],["H8071","their clothes",15,28],["H6006","and laded",30,39],["H0376","every man",40,49],["H2543","his ass",50,57],["H7725","and returned",59,71],["H5892","to the city",72,83]]},"44:14":{"text":"And Judah and his brethren came to Joseph's house; for he was yet there: and they fell before him on the ground.","words":[["H3063","And Judah",0,9],["H0251","and his brethren",10,26],["H0935","came",27,31],["H3130","to Joseph's",32,43],["H1004","house",44,49],["H5307","for he was yet there: and they fell",51,86],["H6440","before him",87,97],["H0776","on the ground",98,111]]},"44:15":{"text":"And Joseph said unto them, What deed is this that ye have done? wot ye not that such a man as I can certainly divine?","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H4639","unto them, What deed",16,36],["H6213","is this that ye have done",37,62],["H3045","wot ye",64,70],["H0376","not that such a man",71,90],["H5172","as I can certainly",91,109],["H5172","divine",110,116]]},"44:16":{"text":"And Judah said, What shall we say unto my lord? what shall we speak? or how shall we clear ourselves? God hath found out the iniquity of thy servants: behold, we are my lord's servants, both we, and he also with whom the cup is found.","words":[["H3063","And Judah",0,9],["H0559","said",10,14],["H0559","What shall we say",16,33],["H0113","unto my lord",34,46],["H1696","what shall we speak",48,67],["H6663","or how shall we clear ourselves",69,100],["H0430","God",102,105],["H4672","hath found out",106,120],["H5771","the iniquity",121,133],["H5650","of thy servants",134,149],["H0113","behold, we are my lord's",151,175],["H5650","servants",176,184],["H1571","both we, and he also",186,206],["H0834","with whom",207,216],["H3027","with whom",207,216],["H1375","the cup",217,224],["H4672","is found",225,233]]},"44:17":{"text":"And he said, God forbid that I should do so: but the man in whose hand the cup is found, he shall be my servant; and as for you, get you up in peace unto your father.","words":[["H0559","And he said",0,11],["H2486","God forbid",13,23],["H6213","that I should do",24,40],["H2063","so",41,43],["H0376","but the man",45,56],["H3027","in whose hand",57,70],["H1375","the cup",71,78],["H4672","is found",79,87],["H5650","he shall be my servant",89,111],["H5927","and as for you, get you up",113,139],["H7965","in peace",140,148],["H0001","unto your father",149,165]]},"44:18":{"text":"Then Judah came near unto him, and said, Oh my lord, let thy servant, I pray thee, speak a word in my lord's ears, and let not thine anger burn against thy servant: for thou art even as Pharaoh.","words":[["H3063","Then Judah",0,10],["H5066","came near",11,20],["H0559","unto him, and said",21,39],["H0994","Oh",41,43],["H0113","my lord",44,51],["H5650","let thy servant",53,68],["H1696","I pray thee, speak",70,88],["H1697","a word",89,95],["H0113","in my lord's",96,108],["H0241","ears",109,113],["H0639","and let not thine anger",115,138],["H2734","burn",139,143],["H5650","against thy servant",144,163],["H6547","for thou art even as Pharaoh",165,193]]},"44:19":{"text":"My lord asked his servants, saying, Have ye a father, or a brother?","words":[["H0113","My lord",0,7],["H7592","asked",8,13],["H5650","his servants",14,26],["H0559","saying",28,34],["H3426","Have",36,40],["H0001","ye a father",41,52],["H0251","or a brother",54,66]]},"44:20":{"text":"And we said unto my lord, We have a father, an old man, and a child of his old age, a little one; and his brother is dead, and he alone is left of his mother, and his father loveth him.","words":[["H0559","And we said",0,11],["H0113","unto my lord",12,24],["H3426","We have",26,33],["H0001","a father",34,42],["H2205","an old man",44,54],["H3206","and a child",56,67],["H2208","of his old age",68,82],["H6996","a little one",84,96],["H0251","and his brother",98,113],["H4191","is dead",114,121],["H3498","and he alone is left",123,143],["H0517","of his mother",144,157],["H0001","and his father",159,173],["H0157","loveth",174,180]]},"44:21":{"text":"And thou saidst unto thy servants, Bring him down unto me, that I may set mine eyes upon him.","words":[["H0559","And thou saidst",0,15],["H5650","unto thy servants",16,33],["H3381","Bring him down",35,49],["H7760","unto me, that I may set",50,73],["H5869","mine eyes",74,83]]},"44:22":{"text":"And we said unto my lord, The lad cannot leave his father: for if he should leave his father, his father would die.","words":[["H0559","And we said",0,11],["H0113","unto my lord",12,24],["H5288","The lad",26,33],["H3201","cannot",34,40],["H5800","leave",41,46],["H0001","his father",47,57],["H5800","for if he should leave",59,81],["H0001","his father",82,92],["H4191","his father would die",94,114]]},"44:23":{"text":"And thou saidst unto thy servants, Except your youngest brother come down with you, ye shall see my face no more.","words":[["H0559","And thou saidst",0,15],["H5650","unto thy servants",16,33],["H3808","Except",35,41],["H6996","your youngest",42,55],["H0251","brother",56,63],["H3381","come down",64,73],["H7200","with you, ye shall see",74,96],["H3254","with you, ye shall see",74,96],["H6440","my face",97,104],["H7200","no more",105,112],["H3254","no more",105,112]]},"44:24":{"text":"And it came to pass when we came up unto thy servant my father, we told him the words of my lord.","words":[["H5927","And it came to pass when we came up",0,35],["H5650","unto thy servant",36,52],["H0001","my father",53,62],["H5046","we told",64,71],["H1697","him the words",72,85],["H0113","of my lord",86,96]]},"44:25":{"text":"And our father said, Go again, and buy us a little food.","words":[["H0001","And our father",0,14],["H0559","said",15,19],["H7725","Go again",21,29],["H7666","and buy",31,38],["H4592","us a little",39,50],["H0400","food",51,55]]},"44:26":{"text":"And we said, We cannot go down: if our youngest brother be with us, then will we go down: for we may not see the man's face, except our youngest brother be with us.","words":[["H0559","And we said",0,11],["H3201","We cannot",13,22],["H3381","go down",23,30],["H6996","if our youngest",32,47],["H0251","brother",48,55],["H3426","be",56,58],["H3381","with us, then will we go down",59,88],["H3201","for we may",90,100],["H7200","not see",101,108],["H0376","the man's",109,118],["H6440","face",119,123],["H0369","except",125,131],["H6996","our youngest",132,144],["H0251","brother",145,152]]},"44:27":{"text":"And thy servant my father said unto us, Ye know that my wife bare me two sons:","words":[["H5650","And thy servant",0,15],["H0001","my father",16,25],["H0559","said",26,30],["H3045","unto us, Ye know",31,47],["H0802","that my wife",48,60],["H3205","bare",61,65],["H8147","me two",66,72]]},"44:28":{"text":"And the one went out from me, and I said, Surely he is torn in pieces; and I saw him not since:","words":[["H0259","And the one",0,11],["H3318","went out",12,20],["H0559","from me, and I said",21,40],["H2963","Surely",42,48],["H2963","he is torn in pieces",49,69],["H7200","and I saw him",71,84],["H2008","not since",85,94]]},"44:29":{"text":"And if ye take this also from me, and mischief befall him, ye shall bring down my gray hairs with sorrow to the grave.","words":[["H3947","And if ye take",0,14],["H5973","this also from",15,29],["H6440","me",30,32],["H0611","and mischief",34,46],["H7136","befall him",47,57],["H3381","ye shall bring down",59,78],["H7872","my gray hairs",79,92],["H7451","with sorrow",93,104],["H7585","to the grave",105,117]]},"44:30":{"text":"Now therefore when I come to thy servant my father, and the lad be not with us; seeing that his life is bound up in the lad's life;","words":[["H0935","Now therefore when I come",0,25],["H5650","to thy servant",26,40],["H0001","my father",41,50],["H5288","and the lad",52,63],["H5315","be not with us; seeing that his life",64,100],["H7194","is bound up",101,112],["H5315","in the lad's life",113,130]]},"44:31":{"text":"It shall come to pass, when he seeth that the lad is not with us, that he will die: and thy servants shall bring down the gray hairs of thy servant our father with sorrow to the grave.","words":[["H7200","It shall come to pass, when he seeth",0,36],["H5288","that the lad",37,49],["H4191","is not with us, that he will die",50,82],["H5650","and thy servants",84,100],["H3381","shall bring down",101,117],["H7872","the gray hairs",118,132],["H5650","of thy servant",133,147],["H0001","our father",148,158],["H3015","with sorrow",159,170],["H7585","to the grave",171,183]]},"44:32":{"text":"For thy servant became surety for the lad unto my father, saying, If I bring him not unto thee, then I shall bear the blame to my father for ever.","words":[["H5650","For thy servant",0,15],["H6148","became surety",16,29],["H5288","for the lad",30,41],["H5973","unto",42,46],["H0001","my father",47,56],["H0559","saying",58,64],["H0935","If I bring",66,76],["H2398","him not unto thee, then I shall bear the blame",77,123],["H0001","to my father",124,136],["H3117","for ever",137,145]]},"44:33":{"text":"Now therefore, I pray thee, let thy servant abide instead of the lad a bondman to my lord; and let the lad go up with his brethren.","words":[["H5650","Now therefore, I pray thee, let thy servant",0,43],["H3427","abide",44,49],["H5288","instead of the lad",50,68],["H5650","a bondman",69,78],["H0113","to my lord",79,89],["H5288","and let the lad",91,106],["H5927","go up",107,112],["H0251","with his brethren",113,130]]},"44:34":{"text":"For how shall I go up to my father, and the lad be not with me? lest peradventure I see the evil that shall come on my father.","words":[["H0349","For how",0,7],["H5927","shall I go up",8,21],["H0001","to my father",22,34],["H5288","and the lad",36,47],["H7200","be not with me? lest peradventure I see",48,87],["H7451","the evil",88,96],["H4672","that shall come on",97,115],["H0001","my father",116,125]]},"45:1":{"text":"Then Joseph could not refrain himself before all them that stood by him; and he cried, Cause every man to go out from me. And there stood no man with him, while Joseph made himself known unto his brethren.","words":[["H3130","Then Joseph",0,11],["H3201","could",12,17],["H0662","not refrain",18,29],["H5324","himself before all them that stood",30,64],["H7121","by him; and he cried",65,85],["H3318","Cause",87,92],["H0376","every man",93,102],["H3318","to go out",103,112],["H5975","from me. And there stood",113,137],["H0376","no man",138,144],["H3130","with him, while Joseph",145,167],["H3045","made himself known",168,186],["H0251","unto his brethren",187,204]]},"45:2":{"text":"And he wept aloud: and the Egyptians and the house of Pharaoh heard.","words":[["H6963","And he wept",0,11],["H1065","And he wept",0,11],["H5414","aloud",12,17],["H4714","and the Egyptians",19,36],["H1004","and the house",37,50],["H6547","of Pharaoh",51,61],["H8085","heard",62,67],["H8085","heard",62,67]]},"45:3":{"text":"And Joseph said unto his brethren, I am Joseph; doth my father yet live? And his brethren could not answer him; for they were troubled at his presence.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H0251","unto his brethren",16,33],["H3130","I am Joseph",35,46],["H0001","doth my father",48,62],["H2416","yet live",63,71],["H0251","And his brethren",73,89],["H3201","could",90,95],["H6030","not answer",96,106],["H0926","him; for they were troubled",107,134],["H6440","at his presence",135,150]]},"45:4":{"text":"And Joseph said unto his brethren, Come near to me, I pray you. And they came near. And he said, I am Joseph your brother, whom ye sold into Egypt.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H0251","unto his brethren",16,33],["H5066","Come near",35,44],["H5066","to me, I pray you. And they came near",45,82],["H0559","And he said",84,95],["H3130","I am Joseph",97,108],["H0251","your brother",109,121],["H4376","whom ye sold",123,135],["H4714","into Egypt",136,146]]},"45:5":{"text":"Now therefore be not grieved, nor angry with yourselves, that ye sold me hither: for God did send me before you to preserve life.","words":[["H6087","Now therefore be not grieved",0,28],["H2734","nor angry",30,39],["H5869","with yourselves",40,55],["H4376","that ye sold",57,69],["H0430","me hither: for God",70,88],["H7971","did send",89,97],["H6440","me before you",98,111],["H4241","to preserve life",112,128]]},"45:6":{"text":"For these two years hath the famine been in the land: and yet there are five years, in the which there shall neither be earing nor harvest.","words":[["H8141","For these two years",0,19],["H7458","hath the famine",20,35],["H7130","been in",36,43],["H0776","the land",44,52],["H2568","and yet there are five",54,76],["H8141","years",77,82],["H0369","in the which there shall neither",84,116],["H2758","be earing",117,126],["H7105","nor harvest",127,138]]},"45:7":{"text":"And God sent me before you to preserve you a posterity in the earth, and to save your lives by a great deliverance.","words":[["H0430","And God",0,7],["H7971","sent",8,12],["H6440","me before you",13,26],["H7760","to preserve",27,38],["H7611","you a posterity",39,54],["H0776","in the earth",55,67],["H2421","and to save your lives",69,91],["H1419","by a great",92,102],["H6413","deliverance",103,114]]},"45:8":{"text":"So now it was not you that sent me hither, but God: and he hath made me a father to Pharaoh, and lord of all his house, and a ruler throughout all the land of Egypt.","words":[["H7971","So now it was not you that sent",0,31],["H0430","me hither, but God",32,50],["H7760","and he hath made",52,68],["H0001","me a father",69,80],["H6547","to Pharaoh",81,91],["H0113","and lord",93,101],["H1004","of all his house",102,118],["H4910","and a ruler",120,131],["H0776","throughout all the land",132,155],["H4714","of Egypt",156,164]]},"45:9":{"text":"Haste ye, and go up to my father, and say unto him, Thus saith thy son Joseph, God hath made me lord of all Egypt: come down unto me, tarry not:","words":[["H4116","Haste",0,5],["H5927","ye, and go up",6,19],["H0001","to my father",20,32],["H0559","and say",34,41],["H0559","unto him, Thus saith",42,62],["H1121","thy son",63,70],["H3130","Joseph",71,77],["H0430","God",79,82],["H7760","hath made",83,92],["H0113","me lord",93,100],["H4714","of all Egypt",101,113],["H3381","come down",115,124],["H5975","unto me, tarry",125,139]]},"45:10":{"text":"And thou shalt dwell in the land of Goshen, and thou shalt be near unto me, thou, and thy children, and thy children's children, and thy flocks, and thy herds, and all that thou hast:","words":[["H3427","And thou shalt dwell",0,20],["H0776","in the land",21,32],["H1657","of Goshen",33,42],["H7138","and thou shalt be near",44,66],["H1121","unto me, thou, and thy children",67,98],["H1121","and thy children's",100,118],["H1121","children",119,127],["H6629","and thy flocks",129,143],["H1241","and thy herds",145,158]]},"45:11":{"text":"And there will I nourish thee; for yet there are five years of famine; lest thou, and thy household, and all that thou hast, come to poverty.","words":[["H3557","And there will I nourish",0,24],["H2568","thee; for yet there are five",25,53],["H8141","years",54,59],["H7458","of famine",60,69],["H1004","lest thou, and thy household",71,99],["H3423","and all that thou hast, come to poverty",101,140]]},"45:12":{"text":"And, behold, your eyes see, and the eyes of my brother Benjamin, that it is my mouth that speaketh unto you.","words":[["H5869","And, behold, your eyes",0,22],["H7200","see",23,26],["H5869","and the eyes",28,40],["H0251","of my brother",41,54],["H1144","Benjamin",55,63],["H6310","that it is my mouth",65,84],["H1696","that speaketh",85,98]]},"45:13":{"text":"And ye shall tell my father of all my glory in Egypt, and of all that ye have seen; and ye shall haste and bring down my father hither.","words":[["H5046","And ye shall tell",0,17],["H0001","my father",18,27],["H3519","of all my glory",28,43],["H4714","in Egypt",44,52],["H7200","and of all that ye have seen",54,82],["H4116","and ye shall haste",84,102],["H3381","and bring down",103,117],["H0001","my father",118,127]]},"45:14":{"text":"And he fell upon his brother Benjamin's neck, and wept; and Benjamin wept upon his neck.","words":[["H5307","And he fell",0,11],["H0251","upon his brother",12,28],["H1144","Benjamin's",29,39],["H6677","neck",40,44],["H1058","and wept",46,54],["H1144","and Benjamin",56,68],["H1058","wept",69,73],["H6677","upon his neck",74,87]]},"45:15":{"text":"Moreover he kissed all his brethren, and wept upon them: and after that his brethren talked with him.","words":[["H5401","Moreover he kissed",0,18],["H0251","all his brethren",19,35],["H1058","and wept",37,45],["H0310","upon them: and after",46,66],["H0251","that his brethren",67,84],["H1696","talked",85,91]]},"45:16":{"text":"And the fame thereof was heard in Pharaoh's house, saying, Joseph's brethren are come: and it pleased Pharaoh well, and his servants.","words":[["H6963","And the fame",0,12],["H8085","thereof was heard",13,30],["H6547","in Pharaoh's",31,43],["H1004","house",44,49],["H0559","saying",51,57],["H3130","Joseph's",59,67],["H0251","brethren",68,76],["H0935","are come",77,85],["H3190","and it pleased",87,101],["H5869","and it pleased",87,101],["H6547","Pharaoh",102,109],["H3190","well",110,114],["H5869","well",110,114],["H5869","and",116,119],["H5650","his servants",120,132]]},"45:17":{"text":"And Pharaoh said unto Joseph, Say unto thy brethren, This do ye; lade your beasts, and go, get you unto the land of Canaan;","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H3130","unto Joseph",17,28],["H0559","Say",30,33],["H0251","unto thy brethren",34,51],["H6213","This do",53,60],["H2943","ye; lade",61,69],["H1165","your beasts",70,81],["H3212","and go",83,89],["H0935","get",91,94],["H0776","you unto the land",95,112],["H3667","of Canaan",113,122]]},"45:18":{"text":"And take your father and your households, and come unto me: and I will give you the good of the land of Egypt, and ye shall eat the fat of the land.","words":[["H3947","And take",0,8],["H0001","your father",9,20],["H1004","and your households",21,40],["H0935","and come",42,50],["H5414","unto me: and I will give",51,75],["H2898","you the good",76,88],["H0776","of the land",89,100],["H4714","of Egypt",101,109],["H0398","and ye shall eat",111,127],["H2459","the fat",128,135],["H0776","of the land",136,147]]},"45:19":{"text":"Now thou art commanded, this do ye; take you wagons out of the land of Egypt for your little ones, and for your wives, and bring your father, and come.","words":[["H6680","Now thou art commanded",0,22],["H6213","this do",24,31],["H3947","ye; take",32,40],["H5699","you wagons",41,51],["H0776","out of the land",52,67],["H4714","of Egypt",68,76],["H2945","for your little ones",77,97],["H0802","and for your wives",99,117],["H5375","and bring",119,128],["H0001","your father",129,140],["H0935","and come",142,150]]},"45:20":{"text":"Also regard not your stuff; for the good of all the land of Egypt is yours.","words":[["H5869","Also",0,4],["H2347","regard",5,11],["H3627","not your stuff",12,26],["H2898","for the good",28,40],["H0776","of all the land",41,56],["H4714","of Egypt",57,65]]},"45:21":{"text":"And the children of Israel did so: and Joseph gave them wagons, according to the commandment of Pharaoh, and gave them provision for the way.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H3130","so: and Joseph",31,45],["H5414","gave",46,50],["H5699","them wagons",51,62],["H6310","according to the commandment",64,92],["H6547","of Pharaoh",93,103],["H5414","and gave",105,113],["H6720","them provision",114,128],["H1870","for the way",129,140]]},"45:22":{"text":"To all of them he gave each man changes of raiment; but to Benjamin he gave three hundred pieces of silver, and five changes of raiment.","words":[["H5414","To all of them he gave",0,22],["H0376","each man",23,31],["H2487","changes",32,39],["H8071","of raiment",40,50],["H1144","but to Benjamin",52,67],["H5414","he gave",68,75],["H7969","three",76,81],["H3967","hundred",82,89],["H3701","pieces of silver",90,106],["H2568","and five",108,116],["H2487","changes",117,124],["H8071","of raiment",125,135]]},"45:23":{"text":"And to his father he sent after this manner; ten asses laden with the good things of Egypt, and ten she asses laden with corn and bread and meat for his father by the way.","words":[["H0001","And to his father",0,17],["H7971","he sent",18,25],["H2063","after this",26,36],["H6235","manner; ten",37,48],["H0860","asses",49,54],["H5375","laden",55,60],["H2898","with the good things",61,81],["H4714","of Egypt",82,90],["H6235","and ten",92,99],["H2543","she asses",100,109],["H5375","laden",110,115],["H1250","with corn",116,125],["H3899","and bread",126,135],["H4202","and meat",136,144],["H0001","for his father",145,159],["H1870","by the way",160,170]]},"45:24":{"text":"So he sent his brethren away, and they departed: and he said unto them, See that ye fall not out by the way.","words":[["H7971","So he sent",0,10],["H0251","his brethren",11,23],["H7971","away",24,28],["H3212","and they departed",30,47],["H0559","and he said",49,60],["H7264","unto them, See that ye fall not out",61,96],["H1870","by the way",97,107]]},"45:25":{"text":"And they went up out of Egypt, and came into the land of Canaan unto Jacob their father,","words":[["H5927","And they went up",0,16],["H4714","out of Egypt",17,29],["H0935","and came",31,39],["H0776","into the land",40,53],["H3667","of Canaan",54,63],["H3290","unto Jacob",64,74],["H0001","their father",75,87]]},"45:26":{"text":"And told him, saying, Joseph is yet alive, and he is governor over all the land of Egypt. And Jacob's heart fainted, for he believed them not.","words":[["H5046","And told",0,8],["H0559","him, saying",9,20],["H3130","Joseph",22,28],["H2416","is yet alive",29,41],["H4910","and he is governor",43,61],["H0776","over all the land",62,79],["H4714","of Egypt",80,88],["H3820","And Jacob's heart",90,107],["H6313","fainted",108,115],["H0539","for he believed",117,132]]},"45:27":{"text":"And they told him all the words of Joseph, which he had said unto them: and when he saw the wagons which Joseph had sent to carry him, the spirit of Jacob their father revived:","words":[["H1696","And they told",0,13],["H1697","him all the words",14,31],["H3130","of Joseph",32,41],["H1696","which he had said",43,60],["H7200","unto them: and when he saw",61,87],["H5699","the wagons",88,98],["H3130","which Joseph",99,111],["H7971","had sent",112,120],["H5375","to carry",121,129],["H7307","him, the spirit",130,145],["H3290","of Jacob",146,154],["H0001","their father",155,167],["H2421","revived",168,175]]},"45:28":{"text":"And Israel said, It is enough; Joseph my son is yet alive: I will go and see him before I die.","words":[["H3478","And Israel",0,10],["H0559","said",11,15],["H7227","It is enough",17,29],["H3130","Joseph",31,37],["H1121","my son",38,44],["H2416","is yet alive",45,57],["H3212","I will go",59,68],["H7200","and see him",69,80],["H4191","before I die",81,93]]},"46:1":{"text":"And Israel took his journey with all that he had, and came to Beersheba, and offered sacrifices unto the God of his father Isaac.","words":[["H3478","And Israel",0,10],["H5265","took his journey",11,27],["H0935","with all that he had, and came",28,58],["H0884","to Beersheba",59,71],["H2076","and offered",73,84],["H2077","sacrifices",85,95],["H0430","unto the God",96,108],["H0001","of his father",109,122],["H3327","Isaac",123,128]]},"46:2":{"text":"And God spake unto Israel in the visions of the night, and said, Jacob, Jacob. And he said, Here am I.","words":[["H0430","And God",0,7],["H0559","spake",8,13],["H3478","unto Israel",14,25],["H4759","in the visions",26,40],["H3915","of the night",41,53],["H0559","and said",55,63],["H3290","Jacob",65,70],["H3290","Jacob",72,77],["H0559","And he said",79,90]]},"46:3":{"text":"And he said, I am God, the God of thy father: fear not to go down into Egypt; for I will there make of thee a great nation:","words":[["H0559","And he said",0,11],["H0410","I am God",13,21],["H0430","the God",23,30],["H0001","of thy father",31,44],["H3372","fear",46,50],["H3381","not to go down",51,65],["H4714","into Egypt",66,76],["H7760","for I will there make",78,99],["H1419","of thee a great",100,115],["H1471","nation",116,122]]},"46:4":{"text":"I will go down with thee into Egypt; and I will also surely bring thee up again: and Joseph shall put his hand upon thine eyes.","words":[["H3381","I will go down",0,14],["H4714","with thee into Egypt",15,35],["H5927","and I will also surely",37,59],["H5927","bring thee up",60,73],["H3130","again: and Joseph",74,91],["H7896","shall put",92,101],["H3027","his hand",102,110],["H5869","upon thine eyes",111,126]]},"46:5":{"text":"And Jacob rose up from Beersheba: and the sons of Israel carried Jacob their father, and their little ones, and their wives, in the wagons which Pharaoh had sent to carry him.","words":[["H3290","And Jacob",0,9],["H6965","rose up",10,17],["H0884","from Beersheba",18,32],["H1121","and the sons",34,46],["H3478","of Israel",47,56],["H5375","carried",57,64],["H3290","Jacob",65,70],["H0001","their father",71,83],["H2945","and their little ones",85,106],["H0802","and their wives",108,123],["H5699","in the wagons",125,138],["H6547","which Pharaoh",139,152],["H7971","had sent",153,161],["H5375","to carry",162,170]]},"46:6":{"text":"And they took their cattle, and their goods, which they had gotten in the land of Canaan, and came into Egypt, Jacob, and all his seed with him:","words":[["H3947","And they took",0,13],["H4735","their cattle",14,26],["H7399","and their goods",28,43],["H7408","which they had gotten",45,66],["H0776","in the land",67,78],["H3667","of Canaan",79,88],["H0935","and came",90,98],["H4714","into Egypt",99,109],["H3290","Jacob",111,116],["H2233","and all his seed",118,134]]},"46:7":{"text":"His sons, and his sons' sons with him, his daughters, and his sons' daughters, and all his seed brought he with him into Egypt.","words":[["H1121","His sons",0,8],["H1121","and his sons'",10,23],["H1121","sons",24,28],["H1323","with him, his daughters",29,52],["H1121","and his sons'",54,67],["H1323","daughters",68,77],["H2233","and all his seed",79,95],["H0935","brought he",96,106],["H4714","with him into Egypt",107,126]]},"46:8":{"text":"And these are the names of the children of Israel, which came into Egypt, Jacob and his sons: Reuben, Jacob's firstborn.","words":[["H8034","And these are the names",0,23],["H1121","of the children",24,39],["H3478","of Israel",40,49],["H0935","which came",51,61],["H4714","into Egypt",62,72],["H3290","Jacob",74,79],["H1121","and his sons",80,92],["H7205","Reuben",94,100],["H3290","Jacob's",102,109],["H1060","firstborn",110,119]]},"46:9":{"text":"And the sons of Reuben; Hanoch, and Phallu, and Hezron, and Carmi.","words":[["H1121","And the sons",0,12],["H7205","of Reuben",13,22],["H2585","Hanoch",24,30],["H6396","and Phallu",32,42],["H2696","and Hezron",44,54],["H3756","and Carmi",56,65]]},"46:10":{"text":"And the sons of Simeon; Jemuel, and Jamin, and Ohad, and Jachin, and Zohar, and Shaul the son of a Canaanitish woman.","words":[["H1121","And the sons",0,12],["H8095","of Simeon",13,22],["H3223","Jemuel",24,30],["H3226","and Jamin",32,41],["H0161","and Ohad",43,51],["H3199","and Jachin",53,63],["H6714","and Zohar",65,74],["H7586","and Shaul",76,85],["H1121","the son",86,93],["H3669","of a Canaanitish",94,110]]},"46:11":{"text":"And the sons of Levi; Gershon, Kohath, and Merari.","words":[["H1121","And the sons",0,12],["H3878","of Levi",13,20],["H1648","Gershon",22,29],["H6955","Kohath",31,37],["H4847","and Merari",39,49]]},"46:12":{"text":"And the sons of Judah; Er, and Onan, and Shelah, and Pharez, and Zerah: but Er and Onan died in the land of Canaan. And the sons of Pharez were Hezron and Hamul.","words":[["H1121","And the sons",0,12],["H3063","of Judah",13,21],["H6147","Er",23,25],["H0209","and Onan",27,35],["H7956","and Shelah",37,47],["H6557","and Pharez",49,59],["H2226","and Zerah",61,70],["H6147","but Er",72,78],["H0209","and Onan",79,87],["H4191","died",88,92],["H0776","in the land",93,104],["H3667","of Canaan",105,114],["H1121","And the sons",116,128],["H6557","of Pharez",129,138],["H2696","were Hezron",139,150],["H2538","and Hamul",151,160]]},"46:13":{"text":"And the sons of Issachar; Tola, and Phuvah, and Job, and Shimron.","words":[["H1121","And the sons",0,12],["H3485","of Issachar",13,24],["H8439","Tola",26,30],["H6312","and Phuvah",32,42],["H3102","and Job",44,51],["H8110","and Shimron",53,64]]},"46:14":{"text":"And the sons of Zebulun; Sered, and Elon, and Jahleel.","words":[["H1121","And the sons",0,12],["H2074","of Zebulun",13,23],["H5624","Sered",25,30],["H0356","and Elon",32,40],["H3177","and Jahleel",42,53]]},"46:15":{"text":"These be the sons of Leah, which she bare unto Jacob in Padanaram, with his daughter Dinah: all the souls of his sons and his daughters were thirty and three.","words":[["H1121","These be the sons",0,17],["H3812","of Leah",18,25],["H3205","which she bare",27,41],["H3290","unto Jacob",42,52],["H6307","in Padanaram",53,65],["H1323","with his daughter",67,84],["H1783","Dinah",85,90],["H5315","all the souls",92,105],["H1121","of his sons",106,117],["H1323","and his daughters",118,135],["H7970","were thirty",136,147],["H7969","and three",148,157]]},"46:16":{"text":"And the sons of Gad; Ziphion, and Haggi, Shuni, and Ezbon, Eri, and Arodi, and Areli.","words":[["H1121","And the sons",0,12],["H1410","of Gad",13,19],["H6837","Ziphion",21,28],["H2291","and Haggi",30,39],["H7764","Shuni",41,46],["H0675","and Ezbon",48,57],["H6179","Eri",59,62],["H0722","and Arodi",64,73],["H0692","and Areli",75,84]]},"46:17":{"text":"And the sons of Asher; Jimnah, and Ishuah, and Isui, and Beriah, and Serah their sister: and the sons of Beriah; Heber, and Malchiel.","words":[["H1121","And the sons",0,12],["H0836","of Asher",13,21],["H3232","Jimnah",23,29],["H3438","and Ishuah",31,41],["H3440","and Isui",43,51],["H1283","and Beriah",53,63],["H8294","and Serah",65,74],["H0269","their sister",75,87],["H1121","and the sons",89,101],["H1283","of Beriah",102,111],["H2268","Heber",113,118],["H4439","and Malchiel",120,132]]},"46:18":{"text":"These are the sons of Zilpah, whom Laban gave to Leah his daughter, and these she bare unto Jacob, even sixteen souls.","words":[["H1121","These are the sons",0,18],["H2153","of Zilpah",19,28],["H3837","whom Laban",30,40],["H5414","gave",41,45],["H3812","to Leah",46,53],["H1323","his daughter",54,66],["H3205","and these she bare",68,86],["H3290","unto Jacob",87,97],["H6240","even sixteen",99,111],["H8337","even sixteen",99,111],["H5315","souls",112,117]]},"46:19":{"text":"The sons of Rachel Jacob's wife; Joseph, and Benjamin.","words":[["H1121","The sons",0,8],["H7354","of Rachel",9,18],["H3290","Jacob's",19,26],["H0802","wife",27,31],["H3130","Joseph",33,39],["H1144","and Benjamin",41,53]]},"46:20":{"text":"And unto Joseph in the land of Egypt were born Manasseh and Ephraim, which Asenath the daughter of Potipherah priest of On bare unto him.","words":[["H3130","And unto Joseph",0,15],["H0776","in the land",16,27],["H4714","of Egypt",28,36],["H3205","were born",37,46],["H4519","Manasseh",47,55],["H0669","and Ephraim",56,67],["H0621","which Asenath",69,82],["H1323","the daughter",83,95],["H6319","of Potipherah",96,109],["H3548","priest",110,116],["H0204","of On",117,122],["H3205","bare",123,127]]},"46:21":{"text":"And the sons of Benjamin were Belah, and Becher, and Ashbel, Gera, and Naaman, Ehi, and Rosh, Muppim, and Huppim, and Ard.","words":[["H1121","And the sons",0,12],["H1144","of Benjamin",13,24],["H1106","were Belah",25,35],["H1071","and Becher",37,47],["H0788","and Ashbel",49,59],["H1617","Gera",61,65],["H5283","and Naaman",67,77],["H0278","Ehi",79,82],["H7220","and Rosh",84,92],["H4649","Muppim",94,100],["H2650","and Huppim",102,112],["H0714","and Ard",114,121]]},"46:22":{"text":"These are the sons of Rachel, which were born to Jacob: all the souls were fourteen.","words":[["H1121","These are the sons",0,18],["H7354","of Rachel",19,28],["H3205","which were born",30,45],["H3290","to Jacob",46,54],["H5315","all the souls",56,69],["H0702","were fourteen",70,83],["H6240","were fourteen",70,83]]},"46:23":{"text":"And the sons of Dan; Hushim.","words":[["H1121","And the sons",0,12],["H1835","of Dan",13,19],["H2366","Hushim",21,27]]},"46:24":{"text":"And the sons of Naphtali; Jahzeel, and Guni, and Jezer, and Shillem.","words":[["H1121","And the sons",0,12],["H5321","of Naphtali",13,24],["H3183","Jahzeel",26,33],["H1476","and Guni",35,43],["H3337","and Jezer",45,54],["H8006","and Shillem",56,67]]},"46:25":{"text":"These are the sons of Bilhah, which Laban gave unto Rachel his daughter, and she bare these unto Jacob: all the souls were seven.","words":[["H1121","These are the sons",0,18],["H1090","of Bilhah",19,28],["H3837","which Laban",30,41],["H5414","gave",42,46],["H7354","unto Rachel",47,58],["H1323","his daughter",59,71],["H3205","and she bare",73,85],["H3290","these unto Jacob",86,102],["H5315","all the souls",104,117],["H7651","were seven",118,128]]},"46:26":{"text":"All the souls that came with Jacob into Egypt, which came out of his loins, besides Jacob's sons' wives, all the souls were threescore and six;","words":[["H5315","All the souls",0,13],["H0935","that came",14,23],["H3290","with Jacob",24,34],["H4714","into Egypt",35,45],["H3318","which came out",47,61],["H3409","of his loins",62,74],["H3290","besides Jacob's",76,91],["H1121","sons'",92,97],["H0802","wives",98,103],["H5315","all the souls",105,118],["H8346","were threescore",119,134],["H8337","and six",135,142]]},"46:27":{"text":"And the sons of Joseph, which were born him in Egypt, were two souls: all the souls of the house of Jacob, which came into Egypt, were threescore and ten.","words":[["H1121","And the sons",0,12],["H3130","of Joseph",13,22],["H3205","which were born",24,39],["H4714","him in Egypt",40,52],["H8147","were two",54,62],["H5315","souls",63,68],["H5315","all the souls",70,83],["H1004","of the house",84,96],["H3290","of Jacob",97,105],["H0935","which came",107,117],["H4714","into Egypt",118,128],["H7657","were threescore and ten",130,153]]},"46:28":{"text":"And he sent Judah before him unto Joseph, to direct his face unto Goshen; and they came into the land of Goshen.","words":[["H7971","And he sent",0,11],["H3063","Judah",12,17],["H6440","before him",18,28],["H3130","unto Joseph",29,40],["H3384","to direct",42,51],["H6440","his face",52,60],["H1657","unto Goshen",61,72],["H0935","and they came",74,87],["H0776","into the land",88,101],["H1657","of Goshen",102,111]]},"46:29":{"text":"And Joseph made ready his chariot, and went up to meet Israel his father, to Goshen, and presented himself unto him; and he fell on his neck, and wept on his neck a good while.","words":[["H3130","And Joseph",0,10],["H0631","made ready",11,21],["H4818","his chariot",22,33],["H5927","and went up",35,46],["H7125","to meet",47,54],["H3478","Israel",55,61],["H0001","his father",62,72],["H1657","to Goshen",74,83],["H7200","and presented",85,98],["H5307","himself unto him; and he fell",99,128],["H6677","on his neck",129,140],["H1058","and wept",142,150],["H6677","on his neck",151,162],["H5750","a good while",163,175]]},"46:30":{"text":"And Israel said unto Joseph, Now let me die, since I have seen thy face, because thou art yet alive.","words":[["H3478","And Israel",0,10],["H0559","said",11,15],["H3130","unto Joseph",16,27],["H6471","Now",29,32],["H4191","let me die",33,43],["H0310","since",45,50],["H7200","I have seen",51,62],["H6440","thy face",63,71],["H5750","because thou art yet",73,93],["H2416","alive",94,99]]},"46:31":{"text":"And Joseph said unto his brethren, and unto his father's house, I will go up, and shew Pharaoh, and say unto him, My brethren, and my father's house, which were in the land of Canaan, are come unto me;","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H0251","unto his brethren",16,33],["H0001","and unto his father's",35,56],["H1004","house",57,62],["H5927","I will go up",64,76],["H5046","and shew",78,86],["H6547","Pharaoh",87,94],["H0559","and say",96,103],["H0251","unto him, My brethren",104,125],["H0001","and my father's",127,142],["H1004","house",143,148],["H0776","which were in the land",150,172],["H3667","of Canaan",173,182],["H0935","are come",184,192]]},"46:32":{"text":"And the men are shepherds, for their trade hath been to feed cattle; and they have brought their flocks, and their herds, and all that they have.","words":[["H0582","And the men",0,11],["H7462","are shepherds",12,25],["H6629","are shepherds",12,25],["H4735","for their trade hath been to feed cattle",27,67],["H0935","and they have brought",69,90],["H6629","their flocks",91,103],["H1241","and their herds",105,120]]},"46:33":{"text":"And it shall come to pass, when Pharaoh shall call you, and shall say, What is your occupation?","words":[["H6547","And it shall come to pass, when Pharaoh",0,39],["H7121","shall call",40,50],["H0559","you, and shall say",51,69],["H4639","What is your occupation",71,94]]},"46:34":{"text":"That ye shall say, Thy servants' trade hath been about cattle from our youth even until now, both we, and also our fathers: that ye may dwell in the land of Goshen; for every shepherd is an abomination unto the Egyptians.","words":[["H0559","That ye shall say",0,17],["H5650","Thy servants'",19,32],["H0582","trade",33,38],["H4735","hath been about cattle",39,61],["H5271","from our youth",62,76],["H0001","even until now, both we, and also our fathers",77,122],["H3427","that ye may dwell",124,141],["H0776","in the land",142,153],["H1657","of Goshen",154,163],["H7462","for every shepherd",165,183],["H6629","for every shepherd",165,183],["H8441","is an abomination",184,201],["H4714","unto the Egyptians",202,220]]},"47:1":{"text":"Then Joseph came and told Pharaoh, and said, My father and my brethren, and their flocks, and their herds, and all that they have, are come out of the land of Canaan; and, behold, they are in the land of Goshen.","words":[["H3130","Then Joseph",0,11],["H0935","came",12,16],["H5046","and told",17,25],["H6547","Pharaoh",26,33],["H0559","and said",35,43],["H0001","My father",45,54],["H0251","and my brethren",55,70],["H6629","and their flocks",72,88],["H1241","and their herds",90,105],["H0935","and all that they have, are come out",107,143],["H0776","of the land",144,155],["H3667","of Canaan",156,165],["H0776","and, behold, they are in the land",167,200],["H1657","of Goshen",201,210]]},"47:2":{"text":"And he took some of his brethren, even five men, and presented them unto Pharaoh.","words":[["H3947","And he took",0,11],["H7097","some",12,16],["H0251","of his brethren",17,32],["H2568","even five",34,43],["H0582","men",44,47],["H3322","and presented",49,62],["H6440","them unto",63,72],["H6547","Pharaoh",73,80]]},"47:3":{"text":"And Pharaoh said unto his brethren, What is your occupation? And they said unto Pharaoh, Thy servants are shepherds, both we, and also our fathers.","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H0251","unto his brethren",17,34],["H4639","What is your occupation",36,59],["H0559","And they said",61,74],["H6547","unto Pharaoh",75,87],["H5650","Thy servants",89,101],["H7462","are shepherds",102,115],["H6629","are shepherds",102,115],["H0001","both we, and also our fathers",117,146]]},"47:4":{"text":"They said moreover unto Pharaoh, For to sojourn in the land are we come; for thy servants have no pasture for their flocks; for the famine is sore in the land of Canaan: now therefore, we pray thee, let thy servants dwell in the land of Goshen.","words":[["H0559","They said",0,9],["H6547","moreover unto Pharaoh",10,31],["H1481","For to sojourn",33,47],["H0776","in the land",48,59],["H0935","are we come",60,71],["H5650","for thy servants",73,89],["H4829","have no pasture",90,105],["H6629","for their flocks",106,122],["H7458","for the famine",124,138],["H3515","is sore",139,146],["H0776","in the land",147,158],["H3667","of Canaan",159,168],["H5650","now therefore, we pray thee, let thy servants",170,215],["H3427","dwell",216,221],["H0776","in the land",222,233],["H1657","of Goshen",234,243]]},"47:5":{"text":"And Pharaoh spake unto Joseph, saying, Thy father and thy brethren are come unto thee:","words":[["H6547","And Pharaoh",0,11],["H0559","spake",12,17],["H3130","unto Joseph",18,29],["H0559","saying",31,37],["H0001","Thy father",39,49],["H0251","and thy brethren",50,66],["H0935","are come",67,75]]},"47:6":{"text":"The land of Egypt is before thee; in the best of the land make thy father and brethren to dwell; in the land of Goshen let them dwell: and if thou knowest any men of activity among them, then make them rulers over my cattle.","words":[["H0776","The land",0,8],["H4714","of Egypt",9,17],["H6440","is before thee",18,32],["H4315","in the best",34,45],["H0776","of the land",46,57],["H3427","make",58,62],["H0001","thy father",63,73],["H0251","and brethren",74,86],["H3427","to dwell",87,95],["H0776","in the land",97,108],["H1657","of Goshen",109,118],["H3427","let them dwell",119,133],["H3045","and if thou knowest",135,154],["H3426","and if thou knowest",135,154],["H0582","any men",155,162],["H2428","of activity",163,174],["H7760","among them, then make them",175,201],["H8269","rulers",202,208],["H4735","over my cattle",209,223]]},"47:7":{"text":"And Joseph brought in Jacob his father, and set him before Pharaoh: and Jacob blessed Pharaoh.","words":[["H3130","And Joseph",0,10],["H0935","brought in",11,21],["H3290","Jacob",22,27],["H0001","his father",28,38],["H5975","and set him",40,51],["H6440","before",52,58],["H6547","Pharaoh",59,66],["H3290","and Jacob",68,77],["H1288","blessed",78,85],["H6547","Pharaoh",86,93]]},"47:8":{"text":"And Pharaoh said unto Jacob, How old art thou?","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H3290","unto Jacob",17,27],["H4100","How",29,32],["H2416","old",33,36],["H3117","old",33,36],["H8141","old",33,36]]},"47:9":{"text":"And Jacob said unto Pharaoh, The days of the years of my pilgrimage are an hundred and thirty years: few and evil have the days of the years of my life been, and have not attained unto the days of the years of the life of my fathers in the days of their pilgrimage.","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H6547","unto Pharaoh",15,27],["H3117","The days",29,37],["H8141","of the years",38,50],["H4033","of my pilgrimage",51,67],["H3967","are an hundred",68,82],["H7970","and thirty",83,93],["H8141","years",94,99],["H4592","few",101,104],["H7451","and evil",105,113],["H3117","have the days",114,127],["H8141","of the years",128,140],["H2416","of my life",141,151],["H5381","been, and have not attained",152,179],["H3117","unto the days",180,193],["H8141","of the years",194,206],["H2416","of the life",207,218],["H0001","of my fathers",219,232],["H3117","in the days",233,244],["H4033","of their pilgrimage",245,264]]},"47:10":{"text":"And Jacob blessed Pharaoh, and went out from before Pharaoh.","words":[["H3290","And Jacob",0,9],["H1288","blessed",10,17],["H6547","Pharaoh",18,25],["H3318","and went out",27,39],["H6440","from before",40,51],["H6547","Pharaoh",52,59]]},"47:11":{"text":"And Joseph placed his father and his brethren, and gave them a possession in the land of Egypt, in the best of the land, in the land of Rameses, as Pharaoh had commanded.","words":[["H3130","And Joseph",0,10],["H3427","placed",11,17],["H0001","his father",18,28],["H0251","and his brethren",29,45],["H5414","and gave",47,55],["H0272","them a possession",56,73],["H0776","in the land",74,85],["H4714","of Egypt",86,94],["H4315","in the best",96,107],["H0776","of the land",108,119],["H0776","in the land",121,132],["H7486","of Rameses",133,143],["H6547","as Pharaoh",145,155],["H6680","had commanded",156,169]]},"47:12":{"text":"And Joseph nourished his father, and his brethren, and all his father's household, with bread, according to their families.","words":[["H3130","And Joseph",0,10],["H3557","nourished",11,20],["H0001","his father",21,31],["H0251","and his brethren",33,49],["H0001","and all his father's",51,71],["H1004","household",72,81],["H3899","with bread",83,93],["H6310","according",95,104],["H2945","to their families",105,122]]},"47:13":{"text":"And there was no bread in all the land; for the famine was very sore, so that the land of Egypt and all the land of Canaan fainted by reason of the famine.","words":[["H3899","And there was no bread",0,22],["H0776","in all the land",23,38],["H7458","for the famine",40,54],["H3966","was very",55,63],["H3515","sore",64,68],["H0776","so that the land",70,86],["H4714","of Egypt",87,95],["H0776","and all the land",96,112],["H3667","of Canaan",113,122],["H3856","fainted",123,130],["H6440","by reason",131,140],["H7458","of the famine",141,154]]},"47:14":{"text":"And Joseph gathered up all the money that was found in the land of Egypt, and in the land of Canaan, for the corn which they bought: and Joseph brought the money into Pharaoh's house.","words":[["H3130","And Joseph",0,10],["H3950","gathered up",11,22],["H3701","all the money",23,36],["H4672","that was found",37,51],["H0776","in the land",52,63],["H4714","of Egypt",64,72],["H0776","and in the land",74,89],["H3667","of Canaan",90,99],["H7668","for the corn",101,113],["H7666","which they bought",114,131],["H3130","and Joseph",133,143],["H0935","brought",144,151],["H3701","the money",152,161],["H6547","into Pharaoh's",162,176],["H1004","house",177,182]]},"47:15":{"text":"And when money failed in the land of Egypt, and in the land of Canaan, all the Egyptians came unto Joseph, and said, Give us bread: for why should we die in thy presence? for the money faileth.","words":[["H3701","And when money",0,14],["H8552","failed",15,21],["H0776","in the land",22,33],["H4714","of Egypt",34,42],["H0776","and in the land",44,59],["H3667","of Canaan",60,69],["H4714","all the Egyptians",71,88],["H0935","came",89,93],["H3130","unto Joseph",94,105],["H0559","and said",107,115],["H3051","Give",117,121],["H3899","us bread",122,130],["H4191","for why should we die",132,153],["H3701","in thy presence? for the money",154,184],["H0656","faileth",185,192]]},"47:16":{"text":"And Joseph said, Give your cattle; and I will give you for your cattle, if money fail.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H3051","Give",17,21],["H4735","your cattle",22,33],["H5414","and I will give",35,50],["H4735","you for your cattle",51,70],["H3701","if money",72,80],["H0656","fail",81,85]]},"47:17":{"text":"And they brought their cattle unto Joseph: and Joseph gave them bread in exchange for horses, and for the flocks, and for the cattle of the herds, and for the asses: and he fed them with bread for all their cattle for that year.","words":[["H0935","And they brought",0,16],["H4735","their cattle",17,29],["H3130","unto Joseph",30,41],["H3130","and Joseph",43,53],["H5414","gave",54,58],["H3899","them bread",59,69],["H5483","in exchange for horses",70,92],["H6629","and for the flocks",94,112],["H4735","and for the cattle",114,132],["H1241","of the herds",133,145],["H2543","and for the asses",147,164],["H5095","and he fed",166,176],["H3899","them with bread",177,192],["H4735","for all their cattle",193,213],["H8141","for that year",214,227]]},"47:18":{"text":"When that year was ended, they came unto him the second year, and said unto him, We will not hide it from my lord, how that our money is spent; my lord also hath our herds of cattle; there is not ought left in the sight of my lord, but our bodies, and our lands:","words":[["H8141","When that year",0,14],["H8552","was ended",15,24],["H0935","they came",26,35],["H8145","unto him the second",36,55],["H8141","year",56,60],["H0559","and said",62,70],["H3582","unto him, We will not hide",71,97],["H0113","it from my lord",98,113],["H3701","how that our money",115,133],["H8552","is spent",134,142],["H0113","my lord",144,151],["H0413","also hath",152,161],["H4735","our herds",162,171],["H0929","of cattle",172,181],["H7604","there is not ought left",183,206],["H6440","in the sight",207,219],["H0113","of my lord",220,230],["H1472","but our bodies",232,246],["H0127","and our lands",248,261]]},"47:19":{"text":"Wherefore shall we die before thine eyes, both we and our land? buy us and our land for bread, and we and our land will be servants unto Pharaoh: and give us seed, that we may live, and not die, that the land be not desolate.","words":[["H4191","Wherefore shall we die",0,22],["H5869","before thine eyes",23,40],["H0127","both we and our land",42,62],["H7069","buy",64,67],["H0127","us and our land",68,83],["H3899","for bread",84,93],["H0127","and we and our land",95,114],["H5650","will be servants",115,131],["H6547","unto Pharaoh",132,144],["H5414","and give",146,154],["H2233","us seed",155,162],["H2421","that we may live",164,180],["H4191","and not die",182,193],["H0127","that the land",195,208],["H3456","be not desolate",209,224]]},"47:20":{"text":"And Joseph bought all the land of Egypt for Pharaoh; for the Egyptians sold every man his field, because the famine prevailed over them: so the land became Pharaoh's.","words":[["H3130","And Joseph",0,10],["H7069","bought",11,17],["H0127","all the land",18,30],["H4714","of Egypt",31,39],["H6547","for Pharaoh",40,51],["H4714","for the Egyptians",53,70],["H4376","sold",71,75],["H0376","every man",76,85],["H7704","his field",86,95],["H7458","because the famine",97,115],["H2388","prevailed",116,125],["H0776","over them: so the land",126,148],["H6547","became Pharaoh's",149,165]]},"47:21":{"text":"And as for the people, he removed them to cities from one end of the borders of Egypt even to the other end thereof.","words":[["H5971","And as for the people",0,21],["H5674","he removed",23,33],["H5892","them to cities",34,48],["H7097","from one end",49,61],["H1366","of the borders",62,76],["H4714","of Egypt",77,85],["H7097","even to the other end",86,107]]},"47:22":{"text":"Only the land of the priests bought he not; for the priests had a portion assigned them of Pharaoh, and did eat their portion which Pharaoh gave them: wherefore they sold not their lands.","words":[["H0127","Only the land",0,13],["H3548","of the priests",14,28],["H7069","bought he",29,38],["H3548","not; for the priests",39,59],["H2706","had a portion",60,73],["H6547","assigned them of Pharaoh",74,98],["H0398","and did eat",100,111],["H2706","their portion",112,125],["H6547","which Pharaoh",126,139],["H5414","gave",140,144],["H4376","them: wherefore they sold",145,170],["H0127","not their lands",171,186]]},"47:23":{"text":"Then Joseph said unto the people, Behold, I have bought you this day and your land for Pharaoh: lo, here is seed for you, and ye shall sow the land.","words":[["H3130","Then Joseph",0,11],["H0559","said",12,16],["H5971","unto the people",17,32],["H7069","Behold, I have bought",34,55],["H0853","",-1,-1],["H3117","you this day",56,68],["H0127","and your land",69,82],["H6547","for Pharaoh",83,94],["H1887","lo",96,98],["H2233","here is seed",100,112],["H2232","for you, and ye shall sow",113,138],["H0127","the land",139,147]]},"47:24":{"text":"And it shall come to pass in the increase, that ye shall give the fifth part unto Pharaoh, and four parts shall be your own, for seed of the field, and for your food, and for them of your households, and for food for your little ones.","words":[["H8393","And it shall come to pass in the increase",0,41],["H5414","that ye shall give",43,61],["H2549","the fifth",62,71],["H6547","part unto Pharaoh",72,89],["H0702","and four",91,99],["H3027","parts",100,105],["H2233","shall be your own, for seed",106,133],["H7704","of the field",134,146],["H0400","and for your food",148,165],["H1004","and for them of your households",167,198],["H0398","and for food",200,212],["H2945","for your little ones",213,233]]},"47:25":{"text":"And they said, Thou hast saved our lives: let us find grace in the sight of my lord, and we will be Pharaoh's servants.","words":[["H0559","And they said",0,13],["H2421","Thou hast saved our lives",15,40],["H4672","let us find",42,53],["H2580","grace",54,59],["H5869","in the sight",60,72],["H0113","of my lord",73,83],["H6547","and we will be Pharaoh's",85,109],["H5650","servants",110,118]]},"47:26":{"text":"And Joseph made it a law over the land of Egypt unto this day, that Pharaoh should have the fifth part; except the land of the priests only, which became not Pharaoh's.","words":[["H3130","And Joseph",0,10],["H7760","made",11,15],["H2706","it a law",16,24],["H0127","over the land",25,38],["H4714","of Egypt",39,47],["H3117","unto this day",48,61],["H6547","that Pharaoh",63,75],["H2569","should have the fifth",76,97],["H7535","part; except",98,110],["H0127","the land",111,119],["H3548","of the priests",120,134],["H6547","only, which became not Pharaoh's",135,167]]},"47:27":{"text":"And Israel dwelt in the land of Egypt, in the country of Goshen; and they had possessions therein, and grew, and multiplied exceedingly.","words":[["H3478","And Israel",0,10],["H3427","dwelt",11,16],["H0776","in the land",17,28],["H4714","of Egypt",29,37],["H0776","in the country",39,53],["H1657","of Goshen",54,63],["H0270","and they had possessions",65,89],["H6509","therein, and grew",90,107],["H7235","and multiplied",109,123],["H3966","exceedingly",124,135]]},"47:28":{"text":"And Jacob lived in the land of Egypt seventeen years: so the whole age of Jacob was an hundred forty and seven years.","words":[["H3290","And Jacob",0,9],["H2421","lived",10,15],["H0776","in the land",16,27],["H4714","of Egypt",28,36],["H6240","seventeen",37,46],["H7651","seventeen",37,46],["H8141","years",47,52],["H2416","so the whole age",54,70],["H3117","so the whole age",54,70],["H3290","of Jacob",71,79],["H3967","was an hundred",80,94],["H0705","forty",95,100],["H8141","forty",95,100],["H7651","and seven",101,110],["H8141","years",111,116]]},"47:29":{"text":"And the time drew nigh that Israel must die: and he called his son Joseph, and said unto him, If now I have found grace in thy sight, put, I pray thee, thy hand under my thigh, and deal kindly and truly with me; bury me not, I pray thee, in Egypt:","words":[["H3117","And the time",0,12],["H7126","drew nigh",13,22],["H3478","that Israel",23,34],["H4191","must die",35,43],["H7121","and he called",45,58],["H1121","his son",59,66],["H3130","Joseph",67,73],["H0559","and said",75,83],["H4672","unto him, If now I have found",84,113],["H2580","grace",114,119],["H5869","in thy sight",120,132],["H7760","put",134,137],["H3027","I pray thee, thy hand",139,160],["H3409","under my thigh",161,175],["H6213","and deal",177,185],["H2617","kindly",186,192],["H0571","and truly",193,202],["H6912","with me; bury",203,216],["H4714","me not, I pray thee, in Egypt",217,246]]},"47:30":{"text":"But I will lie with my fathers, and thou shalt carry me out of Egypt, and bury me in their buryingplace. And he said, I will do as thou hast said.","words":[["H7901","But I will lie",0,14],["H0001","with my fathers",15,30],["H5375","and thou shalt carry",32,52],["H4714","me out of Egypt",53,68],["H6912","and bury",70,78],["H6900","me in their buryingplace",79,103],["H0559","And he said",105,116],["H6213","I will do",118,127],["H1697","as thou hast said",128,145]]},"47:31":{"text":"And he said, Swear unto me. And he sware unto him. And Israel bowed himself upon the bed's head.","words":[["H0559","And he said",0,11],["H7650","Swear",13,18],["H7650","unto me. And he sware",19,40],["H3478","unto him. And Israel",41,61],["H7812","bowed",62,67],["H4296","himself upon the bed's",68,90],["H7218","head",91,95]]},"48:1":{"text":"And it came to pass after these things, that one told Joseph, Behold, thy father is sick: and he took with him his two sons, Manasseh and Ephraim.","words":[["H0310","And it came to pass after",0,25],["H1697","these things",26,38],["H0559","that one told",40,53],["H3130","Joseph",54,60],["H0001","Behold, thy father",62,80],["H2470","is sick",81,88],["H3947","and he took",90,101],["H8147","with him his two",102,118],["H1121","sons",119,123],["H4519","Manasseh",125,133],["H0669","and Ephraim",134,145]]},"48:2":{"text":"And one told Jacob, and said, Behold, thy son Joseph cometh unto thee: and Israel strengthened himself, and sat upon the bed.","words":[["H5046","And one told",0,12],["H3290","Jacob",13,18],["H0559","and said",20,28],["H1121","Behold, thy son",30,45],["H3130","Joseph",46,52],["H0935","cometh",53,59],["H3478","unto thee: and Israel",60,81],["H2388","strengthened",82,94],["H3427","himself, and sat",95,111],["H4296","upon the bed",112,124]]},"48:3":{"text":"And Jacob said unto Joseph, God Almighty appeared unto me at Luz in the land of Canaan, and blessed me,","words":[["H3290","And Jacob",0,9],["H0559","said",10,14],["H3130","unto Joseph",15,26],["H0410","God",28,31],["H7706","Almighty",32,40],["H7200","appeared",41,49],["H3870","unto me at Luz",50,64],["H0776","in the land",65,76],["H3667","of Canaan",77,86],["H1288","and blessed",88,99]]},"48:4":{"text":"And said unto me, Behold, I will make thee fruitful, and multiply thee, and I will make of thee a multitude of people; and will give this land to thy seed after thee for an everlasting possession.","words":[["H0559","And said",0,8],["H6509","unto me, Behold, I will make thee fruitful",9,51],["H7235","and multiply",53,65],["H5414","thee, and I will make",66,87],["H6951","of thee a multitude",88,107],["H5971","of people",108,117],["H5414","and will give",119,132],["H0776","this land",133,142],["H2233","to thy seed",143,154],["H0310","after thee",155,165],["H5769","for an everlasting",166,184],["H0272","possession",185,195]]},"48:5":{"text":"And now thy two sons, Ephraim and Manasseh, which were born unto thee in the land of Egypt before I came unto thee into Egypt, are mine; as Reuben and Simeon, they shall be mine.","words":[["H8147","And now thy two",0,15],["H1121","sons",16,20],["H0669","Ephraim",22,29],["H4519","and Manasseh",30,42],["H3205","which were born",44,59],["H0776","unto thee in the land",60,81],["H4714","of Egypt",82,90],["H5704","before",91,97],["H0935","I came",98,104],["H4714","unto thee into Egypt",105,125],["H7205","are mine; as Reuben",127,146],["H8095","and Simeon",147,157]]},"48:6":{"text":"And thy issue, which thou begettest after them, shall be thine, and shall be called after the name of their brethren in their inheritance.","words":[["H4138","And thy issue",0,13],["H3205","which thou begettest",15,35],["H0310","after",36,41],["H7121","them, shall be thine, and shall be called",42,83],["H5921","after",84,89],["H8034","the name",90,98],["H0251","of their brethren",99,116],["H5159","in their inheritance",117,137]]},"48:7":{"text":"And as for me, when I came from Padan, Rachel died by me in the land of Canaan in the way, when yet there was but a little way to come unto Ephrath: and I buried her there in the way of Ephrath; the same is Bethlehem.","words":[["H0935","And as for me, when I came",0,26],["H6307","from Padan",27,37],["H7354","Rachel",39,45],["H4191","died",46,50],["H0776","by me in the land",51,68],["H3667","of Canaan",69,78],["H1870","in the way",79,89],["H5750","when",91,95],["H3530","yet there was but a little",96,122],["H0776","way",123,126],["H0935","to come",127,134],["H0672","unto Ephrath",135,147],["H6912","and I buried her",149,165],["H1870","there in the way",166,182],["H0672","of Ephrath",183,193],["H1035","the same is Bethlehem",195,216]]},"48:8":{"text":"And Israel beheld Joseph's sons, and said, Who are these?","words":[["H3478","And Israel",0,10],["H7200","beheld",11,17],["H3130","Joseph's",18,26],["H1121","sons",27,31],["H0559","and said",33,41]]},"48:9":{"text":"And Joseph said unto his father, They are my sons, whom God hath given me in this place. And he said, Bring them, I pray thee, unto me, and I will bless them.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H0001","unto his father",16,31],["H1121","They are my sons",33,49],["H0430","whom God",51,59],["H5414","hath given",60,70],["H0559","me in this place. And he said",71,100],["H3947","Bring them",102,112],["H1288","I pray thee, unto me, and I will bless",114,152]]},"48:10":{"text":"Now the eyes of Israel were dim for age, so that he could not see. And he brought them near unto him; and he kissed them, and embraced them.","words":[["H5869","Now the eyes",0,12],["H3478","of Israel",13,22],["H3513","were dim",23,31],["H2207","for age",32,39],["H3201","so that he could",41,57],["H7200","not see",58,65],["H5066","And he brought them near",67,91],["H5401","unto him; and he kissed",92,115],["H2263","them, and embraced",116,134]]},"48:11":{"text":"And Israel said unto Joseph, I had not thought to see thy face: and, lo, God hath shewed me also thy seed.","words":[["H3478","And Israel",0,10],["H0559","said",11,15],["H3130","unto Joseph",16,27],["H6419","I had not thought",29,46],["H7200","to see",47,53],["H6440","thy face",54,62],["H0430","and, lo, God",64,76],["H7200","hath shewed",77,88],["H2233","me also thy seed",89,105]]},"48:12":{"text":"And Joseph brought them out from between his knees, and he bowed himself with his face to the earth.","words":[["H3130","And Joseph",0,10],["H3318","brought them out",11,27],["H5973","from between",28,40],["H1290","his knees",41,50],["H7812","and he bowed",52,64],["H0639","himself with his face",65,86],["H0776","to the earth",87,99]]},"48:13":{"text":"And Joseph took them both, Ephraim in his right hand toward Israel's left hand, and Manasseh in his left hand toward Israel's right hand, and brought them near unto him.","words":[["H3130","And Joseph",0,10],["H3947","took",11,15],["H8147","them both",16,25],["H0669","Ephraim",27,34],["H3225","in his right hand",35,52],["H3478","toward Israel's",53,68],["H8040","left hand",69,78],["H4519","and Manasseh",80,92],["H8040","in his left hand",93,109],["H3478","toward Israel's",110,125],["H3225","right hand",126,136],["H5066","and brought them near",138,159]]},"48:14":{"text":"And Israel stretched out his right hand, and laid it upon Ephraim's head, who was the younger, and his left hand upon Manasseh's head, guiding his hands wittingly; for Manasseh was the firstborn.","words":[["H3478","And Israel",0,10],["H7971","stretched out",11,24],["H3225","his right hand",25,39],["H7896","and laid",41,49],["H0669","it upon Ephraim's",50,67],["H7218","head",68,72],["H6810","who was the younger",74,93],["H8040","and his left hand",95,112],["H4519","upon Manasseh's",113,128],["H7218","head",129,133],["H7919","guiding",135,142],["H3027","his hands",143,152],["H7919","wittingly",153,162],["H4519","for Manasseh",164,176],["H1060","was the firstborn",177,194]]},"48:15":{"text":"And he blessed Joseph, and said, God, before whom my fathers Abraham and Isaac did walk, the God which fed me all my life long unto this day,","words":[["H1288","And he blessed",0,14],["H3130","Joseph",15,21],["H0559","and said",23,31],["H0430","God",33,36],["H6440","before",38,44],["H0001","whom my fathers",45,60],["H0085","Abraham",61,68],["H3327","and Isaac",69,78],["H1980","did walk",79,87],["H0430","the God",89,96],["H7462","which fed",97,106],["H5750","me all my life long",107,126],["H3117","unto this day",127,140]]},"48:16":{"text":"The Angel which redeemed me from all evil, bless the lads; and let my name be named on them, and the name of my fathers Abraham and Isaac; and let them grow into a multitude in the midst of the earth.","words":[["H4397","The Angel",0,9],["H1350","which redeemed",10,24],["H7451","me from all evil",25,41],["H1288","bless",43,48],["H5288","the lads",49,57],["H8034","and let my name",59,74],["H7121","be named",75,83],["H8034","on them, and the name",84,105],["H0001","of my fathers",106,119],["H0085","Abraham",120,127],["H3327","and Isaac",128,137],["H1711","and let them grow",139,156],["H7230","into a multitude",157,173],["H7130","in the midst",174,186],["H0776","of the earth",187,199]]},"48:17":{"text":"And when Joseph saw that his father laid his right hand upon the head of Ephraim, it displeased him: and he held up his father's hand, to remove it from Ephraim's head unto Manasseh's head.","words":[["H3130","And when Joseph",0,15],["H7200","saw",16,19],["H0001","that his father",20,35],["H7896","laid",36,40],["H3225","his right",41,50],["H3027","hand",51,55],["H7218","upon the head",56,69],["H0669","of Ephraim",70,80],["H3415","it displeased",82,95],["H5869","it displeased",82,95],["H8551","him: and he held up",96,115],["H0001","his father's",116,128],["H3027","hand",129,133],["H5493","to remove",135,144],["H0669","it from Ephraim's",145,162],["H7218","head",163,167],["H4519","unto Manasseh's",168,183],["H7218","head",184,188]]},"48:18":{"text":"And Joseph said unto his father, Not so, my father: for this is the firstborn; put thy right hand upon his head.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H0001","unto his father",16,31],["H0001","Not so, my father",33,50],["H1060","for this is the firstborn",52,77],["H7760","put",79,82],["H3225","thy right hand",83,97],["H7218","upon his head",98,111]]},"48:19":{"text":"And his father refused, and said, I know it, my son, I know it: he also shall become a people, and he also shall be great: but truly his younger brother shall be greater than he, and his seed shall become a multitude of nations.","words":[["H0001","And his father",0,14],["H3985","refused",15,22],["H0559","and said",24,32],["H3045","I know",34,40],["H1121","it, my son",41,51],["H3045","I know",53,59],["H5971","it: he also shall become a people",60,93],["H1431","and he also shall be great",95,121],["H0199","but truly",123,132],["H6996","his younger",133,144],["H0251","brother",145,152],["H1431","shall be greater",153,169],["H2233","than he, and his seed",170,191],["H4393","shall become a multitude",192,216],["H1471","of nations",217,227]]},"48:20":{"text":"And he blessed them that day, saying, In thee shall Israel bless, saying, God make thee as Ephraim and as Manasseh: and he set Ephraim before Manasseh.","words":[["H1288","And he blessed",0,14],["H3117","them that day",15,28],["H0559","saying",30,36],["H3478","In thee shall Israel",38,58],["H1288","bless",59,64],["H0559","saying",66,72],["H0430","God",74,77],["H7760","make",78,82],["H0669","thee as Ephraim",83,98],["H4519","and as Manasseh",99,114],["H7760","and he set",116,126],["H0669","Ephraim",127,134],["H6440","before",135,141],["H4519","Manasseh",142,150]]},"48:21":{"text":"And Israel said unto Joseph, Behold, I die: but God shall be with you, and bring you again unto the land of your fathers.","words":[["H3478","And Israel",0,10],["H0559","said",11,15],["H3130","unto Joseph",16,27],["H4191","Behold, I die",29,42],["H0430","but God",44,51],["H7725","shall be with you, and bring you again",52,90],["H0776","unto the land",91,104],["H0001","of your fathers",105,120]]},"48:22":{"text":"Moreover I have given to thee one portion above thy brethren, which I took out of the hand of the Amorite with my sword and with my bow.","words":[["H5414","Moreover I have given",0,21],["H0259","to thee one",22,33],["H7926","portion",34,41],["H0251","above thy brethren",42,60],["H3947","which I took",62,74],["H3027","out of the hand",75,90],["H0567","of the Amorite",91,105],["H2719","with my sword",106,119],["H7198","and with my bow",120,135]]},"49:1":{"text":"And Jacob called unto his sons, and said, Gather yourselves together, that I may tell you that which shall befall you in the last days.","words":[["H3290","And Jacob",0,9],["H7121","called",10,16],["H1121","unto his sons",17,30],["H0559","and said",32,40],["H0622","Gather yourselves together",42,68],["H5046","that I may tell",70,85],["H7122","you that which shall befall",86,113],["H0319","you in the last",114,129],["H3117","days",130,134]]},"49:2":{"text":"Gather yourselves together, and hear, ye sons of Jacob; and hearken unto Israel your father.","words":[["H6908","Gather yourselves together",0,26],["H8085","and hear",28,36],["H1121","ye sons",38,45],["H3290","of Jacob",46,54],["H8085","and hearken",56,67],["H3478","unto Israel",68,79],["H0001","your father",80,91]]},"49:3":{"text":"Reuben, thou art my firstborn, my might, and the beginning of my strength, the excellency of dignity, and the excellency of power:","words":[["H7205","Reuben",0,6],["H1060","thou art my firstborn",8,29],["H3581","my might",31,39],["H7225","and the beginning",41,58],["H0202","of my strength",59,73],["H3499","the excellency",75,89],["H7613","of dignity",90,100],["H3499","and the excellency",102,120],["H5794","of power",121,129]]},"49:4":{"text":"Unstable as water, thou shalt not excel; because thou wentest up to thy father's bed; then defiledst thou it: he went up to my couch.","words":[["H6349","Unstable",0,8],["H4325","as water",9,17],["H3498","thou shalt not excel",19,39],["H5927","because thou wentest up",41,64],["H0001","to thy father's",65,80],["H4904","bed",81,84],["H2490","then defiledst thou",86,105],["H5927","it: he went up",106,120],["H3326","to my couch",121,132]]},"49:5":{"text":"Simeon and Levi are brethren; instruments of cruelty are in their habitations.","words":[["H8095","Simeon",0,6],["H3878","and Levi",7,15],["H0251","are brethren",16,28],["H3627","instruments",30,41],["H2555","of cruelty",42,52],["H4380","are in their habitations",53,77]]},"49:6":{"text":"O my soul, come not thou into their secret; unto their assembly, mine honour, be not thou united: for in their anger they slew a man, and in their selfwill they digged down a wall.","words":[["H5315","O my soul",0,9],["H0935","come",11,15],["H5475","not thou into their secret",16,42],["H6951","unto their assembly",44,63],["H3519","mine honour",65,76],["H3161","be not thou united",78,96],["H0639","for in their anger",98,116],["H2026","they slew",117,126],["H0376","a man",127,132],["H7522","and in their selfwill",134,155],["H6131","they digged down",156,172],["H7794","a wall",173,179]]},"49:7":{"text":"Cursed be their anger, for it was fierce; and their wrath, for it was cruel: I will divide them in Jacob, and scatter them in Israel.","words":[["H0779","Cursed",0,6],["H0639","be their anger",7,21],["H5794","for it was fierce",23,40],["H5678","and their wrath",42,57],["H7185","for it was cruel",59,75],["H2505","I will divide",77,90],["H3290","them in Jacob",91,104],["H6327","and scatter",106,117],["H3478","them in Israel",118,132]]},"49:8":{"text":"Judah, thou art he whom thy brethren shall praise: thy hand shall be in the neck of thine enemies; thy father's children shall bow down before thee.","words":[["H3063","Judah",0,5],["H0251","thou art he whom thy brethren",7,36],["H3034","shall praise",37,49],["H3027","thy hand",51,59],["H6203","shall be in the neck",60,80],["H0341","of thine enemies",81,97],["H0001","thy father's",99,111],["H1121","children",112,120],["H7812","shall bow down",121,135]]},"49:9":{"text":"Judah is a lion's whelp: from the prey, my son, thou art gone up: he stooped down, he couched as a lion, and as an old lion; who shall rouse him up?","words":[["H3063","Judah",0,5],["H0738","is a lion's",6,17],["H1482","whelp",18,23],["H2964","from the prey",25,38],["H1121","my son",40,46],["H5927","thou art gone up",48,64],["H3766","he stooped down",66,81],["H7257","he couched",83,93],["H0738","as a lion",94,103],["H3833","and as an old lion",105,123],["H6965","who shall rouse him up",125,147]]},"49:10":{"text":"The sceptre shall not depart from Judah, nor a lawgiver from between his feet, until Shiloh come; and unto him shall the gathering of the people be.","words":[["H7626","The sceptre",0,11],["H5493","shall not depart",12,28],["H3063","from Judah",29,39],["H2710","nor a lawgiver",41,55],["H7272","from between his feet",56,77],["H3588","until",79,84],["H7886","Shiloh",85,91],["H0935","come",92,96],["H3349","and unto him shall the gathering",98,130],["H5971","of the people",131,144]]},"49:11":{"text":"Binding his foal unto the vine, and his ass's colt unto the choice vine; he washed his garments in wine, and his clothes in the blood of grapes:","words":[["H0631","Binding",0,7],["H5895","his foal",8,16],["H1612","unto the vine",17,30],["H0860","and his ass's",32,45],["H1121","colt",46,50],["H8321","unto the choice vine",51,71],["H3526","he washed",73,82],["H3830","his garments",83,95],["H3196","in wine",96,103],["H5497","and his clothes",105,120],["H1818","in the blood",121,133],["H6025","of grapes",134,143]]},"49:12":{"text":"His eyes shall be red with wine, and his teeth white with milk.","words":[["H5869","His eyes",0,8],["H2447","shall be red",9,21],["H3196","with wine",22,31],["H8127","and his teeth",33,46],["H3836","white",47,52],["H2461","with milk",53,62]]},"49:13":{"text":"Zebulun shall dwell at the haven of the sea; and he shall be for an haven of ships; and his border shall be unto Zidon.","words":[["H2074","Zebulun",0,7],["H7931","shall dwell",8,19],["H2348","at the haven",20,32],["H3220","of the sea",33,43],["H2348","and he shall be for an haven",45,73],["H0591","of ships",74,82],["H3411","and his border",84,98],["H6721","shall be unto Zidon",99,118]]},"49:14":{"text":"Issachar is a strong ass couching down between two burdens:","words":[["H3485","Issachar",0,8],["H1634","is a strong",9,20],["H2543","ass",21,24],["H7257","couching down",25,38],["H4942","between two burdens",39,58]]},"49:15":{"text":"And he saw that rest was good, and the land that it was pleasant; and bowed his shoulder to bear, and became a servant unto tribute.","words":[["H7200","And he saw",0,10],["H4496","that rest",11,20],["H2896","was good",21,29],["H0776","and the land",31,43],["H5276","that it was pleasant",44,64],["H5186","and bowed",66,75],["H7926","his shoulder",76,88],["H5445","to bear",89,96],["H5647","and became a servant",98,118],["H4522","unto tribute",119,131]]},"49:16":{"text":"Dan shall judge his people, as one of the tribes of Israel.","words":[["H1835","Dan",0,3],["H1777","shall judge",4,15],["H5971","his people",16,26],["H0259","as one",28,34],["H7626","of the tribes",35,48],["H3478","of Israel",49,58]]},"49:17":{"text":"Dan shall be a serpent by the way, an adder in the path, that biteth the horse heels, so that his rider shall fall backward.","words":[["H1835","Dan",0,3],["H5175","shall be a serpent",4,22],["H1870","by the way",23,33],["H8207","an adder",35,43],["H0734","in the path",44,55],["H5391","that biteth",57,68],["H5483","the horse",69,78],["H6119","heels",79,84],["H7392","so that his rider",86,103],["H5307","shall fall",104,114],["H0268","backward",115,123]]},"49:18":{"text":"I have waited for thy salvation, O LORD.","words":[["H6960","I have waited for",0,17],["H3444","thy salvation",18,31],["H3068","O LORD",33,39]]},"49:19":{"text":"Gad, a troop shall overcome him: but he shall overcome at the last.","words":[["H1410","Gad",0,3],["H1416","a troop",5,12],["H1464","shall overcome",13,27],["H1464","him: but he shall overcome",28,54],["H6119","at the last",55,66]]},"49:20":{"text":"Out of Asher his bread shall be fat, and he shall yield royal dainties.","words":[["H0836","Out of Asher",0,12],["H3899","his bread",13,22],["H8082","shall be fat",23,35],["H5414","and he shall yield",37,55],["H4428","royal",56,61],["H4574","dainties",62,70]]},"49:21":{"text":"Naphtali is a hind let loose: he giveth goodly words.","words":[["H5321","Naphtali",0,8],["H0355","is a hind",9,18],["H7971","let loose",19,28],["H5414","he giveth",30,39],["H8233","goodly",40,46],["H0561","words",47,52]]},"49:22":{"text":"Joseph is a fruitful bough, even a fruitful bough by a well; whose branches run over the wall:","words":[["H3130","Joseph",0,6],["H6509","is a fruitful",7,20],["H1121","bough",21,26],["H6509","even a fruitful",28,43],["H1121","bough",44,49],["H5869","by a well",50,59],["H1323","whose branches",61,75],["H6805","run",76,79],["H7791","over the wall",80,93]]},"49:23":{"text":"The archers have sorely grieved him, and shot at him, and hated him:","words":[["H1167","The archers",0,11],["H2671","The archers",0,11],["H4843","have sorely grieved him",12,35],["H7232","and shot",37,45],["H7852","at him, and hated him",46,67]]},"49:24":{"text":"But his bow abode in strength, and the arms of his hands were made strong by the hands of the mighty God of Jacob; (from thence is the shepherd, the stone of Israel:)","words":[["H7198","But his bow",0,11],["H3427","abode",12,17],["H0386","in strength",18,29],["H2220","and the arms",31,43],["H3027","of his hands",44,56],["H6339","were made strong",57,73],["H3027","by the hands",74,86],["H0046","of the mighty",87,100],["H3290","God of Jacob",101,113],["H7462","(from thence is the shepherd",115,143],["H0068","the stone",145,154],["H3478","of Israel",155,164]]},"49:25":{"text":"Even by the God of thy father, who shall help thee; and by the Almighty, who shall bless thee with blessings of heaven above, blessings of the deep that lieth under, blessings of the breasts, and of the womb:","words":[["H0410","Even by the God",0,15],["H0001","of thy father",16,29],["H5826","who shall help",31,45],["H0854","thee; and by",46,58],["H7706","the Almighty",59,71],["H1288","who shall bless",73,88],["H1293","thee with blessings",89,108],["H8064","of heaven",109,118],["H5920","above",119,124],["H1293","blessings",126,135],["H8415","of the deep",136,147],["H7257","that lieth",148,158],["H1293","under, blessings",159,175],["H7699","of the breasts",176,190],["H7356","and of the womb",192,207]]},"49:26":{"text":"The blessings of thy father have prevailed above the blessings of my progenitors unto the utmost bound of the everlasting hills: they shall be on the head of Joseph, and on the crown of the head of him that was separate from his brethren.","words":[["H1293","The blessings",0,13],["H0001","of thy father",14,27],["H1396","have prevailed",28,42],["H1293","above the blessings",43,62],["H2029","of my progenitors",63,80],["H8379","unto the utmost bound",81,102],["H5769","of the everlasting",103,121],["H1389","hills",122,127],["H7218","they shall be on the head",129,154],["H3130","of Joseph",155,164],["H6936","and on the crown of the head",166,194],["H5139","of him that was separate",195,219],["H0251","from his brethren",220,237]]},"49:27":{"text":"Benjamin shall ravin as a wolf: in the morning he shall devour the prey, and at night he shall divide the spoil.","words":[["H1144","Benjamin",0,8],["H2963","shall ravin",9,20],["H2061","as a wolf",21,30],["H1242","in the morning",32,46],["H0398","he shall devour",47,62],["H5706","the prey",63,71],["H6153","and at night",73,85],["H2505","he shall divide",86,101],["H7998","the spoil",102,111]]},"49:28":{"text":"All these are the twelve tribes of Israel: and this is it that their father spake unto them, and blessed them; every one according to his blessing he blessed them.","words":[["H6240","All these are the twelve",0,24],["H8147","All these are the twelve",0,24],["H7626","tribes",25,31],["H3478","of Israel",32,41],["H0001","and this is it that their father",43,75],["H1696","spake",76,81],["H1288","unto them, and blessed",82,104],["H0834","them; every",105,116],["H0376","one",117,120],["H1293","according to his blessing",121,146],["H1288","he blessed",147,157]]},"49:29":{"text":"And he charged them, and said unto them, I am to be gathered unto my people: bury me with my fathers in the cave that is in the field of Ephron the Hittite,","words":[["H6680","And he charged",0,14],["H0559","them, and said",15,29],["H0622","unto them, I am to be gathered",30,60],["H5971","unto my people",61,75],["H6912","bury",77,81],["H0001","me with my fathers",82,100],["H4631","in the cave",101,112],["H7704","that is in the field",113,133],["H6085","of Ephron",134,143],["H2850","the Hittite",144,155]]},"49:30":{"text":"In the cave that is in the field of Machpelah, which is before Mamre, in the land of Canaan, which Abraham bought with the field of Ephron the Hittite for a possession of a buryingplace.","words":[["H4631","In the cave",0,11],["H7704","that is in the field",12,32],["H4375","of Machpelah",33,45],["H6440","which is before",47,62],["H4471","Mamre",63,68],["H0776","in the land",70,81],["H3667","of Canaan",82,91],["H0085","which Abraham",93,106],["H7069","bought",107,113],["H7704","with the field",114,128],["H6085","of Ephron",129,138],["H2850","the Hittite",139,150],["H0272","for a possession",151,167],["H6913","of a buryingplace",168,185]]},"49:31":{"text":"There they buried Abraham and Sarah his wife; there they buried Isaac and Rebekah his wife; and there I buried Leah.","words":[["H6912","There they buried",0,17],["H0085","Abraham",18,25],["H8283","and Sarah",26,35],["H0802","his wife",36,44],["H6912","there they buried",46,63],["H3327","Isaac",64,69],["H7259","and Rebekah",70,81],["H0802","his wife",82,90],["H6912","and there I buried",92,110],["H3812","Leah",111,115]]},"49:32":{"text":"The purchase of the field and of the cave that is therein was from the children of Heth.","words":[["H4735","The purchase",0,12],["H7704","of the field",13,25],["H4631","and of the cave",26,41],["H1121","that is therein was from the children",42,79],["H2845","of Heth",80,87]]},"49:33":{"text":"And when Jacob had made an end of commanding his sons, he gathered up his feet into the bed, and yielded up the ghost, and was gathered unto his people.","words":[["H3290","And when Jacob",0,14],["H3615","had made an end",15,30],["H6680","of commanding",31,44],["H1121","his sons",45,53],["H0622","he gathered up",55,69],["H7272","his feet",70,78],["H4296","into the bed",79,91],["H1478","and yielded up the ghost",93,117],["H0622","and was gathered",119,135],["H5971","unto his people",136,151]]},"50:1":{"text":"And Joseph fell upon his father's face, and wept upon him, and kissed him.","words":[["H3130","And Joseph",0,10],["H5307","fell",11,15],["H0001","upon his father's",16,33],["H6440","face",34,38],["H1058","and wept",40,48],["H5401","upon him, and kissed",49,69]]},"50:2":{"text":"And Joseph commanded his servants the physicians to embalm his father: and the physicians embalmed Israel.","words":[["H3130","And Joseph",0,10],["H6680","commanded",11,20],["H5650","his servants",21,33],["H7495","the physicians",34,48],["H2590","to embalm",49,58],["H0001","his father",59,69],["H7495","and the physicians",71,89],["H2590","embalmed",90,98],["H3478","Israel",99,105]]},"50:3":{"text":"And forty days were fulfilled for him; for so are fulfilled the days of those which are embalmed: and the Egyptians mourned for him threescore and ten days.","words":[["H0705","And forty",0,9],["H3117","days",10,14],["H4390","were fulfilled",15,29],["H4390","for him; for so are fulfilled",30,59],["H3117","the days",60,68],["H2590","of those which are embalmed",69,96],["H4714","and the Egyptians",98,115],["H1058","mourned",116,123],["H7657","for him threescore and ten",124,150],["H3117","days",151,155]]},"50:4":{"text":"And when the days of his mourning were past, Joseph spake unto the house of Pharaoh, saying, If now I have found grace in your eyes, speak, I pray you, in the ears of Pharaoh, saying,","words":[["H3117","And when the days",0,17],["H1068","of his mourning",18,33],["H5674","were past",34,43],["H3130","Joseph",45,51],["H1696","spake",52,57],["H1004","unto the house",58,72],["H6547","of Pharaoh",73,83],["H0559","saying",85,91],["H4672","If now I have found",93,112],["H2580","grace",113,118],["H5869","in your eyes",119,131],["H1696","speak",133,138],["H0241","I pray you, in the ears",140,163],["H6547","of Pharaoh",164,174],["H0559","saying",176,182]]},"50:5":{"text":"My father made me swear, saying, Lo, I die: in my grave which I have digged for me in the land of Canaan, there shalt thou bury me. Now therefore let me go up, I pray thee, and bury my father, and I will come again.","words":[["H0001","My father",0,9],["H7650","made me swear",10,23],["H0559","saying",25,31],["H2009","Lo",33,35],["H4191","I die",37,42],["H6913","in my grave",44,55],["H3738","which I have digged",56,75],["H0776","for me in the land",76,94],["H3667","of Canaan",95,104],["H6912","there shalt thou bury me",106,130],["H5927","Now therefore let me go up",132,158],["H6912","I pray thee, and bury",160,181],["H0001","my father",182,191],["H7725","and I will come again",193,214]]},"50:6":{"text":"And Pharaoh said, Go up, and bury thy father, according as he made thee swear.","words":[["H6547","And Pharaoh",0,11],["H0559","said",12,16],["H5927","Go up",18,23],["H6912","and bury",25,33],["H0001","thy father",34,44],["H7650","according as he made thee swear",46,77]]},"50:7":{"text":"And Joseph went up to bury his father: and with him went up all the servants of Pharaoh, the elders of his house, and all the elders of the land of Egypt,","words":[["H3130","And Joseph",0,10],["H5927","went up",11,18],["H6912","to bury",19,26],["H0001","his father",27,37],["H5927","and with him went up",39,59],["H5650","all the servants",60,76],["H6547","of Pharaoh",77,87],["H2205","the elders",89,99],["H1004","of his house",100,112],["H2205","and all the elders",114,132],["H0776","of the land",133,144],["H4714","of Egypt",145,153]]},"50:8":{"text":"And all the house of Joseph, and his brethren, and his father's house: only their little ones, and their flocks, and their herds, they left in the land of Goshen.","words":[["H1004","And all the house",0,17],["H3130","of Joseph",18,27],["H0251","and his brethren",29,45],["H0001","and his father's",47,63],["H1004","house",64,69],["H2945","only their little ones",71,93],["H6629","and their flocks",95,111],["H1241","and their herds",113,128],["H5800","they left",130,139],["H0776","in the land",140,151],["H1657","of Goshen",152,161]]},"50:9":{"text":"And there went up with him both chariots and horsemen: and it was a very great company.","words":[["H5927","And there went up",0,17],["H7393","with him both chariots",18,40],["H6571","and horsemen",41,53],["H3966","and it was a very",55,72],["H3515","great",73,78],["H4264","company",79,86]]},"50:10":{"text":"And they came to the threshingfloor of Atad, which is beyond Jordan, and there they mourned with a great and very sore lamentation: and he made a mourning for his father seven days.","words":[["H0935","And they came",0,13],["H1637","to the threshingfloor",14,35],["H0329","of Atad",36,43],["H5676","which is beyond",45,60],["H3383","Jordan",61,67],["H5594","and there they mourned",69,91],["H1419","with a great",92,104],["H3966","and very",105,113],["H3515","sore",114,118],["H4553","lamentation",119,130],["H6213","and he made",132,143],["H0060","a mourning",144,154],["H0001","for his father",155,169],["H7651","seven",170,175],["H3117","days",176,180]]},"50:11":{"text":"And when the inhabitants of the land, the Canaanites, saw the mourning in the floor of Atad, they said, This is a grievous mourning to the Egyptians: wherefore the name of it was called Abelmizraim, which is beyond Jordan.","words":[["H3427","And when the inhabitants",0,24],["H0776","of the land",25,36],["H3669","the Canaanites",38,52],["H7200","saw",54,57],["H0060","the mourning",58,70],["H1637","in the floor",71,83],["H0329","of Atad",84,91],["H0559","they said",93,102],["H3515","This is a grievous",104,122],["H0060","mourning",123,131],["H4714","to the Egyptians",132,148],["H8034","wherefore the name of it",150,174],["H7121","was called",175,185],["H0067","Abelmizraim",186,197],["H5676","which is beyond",199,214],["H3383","Jordan",215,221]]},"50:12":{"text":"And his sons did unto him according as he commanded them:","words":[["H1121","And his sons",0,12],["H6213","did",13,16],["H6680","unto him according as he commanded",17,51]]},"50:13":{"text":"For his sons carried him into the land of Canaan, and buried him in the cave of the field of Machpelah, which Abraham bought with the field for a possession of a buryingplace of Ephron the Hittite, before Mamre.","words":[["H1121","For his sons",0,12],["H5375","carried",13,20],["H0776","him into the land",21,38],["H3667","of Canaan",39,48],["H6912","and buried",50,60],["H4631","him in the cave",61,76],["H7704","of the field",77,89],["H4375","of Machpelah",90,102],["H0085","which Abraham",104,117],["H7069","bought",118,124],["H7704","with the field",125,139],["H0272","for a possession",140,156],["H6913","of a buryingplace",157,174],["H6085","of Ephron",175,184],["H2850","the Hittite",185,196],["H6440","before",198,204],["H4471","Mamre",205,210]]},"50:14":{"text":"And Joseph returned into Egypt, he, and his brethren, and all that went up with him to bury his father, after he had buried his father.","words":[["H3130","And Joseph",0,10],["H7725","returned",11,19],["H4714","into Egypt",20,30],["H0251","he, and his brethren",32,52],["H5927","and all that went up",54,74],["H6912","with him to bury",75,91],["H0001","his father",92,102],["H0310","after",104,109],["H6912","he had buried",110,123],["H0001","his father",124,134]]},"50:15":{"text":"And when Joseph's brethren saw that their father was dead, they said, Joseph will peradventure hate us, and will certainly requite us all the evil which we did unto him.","words":[["H3130","And when Joseph's",0,17],["H0251","brethren",18,26],["H7200","saw",27,30],["H0001","that their father",31,48],["H4191","was dead",49,57],["H0559","they said",59,68],["H3130","Joseph",70,76],["H3863","will peradventure",77,94],["H7852","hate us",95,102],["H7725","and will certainly",104,122],["H7725","requite",123,130],["H7451","us all the evil",131,146],["H1580","which we did",147,159]]},"50:16":{"text":"And they sent a messenger unto Joseph, saying, Thy father did command before he died, saying,","words":[["H6680","And they sent a messenger",0,25],["H3130","unto Joseph",26,37],["H0559","saying",39,45],["H0001","Thy father",47,57],["H6680","did command",58,69],["H6440","before",70,76],["H4194","he died",77,84],["H0559","saying",86,92]]},"50:17":{"text":"So shall ye say unto Joseph, Forgive, I pray thee now, the trespass of thy brethren, and their sin; for they did unto thee evil: and now, we pray thee, forgive the trespass of the servants of the God of thy father. And Joseph wept when they spake unto him.","words":[["H0559","So shall ye say",0,15],["H3130","unto Joseph",16,27],["H5375","Forgive",29,36],["H0577","I pray thee",38,49],["H6588","now, the trespass",50,67],["H0251","of thy brethren",68,83],["H2403","and their sin",85,98],["H1580","for they did",100,112],["H7451","unto thee evil",113,127],["H5375","and now, we pray thee, forgive",129,159],["H6588","the trespass",160,172],["H5650","of the servants",173,188],["H0430","of the God",189,199],["H0001","of thy father",200,213],["H3130","And Joseph",215,225],["H1058","wept",226,230],["H1696","when they spake",231,246]]},"50:18":{"text":"And his brethren also went and fell down before his face; and they said, Behold, we be thy servants.","words":[["H0251","And his brethren",0,16],["H3212","also went",17,26],["H5307","and fell down",27,40],["H6440","before his face",41,56],["H0559","and they said",58,71],["H5650","Behold, we be thy servants",73,99]]},"50:19":{"text":"And Joseph said unto them, Fear not: for am I in the place of God?","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H3372","unto them, Fear",16,31],["H0430","not: for am I in the place of God",32,65]]},"50:20":{"text":"But as for you, ye thought evil against me; but God meant it unto good, to bring to pass, as it is this day, to save much people alive.","words":[["H2803","But as for you, ye thought",0,26],["H7451","evil",27,31],["H0430","against me; but God",32,51],["H2803","meant it",52,60],["H2896","unto good",61,70],["H4616","to",72,74],["H6213","bring to pass",75,88],["H3117","as it is this day",90,107],["H2421","to save",109,116],["H7227","much",117,121],["H5971","people",122,128],["H2421","alive",129,134]]},"50:21":{"text":"Now therefore fear ye not: I will nourish you, and your little ones. And he comforted them, and spake kindly unto them.","words":[["H3372","Now therefore fear",0,18],["H3557","ye not: I will nourish",19,41],["H2945","you, and your little ones",42,67],["H5162","And he comforted",69,85],["H1696","them, and spake",86,101],["H3820","kindly",102,108]]},"50:22":{"text":"And Joseph dwelt in Egypt, he, and his father's house: and Joseph lived an hundred and ten years.","words":[["H3130","And Joseph",0,10],["H3427","dwelt",11,16],["H4714","in Egypt",17,25],["H0001","he, and his father's",27,47],["H1004","house",48,53],["H3130","and Joseph",55,65],["H2421","lived",66,71],["H3967","an hundred",72,82],["H6235","and ten",83,90],["H8141","years",91,96]]},"50:23":{"text":"And Joseph saw Ephraim's children of the third generation: the children also of Machir the son of Manasseh were brought up upon Joseph's knees.","words":[["H3130","And Joseph",0,10],["H7200","saw",11,14],["H0669","Ephraim's",15,24],["H1121","children",25,33],["H8029","of the third",34,46],["H1121","generation: the children",47,71],["H4353","also of Machir",72,86],["H1121","the son",87,94],["H4519","of Manasseh",95,106],["H3205","were brought up",107,122],["H3130","upon Joseph's",123,136],["H1290","knees",137,142]]},"50:24":{"text":"And Joseph said unto his brethren, I die: and God will surely visit you, and bring you out of this land unto the land which he sware to Abraham, to Isaac, and to Jacob.","words":[["H3130","And Joseph",0,10],["H0559","said",11,15],["H0251","unto his brethren",16,33],["H4191","I die",35,40],["H0430","and God",42,49],["H6485","will surely",50,61],["H6485","visit",62,67],["H5927","you, and bring you out",68,90],["H0776","of this land",91,103],["H0776","unto the land",104,117],["H7650","which he sware",118,132],["H0085","to Abraham",133,143],["H3327","to Isaac",145,153],["H3290","and to Jacob",155,167]]},"50:25":{"text":"And Joseph took an oath of the children of Israel, saying, God will surely visit you, and ye shall carry up my bones from hence.","words":[["H3130","And Joseph",0,10],["H7650","took an oath",11,23],["H1121","of the children",24,39],["H3478","of Israel",40,49],["H0559","saying",51,57],["H0430","God",59,62],["H6485","will surely",63,74],["H6485","visit",75,80],["H5927","you, and ye shall carry up",81,107],["H6106","my bones",108,116],["H2088","from hence",117,127]]},"50:26":{"text":"So Joseph died, being an hundred and ten years old: and they embalmed him, and he was put in a coffin in Egypt.","words":[["H3130","So Joseph",0,9],["H4191","died",10,14],["H3967","being an hundred",16,32],["H6235","and ten",33,40],["H8141","years",41,46],["H1121","old",47,50],["H2590","and they embalmed",52,69],["H3455","him, and he was put",70,89],["H0727","in a coffin",90,101],["H4714","in Egypt",102,110]]}}};
